UPDATE hadiths SET urdu = 'ہم سے حدیث بیان کی عمرو بن خالد نے، ان کو لیث نے، وہ روایت کرتے ہیں یزید سے، وہ ابوالخیر سے، وہ عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے کہ ایک دن ایک آدمی نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ کون سا اسلام بہتر ہے؟ فرمایا کہ تم کھانا کھلاؤ، اور جس کو پہچانو اس کو بھی اور جس کو نہ پہچانو اس کو بھی، الغرض سب کو سلام کرو۔' WHERE id = 13;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے یہ حدیث بیان کی، وہ کہتے ہیں ان سے مالک نے، وہ عمرو بن یحییٰ المازنی سے نقل کرتے ہیں، وہ اپنے باپ سے روایت کرتے ہیں اور وہ ابو سعید خدری رضی اللہ عنہ اور وہ نبی اکرم صلی اللہ علیہ وسلم سے نقل کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا جب جنتی جنت میں اور دوزخی دوزخ میں داخل ہو جائیں گے۔ اللہ پاک فرمائے گا، جس کے دل میں رائی کے دانے کے برابر ( بھی ) ایمان ہو، اس کو بھی دوزخ سے نکال لو۔ تب ( ایسے لوگ ) دوزخ سے نکال لیے جائیں گے اور وہ جل کر کوئلے کی طرح سیاہ ہو چکے ہوں گے۔ پھر زندگی کی نہر میں یا بارش کے پانی میں ڈالے جائیں گے۔ ( یہاں راوی کو شک ہو گیا ہے کہ اوپر کے راوی نے کون سا لفظ استعمال کیا ) اس وقت وہ دانے کی طرح اگ آئیں گے جس طرح ندی کے کنارے دانے اگ آتے ہیں۔ کیا تم نے نہیں دیکھا کہ دانہ زردی مائل پیچ در پیچ نکلتا ہے۔ وہیب نے کہا کہ ہم سے عمرو نے ( «حياء» کی بجائے ) «حياة»،‏‏‏‏ اور ( «خردل من ايمان» ) کی بجائے ( «خردل من خير» ) کا لفظ بیان کیا۔' WHERE id = 23;
UPDATE hadiths SET urdu = 'ہمارے سامنے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا کہ ہم سے (اسی حدیث کو) بشر نے بیان کیا، ان سے محمد نے، ان سے شعبہ نے، انہوں نے سلیمان سے، انہوں نے علقمہ سے، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے جب سورۃ الانعام کی یہ آیت اتری جو لوگ ایمان لائے اور انہوں نے اپنے ایمان میں گناہوں کی آمیزش نہیں کی تو آپ صلی اللہ علیہ وسلم کے اصحاب نے کہا یا رسول اللہ! یہ تو بہت ہی مشکل ہے۔ ہم میں کون ایسا ہے جس نے گناہ نہیں کیا۔ تب اللہ پاک نے سورۃ لقمان کی یہ آیت اتاری «إن الشرك لظلم عظيم‏» کہ بیشک شرک بڑا ظلم ہے۔' WHERE id = 33;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، ان سے عبدالرزاق نے، انہیں معمر نے ہمام سے خبر دی، وہ ابوہریرہ رضی اللہ عنہ سے نقل کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے کوئی شخص جب اپنے اسلام کو عمدہ بنا لے ( یعنی نفاق اور ریا سے پاک کر لے ) تو ہر نیک کام جو وہ کرتا ہے اس کے عوض دس سے لے کر سات سو گنا تک نیکیاں لکھی جاتی ہیں اور ہر برا کام جو کرتا ہے تو وہ اتنا ہی لکھا جاتا ہے ( جتنا کہ اس نے کیا ہے ) ۔' WHERE id = 43;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زکریا نے، انہوں نے عامر سے، کہا میں نے نعمان بن بشیر رضی اللہ عنہما سے سنا، وہ کہتے تھے میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم فرماتے تھے حلال کھلا ہوا ہے اور حرام بھی کھلا ہوا ہے اور ان دونوں کے درمیان بعض چیزیں شبہ کی ہیں جن کو بہت لوگ نہیں جانتے ( کہ حلال ہیں یا حرام ) پھر جو کوئی شبہ کی چیزوں سے بھی بچ گیا اس نے اپنے دین اور عزت کو بچا لیا اور جو کوئی ان شبہ کی چیزوں میں پڑ گیا اس کی مثال اس چرواہے کی ہے جو ( شاہی محفوظ ) چراگاہ کے آس پاس اپنے جانوروں کو چرائے۔ وہ قریب ہے کہ کبھی اس چراگاہ کے اندر گھس جائے ( اور شاہی مجرم قرار پائے ) سن لو ہر بادشاہ کی ایک چراگاہ ہوتی ہے۔ اللہ کی چراگاہ اس کی زمین پر حرام چیزیں ہیں۔ ( پس ان سے بچو اور ) سن لو بدن میں ایک گوشت کا ٹکڑا ہے جب وہ درست ہو گا سارا بدن درست ہو گا اور جہاں بگڑا سارا بدن بگڑ گیا۔ سن لو وہ ٹکڑا آدمی کا دل ہے۔' WHERE id = 53;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان بن بلال نے بیان کیا، کہا ہم سے عبداللہ بن دینار نے بیان کیا، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ ( ایک مرتبہ ) آپ صلی اللہ علیہ وسلم نے فرمایا درختوں میں سے ایک درخت ایسا ہے کہ اس کے پتے نہیں جھڑتے اور مسلمان کی بھی یہی مثال ہے بتلاؤ وہ کون سا درخت ہے؟ یہ سن کر لوگوں کے خیالات جنگل کے درختوں میں چلے گئے۔ عبداللہ نے کہا کہ میرے دل میں آیا کہ بتلا دوں کہ وہ کھجور کا درخت ہے لیکن ( وہاں بہت سے بزرگ موجود تھے اس لیے ) مجھ کو شرم آئی۔ آخر صحابہ نے عرض کیا یا رسول اللہ! آپ ہی بیان فرما دیجیئے۔ آپ صلی اللہ علیہ وسلم نے بتلایا کہ وہ کھجور کا درخت ہے۔' WHERE id = 63;
UPDATE hadiths SET urdu = 'ہم سے علی (بن مدینی) نے بیان کیا، ان سے سفیان نے، ان سے ابن ابی نجیح نے مجاہد کے واسطے سے نقل کیا، وہ کہتے ہیں کہ میں عبداللہ بن عمر رضی اللہ عنہما کے ساتھ مدینے تک رہا، میں نے ( اس ) ایک حدیث کے سوا ان سے رسول اللہ صلی اللہ علیہ وسلم کی کوئی اور حدیث نہیں سنی، وہ کہتے تھے کہ ہم رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر تھے کہ آپ صلی اللہ علیہ وسلم کے پاس کھجور کا ایک گابھا لایا گیا۔ ( اسے دیکھ کر ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ درختوں میں ایک درخت ایسا ہے اس کی مثال مسلمان کی طرح ہے۔ ( ابن عمر رضی اللہ عنہما کہتے ہیں کہ یہ سن کر ) میں نے ارادہ کیا کہ عرض کروں کہ وہ ( درخت ) کھجور کا ہے مگر چونکہ میں سب میں چھوٹا تھا اس لیے خاموش رہا۔ ( پھر ) رسول اللہ صلی اللہ علیہ وسلم نے خود ہی فرمایا کہ وہ کھجور ہے۔' WHERE id = 73;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا مجھ سے لیث نے، ان سے عقیل نے ابن شہاب کے واسطے سے نقل کیا، وہ حمزہ بن عبداللہ بن عمر سے نقل کرتے ہیں کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا ہے کہ میں سو رہا تھا ( اسی حالت میں ) مجھے دودھ کا ایک پیالہ دیا گیا۔ میں نے ( خوب اچھی طرح ) پی لیا۔ حتیٰ کہ میں نے دیکھا کہ تازگی میرے ناخنوں سے نکل رہی ہے۔ پھر میں نے اپنا بچا ہوا ( دودھ ) عمر بن الخطاب کو دے دیا۔ صحابہ رضی اللہ عنہم نے پوچھا آپ نے اس کی کیا تعبیر لی؟ آپ صلی اللہ علیہ وسلم نے فرمایا علم۔' WHERE id = 83;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، ان سے ابواسامہ نے برید کے واسطے سے بیان کیا، وہ ابوبردہ سے اور وہ ابوموسیٰ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم سے کچھ ایسی باتیں دریافت کی گئیں کہ آپ صلی اللہ علیہ وسلم کو برا معلوم ہوا اور جب ( اس قسم کے سوالات کی ) آپ صلی اللہ علیہ وسلم پر بہت زیادتی کی گئی تو آپ کو غصہ آ گیا۔ پھر آپ صلی اللہ علیہ وسلم نے لوگوں سے فرمایا ( اچھا اب ) مجھ سے جو چاہو پوچھو۔ تو ایک شخص نے دریافت کیا کہ میرا باپ کون ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا، تیرا باپ حذافہ ہے۔ پھر دوسرا آدمی کھڑا ہوا اور اس نے پوچھا کہ یا رسول اللہ! میرا باپ کون ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تیرا باپ سالم شبیہ کا آزاد کردہ غلام ہے۔ آخر عمر رضی اللہ عنہ نے آپ کے چہرہ مبارک کا حال دیکھا تو عرض کیا یا رسول اللہ! ہم ( ان باتوں کے دریافت کرنے سے جو آپ کو ناگوار ہوں ) اللہ سے توبہ کرتے ہیں۔' WHERE id = 93;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، ان سے غندر نے، ان سے شعبہ نے عبدالرحمٰن بن الاصبہانی کے واسطے سے بیان کیا، وہ ذکوان سے، وہ ابوسعید سے اور ابو سعید خدری رضی اللہ عنہ، رسول اللہ صلی اللہ علیہ وسلم سے یہی حدیث روایت کرتے ہیں۔ اور (دوسری سند میں) عبدالرحمٰن الاصبہانی کہتے ہیں کہ میں نے ابوحازم سے سنا، وہ ابوہریرہ سے نقل کرتے ہیں کہ انہوں نے فرمایا کہ ایسے تین ( بچے ) جو ابھی بلوغت کو نہ پہنچے ہوں۔' WHERE id = 103;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم الفضل بن دکین نے بیان کیا، ان سے شیبان نے یحییٰ کے واسطے سے نقل کیا، وہ ابوسلمہ سے، وہ ابوہریرہ رضی اللہ عنہ سے روایت کرتے ہیں کہ قبیلہ خزاعہ ( کے کسی شخص ) نے بنو لیث کے کسی آدمی کو اپنے کسی مقتول کے بدلے میں مار دیا تھا، یہ فتح مکہ والے سال کی بات ہے، رسول اللہ صلی اللہ علیہ وسلم کو یہ خبر دی گئی، آپ نے اپنی اونٹنی پر سوار ہو کر خطبہ پڑھا اور فرمایا کہ اللہ نے مکہ سے قتل یا ہاتھی کو روک لیا۔ امام بخاری رحمہ اللہ فرماتے ہیں اس لفظ کو شک کے ساتھ سمجھو، ایسا ہی ابونعیم وغیرہ نے «القتل» اور «الفيل» کہا ہے۔ ان کے علاوہ دوسرے لوگ «الفيل» کہتے ہیں۔ ( پھر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ) کہ اللہ نے ان پر اپنے رسول اور مسلمان کو غالب کر دیا اور سمجھ لو کہ وہ ( مکہ ) کسی کے لیے حلال نہیں ہوا۔ نہ مجھ سے پہلے اور نہ ( آئندہ ) کبھی ہو گا اور میرے لیے بھی صرف دن کے تھوڑے سے حصہ کے لیے حلال کر دیا گیا تھا۔ سن لو کہ وہ اس وقت حرام ہے۔ نہ اس کا کوئی کانٹا توڑا جائے، نہ اس کے درخت کاٹے جائیں اور اس کی گری پڑی چیزیں بھی وہی اٹھائے جس کا منشاء یہ ہو کہ وہ اس چیز کا تعارف کرا دے گا۔ تو اگر کوئی شخص مارا جائے تو ( اس کے عزیزوں کو ) اختیار ہے دو باتوں کا، یا دیت لیں یا بدلہ۔ اتنے میں ایک یمنی آدمی ( ابوشاہ نامی ) آیا اور کہنے لگا ( یہ مسائل ) میرے لیے لکھوا دیجیئے۔ تب آپ صلی اللہ علیہ وسلم نے فرمایا کہ ابوفلاں کے لیے ( یہ مسائل ) لکھ دو۔ تو ایک قریشی شخص نے کہا کہ یا رسول اللہ! مگر اذخر ( یعنی اذخر کاٹنے کی اجازت دے دیجیئے ) کیونکہ اسے ہم گھروں کی چھتوں پر ڈالتے ہیں۔ ( یا مٹی ملا کر ) اور اپنی قبروں میں بھی ڈالتے ہیں ( یہ سن کر ) رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ( ہاں ) مگر اذخر، مگر اذخر۔' WHERE id = 113;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد المسندی نے بیان کیا، ان سے سفیان نے، ان سے عمرو نے، انہیں سعید بن جبیر رضی اللہ عنہ نے خبر دی، وہ کہتے ہیں کہ میں نے ابن عباس رضی اللہ عنہما سے کہا کہ نوف بکالی کا یہ خیال ہے کہ موسیٰ علیہ السلام ( جو خضر علیہ السلام کے پاس گئے تھے وہ ) موسیٰ بنی اسرائیل والے نہیں تھے بلکہ دوسرے موسیٰ تھے، ( یہ سن کر ) ابن عباس رضی اللہ عنہما بولے کہ اللہ کے دشمن نے جھوٹ کہا ہے۔ ہم سے ابی ابن کعب رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے نقل کیا کہ ( ایک روز ) موسیٰ علیہ السلام نے کھڑے ہو کر بنی اسرائیل میں خطبہ دیا، تو آپ سے پوچھا گیا کہ لوگوں میں سب سے زیادہ صاحب علم کون ہے؟ انہوں نے فرمایا کہ میں ہوں۔ اس وجہ سے اللہ کا غصہ ان پر ہوا کہ انہوں نے علم کو اللہ کے حوالے کیوں نہ کر دیا۔ تب اللہ نے ان کی طرف وحی بھیجی کہ میرے بندوں میں سے ایک بندہ دریاؤں کے سنگم پر ہے۔ ( جہاں فارس اور روم کے سمندر ملتے ہیں ) وہ تجھ سے زیادہ عالم ہے، موسیٰ علیہ السلام نے کہا اے پروردگار! میری ان سے ملاقات کیسے ہو؟ حکم ہوا کہ ایک مچھلی زنبیل میں رکھ لو، پھر جہاں تم اس مچھلی کو گم کر دو گے تو وہ بندہ تمہیں ( وہیں ) ملے گا۔ تب موسیٰ علیہ السلام چلے اور ساتھ اپنے خادم یوشع بن نون کو لے لیا اور انہوں نے زنبیل میں مچھلی رکھ لی، جب ( ایک ) پتھر کے پاس پہنچے، دونوں اپنے سر اس پر رکھ کر سو گئے اور مچھلی زنبیل سے نکل کر دریا میں اپنی راہ بناتی چلی گئی اور یہ بات موسیٰ علیہ السلام اور ان کے ساتھی کے لیے بےحد تعجب کی تھی، پھر دونوں باقی رات اور دن میں ( جتنا وقت باقی تھا ) چلتے رہے، جب صبح ہوئی موسیٰ علیہ السلام نے خادم سے کہا، ہمارا ناشتہ لاؤ، اس سفر میں ہم نے ( کافی ) تکلیف اٹھائی ہے اور موسیٰ علیہ السلام بالکل نہیں تھکے تھے، مگر جب اس جگہ سے آگے نکل گئے، جہاں تک انہیں جانے کا حکم ملا تھا، تب ان کے خادم نے کہا، کیا آپ نے دیکھا تھا کہ جب ہم صخرہ کے پاس ٹھہرے تھے تو میں مچھلی کا ذکر بھول گیا، ( بقول بعض صخرہ کے نیچے آب حیات تھا، وہ اس مچھلی پر پڑا، اور وہ زندہ ہو کر بقدرت الٰہی دریا میں چل دی ) ( یہ سن کر ) موسیٰ علیہ السلام بولے کہ یہ ہی وہ جگہ ہے جس کی ہمیں تلاش تھی، تو وہ پچھلے پاؤں واپس ہو گئے، جب پتھر تک پہنچے تو دیکھا کہ ایک شخص کپڑا اوڑھے ہوئے ( موجود ہے ) موسیٰ علیہ السلام نے انہیں سلام کیا، خضر علیہ السلام نے کہا کہ تمہاری سر زمین میں سلام کہاں؟ پھر موسیٰ علیہ السلام نے کہا کہ میں موسیٰ ( علیہ السلام ) ہوں، خضر بولے کہ بنی اسرائیل کے موسیٰ؟ انہوں نے جواب دیا کہ ہاں! پھر کہا کیا میں آپ کے ساتھ چل سکتا ہوں، تاکہ آپ مجھے ہدایت کی وہ باتیں بتلائیں جو اللہ نے خاص آپ ہی کو سکھلائی ہیں۔ خضر علیہ السلام بولے کہ تم میرے ساتھ صبر نہیں کر سکو گے۔ اسے موسیٰ! مجھے اللہ نے ایسا علم دیا ہے جسے تم نہیں جانتے اور تم کو جو علم دیا ہے اسے میں نہیں جانتا۔ ( اس پر ) موسیٰ نے کہا کہ اللہ نے چاہا تو آپ مجھے صابر پاؤ گے اور میں کسی بات میں آپ کی نافرمانی نہیں کروں گا۔ پھر دونوں دریا کے کنارے کنارے پیدل چلے، ان کے پاس کوئی کشتی نہ تھی کہ ایک کشتی ان کے سامنے سے گزری، تو کشتی والوں سے انہوں نے کہا کہ ہمیں بٹھا لو۔ خضر علیہ السلام کو انہوں نے پہچان لیا اور بغیر کرایہ کے سوار کر لیا، اتنے میں ایک چڑیا آئی اور کشتی کے کنارے پر بیٹھ گئی، پھر سمندر میں اس نے ایک یا دو چونچیں ماریں ( اسے دیکھ کر ) خضر علیہ السلام بولے کہ اے موسیٰ! میرے اور تمہارے علم نے اللہ کے علم میں سے اتنا ہی کم کیا ہو گا جتنا اس چڑیا نے سمندر ( کے پانی ) سے پھر خضر علیہ السلام نے کشتی کے تختوں میں سے ایک تختہ نکال ڈالا، موسیٰ علیہ السلام نے کہا کہ ان لوگوں نے تو ہمیں کرایہ لیے بغیر ( مفت میں ) سوار کیا اور آپ نے ان کی کشتی ( کی لکڑی ) اکھاڑ ڈالی تاکہ یہ ڈوب جائیں، خضر علیہ السلام بولے کہ کیا میں نے نہیں کہا تھا کہ تم میرے ساتھ صبر نہیں کر سکو گے؟ ( اس پر ) موسیٰ علیہ السلام نے جواب دیا کہ بھول پر میری گرفت نہ کرو۔ موسیٰ علیہ السلام نے بھول کر یہ پہلا اعتراض کیا تھا۔ پھر دونوں چلے ( کشتی سے اتر کر ) ایک لڑکا بچوں کے ساتھ کھیل رہا تھا، خضر علیہ السلام نے اوپر سے اس کا سر پکڑ کر ہاتھ سے اسے الگ کر دیا۔ موسیٰ علیہ السلام بول پڑے کہ آپ نے ایک بےگناہ بچے کو بغیر کسی جانی حق کے مار ڈالا ( غضب ہو گیا ) خضر علیہ السلام بولے کہ میں نے تم سے نہیں کہا تھا کہ تم میرے ساتھ صبر نہیں کر سکو گے۔ ابن عیینہ کہتے ہیں کہ اس کلام میں پہلے سے زیادہ تاکید ہے ( کیونکہ پہلے کلام میں لفظ لک نہیں کہا تھا، اس میں لک زائد کیا، جس سے تاکید ظاہر ہے ) پھر دونوں چلتے رہے۔ حتیٰ کہ ایک گاؤں والوں کے پاس آئے، ان سے کھانا لینا چاہا۔ انہوں نے کھانا کھلانے سے انکار کر دیا۔ انہوں نے وہیں دیکھا کہ ایک دیوار اسی گاؤں میں گرنے کے قریب تھی۔ خضر علیہ السلام نے اپنے ہاتھ کے اشارے سے اسے سیدھا کر دیا۔ موسیٰ بول اٹھے کہ اگر آپ چاہتے تو ( گاؤں والوں سے ) اس کام کی مزدوری لے سکتے تھے۔ خضر نے کہا کہ ( بس اب ) ہم اور تم میں جدائی کا وقت آ گیا ہے۔ جناب محبوب کبریا رسول اللہ صلی اللہ علیہ وسلم فرماتے ہیں کہ اللہ موسیٰ پر رحم کرے، ہماری تمنا تھی کہ موسیٰ کچھ دیر اور صبر کرتے تو مزید واقعات ان دونوں کے بیان کئے جاتے ( اور ہمارے سامنے روشنی میں آتے، مگر موسیٰ علیہ السلام کی عجلت نے اس علم لدنی کے سلسلہ کو جلد ہی منقطع کرا دیا ) محمد بن یوسف کہتے ہیں کہ ہم سے علی بن خشرم نے یہ حدیث بیان کی، ان سے سفیان بن عیینہ نے پوری کی پوری بیان کی۔' WHERE id = 123;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے عبداللہ ابن داؤد نے اعمش کے واسطے سے بیان کیا، انہوں نے منذر ثوری سے نقل کیا، انہوں نے محمد ابن الحنفیہ سے نقل کیا، وہ علی رضی اللہ عنہ سے روایت کرتے ہیں کہ میں ایسا شخص تھا جسے جریان مذی کی شکایت تھی، تو میں نے ( اپنے شاگرد ) مقداد کو حکم دیا کہ وہ رسول اللہ صلی اللہ علیہ وسلم سے دریافت کریں۔ تو انہوں نے آپ صلی اللہ علیہ وسلم سے اس بارے میں پوچھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس ( مرض ) میں غسل نہیں ہے ( ہاں ) وضو فرض ہے۔' WHERE id = 133;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، ان سے شعبہ نے عبدالعزیز بن صہیب کے واسطے سے بیان کیا، انہوں نے انس رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم جب ( قضائے حاجت کے لیے ) بیت الخلاء میں داخل ہوتے تو یہ ( دعا ) پڑھتے «اللهم إني أعوذ بك من الخبث والخبائث» اے اللہ! میں ناپاک جنوں اور ناپاک جنیوں سے تیری پناہ مانگتا ہوں۔' WHERE id = 143;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، ان سے محمد بن جعفر نے، ان سے شعبہ نے عطاء بن ابی میمونہ کے واسطے سے بیان کیا، انہوں نے انس بن مالک سے سنا، وہ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم بیت الخلاء میں جاتے تو میں اور ایک لڑکا پانی کا برتن اور نیزہ لے کر چلتے تھے۔ پانی سے آپ طہارت کرتے تھے، ( دوسری سند سے ) نضر اور شاذان نے اس حدیث کی شعبہ سے متابعت کی ہے۔ عنزہ لاٹھی کو کہتے ہیں جس پر پھلکا لگا ہوا ہو۔' WHERE id = 153;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے ابوالزناد کے واسطے سے خبر دی، وہ اعرج سے، وہ ابوہریرہ رضی اللہ عنہ سے نقل کرتے ہیں کہ رسول ‌اللہ ‌صلی ‌اللہ ‌علیہ ‌وسلم ‌نے ‌فرمایا ‌كہ ‌جب ‌تم ‌سے ‌كوئی ‌وضو ‌كرے ‌تو ‌اسے ‌چاہیئے ‌كہ ‌اپنی ‌ناك ‌میں ‌پانی ‌دے (‌پھر) ‌اسے ‌صاف ‌كرے ‌اور ‌جو ‌شخص ‌پتھروں ‌سے ‌استنجاء ‌كرے ‌اسے ‌چاہیئے ‌كہ ‌بے ‌جوڑ ‌(یعنی ‌ایك ‌یا ‌تین) ‌سے ‌استنجاء ‌كرے ‌. ‌اور ‌جب ‌تم ‌سے ‌كوئی ‌سو ‌كر ‌اٹھے ‌تو ‌وضو ‌كے ‌پانی ‌میں ‌ہاتھ ‌ڈالنے ‌سے ‌پہلے ‌اسے ‌دھولے ‌. ‌كیونكہ ‌تم ‌میں ‌سے ‌كوئی ‌نہیں ‌جانتا ‌كہ ‌رات ‌كو ‌اس ‌كا ‌ہاتھ ‌كہاں ‌رہا ‌ہے ‌' WHERE id = 163;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہیں امام مالک نے ابوالزناد سے خبر دی، وہ اعرج سے، وہ ابوہریرہ رضی اللہ عنہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب کتا تم میں سے کسی کے برتن میں سے ( کچھ ) پی لے تو اس کو سات مرتبہ دھو لو ( تو پاک ہو جائے گا ) ۔' WHERE id = 173;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب نے بیان کیا، انہوں نے کہا میں نے یحییٰ بن سعید سے سنا، انہوں نے کہا مجھے سعد بن ابراہیم نے نافع بن جبیر بن مطعم سے بتلایا۔ انہوں نے عروہ بن مغیرہ بن شعبہ سے سنا، وہ مغیرہ بن شعبہ رضی اللہ عنہ سے نقل کرتے ہیں کہ وہ ایک سفر میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ ( وہاں ) آپ رفع حاجت کے لیے تشریف لے گئے ( جب آپ واپس آئے، آپ صلی اللہ علیہ وسلم نے وضو شروع کیا ) تو مغیرہ بن شعبہ آپ کے ( اعضاء وضو ) پر پانی ڈالنے لگے۔ آپ صلی اللہ علیہ وسلم وضو کر رہے تھے آپ نے اپنے منہ اور ہاتھوں کو دھویا، سر کا مسح کیا اور موزوں پر مسح کیا۔' WHERE id = 183;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے وہیب نے بیان کیا، ان سے عمرو بن یحییٰ نے اپنے باپ (یحییٰ) کے واسطے سے بیان کیا، وہ کہتے ہیں کہ میری موجودگی میں عمرو بن حسن نے عبداللہ بن زید رضی اللہ عنہ سے رسول اللہ صلی اللہ علیہ وسلم کے وضو کے بارے میں پوچھا۔ تو عبداللہ بن زید رضی اللہ عنہ نے پانی کا ایک طشت منگوایا، پھر ان ( لوگوں ) کے دکھانے کے لیے وضو ( شروع ) کیا۔ ( پہلے ) طشت سے اپنے ہاتھوں پر پانی گرایا۔ پھر انہیں تین بار دھویا۔ پھر اپنا ہاتھ برتن کے اندر ڈالا، پھر کلی کی اور ناک میں پانی ڈال کر ناک صاف کی، تین چلوؤں سے تین دفعہ۔ پھر اپنا ہاتھ برتن کے اندر ڈالا اور اپنے منہ کو تین بار دھویا۔ پھر اپنا ہاتھ برتن کے اندر ڈالا اور دونوں ہاتھ کہنیوں تک دو دو بار دھوئے ( پھر ) سر پر مسح کیا اس طرح کہ ( پہلے ) آگے کی طرف اپنا ہاتھ لائے پھر پیچھے کی طرف لے گئے۔ پھر برتن میں اپنا ہاتھ ڈالا اور اپنے دونوں پاؤں دھوئے ( دوسری روایت میں ) ہم سے موسیٰ نے، ان سے وہیب نے بیان کیا کہ آپ نے سر کا مسح ایک دفعہ کیا۔' WHERE id = 193;
UPDATE hadiths SET urdu = 'ہم سے اصبغ ابن الفرج نے بیان کیا، وہ ابن وہب سے کرتے ہیں، کہا مجھ سے عمرو نے بیان کیا، کہا مجھ سے ابوالنضر نے ابوسلمہ بن عبدالرحمٰن کے واسطے سے نقل کیا، وہ عبداللہ بن عمر سے، وہ سعد بن ابی وقاص سے، وہ رسول اللہ صلی اللہ علیہ وسلم سے نقل کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے موزوں پر مسح کیا۔ عبداللہ بن عمر رضی اللہ عنہما نے اپنے والد ماجد عمر رضی اللہ عنہ سے اس کے بارے میں پوچھا تو انہوں نے کہا ( سچ ہے اور یاد رکھو ) جب تم سے سعد رسول اللہ صلی اللہ علیہ وسلم کی کوئی حدیث بیان فرمائیں۔ تو اس کے متعلق ان کے سوا ( کسی ) دوسرے آدمی سے مت پوچھو اور موسیٰ بن عقبہ کہتے ہیں کہ مجھے ابوالنضر نے بتلایا، انہیں ابوسلمہ نے خبر دی کہ سعد بن ابی وقاص نے ان سے ( رسول اللہ صلی اللہ علیہ وسلم کی یہ ) حدیث بیان کی۔ پھر عمر رضی اللہ عنہ نے ( اپنے بیٹے ) عبداللہ سے ایسا کہا۔' WHERE id = 203;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا مجھ کو مالک نے ہشام سے، انہوں نے اپنے باپ سے خبر دی، انہوں نے عائشہ رضی اللہ عنہا سے نقل کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب نماز پڑھتے وقت تم میں سے کسی کو اونگھ آ جائے، تو چاہیے کہ وہ سو رہے یہاں تک کہ نیند ( کا اثر ) اس سے ختم ہو جائے۔ اس لیے کہ جب تم میں سے کوئی شخص نماز پڑھنے لگے اور وہ اونگھ رہا ہو تو وہ کچھ نہیں جانے گا کہ وہ ( اللہ تعالیٰ سے ) مغفرت طلب کر رہا ہے یا اپنے نفس کو بددعا دے رہا ہے۔' WHERE id = 213;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے ہشام بن عروہ سے خبر دی، انہوں نے اپنے باپ (عروہ) سے، انہوں نے ام المؤمنین عائشہ رضی اللہ عنہا سے روایت کی ہے کہ رسول اللہ صلی اللہ علیہ وسلم کے پاس ایک بچہ لایا گیا۔ اس نے آپ صلی اللہ علیہ وسلم کے کپڑے پر پیشاب کر دیا تو آپ صلی اللہ علیہ وسلم نے پانی منگایا اور اس پر ڈال دیا۔' WHERE id = 223;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا ہم سے زہیر نے، کہا ہم سے عمرو بن میمون بن مہران نے، انہوں نے سلیمان بن یسار سے، وہ عائشہ رضی اللہ عنہا سے روایت کرتے ہیں کہ وہ رسول اللہ صلی اللہ علیہ وسلم کے کپڑے سے منی کو دھو ڈالتی تھیں ( وہ فرماتی ہیں کہ ) پھر ( کبھی ) میں ایک دھبہ یا کئی دھبے دیکھتی تھی۔' WHERE id = 233;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے، ان سے زہری نے ابوسلمہ کے واسطے سے بیان کیا، وہ عائشہ رضی اللہ عنہا سے وہ رسول اللہ صلی اللہ علیہ وسلم سے روایت کرتی ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پینے کی ہر وہ چیز جو نشہ لانے والی ہو حرام ہے۔' WHERE id = 243;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے حدیث بیان کی، انہوں نے کہا کہ ہم سے یحییٰ بن آدم نے حدیث بیان کی، انہوں نے کہا ہم سے زہیر نے ابواسحاق کے واسطے سے، انہوں نے کہا ہم سے ابوجعفر (محمد باقر) نے بیان کیا کہ وہ اور ان کے والد ( جناب زین العابدین ) جابر بن عبداللہ رضی اللہ عنہ کے پاس تھے اور کچھ اور لوگ بھی بیٹھے ہوئے تھے۔ ان لوگوں نے آپ سے غسل کے بارے میں پوچھا تو آپ نے فرمایا کہ ایک صاع کافی ہے۔ اس پر ایک شخص بولا یہ مجھے تو کافی نہ ہو گا۔ جابر رضی اللہ عنہ نے فرمایا کہ یہ ان کے لیے کافی ہوتا تھا جن کے بال تم سے زیادہ تھے اور جو تم سے بہتر تھے ( یعنی رسول اللہ صلی اللہ علیہ وسلم ) پھر جابر رضی اللہ عنہ نے صرف ایک کپڑا پہن کر ہمیں نماز پڑھائی۔ ( نوٹ: صاع کے اندر 2.488 کلو گرام ہوتا ہے۔)' WHERE id = 253;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے حماد نے ہشام کے واسطے سے بیان کیا، وہ اپنے والد سے، وہ عائشہ رضی اللہ عنہا سے، آپ نے فرمایا کہ جب رسول اللہ صلی اللہ علیہ وسلم غسل جنابت فرماتے تو ( پہلے ) اپنا ہاتھ دھوتے۔' WHERE id = 263;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن عیسیٰ نے بیان کیا، انہوں نے کہا ہم سے فضل بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا انہوں نے سالم کے واسطہ سے، انہوں نے کریب مولیٰ ابن عباس سے، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے بیان کیا، انہوں نے ام المؤمنین میمونہ رضی اللہ عنہا سے روایت کیا، انہوں نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے غسل جنابت کے لیے پانی رکھا پھر آپ صلی اللہ علیہ وسلم نے پہلے دو یا تین مرتبہ اپنے دائیں ہاتھ سے بائیں ہاتھ پر پانی ڈالا۔ پھر شرمگاہ دھوئی۔ پھر ہاتھ کو زمین پر یا دیوار پر دو یا تین بار رگڑا۔ پھر کلی کی اور ناک میں پانی ڈالا اور اپنے چہرے اور بازوؤں کو دھویا۔ پھر سر پر پانی بہایا اور سارے بدن کا غسل کیا۔ پھر اپنی جگہ سے سرک کر پاؤں دھوئے۔ میمونہ رضی اللہ عنہا نے فرمایا کہ میں ایک کپڑا لائی تو آپ صلی اللہ علیہ وسلم نے اسے نہیں لیا اور ہاتھوں ہی سے پانی جھاڑنے لگے۔' WHERE id = 274;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلیٰ بن حماد نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا، انہوں نے کہا ہم سے سعید بن ابی عروبہ نے بیان کیا، انہوں نے قتادہ سے، کہ انس بن مالک رضی اللہ عنہ نے ان سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اپنی تمام ازواج کے پاس ایک ہی رات میں تشریف لے گئے۔ اس وقت آپ صلی اللہ علیہ وسلم کے ازواج میں نو بیویاں تھیں۔' WHERE id = 284;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے، کہا میں نے عبدالرحمٰن بن قاسم سے سنا، کہا میں نے قاسم سے سنا۔ وہ کہتے تھے میں نے عائشہ رضی اللہ عنہا سے سنا۔ آپ فرماتی تھیں کہ ہم حج کے ارادہ سے نکلے۔ جب ہم مقام سرف میں پہنچے تو میں حائضہ ہو گئی اور اس رنج میں رونے لگی کہ رسول اللہ صلی اللہ علیہ وسلم تشریف لائے، آپ صلی اللہ علیہ وسلم نے پوچھا تمہیں کیا ہو گیا۔ کیا حائضہ ہو گئی ہو۔ میں نے کہا، ہاں! آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ایک ایسی چیز ہے جس کو اللہ تعالیٰ نے آدم کی بیٹیوں کے لیے لکھ دیا ہے۔ اس لیے تم بھی حج کے افعال پورے کر لو۔ البتہ بیت اللہ کا طواف نہ کرنا۔ عائشہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کی طرف سے گائے کی قربانی کی۔ ( سرف ایک مقام مکہ سے چھ سات میل کے فاصلہ پر ہے ) ۔' WHERE id = 294;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے بیان کیا، انہوں نے ہشام بن عروہ کے واسطے سے، انہوں نے فاطمہ بنت منذر سے، انہوں نے اسماء بنت ابی بکر صدیق رضی اللہ عنہما سے، انہوں نے کہا کہ ایک عورت نے رسول اللہ صلی اللہ علیہ وسلم سے سوال کیا۔ اس نے پوچھا کہ یا رسول اللہ! آپ ایک ایسی عورت کے متعلق کیا فرماتے ہیں جس کے کپڑے پر حیض کا خون لگ گیا ہو۔ تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر کسی عورت کے کپڑے پر حیض کا خون لگ جائے تو چاہیے کہ اسے رگڑ ڈالے، اس کے بعد اسے پانی سے دھوئے، پھر اس کپڑے میں نماز پڑھ لے۔' WHERE id = 305;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ حماد نے ہشام بن عروہ کے واسطے سے بیان کیا، انہوں نے اپنے والد سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ انہوں نے فرمایا ہم ذی الحجہ کا چاند دیکھتے ہی نکلے۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس کا دل چاہے تو اسے عمرہ کا احرام باندھ لینا چاہیے۔ کیونکہ اگر میں ہدی ساتھ نہ لاتا تو میں بھی عمرہ کا احرام باندھتا۔ اس پر بعض صحابہ نے عمرہ کا احرام باندھا اور بعض نے حج کا۔ میں بھی ان لوگوں میں سے تھی جنہوں نے عمرہ کا احرام باندھا تھا۔ مگر عرفہ کا دن آ گیا اور میں حیض کی حالت میں تھی۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے اس کے متعلق شکایت کی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ عمرہ چھوڑ اور اپنا سر کھول اور کنگھا کر اور حج کا احرام باندھ لے۔ میں نے ایسا ہی کیا۔ یہاں تک کہ جب حصبہ کی رات آئی تو رسول اللہ صلی اللہ علیہ وسلم نے میرے ساتھ میرے بھائی عبدالرحمٰن بن ابی بکر کو بھیجا۔ میں تنعیم میں گئی اور وہاں سے اپنے عمرہ کے بدلے دوسرے عمرہ کا احرام باندھا۔ ہشام نے کہا کہ ان میں سے کسی بات کی وجہ سے بھی نہ ہدی واجب ہوئی اور نہ روزہ اور نہ صدقہ۔ ( تنعیم حد حرم سے قریب تین میل دور ایک مقام کا نام ہے ) ۔' WHERE id = 315;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر حزامی نے بیان کیا، انہوں نے کہا ہم سے معن بن عیسیٰ نے بیان کیا، انہوں نے ایوب بن ابی ذئب سے، انہوں نے ابن شہاب سے، انہوں نے عروہ اور عمرہ سے، انہوں نے عائشہ رضی اللہ عنہا سے ( جو نبی کریم صلی اللہ علیہ وسلم کی بیوی ہیں ) کہ ام حبیبہ رضی اللہ عنہا سات سال تک مستحاضہ رہیں۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے اس کے بارے میں پوچھا تو آپ صلی اللہ علیہ وسلم نے انہیں غسل کرنے کا حکم دیا اور فرمایا کہ یہ رگ ( کی وجہ سے بیماری ) ہے۔ پس ام حبیبہ رضی اللہ عنہا ہر نماز کے لیے غسل کرتی تھیں۔' WHERE id = 325;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے کہا کہ مجھے حکم بن عیینہ نے خبر دی ذر بن عبداللہ سے، وہ سعید بن عبدالرحمٰن بن ابزیٰ سے، وہ اپنے باپ سے کہ عمار نے یہ واقعہ بیان کیا ( جو پہلے گزر چکا ) اور شعبہ نے اپنے ہاتھوں کو زمین پر مارا۔ پھر انہیں اپنے منہ کے قریب کر لیا ( اور پھونکا ) پھر ان سے اپنے چہرے اور پہنچوں کا مسح کیا اور نضر بن شمیل نے بیان کیا کہ مجھے شعبہ نے خبر دی حکم سے کہ میں نے ذر بن عبداللہ سے سنا، وہ سعید بن عبدالرحمٰن بن ابزیٰ کے حوالہ سے حدیث روایت کرتے تھے۔ حکم نے کہا کہ میں نے یہ حدیث ابن عبدالرحمٰن بن ابزی سے سنی، وہ اپنے والد کے حوالہ سے بیان کرتے تھے کہ عمار نے کہا ( جو پہلے مذکور ہوا ) ۔' WHERE id = 336;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے یونس کے واسطہ سے بیان کیا، انہوں نے ابن شہاب سے، انہوں نے انس بن مالک سے، انہوں نے فرمایا کہ ابوذر غفاری رضی اللہ عنہ یہ حدیث بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرے گھر کی چھت کھول دی گئی، اس وقت میں مکہ میں تھا۔ پھر جبرائیل علیہ السلام اترے اور انہوں نے میرا سینہ چاک کیا۔ پھر اسے زمزم کے پانی سے دھویا۔ پھر ایک سونے کا طشت لائے جو حکمت اور ایمان سے بھرا ہوا تھا۔ اس کو میرے سینے میں رکھ دیا، پھر سینے کو جوڑ دیا، پھر میرا ہاتھ پکڑا اور مجھے آسمان کی طرف لے کر چلے۔ جب میں پہلے آسمان پر پہنچا تو جبرائیل علیہ السلام نے آسمان کے داروغہ سے کہا کھولو۔ اس نے پوچھا، آپ کون ہیں؟ جواب دیا کہ جبرائیل، پھر انہوں نے پوچھا کیا آپ کے ساتھ کوئی اور بھی ہے؟ جواب دیا، ہاں میرے ساتھ محمد ( صلی اللہ علیہ وسلم ) ہیں۔ انہوں نے پوچھا کہ کیا ان کے بلانے کے لیے آپ کو بھیجا گیا تھا؟ کہا، جی ہاں! پھر جب انہوں نے دروازہ کھولا تو ہم پہلے آسمان پر چڑھ گئے، وہاں ہم نے ایک شخص کو بیٹھے ہوئے دیکھا۔ ان کے داہنی طرف کچھ لوگوں کے جھنڈ تھے اور کچھ جھنڈ بائیں طرف تھے۔ جب وہ اپنی داہنی طرف دیکھتے تو مسکرا دیتے اور جب بائیں طرف نظر کرتے تو روتے۔ انہوں نے مجھے دیکھ کر فرمایا، آؤ اچھے آئے ہو۔ صالح نبی اور صالح بیٹے! میں نے جبرائیل علیہ السلام سے پوچھا یہ کون ہیں؟ انہوں نے کہا کہ یہ آدم علیہ السلام ہیں اور ان کے دائیں بائیں جو جھنڈ ہیں یہ ان کے بیٹوں کی روحیں ہیں۔ جو جھنڈ دائیں طرف ہیں وہ جنتی ہیں اور بائیں طرف کے جھنڈ دوزخی روحیں ہیں۔ اس لیے جب وہ اپنے دائیں طرف دیکھتے ہیں تو خوشی سے مسکراتے ہیں اور جب بائیں طرف دیکھتے ہیں تو ( رنج سے ) روتے ہیں۔ پھر جبرائیل مجھے لے کر دوسرے آسمان تک پہنچے اور اس کے داروغہ سے کہا کہ کھولو۔ اس آسمان کے داروغہ نے بھی پہلے کی طرح پوچھا پھر کھول دیا۔ انس نے کہا کہ ابوذر نے ذکر کیا کہ آپ صلی اللہ علیہ وسلم یعنی نبی کریم صلی اللہ علیہ وسلم نے آسمان پر آدم، ادریس، موسیٰ، عیسیٰ اور ابراہیم علیہم السلام کو موجود پایا۔ اور ابوذر رضی اللہ عنہ نے ہر ایک کا ٹھکانہ نہیں بیان کیا۔ البتہ اتنا بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے آدم کو پہلے آسمان پر پایا اور ابراہیم علیہ السلام کو چھٹے آسمان پر۔ انس نے بیان کیا کہ جب جبرائیل علیہ السلام نبی کریم صلی اللہ علیہ وسلم کے ساتھ ادریس علیہ السلام پر گزرے۔ تو انہوں نے فرمایا کہ آؤ اچھے آئے ہو صالح نبی اور صالح بھائی۔ میں نے پوچھا یہ کون ہیں؟ جواب دیا کہ یہ ادریس علیہ السلام ہیں۔ پھر موسیٰ علیہ السلام تک پہنچا تو انہوں نے فرمایا آؤ اچھے آئے ہو صالح نبی اور صالح بھائی۔ میں نے پوچھا یہ کون ہیں؟ جبرائیل علیہ السلام نے بتایا کہ موسیٰ علیہ السلام ہیں۔ پھر میں عیسیٰ علیہ السلام تک پہنچا، انہوں نے کہا آؤ اچھے آئے ہو صالح نبی اور صالح بھائی۔ میں نے پوچھا یہ کون ہیں؟ جبرائیل علیہ السلام نے بتایا کہ یہ عیسیٰ علیہ السلام ہیں۔ پھر میں ابراہیم علیہ السلام تک پہنچا۔ انہوں نے فرمایا آؤ اچھے آئے ہو صالح نبی اور صالح بیٹے۔ میں نے پوچھا یہ کون ہیں؟ جبرائیل علیہ السلام نے بتایا کہ یہ ابراہیم علیہ السلام ہیں۔ ابن شہاب نے کہا کہ مجھے ابوبکر بن حزم نے خبر دی کہ عبداللہ بن عباس اور ابوحبۃ الانصاری رضی اللہ عنہم کہا کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، پھر مجھے جبرائیل علیہ السلام لے کر چڑھے، اب میں اس بلند مقام تک پہنچ گیا جہاں میں نے قلم کی آواز سنی ( جو لکھنے والے فرشتوں کی قلموں کی آواز تھی ) ابن حزم نے ( اپنے شیخ سے ) اور انس بن مالک نے ابوذر رضی اللہ عنہ سے نقل کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ پس اللہ تعالیٰ نے میری امت پر پچاس وقت کی نمازیں فرض کیں۔ میں یہ حکم لے کر واپس لوٹا۔ جب موسیٰ علیہ السلام تک پہنچا تو انہوں نے پوچھا کہ آپ کی امت پر اللہ نے کیا فرض کیا ہے؟ میں نے کہا کہ پچاس وقت کی نمازیں فرض کی ہیں۔ انہوں نے فرمایا آپ واپس اپنے رب کی بارگاہ میں جائیے۔ کیونکہ آپ کی امت اتنی نمازوں کو ادا کرنے کی طاقت نہیں رکھتی ہے۔ میں واپس بارگاہ رب العزت میں گیا تو اللہ نے اس میں سے ایک حصہ کم کر دیا، پھر موسیٰ علیہ السلام کے پاس آیا اور کہا کہ ایک حصہ کم کر دیا گیا ہے، انہوں نے کہا کہ دوبارہ جائیے کیونکہ آپ کی امت میں اس کے برداشت کی بھی طاقت نہیں ہے۔ پھر میں بارگاہ رب العزت میں حاضر ہوا۔ پھر ایک حصہ کم ہوا۔ جب موسیٰ علیہ السلام کے پاس پہنچا تو انہوں نے فرمایا کہ اپنے رب کی بارگاہ میں پھر جائیے، کیونکہ آپ کی امت اس کو بھی برداشت نہ کر سکے گی، پھر میں باربار آیا گیا پس اللہ تعالیٰ نے فرمایا کہ یہ نمازیں ( عمل میں ) پانچ ہیں اور ( ثواب میں ) پچاس ( کے برابر ) ہیں۔ میری بات بدلی نہیں جاتی۔ اب میں موسیٰ علیہ السلام کے پاس آیا تو انہوں نے پھر کہا کہ اپنے رب کے پاس جائیے۔ لیکن میں نے کہا مجھے اب اپنے رب سے شرم آتی ہے۔ پھر جبرائیل مجھے سدرۃ المنتہیٰ تک لے گئے جسے کئی طرح کے رنگوں نے ڈھانک رکھا تھا۔ جن کے متعلق مجھے معلوم نہیں ہوا کہ وہ کیا ہیں۔ اس کے بعد مجھے جنت میں لے جایا گیا، میں نے دیکھا کہ اس میں موتیوں کے ہار ہیں اور اس کی مٹی مشک کی ہے۔' WHERE id = 346;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم ضحاک بن مخلد نے امام مالک رحمہ اللہ کے حوالہ سے بیان کیا، انہوں نے ابوالزناد سے، انہوں نے عبدالرحمٰن اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کسی شخص کو بھی ایک کپڑے میں نماز اس طرح نہ پڑھنی چاہیے کہ اس کے کندھوں پر کچھ نہ ہو۔' WHERE id = 356;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، انہوں نے کہا مجھے میرے بھائی ابن شہاب نے اپنے چچا کے واسطہ سے، انہوں نے کہا مجھے حمید بن عبدالرحمٰن بن عوف نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نے فرمایا کہ اس حج کے موقع پر مجھے ابوبکر رضی اللہ عنہ نے یوم نحر ( ذی الحجہ کی دسویں تاریخ ) میں اعلان کرنے والوں کے ساتھ بھیجا۔ تاکہ ہم منیٰ میں اس بات کا اعلان کر دیں کہ اس سال کے بعد کوئی مشرک حج نہیں کر سکتا اور کوئی شخص ننگے ہو کر بیت اللہ کا طواف نہیں کر سکتا۔ حمید بن عبدالرحمٰن نے کہا اس کے بعد رسول اللہ صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ کو ابوبکر رضی اللہ عنہ کے پیچھے بھیجا اور انہیں حکم دیا کہ وہ سورۃ برات پڑھ کر سنا دیں اور اس کے مضامین کا عام اعلان کر دیں۔ ابوہریرہ رضی اللہ عنہ فرماتے ہیں کہ علی رضی اللہ عنہ نے ہمارے ساتھ نحر کے دن منیٰ میں دسویں تاریخ کو یہ سنایا کہ آج کے بعد کوئی مشرک نہ حج کر سکے گا اور نہ بیت اللہ کا طواف کوئی شخص ننگے ہو کر کر سکے گا۔' WHERE id = 366;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا خالد سے، کہا کہ ہم سے سلیمان شیبانی نے بیان کیا عبداللہ بن شداد سے، انہوں نے میمونہ رضی اللہ عنہا سے، آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نماز پڑھتے اور حائضہ ہونے کے باوجود میں ان کے سامنے ہوتی، اکثر جب آپ صلی اللہ علیہ وسلم سجدہ کرتے تو آپ صلی اللہ علیہ وسلم کا کپڑا مجھے چھو جاتا۔ انہوں نے کہا کہ آپ صلی اللہ علیہ وسلم ( کھجور کے پتوں سے بنے ہوئے ایک چھوٹے سے ) مصلے پر نماز پڑھتے تھے۔' WHERE id = 376;
UPDATE hadiths SET urdu = 'ہمیں صلت بن محمد نے بیان کیا، کہا ہم سے مہدی بن میمون نے واصل کے واسطہ سے، وہ ابووائل شقیق بن سلمہ سے، وہ حذیفہ رضی اللہ عنہ سے کہ انھوں نے ایک شخص کو دیکھا جو رکوع اور سجدہ پوری طرح نہیں کرتا تھا۔ جب اس نے اپنی نماز پوری کر لی تو حذیفہ رضی اللہ عنہ نے فرمایا کہ تم نے نماز ہی نہیں پڑھی۔ ابووائل راوی نے کہا، میں خیال کرتا ہوں کہ حذیفہ رضی اللہ عنہ نے یہ بھی فرمایا کہ اگر تو ایسی ہی نماز پر مر جاتا تو نبی کریم صلی اللہ علیہ وسلم کی سنت پر نہیں مرتا۔' WHERE id = 386;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے منصور کے واسطے سے، انہوں نے ابراہیم سے، انہوں نے علقمہ سے، کہ عبداللہ بن مسعود رضی اللہ عنہ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھائی۔ ابراہیم نے کہا مجھے نہیں معلوم کہ نماز میں زیادتی ہوئی یا کمی۔ پھر جب آپ صلی اللہ علیہ وسلم نے سلام پھیرا تو آپ صلی اللہ علیہ وسلم سے کہا گیا کہ یا رسول اللہ! کیا نماز میں کوئی نیا حکم آیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا آخر کیا بات ہے؟ لوگوں نے کہا آپ نے اتنی اتنی رکعتیں پڑھی ہیں۔ یہ سن کر آپ صلی اللہ علیہ وسلم نے اپنے دونوں پاؤں پھیرے اور قبلہ کی طرف منہ کر لیا اور ( سہو کے ) دو سجدے کئے اور سلام پھیرا۔ پھر ہماری طرف متوجہ ہوئے اور فرمایا کہ اگر نماز میں کوئی نیا حکم نازل ہوا ہوتا تو میں تمہیں پہلے ہی ضرور کہہ دیتا لیکن میں تو تمہارے ہی جیسا آدمی ہوں، جس طرح تم بھولتے ہو میں بھی بھول جاتا ہوں۔ اس لیے جب میں بھول جایا کروں تو تم مجھے یاد دلایا کرو اور اگر کسی کو نماز میں شک ہو جائے تو اس وقت ٹھیک بات سوچ لے اور اسی کے مطابق نماز پوری کرے پھر سلام پھیر کر دو سجدے ( سہو کے ) کر لے۔' WHERE id = 397;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، کہا ہم سے قتادہ نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مسجد میں تھوکنا گناہ ہے اور اس کا کفارہ اسے ( زمین میں ) چھپا دینا ہے۔' WHERE id = 410;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا کہ مجھ سے عقیل نے ابن شہاب کے واسطہ سے بیان کیا کہ مجھے محمود بن ربیع انصاری نے کہ عتبان بن مالک انصاری رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کے صحابی اور غزوہ بدر کے حاضر ہونے والوں میں سے تھے، وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور کہا یا رسول اللہ! میری بینائی میں کچھ فرق آ گیا ہے اور میں اپنی قوم کے لوگوں کو نماز پڑھایا کرتا ہوں لیکن جب برسات کا موسم آتا ہے تو میرے اور میری قوم کے درمیان جو وادی ہے وہ بھر جاتی ہے اور بہنے لگ جاتی ہے اور میں انہیں نماز پڑھانے کے لیے مسجد تک نہیں جا سکتا یا رسول اللہ! میری خواہش ہے کہ آپ میرے گھر تشریف لائیں اور ( کسی جگہ ) نماز پڑھ دیں تاکہ میں اسے نماز پڑھنے کی جگہ بنا لوں۔ راوی نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے عتبان سے فرمایا، انشاء اللہ تعالیٰ میں تمہاری اس خواہش کو پورا کروں گا۔ عتبان نے کہا کہ ( دوسرے دن ) رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر صدیق رضی اللہ عنہ جب دن چڑھا تو دونوں تشریف لے آئے اور رسول اللہ صلی اللہ علیہ وسلم نے اندر آنے کی اجازت چاہی، میں نے اجازت دے دی۔ جب آپ گھر میں تشریف لائے تو بیٹھے بھی نہیں اور پوچھا کہ تم اپنے گھر کے کس حصہ میں مجھ سے نماز پڑھنے کی خواہش رکھتے ہو۔ عتبان نے کہا کہ میں نے گھر میں ایک کونے کی طرف اشارہ کیا، تو رسول اللہ صلی اللہ علیہ وسلم ( اس جگہ ) کھڑے ہوئے اور تکبیر کہی ہم بھی آپ کے پیچھے کھڑے ہو گئے اور صف باندھی پس آپ نے دو رکعت ( نفل ) نماز پڑھائی پھر سلام پھیرا۔ عتبان نے کہا کہ ہم نے آپ کو تھوڑی دیر کے لیے روکا اور آپ کی خدمت میں حلیم پیش کیا جو آپ ہی کے لیے تیار کیا گیا تھا۔ عتبان نے کہا کہ محلہ والوں کا ایک مجمع گھر میں لگ گیا اور مجمع میں سے ایک شخص بولا کہ مالک بن دخشن یا ( یہ کہا ) ابن دخشن دکھائی نہیں دیتا۔ اس پر کسی دوسرے نے کہہ دیا کہ وہ تو منافق ہے جسے اللہ اور رسول سے کوئی محبت نہیں رسول اللہ صلی اللہ علیہ وسلم نے یہ سن کر فرمایا ایسا مت کہو، کیا تم دیکھتے نہیں کہ اس نے «لا إله إلا الله» کہا ہے اور اس سے مقصود خالص اللہ کی رضا مندی حاصل کرنا ہے۔ تب منافقت کا الزام لگانے والا بولا کہ اللہ اور اس کے رسول کو زیادہ علم ہے ہم تو بظاہر اس کی توجہات اور دوستی منافقوں ہی کے ساتھ دیکھتے ہیں۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے «لا إله إلا الله» کہنے والے پر اگر اس کا مقصد خالص اللہ کی رضا حاصل کرنا ہو دوزخ کی آگ حرام کر دی ہے۔ ابن شہاب نے کہا کہ پھر میں نے محمود سے سن کر حصین بن محمد انصاری سے جو بنوسالم کے شریف لوگوں میں سے ہیں ( اس حدیث ) کے متعلق پوچھا تو انہوں نے اس کی تصدیق کی اور کہا کہ محمود سچا ہے۔' WHERE id = 420;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے مالک کے واسطے سے، انہوں نے ابن شہاب سے، انہوں نے سعید بن مسیب سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، یہودیوں پر اللہ کی لعنت ہو انہوں نے اپنے انبیاء کی قبروں کو مساجد بنا لیا۔' WHERE id = 431;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے عبدالعزیز بن مختار نے بیان کیا، کہا کہ ہم سے خالد حذاء نے عکرمہ سے، انہوں نے بیان کیا کہ مجھ سے اور اپنے صاحبزادے علی سے ابن عباس رضی اللہ عنہما نے کہا کہ ابو سعید خدری رضی اللہ عنہ کی خدمت میں جاؤ اور ان کی احادیث سنو۔ ہم گئے۔ دیکھا کہ ابوسعید رضی اللہ عنہ اپنے باغ کو درست کر رہے تھے۔ ہم کو دیکھ کر آپ نے اپنی چادر سنبھالی اور گوٹ مار کر بیٹھ گئے۔ پھر ہم سے حدیث بیان کرنے لگے۔ جب مسجد نبوی کے بنانے کا ذکر آیا تو آپ نے بتایا کہ ہم تو ( مسجد کے بنانے میں حصہ لیتے وقت ) ایک ایک اینٹ اٹھاتے۔ لیکن عمار دو دو اینٹیں اٹھا رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں دیکھا تو ان کے بدن سے مٹی جھاڑنے لگے اور فرمایا، افسوس! عمار کو ایک باغی جماعت قتل کرے گی۔ جسے عمار جنت کی دعوت دیں گے اور وہ جماعت عمار کو جہنم کی دعوت دے رہی ہو گی۔ ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ عمار رضی اللہ عنہ کہتے تھے کہ میں فتنوں سے اللہ کی پناہ مانگتا ہوں۔' WHERE id = 441;
UPDATE hadiths SET urdu = 'ہم سے عبدان بن عبداللہ بن عثمان نے ابوحمزہ محمد بن میمون کے واسطہ سے بیان کیا، انہوں نے اعمش سے، انہوں نے مسلم سے، انہوں نے مسروق سے، انہوں نے عائشہ رضی اللہ عنہا سے۔ آپ فرماتی ہیں کہ جب سورۃ البقرہ کی سود سے متعلق آیات نازل ہوئیں تو نبی کریم صلی اللہ علیہ وسلم مسجد میں تشریف لے گئے اور ان آیات کی لوگوں کے سامنے تلاوت فرمائی۔ پھر فرمایا کہ شراب کی تجارت حرام ہے۔' WHERE id = 452;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے سعید بن ابی سعید مقبری کے واسطہ سے بیان کیا انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے کچھ سواروں کو نجد کی طرف بھیجا تھا۔ وہ لوگ بنو حنیفہ کے ایک شخص ثمامہ بن اثال کو ( بطور جنگی قیدی ) پکڑ لائے اور مسجد میں ایک ستون سے باندھ دیا۔' WHERE id = 462;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے سفیان ثوری نے ابی بردہ بن عبداللہ بن ابی بردہ سے، انہوں نے اپنے دادا (ابوبردہ) سے، انہوں نے ابوموسیٰ اشعری رضی اللہ عنہ سے۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا ایک مومن دوسرے مومن کے لیے عمارت کی طرح ہے کہ اس کا ایک حصہ دوسرے حصہ کو قوت پہنچاتا ہے۔ اور آپ صلی اللہ علیہ وسلم نے ایک ہاتھ کی انگلیوں کو دوسرے ہاتھ کی انگلیوں میں داخل کیا۔' WHERE id = 473;
UPDATE hadiths SET urdu = 'اور عبداللہ بن عمر رضی اللہ عنہما نے نافع سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مقام ذی طویٰ میں قیام فرماتے اور رات یہیں گزارا کرتے تھے اور صبح ہوتی تو نماز فجر یہیں پڑھتے۔ مکہ جاتے ہوئے۔ یہاں نبی کریم صلی اللہ علیہ وسلم کے نماز پڑھنے کی جگہ ایک بڑے سے ٹیلے پر تھی۔ اس مسجد میں نہیں جواب وہاں بنی ہوئی ہے بلکہ اس سے نیچے ایک بڑا ٹیلا تھا۔' WHERE id = 483;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے حکم بن عیینہ سے، انہوں نے ابوحجیفہ سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم ہمارے پاس دوپہر کے وقت تشریف لائے اور آپ صلی اللہ علیہ وسلم نے بطحاء میں ظہر اور عصر کی دو دو رکعتیں پڑھیں۔ آپ صلی اللہ علیہ وسلم کے سامنے عنزہ گاڑ دیا گیا تھا اور جب آپ صلی اللہ علیہ وسلم نے وضو کیا تو لوگ آپ صلی اللہ علیہ وسلم کے وضو کے پانی کو اپنے بدن پر لگا رہے تھے۔' WHERE id = 493;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن خلیل نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا سلیمان اعمش کے واسطہ سے، انہوں نے مسلم بن صبیح سے، انہوں نے مسروق سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ ان کے سامنے ذکر ہوا کہ نماز کو کیا چیزیں توڑ دیتی ہیں، لوگوں نے کہا کہ کتا، گدھا اور عورت ( بھی ) نماز کو توڑ دیتی ہے۔ ( جب سامنے آ جائے ) عائشہ رضی اللہ عنہا نے فرمایا کہ تم نے ہمیں کتوں کے برابر بنا دیا۔ حالانکہ میں جانتی ہوں کہ نبی کریم صلی اللہ علیہ وسلم نماز پڑھ رہے تھے۔ میں آپ صلی اللہ علیہ وسلم کے اور آپ صلی اللہ علیہ وسلم کے قبلہ کے درمیان ( سامنے ) چارپائی پر لیٹی ہوئی تھی۔ مجھے ضرورت پیش آتی تھی اور یہ بھی اچھا نہیں معلوم ہوتا تھا کہ خود کو آپ صلی اللہ علیہ وسلم کے سامنے کر دوں۔ اس لیے میں آہستہ سے نکل آتی تھی۔ اعمش نے ابراہیم سے، انہوں نے اسود سے، انہوں نے عائشہ سے اسی طرح یہ حدیث بیان کی۔' WHERE id = 503;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عباد بن عباد بصریٰ نے، اور یہ عباد کے لڑکے ہیں، ابوجمرہ (نصر بن عمران) کے ذریعہ سے، انہوں نے ابن عباس رضی اللہ عنہما سے، انہوں نے کہا کہ عبدالقیس کا وفد رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں آیا اور کہا کہ ہم اس ربیعہ قبیلہ سے ہیں اور ہم آپ صلی اللہ علیہ وسلم کی خدمت میں صرف حرمت والے مہینوں ہی میں حاضر ہو سکتے ہیں، اس لیے آپ صلی اللہ علیہ وسلم کسی ایسی بات کا ہمیں حکم دیجیئے، جسے ہم آپ صلی اللہ علیہ وسلم سے سیکھ لیں اور اپنے پیچھے رہنے والے دوسرے لوگوں کو بھی اس کی دعوت دے سکیں، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہیں چار چیزوں کا حکم دیتا ہوں اور چار چیزوں سے روکتا ہوں، پہلے اللہ پر ایمان لانے کا، پھر آپ صلی اللہ علیہ وسلم نے اس کی تفصیل بیان فرمائی کہ اس بات کی شہادت دینا کہ اللہ کے سوا کوئی معبود نہیں اور یہ کہ میں اللہ کا رسول ہوں، اور دوسرے نماز قائم کرنے کا، تیسرے زکوٰۃ دینے کا، اور چوتھے جو مال تمہیں غنیمت میں ملے، اس میں سے پانچواں حصہ ادا کرنے کا اور تمہیں میں تونبڑی حنتم، قسار اور نقیر کے استعمال سے روکتا ہوں۔ ( نوٹ: یہ تمام برتن شراب بنانے کے لیے استعمال ہوتے تھے ) ۔' WHERE id = 514;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر محمد بن جعفر نے بیان کیا، ان سے شعبہ بن حجاج نے مہاجر ابوالحسن کی روایت سے بیان کیا، انہوں نے زید بن وہب ہمدانی سے سنا۔ انہوں نے ابوذر رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم کے مؤذن ( بلال ) نے ظہر کی اذان دی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ٹھنڈا کر، ٹھنڈا کر، یا یہ فرمایا کہ انتظار کر، انتظار کر، اور فرمایا کہ گرمی کی تیزی جہنم کی آگ کی بھاپ سے ہے۔ اس لیے جب گرمی سخت ہو جائے تو نماز ٹھنڈے وقت میں پڑھا کرو، پھر ظہر کی اذان اس وقت کہی گئی جب ہم نے ٹیلوں کے سائے دیکھ لیے۔' WHERE id = 525;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، انہوں نے کہا ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہمیں عوف نے خبر دی سیار بن سلامہ سے، انہوں نے بیان کیا کہ میں اور میرے باپ ابوبرزہ اسلمی رضی اللہ عنہ کی خدمت میں حاضر ہوئے۔ ان سے میرے والد نے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم فرض نمازیں کن وقتوں میں پڑھتے تھے۔ انہوں نے فرمایا کہ دوپہر کی نماز جسے تم ”پہلی نماز“ کہتے ہو سورج ڈھلنے کے بعد پڑھتے تھے۔ اور جب عصر پڑھتے اس کے بعد کوئی شخص مدینہ کے انتہائی کنارہ پر اپنے گھر واپس جاتا تو سورج اب بھی تیز ہوتا تھا۔ سیار نے کہا کہ مغرب کے وقت کے متعلق آپ نے جو کچھ کہا تھا وہ مجھے یاد نہیں رہا۔ اور عشاء کی نماز جسے تم «عتمه» کہتے ہو اس میں دیر کو پسند فرماتے تھے اور اس سے پہلے سونے کو اور اس کے بعد بات چیت کرنے کو ناپسند فرماتے اور صبح کی نماز سے اس وقت فارغ ہو جاتے جب آدمی اپنے قریب بیٹھے ہوئے دوسرے شخص کو پہچان سکتا اور صبح کی نماز میں آپ ساٹھ سے سو تک آیتیں پڑھا کرتے تھے۔' WHERE id = 536;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا مجھ سے ابراہیم بن سعد نے ابن شہاب سے، انہوں نے سالم بن عبداللہ بن عمر رضی اللہ عنہما سے، انہوں نے اپنے باپ عبداللہ بن عمر رضی اللہ عنہما سے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ تم سے پہلے کی امتوں کے مقابلہ میں تمہاری زندگی صرف اتنی ہے جتنا عصر سے سورج ڈوبنے تک کا وقت ہوتا ہے۔ توراۃ والوں کو توراۃ دی گئی۔ تو انہوں نے اس پر ( صبح سے ) عمل کیا۔ آدھے دن تک پھر وہ عاجز آ گئے، کام پورا نہ کر سکے، ان لوگوں کو ان کے عمل کا بدلہ ایک ایک قیراط دیا گیا۔ پھر انجیل والوں کو انجیل دی گئی، انہوں نے ( آدھے دن سے ) عصر تک اس پر عمل کیا، اور وہ بھی عاجز آ گئے۔ ان کو بھی ایک ایک قیراط ان کے عمل کا بدلہ دیا گیا۔ پھر ( عصر کے وقت ) ہم کو قرآن ملا۔ ہم نے اس پر سورج کے غروب ہونے تک عمل کیا ( اور کام پورا کر دیا ) ہمیں دو دو قیراط ثواب ملا۔ اس پر ان دونوں کتاب والوں نے کہا۔ اے ہمارے پروردگار! انہیں تو آپ نے دو دو قیراط دئیے اور ہمیں صرف ایک ایک قیراط۔ حالانکہ عمل ہم نے ان سے زیادہ کیا۔ اللہ عزوجل نے فرمایا، تو کیا میں نے اجر دینے میں تم پر کچھ ظلم کیا۔ انہوں نے عرض کی کہ نہیں۔ اللہ تعالیٰ نے فرمایا کہ پھر یہ ( زیادہ اجر دینا ) میرا فضل ہے جسے میں چاہوں دے سکتا ہوں۔' WHERE id = 546;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا کہا ہم سے ابواسامہ نے برید کے واسطہ سے، انہوں نے ابی بردہ سے انہوں نے ابوموسیٰ اشعری رضی اللہ عنہ سے، آپ نے فرمایا کہ میں نے اپنے ان ساتھیوں کے ساتھ جو کشتی میں میرے ساتھ ( حبشہ سے ) آئے تھے ”بقیع بطحان“ میں قیام کیا۔ اس وقت نبی کریم صلی اللہ علیہ وسلم مدینہ میں تشریف رکھتے تھے۔ ہم میں سے کوئی نہ کوئی عشاء کی نماز میں روزانہ باری مقرر کر کے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا کرتا تھا۔ اتفاق سے میں اور میرے ایک ساتھی ایک مرتبہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ آپ صلی اللہ علیہ وسلم اپنے کسی کام میں مشغول تھے۔ ( کسی ملی معاملہ میں آپ صلی اللہ علیہ وسلم اور ابوبکر صدیق رضی اللہ عنہ گفتگو فرما رہے تھے ) جس کی وجہ سے نماز میں دیر ہو گئی اور تقریباً آدھی رات گزر گئی۔ پھر نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور نماز پڑھائی۔ نماز پوری کر چکے تو حاضرین سے فرمایا کہ اپنی اپنی جگہ پر وقار کے ساتھ بیٹھے رہو اور ایک خوشخبری سنو۔ تمہارے سوا دنیا میں کوئی بھی ایسا آدمی نہیں جو اس وقت نماز پڑھتا ہو، یا آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ تمہارے سوا اس وقت کسی ( امت ) نے بھی نماز نہیں پڑھی تھی۔ یہ یقین نہیں کہ آپ نے ان دو جملوں میں سے کون سا جملہ کہا تھا۔ پھر راوی نے کہا کہ ابوموسیٰ رضی اللہ عنہ نے فرمایا۔ پس ہم نبی کریم صلی اللہ علیہ وسلم سے یہ سن کر بہت ہی خوش ہو کر لوٹے۔' WHERE id = 556;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا امام مالک سے، انہوں نے زید بن اسلم سے، انہوں نے عطاء بن یسار اور بسر بن سعید اور عبدالرحمٰن بن ہرمز اعرج سے، ان تینوں نے ابوہریرہ رضی اللہ عنہ کے واسطے سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے فجر کی ایک رکعت ( جماعت کے ساتھ ) سورج نکلنے سے پہلے پا لی اس نے فجر کی نماز ( باجماعت کا ثواب ) پا لیا۔ اور جس نے عصر کی ایک رکعت ( جماعت کے ساتھ ) سورج ڈوبنے سے پہلے پا لی، اس نے عصر کی نماز ( باجماعت کا ثواب ) پا لیا۔' WHERE id = 567;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، کہا کہ مجھے میرے باپ عروہ نے خبر دی، کہا کہ عائشہ رضی اللہ عنہا نے فرمایا میرے بھانجے! نبی کریم صلی اللہ علیہ وسلم نے عصر کے بعد کی دو رکعات میرے یہاں کبھی ترک نہیں کیں۔' WHERE id = 578;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا انہوں نے کہا کہ ہمیں شعیب بن ابی حمزہ نے زہری سے خبر دی، کہا کہ مجھ سے سالم بن عبداللہ بن عمر رضی اللہ عنہما اور ابوبکر بن ابی حثمہ نے حدیث بیان کی کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے عشاء کی نماز پڑھی اپنی زندگی کے آخری زمانے میں۔ سلام پھیرنے کے بعد آپ کھڑے ہوئے اور فرمایا کہ اس رات کے متعلق تمہیں کچھ معلوم ہے؟ آج اس روئے زمین پر جتنے انسان زندہ ہیں۔ سو سال بعد ان میں سے کوئی بھی باقی نہیں رہے گا۔ لوگوں نے نبی کریم صلی اللہ علیہ وسلم کا کلام سمجھنے میں غلطی کی اور مختلف باتیں کرنے لگے۔ ( ابومسعود رضی اللہ عنہ نے یہ سمجھا کہ سو برس بعد قیامت آئے گی ) حالانکہ آپ صلی اللہ علیہ وسلم کا مقصد صرف یہ تھا کہ جو لوگ آج ( اس گفتگو کے وقت ) زمین پر بستے ہیں۔ ان میں سے کوئی بھی آج سے ایک صدی بعد باقی نہیں رہے گا۔ آپ صلی اللہ علیہ وسلم کا مطلب یہ تھا کہ سو برس میں یہ قرن گزر جائے گا۔' WHERE id = 588;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے ابن شہاب زہری سے خبر دی، انہوں نے عطاء بن یزید لیثی سے، انہوں نے ابو سعید خدری رضی اللہ عنہ سے، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہ جب تم اذان سنو تو جس طرح مؤذن کہتا ہے اسی طرح تم بھی کہو۔' WHERE id = 598;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا کہ ہم سے زہیر بن معاویہ جعفی نے بیان کیا، کہا کہ ہم سے سلیمان بن طرخان تیمی نے بیان کیا ابوعثمان عبدالرحمٰن نہدی سے، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ بلال کی اذان تمہیں سحری کھانے سے نہ روک دے کیونکہ وہ رات رہے سے اذان دیتے ہیں یا ( یہ کہا کہ ) پکارتے ہیں۔ تاکہ جو لوگ عبادت کے لیے جاگے ہیں وہ آرام کرنے کے لیے لوٹ جائیں اور جو ابھی سوئے ہوئے ہیں وہ ہوشیار ہو جائیں۔ کوئی یہ نہ سمجھ بیٹھے کہ فجر یا صبح صادق ہو گئی اور آپ نے اپنی انگلیوں کے اشارے سے ( طلوع صبح کی کیفیت ) بتائی۔ انگلیوں کو اوپر کی طرف اٹھایا اور پھر آہستہ سے انہیں نیچے لائے اور پھر فرمایا کہ اس طرح ( فجر ہوتی ہے ) زہیر راوی نے بھی شہادت کی انگلی ایک دوسری پر رکھی، پھر انہیں دائیں بائیں جانب پھیلا دیا۔' WHERE id = 608;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، انہوں نے کہا کہ ہمیں جعفر بن عون نے خبر دی، انہوں نے کہا کہ ہم سے ابوالعمیس نے بیان کیا، انہوں نے عون بن ابی حجیفہ سے ابوحجیفہ کے واسطہ سے بیان کیا، کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو ابطح میں دیکھا کہ بلال حاضر ہوئے اور آپ صلی اللہ علیہ وسلم کو نماز کی خبر دی پھر بلال رضی اللہ عنہ برچھی لے کر آگے بڑھے اور اسے آپ صلی اللہ علیہ وسلم کے سامنے ( بطور سترہ ) مقام ابطح میں گاڑ دیا اور آپ صلی اللہ علیہ وسلم نے ( اس کو سترہ بنا کر ) نماز پڑھائی۔' WHERE id = 619;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا، کہا کہ ہم سے عبدالاعلیٰ نے بیان کیا، کہا کہ ہم سے حمید طویل نے بیان کیا، کہا کہ میں نے ثابت بنانی سے ایک شخص کے متعلق مسئلہ دریافت کیا جو نماز کے لیے تکبیر ہونے کے بعد گفتگو کرتا رہے۔ اس پر انہوں نے انس بن مالک رضی اللہ عنہ سے بیان کیا کہ انہوں نے فرمایا کہ تکبیر ہو چکی تھی۔ اتنے میں ایک شخص نبی کریم صلی اللہ علیہ وسلم سے راستہ میں ملا اور آپ صلی اللہ علیہ وسلم کو نماز کے لیے تکبیر کہی جانے کے بعد بھی روکے رکھا۔' WHERE id = 629;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن حوشب نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالوہاب ثقفی نے بیان کیا، انہوں نے کہا کہ مجھ سے حمید طویل نے انس بن مالک رضی اللہ عنہ سے بیان کیا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اے بنو سلمہ والو! کیا تم اپنے قدموں کا ثواب نہیں چاہتے؟' WHERE id = 639;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے نافع سے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما نے ایک ٹھنڈی اور برسات کی رات میں اذان دی، پھر یوں پکار کر کہہ دیا «ألا صلوا في الرحال‏» کہ لوگو! اپنی قیام گاہوں پر ہی نماز پڑھ لو۔ پھر فرمایا کہ نبی کریم صلی اللہ علیہ وسلم سردی و بارش کی راتوں میں مؤذن کو حکم دیتے تھے کہ وہ اعلان کر دے کہ لوگو اپنی قیام گاہوں پر ہی نماز پڑھ لو۔' WHERE id = 649;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے حکم بن عتبہ نے ابراہیم نخعی سے بیان کیا، انہوں نے اسود بن یزید سے، انہوں نے کہا کہ میں نے عائشہ رضی اللہ عنہا سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے گھر میں کیا کیا کرتے تھے آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم اپنے گھر کے کام کاج یعنی اپنے گھر والیوں کی خدمت کیا کرتے تھے اور جب نماز کا وقت ہوتا تو فوراً ( کام کاج چھوڑ کر ) نماز کے لیے چلے جاتے تھے۔' WHERE id = 659;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن اسد نے بیان کیا، کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، کہا کہ ہمیں معمر نے زہری سے خبر دی، کہا کہ مجھے محمود بن ربیع نے خبر دی، کہا کہ میں نے عتبان بن مالک انصاری رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( میرے گھر تشریف لانے کی ) اجازت چاہی اور میں نے آپ کو اجازت دی، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تم لوگ اپنے گھر میں جس جگہ پسند کرو میں نماز پڑھ دوں میں جہاں چاہتا تھا اس کی طرف میں نے اشارہ کیا۔ پھر آپ کھڑے ہو گئے اور ہم نے آپ کے پیچھے صف باندھ لی۔ پھر آپ نے جب سلام پھیرا تو ہم نے بھی سلام پھیرا۔' WHERE id = 669;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابان نے بیان کیا، کہا کہ ہم سے غندر محمد بن جعفر نے بیان کیا شعبہ سے، انہوں نے ابوالتیاح سے، انہوں نے انس بن مالک سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے ابوذر سے فرمایا ( حاکم کی ) سن اور اطاعت کر۔ خواہ وہ ایک ایسا حبشی غلام ہی کیوں نہ ہو جس کا سر منقے کے برابر ہو۔' WHERE id = 680;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر عبداللہ بن عمرو نے بیان کیا، کہا کہ ہم سے عبدالوارث بن سعید نے بیان کیا، کہا کہ ہم سے عبدالعزیز بن صہیب نے انس بن مالک رضی اللہ عنہ سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نماز کو مختصر اور پوری پڑھتے تھے۔' WHERE id = 690;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ ہم سے امام مالک بن انس نے ہشام بن عروہ سے بیان کیا، انہوں نے اپنے باپ سے، انہوں نے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا سے کہ رسول اللہ صلی اللہ علیہ وسلم نے مرض الوفات میں فرمایا کہ ابوبکر سے لوگوں کو نماز پڑھانے کے لیے کہو۔ عائشہ رضی اللہ عنہا کہتی ہیں کہ میں نے عرض کی کہ ابوبکر اگر آپ کی جگہ کھڑے ہوئے تو رونے کی وجہ سے لوگوں کو اپنی آواز نہ سنا سکیں گے۔ اس لیے آپ عمر رضی اللہ عنہ سے فرمائیے کہ وہ نماز پڑھائیں۔ آپ نے پھر فرمایا کہ نہیں ابوبکر ہی سے نماز پڑھانے کے لیے کہو۔ عائشہ رضی اللہ عنہا بیان کرتی ہیں کہ میں نے حفصہ رضی اللہ عنہا سے کہا کہ تم بھی تو نبی کریم صلی اللہ علیہ وسلم سے عرض کرو کہ اگر ابوبکر آپ کی جگہ کھڑے ہوئے تو آپ کو یاد کر کے گریہ و زاری کی وجہ سے لوگوں کو قرآن نہ سنا سکیں گے۔ اس لیے عمر رضی اللہ عنہ سے کہئے کہ وہ نماز پڑھائیں۔ حفصہ رضی اللہ عنہا نے بھی کہہ دیا۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا۔ بس چپ رہو، تم لوگ صواحب یوسف سے کسی طرح کم نہیں ہو۔ ابوبکر سے کہو کہ وہ نماز پڑھائیں۔ بعد میں حفصہ رضی اللہ عنہا نے عائشہ رضی اللہ عنہا سے کہا۔ بھلا مجھ کو تم سے کہیں بھلائی ہونی ہے۔' WHERE id = 700;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے ثابت بن یزید نے بیان کیا، کہا کہ ہم سے عاصم احول نے عامر شعبی سے بیان کیا، انہوں نے ابن عباس رضی اللہ عنہما سے، آپ نے بتلایا کہ میں ایک رات نبی کریم صلی اللہ علیہ وسلم کے بائیں طرف ( آپ صلی اللہ علیہ وسلم کے گھر میں ) نماز ( تہجد ) پڑھنے کے لیے کھڑا ہو گیا۔ اس لیے آپ صلی اللہ علیہ وسلم نے میرا سر یا بازو پکڑ کر مجھ کو اپنی دائیں طرف کھڑا کر دیا۔ آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ سے اشارہ کیا تھا کہ پیچھے سے گھوم آؤ۔' WHERE id = 711;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے زہری سے خبر دی، انہوں نے کہا کہ مجھے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا کہ آپ صلی اللہ علیہ وسلم نماز تکبیر تحریمہ سے شروع کرتے اور تکبیر کہتے وقت اپنے دونوں ہاتھوں کو کندھوں تک اٹھا کر لے جاتے اور جب رکوع کے لیے تکبیر کہتے تب بھی اسی طرح کرتے اور جب «سمع الله لمن حمده» کہتے تب بھی اسی طرح کرتے اور «ربنا ولك الحمد» کہتے۔ سجدہ کرتے وقت یا سجدے سے سر اٹھاتے وقت اس طرح رفع یدین نہیں کرتے تھے۔' WHERE id = 721;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھے امام مالک نے زید بن اسلم سے بیان کیا، انہوں نے عطاء بن یسار سے، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کے عہد میں سورج گہن ہوا تو آپ صلی اللہ علیہ وسلم نے گہن کی نماز پڑھی۔ لوگوں نے پوچھا کہ یا رسول اللہ! ہم نے دیکھا کہ ( نماز میں ) آپ صلی اللہ علیہ وسلم اپنی جگہ سے کچھ لینے کو آگے بڑھے تھے پھر ہم نے دیکھا کہ کچھ پیچھے ہٹے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے جنت دیکھی تو اس میں سے ایک خوشہ لینا چاہا اور اگر میں لے لیتا تو اس وقت تک تم اسے کھاتے رہتے جب تک دنیا موجود ہے۔' WHERE id = 731;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل نے بیان کیا، کہا کہ ہم سے ابوعوانہ وضاح یشکری نے عبدالملک بن عمیر سے بیان کیا، انہوں نے جابر بن سمرہ سے کہ سعد بن ابی وقاص رضی اللہ عنہ نے عمر رضی اللہ عنہ سے کہا میں ان ( کوفہ والوں ) کو نبی کریم صلی اللہ علیہ وسلم کی طرح نماز پڑھاتا تھا۔ ظہر اور عصر کی دونوں نمازیں، کسی قسم کا نقص ان میں نہیں چھوڑتا تھا۔ پہلی دو رکعتیں لمبی پڑھتا اور دوسری دو رکعتیں ہلکی۔ تو عمر رضی اللہ عنہ نے فرمایا کہ مجھ کو تم سے امید بھی یہی تھی۔' WHERE id = 741;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، کہا کہ ہم سے تیمی نے ابوبکر سے، انہوں نے ابورافع سے، انہوں نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ کے ساتھ عشاء پڑھی، آپ نے «إذا السماء انشقت‏» اور سجدہ کیا۔ اس پر میں نے کہا کہ یہ سجدہ کیسا ہے؟ آپ نے جواب دیا کہ اس سورت میں میں نے ابوالقاسم صلی اللہ علیہ وسلم کے پیچھے سجدہ کیا تھا۔ اس لیے میں بھی ہمیشہ اس میں سجدہ کروں گا، یہاں تک کہ آپ سے مل جاؤں۔' WHERE id = 751;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، انہوں نے کہا کہ ہم سے امام عبدالرحمٰن اوزاعی نے بیان کیا، انہوں نے کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، انہوں نے کہا کہ مجھ سے عبداللہ بن ابی قتادہ نے بیان کیا، وہ اپنے والد ابوقتادہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم ظہر اور عصر کی دو پہلی رکعتوں میں سورۃ فاتحہ اور کوئی اور سورۃ پڑھتے تھے۔ کبھی کبھی آپ صلی اللہ علیہ وسلم کوئی آیت ہمیں سنا بھی دیا کرتے تھے۔ پہلی رکعت میں قرآت زیادہ طویل کرتے تھے۔' WHERE id = 762;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے ہمام بن یحییٰ نے قتادہ سے بیان کیا، وہ عکرمہ سے، کہا کہ میں نے مکہ میں ایک بوڑھے کے پیچھے ( ظہر کی ) نماز پڑھی۔ انہوں نے ( تمام نماز میں ) بائیس تکبیریں کہیں۔ اس پر میں نے ابن عباس رضی اللہ عنہما سے کہا کہ یہ بوڑھا بالکل بے عقل معلوم ہوتا ہے ابن عباس رضی اللہ عنہما نے فرمایا تمہاری ماں تمہیں روئے یہ تو ابوالقاسم صلی اللہ علیہ وسلم کی سنت ہے۔ اور موسیٰ بن اسماعیل نے یوں بھی بیان کیا کہ ہم سے ابان نے بیان کیا، کہ کہا ہم سے قتادہ نے، انہوں نے کہا کہ ہم سے عکرمہ نے یہ حدیث بیان کی۔' WHERE id = 772;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، انہوں نے کہا کہ ہم سے اسماعیل بن علیہ نے بیان کیا، انہوں نے خالد بن حذاء سے بیان کیا، انہوں نے ابوقلابہ (عبداللہ بن زید) سے، انہوں نے انس رضی اللہ عنہ سے کہ آپ نے فرمایا کہ دعا قنوت فجر اور مغرب کی نمازوں میں پڑھی جاتی ہے۔' WHERE id = 782;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد بصریٰ نے بیان کیا، کہا ہم سے مہدی بن میمون نے واصل سے بیان کیا، انہوں نے ابووائل سے، انہوں نے حذیفہ رضی اللہ عنہ سے کہ انہوں نے ایک شخص کو دیکھا جو رکوع اور سجدہ پوری طرح نہیں کرتا تھا۔ جب وہ نماز پڑھ چکا تو انہوں نے اس سے فرمایا کہ تو نے نماز ہی نہیں پڑھی۔ ابووائل نے کہا کہ مجھے یاد آتا ہے کہ حذیفہ نے یہ فرمایا کہ اگر تم مر گئے تو تمہاری موت محمد صلی اللہ علیہ وسلم کے طریق پر نہیں ہو گی۔' WHERE id = 792;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم صاعقہ نے بیان کیا، انہوں نے کہا کہ ہم سے ابواحمد محمد بن عبداللہ زبیری نے کہا کہ ہم سے مسعر بن کدام نے حکم عتیبہ کوفی سے انہوں نے عبدالرحمٰن بن ابی لیلیٰ سے انہوں نے براء بن عازب رضی اللہ عنہ سے انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کا سجدہ، رکوع اور دونوں سجدوں کے درمیان بیٹھنے کی مقدار تقریباً برابر ہوتی تھی۔' WHERE id = 803;
UPDATE hadiths SET urdu = 'قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے بکر بن مضر نے جعفر بن ربیعہ سے بیان کیا، انہوں نے اعرج سے بیان کیا، ان سے عبداللہ بن مالک بن بحینہ رضی اللہ عنہ نے، کہا کہ ہمیں رسول اللہ صلی اللہ علیہ وسلم نے نماز ظہر پڑھائی۔ آپ کو چاہیے تھا بیٹھنا لیکن آپ صلی اللہ علیہ وسلم ( بھول کر ) کھڑے ہو گئے پھر نماز کے آخر میں بیٹھے ہی بیٹھے دو سجدے کئے۔' WHERE id = 813;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر نے بیان کیا، انہوں نے کہا کہ ہم سے معتمر بن سلیمان نے بیان کیا، ان سے عبیداللہ عمری نے بیان کیا، ان سے سمی نے بیان کیا، ان سے ابوصالح ذکوان نے بیان کیا ان سے ابوہریرہ رضی اللہ عنہ نے فرمایا کہ نادار لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور کہا کہ امیر و رئیس لوگ بلند درجات اور ہمیشہ رہنے والی جنت حاصل کر چکے حالانکہ جس طرح ہم نماز پڑھتے ہیں وہ بھی پڑھتے ہیں اور جیسے ہم روزے رکھتے ہیں وہ بھی رکھتے ہیں لیکن مال و دولت کی وجہ سے انہیں ہم پر فوقیت حاصل ہے کہ اس کی وجہ سے وہ حج کرتے ہیں۔ عمرہ کرتے ہیں۔ جہاد کرتے ہیں اور صدقے دیتے ہیں ( اور ہم محتاجی کی وجہ سے ان کاموں کو نہیں کر پاتے ) اس پر آپ نے فرمایا کہ لو میں تمہیں ایک ایسا عمل بتاتا ہوں کہ اگر تم اس کی پابندی کرو گے تو جو لوگ تم سے آگے بڑھ چکے ہیں انہیں تم پالو گے اور تمہارے مرتبہ تک پھر کوئی نہیں پہنچ سکتا اور تم سب سے اچھے ہو جاؤ گے سوا ان کے جو یہی عمل شروع کر دیں ہر نماز کے بعد تینتیس تینتیس مرتبہ تسبیح «سبحان الله»،‏‏‏‏ تحمید «الحمد لله»،‏‏‏‏ تکبیر «الله أكبر» کہا کرو۔ پھر ہم میں اختلاف ہو گیا کسی نے کہا کہ ہم تسبیح «سبحان الله» تینتیس مرتبہ، تحمید «الحمد لله» تینتیس مرتبہ اور تکبیر «الله أكبر» چونتیس مرتبہ کہیں گے۔ میں نے اس پر آپ صلی اللہ علیہ وسلم سے دوبارہ معلوم کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ «سبحان الله»،‏‏‏‏ «الحمد لله» اور «الله أكبر» کہو تاآنکہ ہر ایک ان میں سے تینتیس مرتبہ ہو جائے۔' WHERE id = 824;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ ہم سے ابن وہب نے یونس سے بیان کیا، ان سے ابن شہاب نے کہ عطاء جابر بن عبداللہ سے روایت کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو لہسن یا پیاز کھائے ہوئے ہو تو وہ ہم سے دور رہے یا ( یہ کہا کہ اسے ) ہماری مسجد سے دور رہنا چاہیے یا اسے اپنے گھر میں ہی بیٹھنا چاہیے۔ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ایک ہانڈی لائی گئی جس میں کئی قسم کی ہری ترکاریاں تھیں۔ ( پیاز یا گندنا بھی ) آپ صلی اللہ علیہ وسلم نے اس میں بو محسوس کی اور اس کے متعلق دریافت کیا۔ اس سالن میں جتنی ترکاریاں ڈالیں گئی تھیں وہ آپ صلی اللہ علیہ وسلم کو بتا دی گئیں۔ وہاں ایک صحابی موجود تھے آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی طرف یہ سالن بڑھا دو۔ آپ صلی اللہ علیہ وسلم نے اسے کھانا پسند نہیں فرمایا اور فرمایا کہ تم لوگ کھا لو۔ میری جن سے سرگوشی رہتی ہے تمہاری نہیں رہتی اور احمد بن صالح نے ابن وہب سے یوں نقل کیا کہ تھال آپ صلی اللہ علیہ وسلم کی خدمت میں لائی گئی تھی۔ ابن وہب نے کہا کہ طبق جس میں ہری ترکاریاں تھیں اور لیث اور ابوصفوان نے یونس سے روایت میں ہانڈی کا قصہ نہیں بیان کیا ہے۔ امام بخاری رحمہ اللہ نے ( یا سعید یا ابن وہب نے کہا ) میں نہیں کہہ سکتا کہ یہ خود زہری کا قول ہے یا حدیث میں داخل ہے۔' WHERE id = 835;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے حنظلہ بن ابی سفیان سے بیان کیا، ان سے سالم بن عبداللہ بن عمر نے، ان سے ان کے باپ ابن عمر رضی اللہ عنہما نے، وہ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے تھے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہاری بیویاں تم سے رات میں مسجد آنے کی اجازت مانگیں تو تم لوگ انہیں اس کی اجازت دے دیا کرو۔ عبیداللہ کے ساتھ اس حدیث کو شعبہ نے بھی اعمش سے روایت کیا، انہوں نے مجاہد سے، انہوں نے ابن عمر رضی اللہ عنہما سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 845;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے نافع سے خبر دی اور ان کو عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے جب کوئی شخص جمعہ کی نماز کے لیے آنا چا ہے تو اسے غسل کر لینا چاہیے۔' WHERE id = 857;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک رحمہ اللہ نے ابوالزناد سے خبر دی، ان سے اعرج نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر مجھے اپنی امت یا لوگوں کی تکلیف کا خیال نہ ہوتا تو میں ہر نماز کے لیے ان کو مسواک کا حکم دے دیتا۔' WHERE id = 867;
UPDATE hadiths SET urdu = 'اس حدیث کی روایت ابان بن صالح نے مجاہد سے کی ہے، ان سے طاؤس نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کا ہر مسلمان پر حق ہے کہ ہر سات دن میں ایک دن ( جمعہ ) غسل کرے۔' WHERE id = 877;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے ابن ابی ذئب نے بیان کیا، کہا کہ ہم سے زہری نے سعید اور ابوسلمہ سے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے (دوسری سند سے بیان کیا) امام بخاری رحمہ اللہ نے کہا اور ہم سے ابوالیمان نے بیان کیا، کہا کہ ہمیں شعیب نے خبر دی، انہیں زہری نے اور انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی، وہ ابوہریرہ رضی اللہ عنہ سے روایت کرتے تھے کہ آپ نے رسول اللہ صلی اللہ علیہ وسلم کو یہ کہتے ہوئے سنا کہ جب نماز کے لیے تکبیر کہی جائے تو دوڑتے ہوئے مت آؤ بلکہ ( اپنی معمولی رفتار سے ) آؤ پورے اطمینان کے ساتھ پھر نماز کا جو حصہ ( امام کے ساتھ ) پالو اسے پڑھ لو اور جو رہ جائے تو اسے بعد میں پورا کرو۔' WHERE id = 887;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا کہ ہم سے محمد بن جعفر بن ابی کثیر نے بیان کیا، کہا کہ مجھے یحییٰ بن سعید نے خبر دی، کہا کہ مجھے حفص بن عبداللہ بن انس نے خبر دی، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا کہ ایک کھجور کا تنا تھا جس پر نبی کریم صلی اللہ علیہ وسلم ٹیک لگا کر کھڑے ہوا کرتے تھے۔ جب آپ صلی اللہ علیہ وسلم کے لیے منبر بن گیا ( آپ صلی اللہ علیہ وسلم نے اس تنے پر ٹیک نہیں لگایا ) تو ہم نے اس سے رونے کی آواز سنی جیسے دس مہینے کی گابھن اونٹنی آواز کرتی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے منبر سے اتر کر اپنا ہاتھ اس پر رکھا ( تب وہ آواز موقوف ہوئی ) اور سلیمان نے یحییٰ سے یوں حدیث بیان کی کہ مجھے حفص بن عبیداللہ بن انس نے خبر دی اور انہوں نے جابر سے سنا۔' WHERE id = 897;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے بشر بن مفضل نے بیان کیا، کہا کہ ہم سے عبیداللہ عمری نے نافع سے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم ( جمعہ میں ) دو خطبے دیتے اور دونوں کے بیچ میں بیٹھتے تھے۔ ( خطبہ جمعہ کے بیچ میں یہ بیٹھنا بھی مسنون طریقہ ہے ) ۔' WHERE id = 907;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا کہ ہم سے ابوغسان محمد بن مطر مدنی نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوحازم سلمہ بن دینار نے سہل بن سعد کے واسطے سے بیان کیا، انہوں نے بیان کیا کہ ہمارے یہاں ایک عورت تھی جو نالوں پر اپنے ایک کھیت میں چقندر بوتی۔ جمعہ کا دن آتا تو وہ چقندر اکھاڑ لاتیں اور اسے ایک ہانڈی میں پکاتیں پھر اوپر سے ایک مٹھی جو کا آٹا چھڑک دیتیں۔ اس طرح یہ چقندر گوشت کی طرح ہو جاتے۔ جمعہ سے واپسی میں ہم انہیں سلام کرنے کے لیے حاضر ہوتے تو یہی پکوان ہمارے آگے کر دیتیں اور ہم اسے چاٹ جاتے۔ ہم لوگ ہر جمعہ کو ان کے اس کھانے کے آرزومند رہا کرتے تھے۔' WHERE id = 917;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے زہری سے خبر دی، انہوں نے کہا کہ مجھے سالم بن عبداللہ نے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ عمر رضی اللہ عنہ ایک موٹے ریشمی کپڑے کا چغہ لے کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے جو بازار میں بک رہا تھا کہنے لگے: یا رسول اللہ! آپ اسے خرید لیجئے اور عید اور وفود کی پذیرائی کے لیے اسے پہن کر زینت فرمایا کیجئے۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو وہ پہنے گا جس کا ( آخرت میں ) کوئی حصہ نہیں۔ اس کے بعد جب تک اللہ نے چاہا عمر رہی پھر ایک دن رسول اللہ صلی اللہ علیہ وسلم نے خود ان کے پاس ایک ریشمی چغہ تحفہ میں بھیجا۔ عمر رضی اللہ عنہ اسے لیے ہوئے آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور کہا کہ یا رسول اللہ! آپ نے تو یہ فرمایا کہ اس کو وہ پہنے گا جس کا آخرت میں کوئی حصہ نہیں پھر آپ نے یہ میرے پاس کیوں بھیجا؟ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے اسے تیرے پہننے کو نہیں بھیجا بلکہ اس لیے کہ تم اسے بیچ کر اس کی قیمت اپنے کام میں لاؤ۔' WHERE id = 927;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے، انہوں نے عدی بن ثابت سے، انہوں نے سعید بن جبیر سے، انہوں نے ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے عیدالفطر کے دن دو رکعتیں پڑھیں نہ ان سے پہلے کوئی نفل پڑھا نہ ان کے بعد۔ پھر ( خطبہ پڑھ کر ) آپ صلی اللہ علیہ وسلم عورتوں کے پاس آئے اور بلال آپ کے ساتھ تھے۔ آپ صلی اللہ علیہ وسلم نے عورتوں سے فرمایا خیرات کرو۔ وہ خیرات دینے لگیں کوئی اپنی بالی پیش کرنے لگی کوئی اپنا ہار دینے لگی۔' WHERE id = 939;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے محمد نے، ان سے ام عطیہ رضی اللہ عنہا نے، آپ نے فرمایا کہ ہمیں حکم تھا کہ پردہ والی دوشیزاؤں کو عیدگاہ کے لیے نکالیں اور ایوب سختیانی نے حفصہ رضی اللہ عنہا سے بھی اسی طرح روایت کی ہے۔ حفصہ رضی اللہ عنہا کی حدیث میں یہ زیادتی ہے کہ دوشیزائیں اور پردہ والیاں ضرور ( عیدگاہ جائیں ) اور حائضہ نماز کی جگہ سے علیحدہ رہیں۔' WHERE id = 949;
UPDATE hadiths SET urdu = 'ہم سے حامد بن عمر نے بیان کیا، ان سے حماد بن زید نے، ان سے ایوب سختیانی نے، ان سے محمد نے، ان سے انس بن مالک رضی اللہ عنہ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے بقر عید کے دن نماز پڑھ کر خطبہ دیا آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس شخص نے نماز سے پہلے جانور ذبح کر لیا اسے دوبارہ قربانی کرنی ہو گی۔ اس پر انصار میں سے ایک صاحب اٹھے کہ یا رسول اللہ! میرے کچھ غریب بھوکے پڑوسی ہیں یا یوں کہا وہ محتاج ہیں۔ اس لیے میں نے نماز سے پہلے ذبح کر دیا البتہ میرے پاس ایک سال کی ایک پٹھیا ہے جو دو بکریوں کے گوشت سے بھی زیادہ مجھے پسند ہے۔ آپ صلی اللہ علیہ وسلم نے انہیں اجازت دے دی۔' WHERE id = 959;
UPDATE hadiths SET urdu = 'ہم سے ابو نعمان نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، کہا کہ ہم سے انس بن سیرین نے بیان کیا، کہا کہ میں نے ابن عمر رضی اللہ عنہما سے پوچھا کہ نماز صبح سے پہلے کی دو رکعتوں کے متعلق آپ کا کیا خیال ہے؟ کیا میں ان میں لمبی قرآت کر سکتا ہوں؟ انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم تو رات کی نماز ( تہجد ) دو، دو رکعت کر کے پڑھتے تھے پھر ایک رکعت پڑھ کر ان کو طاق بنا لیتے اور صبح کی نماز سے پہلے کی دو رکعتیں ( سنت فجر تو ) اس طرح پڑھتے گویا اذان ( اقامت ) کی آواز آپ کے کان میں پڑ رہی ہے۔ حماد کی اس سے مراد یہ ہے کہ آپ جلدی پڑھ لیتے۔' WHERE id = 969;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان ثوری نے عبداللہ بن ابی بکر سے بیان کیا، ان سے عباد بن تمیم نے اور ان سے ان کے چچا عبداللہ بن زید نے کہ نبی کریم صلی اللہ علیہ وسلم پانی کی دعا کرنے کے لیے تشریف لے گئے اور اپنی چادر الٹائی۔' WHERE id = 979;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی ایوب نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، انہوں نے شریک بن عبداللہ بن ابی نمر کے واسطے سے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کہا کہ ایک شخص رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ عرض کی یا رسول اللہ صلی اللہ علیہ وسلم ! مویشی ہلاک ہو گئے اور راستے بند ہو گئے۔ آپ اللہ تعالیٰ سے دعا کیجئے۔ رسول اللہ صلی اللہ علیہ وسلم نے دعا فرمائی تو ایک جمعہ سے دوسرے جمعہ تک بارش ہوتی رہی پھر دوسرے جمعہ کو ایک شخص حاضر خدمت ہوا اور کہا کہ یا رسول اللہ صلی اللہ علیہ وسلم ! ( کثرت باراں سے بہت سے ) مکانات گر گئے، راستے بند ہو گئے اور مویشی ہلاک ہو گئے۔ چنانچہ رسول اللہ صلی اللہ علیہ وسلم نے دعا فرمائی «اللهم على رءوس الجبال والآكام وبطون الأودية ومنابت الشجر» کہ اے اللہ! پہاڑوں ٹیلوں وادیوں اور باغات کی طرف بارش کا رخ کر دے۔ ( جہاں بارش کی کمی ہے ) چنانچہ آپ صلی اللہ علیہ وسلم کی دعا سے بادل کپڑے کی طرح پھٹ گیا۔' WHERE id = 990;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے عبداللہ بن ابی بکر سے بیان کیا، انہوں نے عباد بن تمیم سے سنا اور عباد اپنے چچا عبداللہ بن زید رضی اللہ عنہ سے بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم دعائے استسقاء کے لیے عیدگاہ کو نکلے اور قبلہ رخ ہو کر دو رکعت نماز پڑھی پھر چادر پلٹی۔ سفیان ثوری نے کہا مجھے عبدالرحمٰن بن عبداللہ مسعودی نے ابوبکر کے حوالے سے خبر دی کہ آپ صلی اللہ علیہ وسلم نے چادر کا داہنا کونا بائیں کندھے پر ڈالا۔' WHERE id = 1000;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنی نے بیان کیا، انہوں نے کہا کہ ہم سے حسین بن حسن نے بیان کیا، انہوں نے کہا کہ ہم سے عبداللہ بن عون نے بیان کیا، ان سے نافع نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے فرمایا اے اللہ! ہمارے شام اور یمن پر برکت نازل فرما۔ اس پر لوگوں نے کہا اور ہمارے نجد کے لیے بھی برکت کی دعا کیجئے لیکن آپ نے پھر وہی کہا ”اے اللہ! ہمارے شام اور یمن پر برکت نازک فرما“ پھر لوگوں نے کہا اور ہمارے نجد میں؟ تو آپ نے فرمایا کہ وہاں تو زلزلے اور فتنے ہوں گے اور شیطان کا سینگ وہی سے طلوع ہو گا۔' WHERE id = 1010;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہوں نے کہا کہ مجھے عروہ بن زبیر نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ صدیقہ رضی اللہ عنہا نے خبر دی کہ جس دن سورج میں خسوف ( گرہن ) لگا تو نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھائی۔ آپ صلی اللہ علیہ وسلم کھڑے ہوئے تکبیر کہی پھر دیر تک قرآن مجید پڑھتے رہے۔ لیکن اس کے بعد ایک طویل رکوع کیا۔ رکوع سے سر اٹھایا تو کہا «سمع الله لمن حمده‏» پھر آپ صلی اللہ علیہ وسلم پہلے ہی کی طرح کھڑے ہو گئے اور دیر تک قرآن مجید پڑھتے رہے لیکن اس مرتبہ کی قرآت پہلے سے کچھ کم تھی۔ پھر آپ صلی اللہ علیہ وسلم سجدہ میں گئے اور بہت دیر تک سجدہ میں رہے پھر دوسری رکعت میں بھی آپ صلی اللہ علیہ وسلم نے اسی طرح کیا پھر جب آپ صلی اللہ علیہ وسلم نے سلام پھیرا تو سورج صاف ہو چکا تھا۔ نماز سے فارغ ہو کر آپ صلی اللہ علیہ وسلم نے خطبہ دیا اور فرمایا کہ سورج اور چاند کا «كسوف» ( گرہن ) اللہ تعالیٰ کی ایک نشانی ہے اور ان میں «خسوف» ( گرہن ) کسی کی موت و زندگی پر نہیں لگتا۔ لیکن جب تم سے دیکھو تو فوراً نماز کے لیے لپکو۔' WHERE id = 1020;
UPDATE hadiths SET urdu = 'اور ابواسامہ نے بیان کیا کہ ہم سے ہشام بن عروہ نے بیان کیا، انہوں نے کہا کہ مجھے فاطمہ بنت منذر نے خبر دی، ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے فرمایا کہ جب سورج صاف ہو گیا تو رسول اللہ صلی اللہ علیہ وسلم نماز سے فارغ ہوئے اور آپ صلی اللہ علیہ وسلم نے خطبہ دیا۔ پہلے اللہ تعالیٰ کی شان کے مطابق اس کی تعریف کی اس کے بعد فرمایا «أما بعد» ۔' WHERE id = 1032;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے ابن ابی ذئب نے بیان کیا، کہا کہ ہم سے یزید بن عبداللہ بن قسیط نے بیان کیا، ان سے عطاء بن یسار نے، ان سے زید بن ثابت رضی اللہ عنہ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے سامنے سورۃ النجم کی تلاوت کی اور آپ صلی اللہ علیہ وسلم نے اس میں سجدہ نہیں کیا۔' WHERE id = 1043;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہمیں ابواسحاق نے خبر دی، انہوں نے حارثہ سے سنا اور انہوں نے وہب رضی اللہ عنہ سے کہ آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے منیٰ میں امن کی حالت میں ہمیں دو رکعت نماز پڑھائی تھی۔' WHERE id = 1053;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ ہم سے شیبان نے کہا، ان سے یحییٰ نے بیان کیا، ان سے محمد بن عبدالرحمٰن نے بیان کیا، کہ جابر بن عبداللہ رضی اللہ عنہما نے انہیں خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نفل نماز اپنی اونٹنی پر غیر قبلہ کی طرف منہ کر کے بھی پڑھتے تھے۔' WHERE id = 1063;
UPDATE hadiths SET urdu = 'اور لیث بن سعد رحمہ اللہ نے کہا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، انہوں نے کہا کہ مجھ سے عبداللہ بن عامر بن ربیعہ نے بیان کیا کہ انہیں ان کے باپ نے خبر دی کہ انہوں نے خود دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم ( رات میں ) سفر میں نفل نمازیں سواری پر پڑھتے تھے، وہ جدھر آپ صلی اللہ علیہ وسلم کو لے جاتی ادھر ہی سہی۔' WHERE id = 1073;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے زہری سے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم گھوڑے سے گر پڑے اور اس کی وجہ سے آپ صلی اللہ علیہ وسلم کے دائیں پہلو پر زخم آ گئے۔ ہم مزاج پرسی کے لیے گئے تو نماز کا وقت آ گیا۔ آپ صلی اللہ علیہ وسلم نے بیٹھ کر نماز پڑھائی۔ ہم نے بھی بیٹھ کر آپ صلی اللہ علیہ وسلم کے پیچھے نماز پڑھی۔ آپ صلی اللہ علیہ وسلم نے اسی موقع پر فرمایا تھا کہ امام اس لیے ہے تاکہ اس کی پیروی کی جائے۔ اس لیے جب وہ تکبیر کہے تو تم بھی تکبیر کہو، جب وہ رکوع کرے تو تم بھی رکوع کرو، جب وہ سر اٹھائے تو تم بھی سر اٹھاؤ اور جب وہ «سمع الله لمن حمده‏» کہے تو تم «ربنا ولك الحمد» کہو۔' WHERE id = 1083;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، انہیں عبداللہ بن مبارک نے خبر دی، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں ہند بنت حارث نے اور انہیں ام سلمہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ایک رات جاگے تو فرمایا سبحان اللہ! آج رات کیا کیا بلائیں اتری ہیں اور ساتھ ہی ( رحمت اور عنایت کے ) کیسے خزانے نازل ہوئے ہیں۔ ان حجرے والیوں ( ازواج مطہرات رضوان اللہ علیہن ) کو کوئی جگانے والا ہے افسوس! کہ دنیا میں بہت سی کپڑے پہننے والی عورتیں آخرت میں ننگی ہوں گی۔' WHERE id = 1094;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے خالد بن عبداللہ نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے ان سے ابووائل نے اور ان سے حذیفہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم جب رات کو تہجد کے لیے کھڑے ہوتے تو پہلے اپنا منہ مسواک سے خوب صاف کرتے۔' WHERE id = 1105;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، (دوسری سند) اور مجھ سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق عمرو بن عبداللہ نے، ان سے اسود بن یزید نے، انہوں نے بتلایا کہ میں نے عائشہ صدیقہ رضی اللہ عنہا سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم رات میں نماز کیونکر پڑھتے تھے؟ آپ نے بتلایا کہ شروع رات میں سو رہتے اور آخر رات میں بیدار ہو کر تہجد کی نماز پڑھتے۔ اس کے بعد بستر پر آ جاتے اور جب مؤذن اذان دیتا تو جلدی سے اٹھ بیٹھتے۔ اگر غسل کی ضرورت ہوتی تو غسل کرتے ورنہ وضو کر کے باہر تشریف لے جاتے۔' WHERE id = 1115;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا، کہا کہ ہم سے سعید بن ابی ایوب نے بیان کیا، کہا کہ مجھ سے جعفر بن ربیعہ نے بیان کیا، ان سے عراک بن مالک نے، ان سے ابوسلمہ نے، ان سے عائشہ صدیقہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے عشاء کی نماز پڑھی پھر رات کو اٹھ کر آپ صلی اللہ علیہ وسلم نے تہجد کی آٹھ رکعتیں پڑھیں اور دو رکعتیں صبح کی اذان و اقامت کے درمیان پڑھیں جن کو آپ صلی اللہ علیہ وسلم کبھی نہیں چھوڑتے تھے ( فجر کی سنتوں پر مداومت ثابت ہوئی ) ۔' WHERE id = 1126;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے سیف بن سلیمان نے بیان کیا کہ میں نے مجاہد سے سنا، انہوں نے فرمایا کہ عبداللہ بن عمر رضی اللہ عنہما ( مکہ شریف میں ) اپنے گھر آئے۔ کسی نے کہا بیٹھے کیا ہو نبی کریم صلی اللہ علیہ وسلم یہ آ گئے بلکہ کعبہ کے اندر بھی تشریف لے جا چکے ہیں۔ عبداللہ نے کہا یہ سن کر میں آیا۔ دیکھا تو نبی کریم صلی اللہ علیہ وسلم کعبہ سے باہر نکل چکے ہیں اور بلال رضی اللہ عنہ دروازے پر کھڑے ہیں۔ میں نے ان سے پوچھا کہ اے بلال! رسول اللہ صلی اللہ علیہ وسلم نے کعبہ میں نماز پڑھی؟ انہوں نے کہا کہ ہاں پڑھی تھی۔ میں نے پوچھا کہ کہاں پڑھی تھی؟ انہوں نے بتایا کہ یہاں ان دو ستونوں کے درمیان۔ پھر آپ باہر تشریف لائے اور دو رکعتیں کعبہ کے دروازے کے سامنے پڑھیں اور ابوہریرہ رضی اللہ عنہ نے کہا کہ مجھے نبی کریم صلی اللہ علیہ وسلم نے چاشت کی دو رکعتوں کی وصیت کی تھی اور عتبان نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر اور عمر رضی اللہ عنہما صبح دن چڑھے میرے گھر تشریف لائے۔ ہم نے آپ صلی اللہ علیہ وسلم کے پیچھے صف بنا لی اور نبی کریم صلی اللہ علیہ وسلم نے دو رکعت نماز پڑھائی۔' WHERE id = 1138;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا کہ ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا کہ ہم سے ہمارے باپ ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے کہا کہ مجھے محمود بن ربیع انصاری رضی اللہ عنہ نے خبر دی کہ انہیں نبی کریم صلی اللہ علیہ وسلم یاد ہیں اور آپ صلی اللہ علیہ وسلم کی وہ کلی بھی یاد ہے جو آپ صلی اللہ علیہ وسلم نے ان کے گھر کے کنویں سے پانی لے کر ان کے منہ میں کی تھی۔' WHERE id = 1150;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہیں امام مالک رحمہ اللہ نے خبر دی، انہیں مخرمہ بن سلیمان نے خبر دی، انہیں ابن عباس کے غلام کریب نے عبداللہ بن عباس رضی اللہ عنہما سے خبر دی کہ آپ ایک رات ام المؤمنین میمونہ رضی اللہ عنہا کے یہاں سوئے۔ ام المؤمنین میمونہ رضی اللہ عنہا آپ کی خالہ تھیں۔ آپ نے بیان کیا کہ میں بستر کے عرض میں لیٹ گیا اور رسول اللہ صلی اللہ علیہ وسلم اور آپ کی بیوی اس کے طول میں لیٹے۔ پھر رسول اللہ صلی اللہ علیہ وسلم سو گئے حتیٰ کہ آدھی رات ہوئی یا اس سے تھوڑی دیر پہلے یا بعد۔ تو آپ صلی اللہ علیہ وسلم بیدار ہو کر بیٹھ گئے اور چہرے سے نیند کے خمار کو اپنے دونوں ہاتھوں سے دور کرنے لگے۔ پھر سورۃ آل عمران کے آخر کی دس آیتیں پڑھیں اس کے بعد پانی کی ایک مشک کے پاس گئے جو لٹک رہی تھی، اس سے آپ صلی اللہ علیہ وسلم نے اچھی طرح وضو کیا، پھر کھڑے ہو کر نماز شروع کی۔ عبداللہ بن عباس رضی اللہ عنہما نے کہا کہ میں بھی اٹھا اور جس طرح نبی کریم صلی اللہ علیہ وسلم نے کیا تھا میں نے بھی کیا اور پھر جا کر آپ صلی اللہ علیہ وسلم کے پہلو میں کھڑا ہو گیا تو نبی کریم صلی اللہ علیہ وسلم نے اپنا داہنا ہاتھ میرے سر پر رکھا اور میرے داہنے کان کو پکڑ کر اسے اپنے ہاتھ سے مروڑنے لگے۔ پھر آپ صلی اللہ علیہ وسلم نے دو رکعت نماز پڑھی، پھر دو رکعت پڑھی، پھر دو رکعت پڑھی، پھر دو رکعت پڑھی، پھر دو رکعت پڑھی، پھر دو رکعت پڑھی۔ اس کے بعد ( ایک رکعت ) وتر پڑھا اور لیٹ گئے۔ جب مؤذن آیا تو آپ صلی اللہ علیہ وسلم دوبارہ اٹھے اور دو ہلکی رکعتیں پڑھ کر باہر نماز ( فجر ) کے لیے تشریف لے گئے۔' WHERE id = 1161;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے بشر بن مفضل نے بیان کیا، کہا کہ ہم سے غالب بن قطان نے بیان کیا، ان سے بکر بن عبداللہ مزنی نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ہم سخت گرمیوں میں جب نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے اور چہرے کو زمین پر پوری طرح رکھنا مشکل ہو جاتا تو اپنا کپڑا بچھا کر اس پر سجدہ کیا کرتے تھے۔' WHERE id = 1172;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ابوحازم سلمہ بن دینار نے اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کو یہ خبر پہنچی کہ قباء کے قبیلہ بنو عمرو بن عوف میں کوئی جھگڑا ہو گیا ہے۔ اس لیے آپ صلی اللہ علیہ وسلم کئی اصحاب کو ساتھ لے کر ان میں صلح کرانے کے لیے تشریف لے گئے۔ وہاں آپ صلی اللہ علیہ وسلم صلح صفائی کے لیے ٹھہر گئے۔ ادھر نماز کا وقت ہو گیا تو بلال رضی اللہ عنہ نے ابوبکر رضی اللہ عنہ سے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نہیں آئے اور نماز کا وقت ہو گیا، تو کیا آپ لوگوں کو نماز پڑھائیں گے؟ آپ نے جواب دیا کہ ہاں اگر تم چاہتے ہو تو پڑھا دوں گا۔ چنانچہ بلال رضی اللہ عنہ نے تکبیر کہی اور ابوبکر رضی اللہ عنہ نے آگے بڑھ کر نیت باندھ لی۔ اتنے میں رسول اللہ صلی اللہ علیہ وسلم بھی تشریف لے آئے اور صفوں سے گزرتے ہوئے آپ صلی اللہ علیہ وسلم پہلی صف میں آ کھڑے ہوئے، لوگوں نے ہاتھ پر ہاتھ مارنے شروع کر دیئے۔ ( سہل نے کہا کہ «تصفيح» کے معنی «تصفيق» کے ہیں ) آپ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نماز میں کسی طرف متوجہ نہیں ہوتے تھے۔ لیکن جب لوگوں نے بہت دستکیں دیں تو انہوں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم کھڑے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اشارہ سے ابوبکر کو نماز پڑھانے کے لیے کہا۔ اس پر ابوبکر رضی اللہ عنہ نے ہاتھ اٹھا کر اللہ تعالیٰ کا شکر ادا کیا اور پھر الٹے پاؤں پیچھے کی طرف چلے آئے اور صف میں کھڑے ہو گئے اور رسول اللہ صلی اللہ علیہ وسلم نے آگے بڑھ کر نماز پڑھائی۔ نماز سے فارغ ہو کر آپ صلی اللہ علیہ وسلم لوگوں کی طرف متوجہ ہوئے اور فرمایا کہ لوگو! یہ کیا بات ہے کہ جب نماز میں کوئی بات پیش آتی ہے تو تم تالیاں بجانے لگتے ہو۔ یہ مسئلہ تو عورتوں کے لیے ہے۔ تمہیں اگر نماز میں کوئی حادثہ پیش آئے تو «سبحان الله» کہا کرو۔ اس کے بعد آپ صلی اللہ علیہ وسلم ابوبکر رضی اللہ عنہ کی طرف متوجہ ہوئے اور فرمایا کہ ابوبکر! میرے کہنے کے باوجود تم نے نماز کیوں نہیں پڑھائی؟ ابوبکر رضی اللہ عنہ نے عرض کیا کہ ابوقحافہ کے بیٹے کو زیب نہیں دیتا کہ رسول اللہ صلی اللہ علیہ وسلم کی موجودگی میں نماز پڑھائے۔' WHERE id = 1182;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک بن انس نے خبر دی، انہیں ایوب بن ابی تمیمہ سختیانی نے خبر دی، انہیں محمد بن سیرین نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم دو رکعت پڑھ کر اٹھ کھڑے ہوئے تو ذوالیدین نے پوچھا کہ یا رسول اللہ! کیا نماز کم کر دی گئی ہے یا آپ بھول گئے ہیں؟ رسول اللہ صلی اللہ علیہ وسلم نے لوگوں سے پوچھا کہ کیا ذوالیدین سچ کہتے ہیں۔ لوگوں نے کہا جی ہاں! یہ سن کر رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوئے اور دو رکعت جو رہ گئی تھیں ان کو پڑھا، پھر سلام پھیرا، پھر «الله اكبر» کہا اور اپنے سجدے کی طرح ( یعنی نماز کے معمولی سجدے کی طرح ) سجدہ کیا یا اس سے لمبا پھر سر اٹھایا۔' WHERE id = 1192;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا کہ ہم سے میرے باپ حفص بن غیاث نے بیان کیا، کہا کہ ہم سے اعمش نے بیان کیا، کہا کہ ہم سے شقیق بن سلمہ نے بیان کیا اور ان سے عبداللہ بن مسعود نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اس حالت میں مرے کہ کسی کو اللہ کا شریک ٹھہراتا تھا تو وہ جہنم میں جائے گا اور میں یہ کہتا ہوں کہ جو اس حال میں مرا کہ اللہ کا کوئی شریک نہ ٹھہراتا ہو وہ جنت میں جائے گا۔' WHERE id = 1203;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے ثابت نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ایک عورت کے پاس سے گزرے جو ایک قبر پر بیٹھی ہوئی رو رہی تھی، آپ صلی اللہ علیہ وسلم نے اس سے فرمایا کہ اللہ سے ڈر اور صبر کر۔' WHERE id = 1215;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، انہوں نے کہا کہ ہم کو عبداللہ نے خبر دی، انہوں نے کہا کہ ہمیں ہشام بن عروہ نے خبر دی، انہیں ان کے باپ عروہ بن زبیر نے اور انہیں (ان کی خالہ) ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم کو یمن کے تین سفید سوتی دھلے ہوئے کپڑوں میں کفن دیا گیا ان میں نہ قمیص تھی نہ عمامہ۔' WHERE id = 1226;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد مکی نے بیان کیا ‘ کہا کہ ہم سے ابراہیم بن سعد نے ‘ ان سے ان کے باپ سعد نے اور ان سے ان کے والد ابراہیم بن عبدالرحمٰن نے بیان کیا کہ عبدالرحمٰن بن عوف رضی اللہ عنہ کے سامنے ایک دن کھانا رکھا گیا تو انہوں نے فرمایا کہ مصعب بن عمیر رضی اللہ عنہ ( غزوہ احد میں ) شہید ہوئے ‘ وہ مجھ سے افضل تھے۔ لیکن ان کے کفن کے لیے ایک چادر کے سوا اور کوئی چیز مہیا نہ ہو سکی۔ اسی طرح جب حمزہ رضی اللہ عنہ شہید ہوئے یا کسی دوسرے صحابی کا نام لیا ‘ وہ بھی مجھ سے افضل تھے۔ لیکن ان کے کفن کے لیے بھی صرف ایک ہی چادر مل سکی۔ مجھے تو ڈر لگتا ہے کہ کہیں ایسا نہ ہو کہ ہمارے چین اور آرام کے سامان ہم کو جلدی سے دنیا ہی میں دے دئیے گئے ہوں پھر وہ رونے لگے۔' WHERE id = 1236;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ انہیں امام مالک نے خبر دی ‘ انہیں عبداللہ بن ابی بکر نے ‘ انہیں ان کے باپ نے اور انہیں عمرہ بنت عبدالرحمٰن نے ‘ انہوں نے نبی کریم صلی اللہ علیہ وسلم کی بیوی عائشہ رضی اللہ عنہا سے سنا۔ آپ نے کہا کہ ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ انہیں امام مالک نے خبر دی ‘ انہیں عبداللہ بن ابی بکر نے ‘ انہیں ان کے باپ نے اور انہیں عمرہ بنت عبدالرحمٰن نے ‘ انہوں نے نبی کریم صلی اللہ علیہ وسلم کی بیوی عائشہ رضی اللہ عنہا سے سنا۔ آپ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کا گزر ایک یہودی عورت پر ہوا جس کے مرنے پر اس کے گھر والے رو رہے تھے۔ اس وقت آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ لوگ رو رہے ہیں حالانکہ اس کو قبر میں عذاب کیا جا رہا ہے۔' WHERE id = 1248;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا ‘ کہا کہ ہم سے عبدالوہاب نے بیان کیا ‘ کہا کہ میں نے یحییٰ سے سنا، انہوں نے کہا کہ مجھے عمرہ نے خبر دی، کہا کہ میں نے عائشہ رضی اللہ عنہا سے سنا آپ نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم کو زید بن حارثہ ‘ جعفر اور عبداللہ بن رواحہ رضی اللہ عنہم کی شہادت ( غزوہ موتہ میں ) کی خبر ملی ‘ تو آپ صلی اللہ علیہ وسلم اس وقت اس طرح تشریف فرما تھے کہ غم کے آثار آپ صلی اللہ علیہ وسلم کے چہرے پر ظاہر تھے۔ میں دروازے کے سوراخ سے دیکھ رہی تھی۔ اتنے میں ایک صاحب آئے اور جعفر رضی اللہ عنہ کے گھر کی عورتوں کے رونے کا ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں رونے سے منع کر دے۔ وہ گئے لیکن واپس آ کر کہا کہ وہ تو نہیں مانتیں۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ انہیں منع کر دے۔ اب وہ تیسری مرتبہ واپس ہوئے اور عرض کیا کہ یا رسول اللہ! قسم اللہ کی وہ تو ہم پر غالب آ گئی ہیں ( عمرہ نے کہا کہ ) عائشہ رضی اللہ عنہا کو یقین ہوا کہ ( ان کے اس کہنے پر ) رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ان کے منہ میں مٹی جھونک دے۔ اس پر میں نے کہا کہ تیرا برا ہو۔ رسول اللہ صلی اللہ علیہ وسلم اب جس کام کا حکم دے رہے ہیں وہ تو کرو گے نہیں لیکن آپ صلی اللہ علیہ وسلم کو تکلیف میں ڈال دیا۔' WHERE id = 1258;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا ‘ ان سے ابن ابی ذئب نے ‘ ان سے سعید مقبری نے اور ان سے ان کے والد نے کہ ہم ایک جنازہ میں شریک تھے کہ ابوہریرہ رضی اللہ عنہ نے مروان کا ہاتھ پکڑا اور یہ دونوں صاحب جنازہ رکھے جانے سے پہلے بیٹھ گئے۔ اتنے میں ابوسعید رضی اللہ عنہ تشریف لائے اور مروان کا ہاتھ پکڑ کر فرمایا کہ اٹھو! اللہ کی قسم! یہ ( ابوہریرہ رضی اللہ عنہ ) جانتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں اس سے منع فرمایا ہے۔ ابوہریرہ رضی اللہ عنہ بولے کہ ابوسعید رضی اللہ عنہ نے سچ کہا ہے۔' WHERE id = 1268;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ ابن اسماعیل نے بیان کیا ‘ کہا کہ ہم سے عبدالواحد نے بیان کیا ‘ کہا کہ ہم سے شیبانی نے بیان کیا ‘ ان سے عامر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کا گزر ایک قبر پر ہوا۔ میت کو ابھی رات ہی دفنایا گیا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ دفن کب کیا گیا ہے؟ لوگوں نے کہا کہ گذشتہ رات۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے کیوں نہیں اطلاع کرائی؟ لوگوں نے عرض کیا کہ اندھیری رات میں دفن کیا گیا ‘ اس لیے ہم نے آپ کو جگانا مناسب نہ سمجھا۔ پھر آپ صلی اللہ علیہ وسلم کھڑے ہو گئے اور ہم نے آپ صلی اللہ علیہ وسلم کے پیچھے صفیں بنا لیں۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں بھی انہیں میں تھا ( نابالغ تھا لیکن ) نماز جنازہ میں شرکت کی۔' WHERE id = 1279;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا ‘ کہا کہ ہم سے سلیم بن حیان نے بیان کیا ‘ کہا کہ ہم سے سعید بن میناء نے بیان کیا اور ان سے جابر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے اصحمہ نجاشی کی نماز جنازہ پڑھائی تو چار تکبیریں کہیں۔ یزید بن ہارون واسطی اور عبدالصمد نے سلیم سے اصحمہ نام نقل کیا ہے اور عبدالصمد نے اس کی متابعت کی ہے۔' WHERE id = 1290;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا کہ ہم سے لیث بن سعد نے بیان کیا ‘ ان سے یزید بن ابی حبیب نے بیان کیا ‘ ان سے ابوالخیر یزید بن عبداللہ نے ‘ ان سے عقبہ بن عامر نے کہ نبی کریم صلی اللہ علیہ وسلم ایک دن باہر تشریف لائے اور احد کے شہیدوں پر اس طرح نماز پڑھی جیسے میت پر پڑھی جاتی ہے۔ پھر منبر پر تشریف لائے اور فرمایا۔ دیکھو میں تم سے پہلے جا کر تمہارے لیے میر ساماں بنوں گا اور میں تم پر گواہ رہوں گا۔ اور قسم اللہ کی میں اس وقت اپنے حوض کو دیکھ رہا ہوں اور مجھے زمین کے خزانوں کی کنجیاں دی گئی ہیں یا ( یہ فرمایا کہ ) مجھے زمین کی کنجیاں دی گئی ہیں اور قسم اللہ کی مجھے اس کا ڈر نہیں کہ میرے بعد تم شرک کرو گے بلکہ اس کا ڈر ہے کہ تم لوگ دنیا حاصل کرنے میں رغبت کرو گے ( نتیجہ یہ کہ آخرت سے غافل ہو جاؤ گے ) ۔' WHERE id = 1300;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا ‘ انہوں نے کہا کہ عبیداللہ بن زیاد نے بیان کیا کہ میں نے عبداللہ بن عباس رضی اللہ عنہما کو یہ کہتے سنا تھا کہ میں اور میری والدہ ( نبی کریم صلی اللہ علیہ وسلم کی ہجرت کے بعد مکہ میں ) کمزور مسلمانوں میں سے تھے۔ میں بچوں میں اور میری والدہ عورتوں میں۔' WHERE id = 1311;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا ‘ کہا ہم سے شعبہ نے ‘ ان سے علقمہ بن مرثد نے ‘ ان سے سعد بن عبیدہ نے اور ان سے براء بن عازب رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مومن جب اپنی قبر میں بٹھایا جاتا ہے تو اس کے پاس فرشتے آتے ہیں۔ وہ شہادت دیتا ہے کہ اللہ کے سوا کوئی معبود نہیں اور محمد صلی اللہ علیہ وسلم اللہ کے رسول ہیں۔ تو یہ اللہ کے اس فرمان کی تعبیر ہے جو سورۃ ابراہیم میں ہے کہ اللہ ایمان والوں کو دنیا کی زندگی اور آخرت میں ٹھیک بات یعنی توحید پر مضبوط رکھتا ہے۔' WHERE id = 1322;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے امام مالک رحمہ اللہ نے یہ حدیث بیان کی ‘ انہوں نے کہا کہ ہم سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں سے کوئی شخص مر جاتا ہے تو اس کا ٹھکانا اسے صبح و شام دکھایا جاتا ہے۔ اگر وہ جنتی ہے تو جنت والوں میں اور جو دوزخی ہے تو دوزخ والوں میں۔ پھر کہا جاتا ہے یہ تیرا ٹھکانا ہے یہاں تک کہ قیامت کے دن اللہ تجھ کو اٹھائے گا۔' WHERE id = 1332;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا ‘ کہا کہ مجھ سے سلیمان بن بلال نے بیان کیا اور ان سے ہشام بن عروہ نے (دوسری سند۔ امام بخاری رحمہ اللہ نے کہا) اور مجھ سے محمد بن حرب نے بیان کیا ‘ کہا ہم سے ابومروان یحییٰ بن ابی زکریا نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم اپنے مرض الوفات میں گویا اجازت لینا چاہتے تھے ( دریافت فرماتے ) آج میری باری کن کے یہاں ہے۔ کل کن کے یہاں ہو گی؟ عائشہ رضی اللہ عنہا کی باری کے دن کے متعلق خیال فرماتے تھے کہ بہت دن بعد آئے گی۔ چنانچہ جب میری باری آئی تو اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم کی روح اس حال میں قبض کی کہ آپ صلی اللہ علیہ وسلم میرے سینے سے ٹیک لگائے ہوئے تھے اور میرے ہی گھر میں آپ صلی اللہ علیہ وسلم دفن کئے گئے۔' WHERE id = 1342;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا ‘ کہا کہ ہمیں شعیب بن ابی حمزہ نے خبر دی ‘ ان سے زہری نے کہا کہ ہم سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم فوت ہو گئے اور ابوبکر رضی اللہ عنہ خلیفہ ہوئے تو عرب کے کچھ قبائل کافر ہو گئے ( اور کچھ نے زکوٰۃ سے انکار کر دیا اور ابوبکر رضی اللہ عنہ نے ان سے لڑنا چاہا ) تو عمر رضی اللہ عنہ نے فرمایا کہ آپ رسول اللہ صلی اللہ علیہ وسلم کے اس فرمان کی موجودگی میں کیونکر جنگ کر سکتے ہیں ”مجھے حکم ہے لوگوں سے اس وقت تک جنگ کروں جب تک کہ وہ «لا إله إلا الله» کی شہادت نہ دیدیں اور جو شخص اس کی شہادت دیدے تو میری طرف سے اس کا مال و جان محفوظ ہو جائے گا۔ سوا اسی کے حق کے ( یعنی قصاص وغیرہ کی صورتوں کے ) اور اس کا حساب اللہ تعالیٰ کے ذمہ ہو گا۔' WHERE id = 1354;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا ‘ انہوں نے کہا کہ ہمیں شعیب نے خبر دی ‘ کہا کہ ہم سے ابوالزناد نے بیان کیا ‘ ان سے عبدالرحمٰن بن ہرمز اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا قیامت آنے سے پہلے مال و دولت کی اس قدر کثرت ہو جائے گی اور لوگ اس قدر مالدار ہو جائیں گے کہ اس وقت صاحب مال کو اس کی فکر ہو گی کہ اس کی زکوٰۃ کون قبول کرے اور اگر کسی کو دینا بھی چاہے گا تو اس کو یہ جواب ملے گا کہ مجھے اس کی حاجت نہیں ہے۔' WHERE id = 1365;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا ‘ کہا کہ ہم اسرائیل بن یونس نے بیان کیا ‘ کہا کہ ہم سے ابوجویریہ (حطان بن خفاف) نے بیان کیا کہ معن بن یزید نے ان سے بیان کیا ‘ انہوں نے کہا کہ میں نے اور میرے والد اور دادا ( اخفش بن حبیب ) نے رسول اللہ صلی اللہ علیہ وسلم کے ہاتھ پر بیعت کی تھی۔ آپ نے میری منگنی بھی کرائی اور آپ ہی نے نکاح بھی پڑھایا تھا اور میں آپ کی خدمت میں ایک مقدمہ لے کر حاضر ہوا تھا۔ وہ یہ کہ میرے والد یزید نے کچھ دینار خیرات کی نیت سے نکالے اور ان کو انہوں نے مسجد میں ایک شخص کے پاس رکھ دیا۔ میں گیا اور میں نے ان کو اس سے لے لیا۔ پھر جب میں انہیں لے کر والد صاحب کے پاس آیا تو انہوں نے فرمایا کہ قسم اللہ کی میرا ارادہ تجھے دینے کا نہیں تھا۔ یہی مقدمہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لے کر حاضر ہوا اور آپ نے یہ فیصلہ دیا کہ دیکھو یزید جو تم نے نیت کی تھی اس کا ثواب تمہیں مل گیا اور معن! جو تو نے لے لیا وہ اب تیرا ہو گیا۔' WHERE id = 1375;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم (ابوعاصم ضحاک) نے بیان کیا اور ان سے ابن جریج نے بیان کیا۔ (دوسری سند) اور مجھ سے محمد بن عبدالرحیم نے بیان کیا ‘ ان سے حجاج بن محمد نے بیان کیا اور انہوں نے کہا کہ ہم سے ابن جریج نے بیان کیا کہ مجھے ابن ابی ملیکہ نے خبر دی ‘ انہیں عباد بن عبداللہ بن زبیر نے اسماء بنت ابی بکر رضی اللہ عنہما سے خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ہاں آئیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( مال کو ) تھیلی میں بند کر کے نہ رکھنا ورنہ اللہ پاک بھی تمہارے لیے اپنے خزانے میں بندش لگا دے گا۔ جہاں تک ہو سکے لوگوں میں خیر خیرات تقسیم کرتی رہ۔' WHERE id = 1386;
UPDATE hadiths SET urdu = 'اور حنظلہ نے طاؤس سے دو زرہیں نقل کیا ہے اور لیث بن سعد نے کہا مجھ سے جعفر بن ربیعہ نے بیان کیا ‘ انہوں نے عبدالرحمٰن بن ہر مز سے سنا کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا انہوں نے نبی کریم صلی اللہ علیہ وسلم سے پھر یہی حدیث بیان کی اس میں دو زرہیں ہیں۔' WHERE id = 1396;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن مثنیٰ انصاری نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے میرے والد نے بیان کیا ‘ انہوں نے کہا کہ مجھ ثمامہ بن عبداللہ بن انس نے بیان کیا ‘ ان سے انس بن مالک رضی اللہ عنہ نے کہ ابوبکر رضی اللہ عنہ نے جب انہیں بحرین ( کا حاکم بنا کر ) بھیجا تو ان کو یہ پروانہ لکھ دیا۔ شروع اللہ کے نام سے جو بڑا مہربان نہایت رحم کرنے والا ہے۔ یہ زکوٰۃ کا وہ فریضہ ہے جسے رسول اللہ صلی اللہ علیہ وسلم نے مسلمانوں کے لیے فرض قرار دیا ہے اور رسول اللہ صلی اللہ علیہ وسلم کو اللہ تعالیٰ نے اس کا حکم دیا۔ اس لیے جو شخص مسلمانوں سے اس پروانہ کے مطابق زکوٰۃ مانگے تو مسلمانوں کو اسے دے دینا چاہیے اور اگر کوئی اس سے زیادہ مانگے تو ہرگز نہ دے۔ چوبیس یا اس سے کم اونٹوں میں ہر پانچ اونٹ پر ایک بکری دینی ہو گی۔ ( پانچ سے کم میں کچھ نہیں ) لیکن جب اونٹوں کی تعداد پچیس تک پہنچ جائے تو پچیس سے پینتیس تک ایک ایک برس کی اونٹنی واجب ہو گی جو مادہ ہوتی ہے۔ جب اونٹ کی تعداد چھتیس تک پہنچ جائے ( تو چھتیس سے ) پینتالیس تک دو برس کی مادہ واجب ہو گی۔ جب تعداد چھیالیس تک پہنچ جائے ( تو چھیالیس سے ) ساٹھ تک میں تین برس کی اونٹنی واجب ہو گی جو جفتی کے قابل ہوتی ہے۔ جب تعداد اکسٹھ تک پہنچ جائے ( تو اکسٹھ سے ) پچھتر تک چار برس کی مادہ واجب ہو گی۔ جب تعداد چھہتر تک پہنچ جائے ( تو چھہتر سے ) نوے تک دو دو برس کی دو اونٹنیاں واجب ہوں گی۔ جب تعداد اکیانوے تک پہنچ جائے تو ( اکیانوے سے ) ایک سو بیس تک تین تین برس کی دو اونٹنیاں واجب ہوں گی جو جفتی کے قابل ہوں۔ پھر ایک سو بیس سے بھی تعداد آگے بڑھ جائے تو ہر چالیس پر دو برس کی اونٹنی واجب ہو گی اور ہر پچاس پر ایک تین برس کی۔ اور اگر کسی کے پاس چار اونٹ سے زیادہ نہیں تو اس پر زکوٰۃ واجب نہ ہو گی مگر جب ان کا مالک اپنی خوشی سے کچھ دے اور ان بکریوں کی زکوٰۃ جو ( سال کے اکثر حصے جنگل یا میدان وغیرہ میں ) چر کر گزارتی ہیں اگر ان کی تعداد چالیس تک پہنچ گئی ہو تو ( چالیس سے ) ایک سو بیس تک ایک بکری واجب ہو گی اور جب ایک سو بیس سے تعداد بڑھ جائے ( تو ایک سو بیس سے ) سے دو سو تک دو بکریاں واجب ہوں گی۔ اگر دو سو سے بھی تعداد بڑھ جائے تو ( تو دو سو سے ) تین سو تک تین بکریاں واجب ہوں گی اور جب تین سو سے بھی تعداد آگے نکل جائے تو اب ہر ایک سو پر ایک بکری واجب ہو گی۔ اگر کسی شخص کی چرنے والی بکریاں چالیس سے ایک بھی کم ہوں تو ان پر زکوٰۃ واجب نہیں ہو گی مگر اپنی خوشی سے مالک کچھ دینا چاہے تو دے سکتا ہے۔ اور چاندی میں زکوٰۃ چالیسواں حصہ واجب ہو گی لیکن اگر کسی کے پاس ایک سو نوے ( درہم ) سے زیادہ نہیں ہیں تو اس پر زکوٰۃ واجب نہیں ہو گی مگر خوشی سے کچھ اگر مالک دینا چاہیے تو اور بات ہے۔' WHERE id = 1406;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا ‘ کہا کہ ہم سے میرے باپ نے بیان کیا ‘ کہا کہ ہم سے اعمش نے بیان کیا ‘ ان سے شقیق نے ‘ ان سے عمرو بن الحارث نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ کی بیوی زینب رضی اللہ عنہا نے۔ (اعمش نے) کہا کہ میں نے اس حدیث کا ذکر ابراہیم نحعی سے کیا۔ تو انہوں نے بھی مجھ سے ابوعبیدہ سے بیان کیا۔ ان سے عمرو بن حارث نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ کی بیوی زینب نے ‘ بالکل اسی طرح حدیث بیان کی (جس طرح شقیق نے کی کہ) زینب رضی اللہ عنہا نے بیان کیا کہ میں مسجد نبوی میں تھی۔ رسول اللہ صلی اللہ علیہ وسلم کو میں نے دیکھا۔ آپ صلی اللہ علیہ وسلم یہ فرما رہے تھے ‘ صدقہ کرو ‘ خواہ اپنے زیور ہی میں سے دو۔ اور زینب اپنا صدقہ اپنے شوہر عبداللہ بن مسعود رضی اللہ عنہ اور چند یتیموں پر بھی جو ان کی پرورش میں تھے خرچ کیا کرتی تھیں۔ اس لیے انہوں نے اپنے خاوند سے کہا کہ آپ رسول اللہ صلی اللہ علیہ وسلم سے پوچھئے کہ کیا وہ صدقہ بھی مجھ سے کفایت کرے گا جو میں آپ پر اور ان چند یتیموں پر خرچ کروں جو میری سپردگی میں ہیں۔ لیکن عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ تم خود جا کر رسول اللہ صلی اللہ علیہ وسلم سے پوچھ لو۔ آخر میں خود رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی۔ اس وقت میں نے آپ صلی اللہ علیہ وسلم کے دروازے پر ایک انصاری خاتون کو پایا۔ جو میری ہی جیسی ضرورت لے کر موجود تھیں۔ ( جو زینب ابومسعود انصاری کی بیوی تھیں ) پھر ہمارے سامنے سے بلال گذرے۔ تو ہم نے ان سے کہا کہ آپ رسول اللہ صلی اللہ علیہ وسلم سے یہ مسئلہ دریافت کیجئے کہ کیا وہ صدقہ مجھ سے کفایت کرے گا جسے میں اپنے شوہر اور اپنی زیر تحویل چند یتیم بچوں پر خرچ کر دوں۔ ہم نے بلال سے یہ بھی کہا کہ ہمارا نام نہ لینا۔ وہ اندر گئے اور آپ صلی اللہ علیہ وسلم سے عرض کیا کہ دو عورتیں مسئلہ دریافت کرتی ہیں۔ تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ دونوں کون ہیں؟ بلال رضی اللہ عنہ نے کہہ دیا کہ زینب نام کی ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کون سی زینب؟ بلال رضی اللہ عنہ نے کہا کہ عبداللہ بن مسعود رضی اللہ عنہ کی بیوی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں! بیشک درست ہے۔ اور انہیں دو گنا ثواب ملے گا۔ ایک قرابت داری کا اور دوسرا خیرات کرنے کا۔' WHERE id = 1417;
UPDATE hadiths SET urdu = 'ہم سے محمد بن غریر زہری نے بیان کیا ‘ کہا کہ ہم سے یعقوب بن ابراہیم نے اپنے باپ سے بیان کیا ‘ ان سے صالح بن کیسان نے ان سے ابن شہاب نے ‘ انہوں نے کہا کہ مجھے عامر بن سعد بن ابی وقاص نے اپنے باپ سعد بن ابی وقاص سے خبر دی۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے چند اشخاص کو کچھ مال دیا۔ اسی جگہ میں بھی بیٹھا ہوا تھا۔ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے ان کے ساتھ ہی بیٹھے ہوئے شخص کو چھوڑ دیا اور انہیں کچھ نہیں دیا۔ حالانکہ ان لوگوں میں وہی مجھے زیادہ پسند تھا۔ آخر میں نے رسول اللہ صلی اللہ علیہ وسلم کے قریب جا کر چپکے سے عرض کیا ‘ فلاں شخص کو آپ نے کچھ بھی نہیں دیا؟ واللہ میں اسے مومن خیال کرتا ہوں۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ‘ یا مسلمان؟ انہوں نے بیان کیا کہ اس پر میں تھوڑی دیر تک خاموش رہا۔ لیکن میں ان کے متعلق جو کچھ جانتا تھا اس نے مجھے مجبور کیا ‘ اور میں نے عرض کیا ‘ یا رسول اللہ! آپ فلاں شخص سے کیوں خفا ہیں ‘ واللہ! میں اسے مومن سمجھتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ‘ یا مسلمان؟ تین مرتبہ ایسا ہی ہوا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک شخص کو دیتا ہوں ( اور دوسرے کو نظر انداز کر جاتا ہوں ) حالانکہ وہ دوسرا میری نظر میں پہلے سے زیادہ پیارا ہوتا ہے۔ کیونکہ ( جس کو میں دیتا ہوں نہ دینے کی صورت میں ) مجھے ڈر اس بات کا رہتا ہے کہ کہیں اسے چہرے کے بل گھسیٹ کر جہنم میں نہ ڈال دیا جائے۔ اور ( یعقوب بن ابراہیم ) اپنے والد سے ‘ وہ صالح سے ‘ وہ اسماعیل بن محمد سے ‘ انہوں نے بیان کیا کہ میں نے اپنے والد سے سنا کہ وہ یہی حدیث بیان کر رہے تھے۔ انہوں نے کہا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے اپنا ہاتھ میری گردن اور مونڈھے کے بیچ میں مارا۔ اور فرمایا۔ سعد! ادھر سنو۔ میں ایک شخص کو دیتا ہوں۔ آخر حدیث تک۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ ( قرآن مجید میں لفظ ) «كبكبوا‏» اوندھے لٹا دینے کے معنی میں ہے۔ اور سورۃ الملک میں جو «مكبا‏» کا لفظ ہے وہ «أكب» سے نکلا ہے۔ «أكب» لازم ہے یعنی اوندھا گرا۔ اور اس کا متعدی «كب» ہے۔ کہتے ہیں کہ «كبه الله لوجهه» یعنی اللہ نے اسے اوندھے منہ گرا دیا۔ اور «كببته» یعنی میں نے اس کو اوندھا گرایا۔ امام بخاری رحمہ اللہ نے کہا صالح بن کیسان عمر میں زہری سے بڑے تھے وہ عبداللہ بن عمر رضی اللہ عنہما سے ملے ہیں۔' WHERE id = 1428;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا کہ ہمیں امام مالک بن انس نے خبر دی ‘ انہیں زید بن اسلم نے اور ان سے ان کے باپ نے بیان کیا ‘ کہ میں نے عمر رضی اللہ عنہ کو یہ کہتے سنا کہ انہوں نے ایک گھوڑا اللہ تعالیٰ کے راستہ میں ایک شخص کو سواری کے لیے دے دیا۔ لیکن اس شخص نے گھوڑے کو خراب کر دیا۔ اس لیے میں نے چاہا کہ اسے خرید لوں۔ میرا یہ بھی خیال تھا کہ وہ اسے سستے داموں بیچ ڈالے گا۔ چنانچہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنا صدقہ واپس نہ لو۔ خواہ وہ تمہیں ایک درہم ہی میں کیوں نہ دے کیونکہ دیا ہوا صدقہ واپس لینے والے کی مثال قے کر کے چاٹنے والے کی سی ہے۔' WHERE id = 1439;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ابواسامہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ہشام بن عروہ نے بیان کیا ‘ ان سے ان کے باپ (عروہ بن زبیر) نے بیان کیا ‘ ان سے ابو حمید ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے بنی اسد کے ایک شخص عبداللہ بن لتبیہ کو بنی سلیم کی زکوٰۃ وصول کرنے پر مقرر فرمایا۔ جب وہ آئے تو آپ صلی اللہ علیہ وسلم نے ان سے حساب لیا۔' WHERE id = 1449;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ابوعمر حفص بن میسرہ نے بیان کیا ‘ ان سے زید بن اسلم نے بیان کیا ‘ ان سے عیاض بن عبداللہ بن سعد نے ‘ ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں عیدالفطر کے دن ( کھانے کے غلہ سے ) ایک صاع نکالتے تھے۔ ابوسعید رضی اللہ عنہ نے بیان کیا کہ ہمارا کھانا ( ان دنوں ) جَو، زبیب، پنیر اور کھجور تھا۔' WHERE id = 1459;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن مبارک نے بیان کیا، انہوں نے کہا کہ ہم سے خالد بن عبداللہ طحان نے بیان کیا، انہوں نے کہا کہ ہمیں حبیب بن ابی عمرہ نے خبر دی، انہیں عائشہ بنت طلحہ نے اور انہیں ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہا کہ انہوں نے پوچھا یا رسول اللہ! ہم دیکھتے ہیں کہ جہاد سب نیک کاموں سے بڑھ کر ہے۔ پھر ہم بھی کیوں نہ جہاد کریں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں بلکہ سب سے افضل جہاد حج ہے جو مبرور ہو۔' WHERE id = 1469;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، ان سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ والوں کے لیے ذوالحلیفہ کو میقات مقرر کیا، شام والوں کے لیے حجفہ، نجد والوں کے لیے قرن المنازل اور یمن والوں کے لیے یلملم۔ یہ ان ملکوں کے باشندوں کے میقات ہیں اور تمام ان دوسرے مسلمانوں کے بھی جو ان ملکوں سے گزر کر آئیں اور حج اور عمرہ کا ارادہ رکھتے ہوں۔ لیکن جو لوگ میقات کے اندر رہتے ہیں تو ( وہ احرام وہیں سے باندھیں ) جہاں سے سفر شروع کریں تاآنکہ مکہ کے لوگ احرام مکہ ہی سے باندھیں۔' WHERE id = 1479;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ ایک شخص نے پوچھا کہ یا رسول اللہ! محرم کو کس طرح کا کپڑا پہننا چاہئے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا نہ کرتہ پہنے، نہ عمامہ باندھے، نہ پاجامہ پہنے، نہ باران کوٹ، نہ موزے۔ لیکن اگر اس کے پاس جوتی نہ ہو تو وہ موزے اس وقت پہن سکتا ہے جب ٹخنوں کے نیچے سے ان کو کاٹ لیا ہو۔ ( اور احرام میں ) کوئی ایسا کپڑا نہ پہنو جس میں زعفران یا ورس لگا ہوا ہو۔ ابوعبداللہ امام بخاری رحمہ اللہ نے کہا کہ محرم اپنا سر دھو سکتا ہے لیکن کنگھا نہ کرے۔ بدن بھی نہ کھجلانا چاہئے او جوں سر اور بدن سے نکال کر زمین پر ڈالی جا سکتی ہے۔' WHERE id = 1490;
UPDATE hadiths SET urdu = 'ہم سے ابوالربیع سلیمان بن داود نے بیان کیا، انہوں نے کہا کہ ہم سے فلیح بن سلیمان نے بیان کیا، ان سے نافع نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما جب مکہ جانے کا ارادہ کرتے تھے پہلے خوشبو کے بغیر تیل استعمال کرتے۔ اس کے بعد مسجد ذوالحلیفہ میں تشریف لاتے یہاں صبح کی نماز پڑھتے، پھر سوار ہوتے، جب اونٹنی آپ کو لے کر پوری طرح کھڑی ہو جاتی تو احرام باندھتے۔ پھر فرماتے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس طرح کرتے دیکھا تھا۔' WHERE id = 1501;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، کہا کہ ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے باپ اور ان سے ابن عباس رضی اللہ عنہما نے کہ عرب سمجھتے تھے کہ حج کے دنوں میں عمرہ کرنا روئے زمین پر سب سے بڑا گناہ ہے۔ یہ لوگ محرم کو صفر بنا لیتے اور کہتے کہ جب اونٹ کی پیٹھ سستا لے اور اس پر خوب بال اگ جائیں اور صفر کا مہینہ ختم ہو جائے ( یعنی حج کے ایام گزر جائیں ) تو عمرہ حلال ہوتا ہے۔ پھر جب نبی کریم صلی اللہ علیہ وسلم اپنے صحابہ کے ساتھ چوتھی کی صبح کو حج کا احرام باندھے ہوئے آئے تو آپ صلی اللہ علیہ وسلم نے انہیں حکم دیا کہ اپنے حج کو عمرہ بنا لیں، یہ حکم ( عرب کے پرانے رواج کی بنا پر ) عام صحابہ پر بڑا بھاری گزرا۔ انہوں نے پوچھا یا رسول اللہ! عمرہ کر کے ہمارے لیے کیا چیز حلال ہو گئی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمام چیزیں حلال ہو جائیں گی۔' WHERE id = 1511;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ قطان نے بیان کیا، انہوں نے کہا کہ ہم سے عبیداللہ عمری نے بیان کیا، ان سے نافع نے ابن عمر رضی اللہ عنہما سے بیان کیا، آپ رضی اللہ عنہ نے فرمایا کہ کہ نبی کریم صلی اللہ علیہ وسلم نے ذی طویٰ میں رات گزاری۔ پھر جب صبح ہوئی تو آپ صلی اللہ علیہ وسلم مکہ میں داخل ہوئے۔ ابن عمر رضی اللہ عنہما بھی اسی طرح کرتے تھے۔' WHERE id = 1521;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا کہ ہم سے ابوالاحوص سلام بن سلیم جعفی نے بیان کیا، ان سے اشعت نے بیان کیا، ان سے اسود بن یزید نے اور ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ کیا حطیم بھی بیت اللہ میں داخل ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، پھر میں نے پوچھا کہ پھر لوگوں نے اسے کعبے میں کیوں نہیں شامل کیا؟ آپ صلی اللہ علیہ وسلم نے جواب دیا کہ تمہاری قوم کے پاس خرچ کی کمی پڑ گئی تھی۔ پھر میں نے پوچھا کہ یہ دروازہ کیوں اونچا بنایا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ بھی تمہاری قوم ہی نے کیا تاکہ جسے چاہیں اندر آنے دیں اور جسے چاہیں روک دیں۔ اگر تمہاری قوم کی جاہلیت کا زمانہ تازہ تازہ نہ ہوتا اور مجھے اس کا خوف نہ ہوتا کہ ان کے دل بگڑ جائیں گے تو اس حطیم کو بھی میں کعبہ میں شامل کر دیتا اور کعبہ کا دروازہ زمین کے برابر کر دیتا۔' WHERE id = 1531;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا کہ ہم سے خالد بن حارث نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، کہا کہ ہم سے واصل احدب نے بیان کیا اور ان سے ابووائل نے بیان کیا کہ میں شیبہ کی خدمت میں حاضر ہوا (دوسری سند) اور ہم سے قبیصہ نے بیان کیا، کہا کہ ہم سے سفیان نے واصل سے بیان کیا اور ان سے ابووائل نے بیان کیا کہ میں شیبہ کے ساتھ کعبہ میں کرسی پر بیٹھا ہوا تھا تو شیبہ نے فرمایا کہ اسی جگہ بیٹھ کر عمر رضی اللہ عنہ نے ( ایک مرتبہ ) فرمایا کہ میرا ارادہ یہ ہوتا ہے کہ کعبہ کے اندر جتنا سونا چاندی ہے اسے نہ چھوڑوں ( جسے زمانہ جاہلیت میں کفار نے جمع کیا تھا ) بلکہ سب کو نکال کر ( مسلمانوں میں ) تقسیم کر دوں۔ میں نے عرض کی کہ آپ کے ساتھیوں ( نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ ) نے تو ایسا نہیں کیا۔ انہوں نے فرمایا کہ میں بھی انہیں کی پیروی کر رہا ہوں ( اسی لیے میں اس کے ہاتھ نہیں لگاتا ) ۔' WHERE id = 1541;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا کہ ہم سے سریج بن نعمان نے بیان کیا، کہا کہ ہم سے فلیح نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پہلے تین چکروں میں رمل کیا اور بقیہ چار چکروں میں حسب معمول چلے، حج اور عمرہ دونوں میں۔ سریج کے ساتھ اس حدیث کو لیث نے روایت کیا ہے۔ کہا کہ مجھ سے کثیر بن فرقد نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے۔' WHERE id = 1551;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا کہ ہم سے ابوضمرہ انس بن عیاض نے بیان کیا، انہوں نے کہا کہ ہم سے موسیٰ بن عقبہ نے بیان کیا، انہوں نے نافع سے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( مکہ ) آنے کے بعد سب سے پہلے حج اور عمرہ کا طواف کیا تھا۔ اس کے تین چکروں میں آپ صلی اللہ علیہ وسلم نے سعی ( رمل ) کی اور باقی چار میں حسب معمول چلے۔ پھر طواف کی دو رکعت نماز پڑھی اور صفا مروہ کی سعی کی۔' WHERE id = 1562;
UPDATE hadiths SET urdu = 'ہم سے حسن بن عمر بصریٰ رحمہ اللہ نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، ان سے حبیب نے، ان سے عطاء نے، ان سے عروہ نے، ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ کچھ لوگوں نے صبح کی نماز کے بعد کعبہ کا طواف کیا۔ پھر ایک وعظ کرنے والے کے پاس بیٹھ گئے اور جب سورج نکلنے لگا تو وہ لوگ نماز ( طواف کی دو رکعت ) پڑھنے کے لیے کھڑے ہو گئے۔ اس پر عائشہ رضی اللہ عنہا نے ( ناگواری کے ساتھ ) فرمایا جب سے تو یہ لوگ بیٹھے تھے اور جب وہ وقت آیا کہ جس میں نماز مکروہ ہے تو نماز کے لیے کھڑے ہو گئے۔' WHERE id = 1573;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے نافع سے بیان کیا کہ جس سال حجاج عبداللہ بن زبیر رضی اللہ عنہما کے مقابلے میں لڑنے آیا تھا۔ عبداللہ بن عمر رضی اللہ عنہما نے جب اس سال حج کا ارادہ کیا تو آپ سے کہا گیا کہ مسلمانوں میں باہم جنگ ہونے والی ہے اور یہ بھی خطرہ ہے کہ آپ کو حج سے روک دیا جائے۔ آپ نے فرمایا تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی زندگی بہترین نمونہ ہے۔ ایسے وقت میں میں بھی وہی کام کروں گا جو رسول اللہ صلی اللہ علیہ وسلم نے کیا تھا۔ تمہیں گواہ بناتا ہوں کہ میں نے اپنے اوپر عمرہ واجب کر لیا ہے۔ پھر آپ چلے اور جب بیداء کے میدان میں پہنچے تو آپ نے فرمایا کہ حج اور عمرہ تو ایک ہی طرح کے ہیں۔ میں تمہیں گواہ بناتا ہوں کہ میں نے اپنے عمرہ کے ساتھ حج بھی واجب کر لیا ہے۔ آپ نے ایک قربانی بھی ساتھ لے لی جو مقام قدید سے خریدی تھی۔ اس کے سوا اور کچھ نہیں کیا۔ دسویں تاریخ سے پہلے نہ آپ نے قربانی کی نہ کسی ایسی چیز کو اپنے لیے جائز کیا جس سے ( احرام کی وجہ سے ) آپ رک گئے تھے۔ نہ سر منڈوایا نہ بال ترشوائے دسویں تاریخ میں آپ نے قربانی کی اور بال منڈوائے۔ آپ کا یہی خیال تھا کہ آپ نے ایک طواف سے حج اور عمرہ دونوں کا طواف ادا کر لیا ہے۔ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے بھی اسی طرح کیا تھا۔' WHERE id = 1584;
UPDATE hadiths SET urdu = 'ہم سے مومل بن ہشام نے بیان کیا، کہا کہ ہم سے اسماعیل بن علیہ نے بیان کیا، ان سے ایوب سختیانی نے اور ان سے حفصہ بنت سیرین نے بیان کیا کہ ہم اپنی کنواری لڑکیوں کو باہر نکلنے سے روکتے تھے۔ پھر ایک خاتون آئیں اور بنی خلف کے محل میں ( جو بصرے میں تھا ) ٹھہریں۔ انہوں نے بیان کیا کہ ان کی بہن ( ام عطیہ رضی اللہ عنہا ) نبی کریم صلی اللہ علیہ وسلم کے ایک صحابی کے گھر میں تھیں۔ ان کے شوہر نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ بارہ جہاد کئے تھے اور میری بہن چھ جہادوں میں ان کے ساتھ رہی تھیں۔ وہ بیان کرتی تھیں کہ ہم ( میدان جنگ میں ) زخمیوں کی مرہم پٹی کرتی تھیں اور مریضوں کی تیمارداری کرتی تھی۔ میری بہن نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ اگر ہمارے پاس چادر نہ ہو تو کیا کوئی حرج ہے اگر ہم عیدگاہ جانے کے لیے باہر نہ نکلیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اس کی سہیلی کو اپنی چادر اسے اڑھا دینی چاہئے اور پھر مسلمانوں کی دعا اور نیک کاموں میں شرکت کرنا چاہئے۔ پھر جب امام عطیہ رضی اللہ عنہا خود بصرہ آئیں تو میں نے ان سے بھی یہی پوچھا یا یہ کہا کہ ہم نے ان سے پوچھا انہوں نے بیان کیا ام عطیہ رضی اللہ عنہا جب بھی رسول اللہ صلی اللہ علیہ وسلم کا ذکر کرتیں تو کہتیں میرے باپ آپ پر فدا ہوں۔ ہاں تو میں نے ان سے پوچھا، کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے اس طرح سنا ہے؟ انہوں نے فرمایا کہ ہاں میرے باپ آپ پر فدا ہوں۔ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کنواری لڑکیاں اور پردہ والیاں بھی باہر نکلیں یا یہ فرمایا کہ پردہ والی دوشیزائیں اور حائضہ عورتیں سب باہر نکلیں اور مسلمانوں کی دعا اور خیر کے کاموں میں شرکت کریں۔ لیکن حائضہ عورتیں نماز کی جگہ سے الگ رہیں۔ میں نے کہا اور حائضہ بھی نکلیں؟ انہوں نے فرمایا کہ کیا حائضہ عورت عرفات اور فلاں فلاں جگہ نہیں جاتی ہیں؟ ( پھر عیدگاہ ہی جانے میں کیا حرج ہے ) ۔' WHERE id = 1594;
UPDATE hadiths SET urdu = 'لیث نے بیان کیا کہ مجھ سے عقیل نے ابن شہاب سے بیان کیا، انہوں نے کہا کہ مجھے سالم نے خبر دی کہ حجاج بن یوسف جس سال عبداللہ بن زبیر رضی اللہ عنہما سے لڑنے کے لیے مکہ میں اترا تو اس موقع پر اس نے عبداللہ بن عمر رضی اللہ عنہما سے پوچھا کہ عرفہ کے دن وقوف میں آپ کیا کرتے تھے؟ اس پر سالم رحمہ اللہ بولے کہ اگر تو سنت پر چلنا چاہتا ہے تو عرفہ کے دن نماز دوپہر ڈھلتے ہی پڑھ لینا۔ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ سالم نے سچ کہا، صحابہ رضی اللہ عنہم نبی کریم صلی اللہ علیہ وسلم کی سنت کے مطابق ظہر اور عصر ایک ہی ساتھ پڑھتے تھے۔ میں نے سالم سے پوچھا کہ کیا رسول اللہ صلی اللہ علیہ وسلم نے بھی اسی طرح کیا تھا؟ سالم نے فرمایا اور کس کی سنت پر اس مسئلہ میں چلتے ہو۔' WHERE id = 1604;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا کہ ہم سے سلیمان بن بلال نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن ابی سعید نے بیان کیا، انہوں نے کہا کہ مجھے عدی بن ثابت نے خبر دی، کہا کہ مجھ سے عبداللہ بن یزید خطمی نے بیان کیا، کہا کہ مجھ سے ابوایوب انصاری رضی اللہ عنہ نے کہا کہ حجۃ الوداع کے موقع پر رسول اللہ صلی اللہ علیہ وسلم نے مزدلفہ میں آ کر مغرب اور عشاء کو ایک ساتھ ملا کر پڑھا تھا۔' WHERE id = 1615;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے ابواسحٰق نے، انہوں نے عمرو بن میمون کو یہ کہتے سنا کہ جب عمر بن خطاب رضی اللہ عنہ نے مزدلفہ میں فجر کی نماز پڑھی تو میں بھی موجود تھا، نماز کے بعد آپ ٹھہرے اور فرمایا کہ مشرکین ( جاہلیت میں یہاں سے ) سورج نکلنے سے پہلے نہیں جاتے تھے کہتے تھے اے ثبیر! تو چمک جا۔ نبی کریم صلی اللہ علیہ وسلم نے مشرکوں کی مخالفت کی اور سورج نکلنے سے پہلے وہاں سے روانہ ہو گئے۔' WHERE id = 1625;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا ہم سے ابن شہاب نے بیان کیا، ان سے عروہ اور عمرہ بنت عبدالرحمٰن نے کہ عائشہ رضی اللہ عنہا نے بیان کیا رسول اللہ صلی اللہ علیہ وسلم مدینہ سے ہدی ساتھ لے کر چلتے تھے اور میں ان کے قلادے بٹا کرتی تھی پھر بھی آپ ( احرام باندھنے سے پہلے ) ان چیزوں سے پرہیز نہیں کرتے تھے جن سے ایک محرم پرہیز کرتا ہے۔' WHERE id = 1637;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا کہ ہم سے ابوضمرہ نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے کہ ابن عمر رضی اللہ عنہما نے ابن زبیر رضی اللہ عنہما کے عہد خلافت میں حجۃ الحروریہ کے سال حج کا ارادہ کیا تو ان سے کہا گیا کہ لوگوں میں باہم قتل و خون ہونے والا ہے اور ہم کو خطرہ اس کا ہے کہ آپ کو ( مفسد لوگ حج سے ) روک دیں، آپ نے جواب میں یہ آیت سنائی کہ ”تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی زندگی بہترین نمونہ ہے۔“ اس وقت میں بھی وہی کام کروں گا جو نبی کریم صلی اللہ علیہ وسلم نے کیا تھا۔ میں تمہیں گواہ بناتا ہوں کہ میں نے اپنے اوپر عمرہ واجب کر لیا ہے، پھر جب آپ بیداء کے بالائی حصہ تک پہنچے تو فرمایا کہ حج اور عمرہ تو ایک ہی ہے میں تمہیں گواہ بناتا ہوں کہ عمرہ کے ساتھ میں نے حج کو بھی جمع کر لیا ہے، پھر آپ نے ایک ہدی بھی ساتھ لے لی جسے ہار پہنایا گیا تھا۔ آپ نے اسے خرید لیا یہاں تک کہ آپ مکہ آئے تو بیت اللہ کا طواف اور صفا و مروہ کی سعی کی، اس سے زیادہ اور کچھ نہیں کیا جو چیزیں ( احرام کی وجہ سے ان پر ) حرام تھیں ان میں سے کسی سے قربانی کے دن تک وہ حلال نہیں ہوئے، پھر سر منڈوایا اور قربانی کی وجہ یہ سمجھتے تھے کہ اپنا پہلا طواف کر کے انہوں نے حج اور عمرہ دونوں کا طواف پورا کر لیا ہے پھر آپ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے بھی اسی طرح کیا تھا۔' WHERE id = 1647;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، ان سے سیف بن ابی سلیمان نے بیان کیا، کہا میں نے مجاہد سے سنا، انہوں نے کہا کہ مجھ سے ابن ابی لیلیٰ نے بیان کیا اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ( حجۃ الوداع کے موقع پر ) سو اونٹ قربان کئے، میں نے آپ صلی اللہ علیہ وسلم کے حکم کے مطابق ان کے گوشت بانٹ دئیے، پھر آپ صلی اللہ علیہ وسلم نے ان کے جھول بھی تقسیم کرنے کا حکم دیا اور میں نے انہیں بھی تقسیم کیا، پھر چمڑے کے لیے حکم دیا اور میں نے انہیں بھی بانٹ دیا۔' WHERE id = 1657;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا، کہا ہم سے محمد بن فضیل نے بیان کیا، ان سے عمارہ بن قعقاع نے بیان کیا، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے دعا فرمائی اے اللہ! سر منڈوانے والوں کی مغفرت فرما! صحابہ رضی اللہ عنہم نے عرض کیا اور کتروانے والوں کے لیے بھی ( یہی دعا فرمائیے ) لیکن نبی کریم صلی اللہ علیہ وسلم نے اس مرتبہ بھی یہی فرمایا اے اللہ! سر منڈوانے والوں کی مغفرت کر۔ پھر صحابہ رضی اللہ عنہم نے عرض کیا اور کتروانے والوں کی بھی! تیسری مرتبہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اور کتروانے والوں کی بھی مغفرت فرما۔' WHERE id = 1667;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا کہ ہمیں یعقوب بن ابراہیم نے خبر دی، ان سے میرے والد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے اور ان سے عیسیٰ بن طلحہ بن عبیداللہ نے بیان کیا، انہوں نے عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے سنا انہوں نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے سواری پر سوا رہو کر ٹھہرے رہے پھر پوری حدیث بیان کی۔ اس کی متابعت معمر نے زہری سے روایت کر کے کی ہے۔' WHERE id = 1677;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے حکم بن عتبہ نے، ان سے ابراہیم نحعی نے، ان سے عبدالرحمٰن بن یزید نے کہ عبداللہ بن مسعود رضی اللہ عنہ جمرہ کبریٰ کے پاس پہنچے تو کعبہ کو اپنے بائیں طرف کیا اور منیٰ کو دائیں طرف، پھر سات کنکریوں سے رمی کی اور فرمایا کہ جن پر سورۃ البقرہ نازل ہوئی تھی صلی اللہ علیہ وسلم انہوں نے بھی اسی طرح رمی کی تھی۔ ( یعنی رسول اللہ صلی اللہ علیہ وسلم ) ۔' WHERE id = 1687;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا کہ ہم سے ابوعوانہ نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نخعی نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ نکلے، ہماری نیت حج کے سوا اور کچھ نہ تھی۔ پھر جب نبی کریم صلی اللہ علیہ وسلم ( مکہ ) پہنچے تو آپ صلی اللہ علیہ وسلم نے بیت اللہ کا طواف اور صفا اور مروہ کی سعی کی، لیکن آپ صلی اللہ علیہ وسلم نے احرام نہیں کھولا کیونکہ آپ کے ساتھ قربانی تھی۔ آپ صلی اللہ علیہ وسلم کے ساتھ آپ صلی اللہ علیہ وسلم کی بیویوں نے اور دیگر اصحاب نے بھی طواف کیا اور جن کے ساتھ قربانی نہیں تھیں انہوں نے ( اس طواف و سعی کے بعد ) احرام کھول دیا لیکن عائشہ رضی اللہ عنہا حائضہ ہو گئی تھیں، سب نے اپنے حج کے تمام مناسک ادا کر لیے تھے، پھر جب لیلۃ حصبہ یعنی روانگی کی رات آئی تو عائشہ رضی اللہ عنہا نے عرض کی یا رسول اللہ صلی اللہ علیہ وسلم آپ صلی اللہ علیہ وسلم کے تمام ساتھی حج اور عمرہ دونوں کر کے جا رہے ہیں صرف میں عمرہ سے محروم ہوں، آپ صلی اللہ علیہ وسلم نے فرمایا کے اچھا جب ہم آئے تھے تو تم ( حیض کی وجہ سے ) بیت اللہ کا طواف نہیں کر سکی تھیں؟ میں نے کہا کہ نہیں، آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر اپنے بھائی کے ساتھ تنعیم چلی جا اور وہاں سے عمرہ کا احرام باندھ ( اور عمرہ کر ) ہم تمہارا فلاں جگہ انتظار کریں گے، چنانچہ میں اپنے بھائی ( عبدالرحمٰن رضی اللہ عنہ ) کے ساتھ تنعیم گئی اور وہاں سے احرام باندھا۔ اسی طرح صفیہ بنت حی رضی اللہ عنہا بھی حائضہ ہو گئی تھیں نبی کریم صلی اللہ علیہ وسلم نے انہیں ( ازراہ محبت ) فرمایا «عقرى حلقى»،‏‏‏‏ تو، تو ہمیں روک لے گی، کیا تو نے قربانی کے دن طواف زیارت نہیں کیا تھا؟ وہ بولیں کہ کیا تھا، اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر کوئی حرج نہیں، چلی چلو۔ میں جب آپ تک پہنچی تو آپ صلی اللہ علیہ وسلم مکہ کے بالائی علاقہ پر چڑھ رہے تھے اور میں اتر رہی تھی یا یہ کہا کہ میں چڑھ رہی تھی اور نبی کریم صلی اللہ علیہ وسلم اتر رہے تھے۔ مسدد کی روایت میں ( رسول اللہ صلی اللہ علیہ وسلم کے کہنے پر ) ہاں کے بجائے نہیں ہے، اس کی متابعت جریر نے منصور کے واسطہ سے ”نہیں“ کے ذکر میں کی ہے۔' WHERE id = 1699;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، انہیں عبداللہ بن مبارک نے خبر دی، انہیں ابن جریج نے خبر دی کہ عکرمہ بن خالد نے ابن عمر رضی اللہ عنہما سے حج سے پہلے عمرہ کرنے کے بارے میں پوچھا تو انہوں نے کہا کوئی حرج نہیں، عکرمہ نے کہا ابن عمر رضی اللہ عنہما نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے حج کرنے سے پہلے عمرہ ہی کیا تھا اور ابراہیم بن سعد نے محمد بن اسحاق سے بیان کیا، ان سے عکرمہ بن خالد نے بیان کیا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے پوچھا پھر یہی حدیث بیان کی۔ ہم سے عمرو بن علی فلاس نے بیان کیا، ان سے ابوعاصم نے بیان کیا، انہیں ابن جریج نے خبر دی، ان سے عکرمہ بن خالد نے بیان کیا کہ میں نے ابن عمر رضی اللہ عنہما سے پوچھا پھر یہی حدیث بیان کی۔' WHERE id = 1710;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ ہم سے یحییٰ بن قطان نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، کہا کہ مجھے میرے والد عروہ نے خبر دی کہا کہ مجھے عائشہ رضی اللہ عنہا نے خبر دی انہوں نے کہا کہ ذی الحجہ کا چاند نکلنے والا تھا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ مدینہ سے حج کے لیے چلے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو عمرہ کا احرام باندھنا چاہے وہ عمرہ کا باندھ لے اور جو حج کا باندھنا چاہے وہ حج کا باندھ لے، اگر میں اپنے ساتھ قربانی نہ لاتا تو میں بھی عمرہ کا ہی احرام باندھتا، چنانچہ بہت سے لوگوں نے عمرہ کا احرام باندھا اور بہتوں نے حج کا۔ میں بھی ان لوگوں میں تھی جنہوں نے عمرہ کا احرام باندھا تھا۔ مگر میں مکہ میں داخل ہونے سے پہلے حائضہ ہو گئی، عرفہ کا دن آ گیا اور ابھی میں حائضہ ہی تھی، اس کا رونا میں رسول اللہ صلی اللہ علیہ وسلم کے سامنے روئی، آپ صلی اللہ علیہ وسلم نے فرمایا کہ عمرہ چھوڑ دے اور سر کھول لے اور کنگھا کر لے پھر حج کا احرام باندھ لینا، چنانچہ میں نے ایسا ہی کیا، اس کے بعد جب محصب کی رات آئی تو نبی کریم صلی اللہ علیہ وسلم نے میرے ساتھ عبدالرحمٰن کو تنعیم بھیجا وہ مجھے اپنی سواری پر پیچھے بٹھا کر لے گئے وہاں سے عائشہ رضی اللہ عنہا نے اپنے ( چھوڑے ہوئے ) عمرے کے بجائے دوسرے عمرہ کا احرام باندھا اس طرح اللہ تعالیٰ نے ان کا بھی حج اور عمرہ دونوں ہی پورے کر دیئے نہ تو اس کے لیے انہیں قربانی لانی پڑی نہ صدقہ دینا پڑا اور نہ روزہ رکھنا پڑا۔' WHERE id = 1721;
UPDATE hadiths SET urdu = 'ہم سے احمد بن حجاج نے بیان کیا، انہوں نے کہا ہم سے انس بن عیاض نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم جب مکہ تشریف لے جاتے تو مسجد شجرہ میں نماز پڑھتے۔ اور جب واپس ہوتے تو ذو الحلیفہ کی وادی کے نشیب میں نماز پڑھتے۔ آپ صلی اللہ علیہ وسلم صبح تک ساری رات وہیں رہتے۔' WHERE id = 1732;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا کہ ہم سے یحییٰ بن صالح نے بیان کیا، ان سے معاویہ بن سلام نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عکرمہ نے بیان کیا کہ ابن عباس رضی اللہ عنہما نے ان سے فرمایا رسول اللہ صلی اللہ علیہ وسلم جب حدیبیہ کے سال مکہ جانے سے روک دیئے گئے تو آپ نے حدیبیہ ہی میں اپنا سر منڈوایا اور ازواج مطہرات کے پاس گئے اور قربانی کو نحر کیا، پھر آئندہ سال ایک دوسرا عمرہ کیا۔' WHERE id = 1742;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے منصور نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس شخص نے اس گھر ( کعبہ ) کا حج کیا اور اس میں نہ «رفث» یعنی شہوت کی بات منہ سے نکالی اور نہ کوئی گناہ کا کام کیا تو وہ اس دن کی طرح واپس ہو گا جس دن اس کی ماں نے اسے جنا تھا۔' WHERE id = 1752;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا مجھ سے ابن وہب نے بیان کیا، انہوں نے کہا مجھے یونس نے خبر دی، انہیں ابن شہاب نے خبر دی، انہیں عروہ بن زبیر نے خبر دی اور انہیں ام المؤمنین عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا پانچ جانور ایسے ہیں جو سب کے سب موذی ہیں اور انہیں حرم میں بھی مارا جا سکتا ہے کوا، چیل، بچھو، چوہا اور کاٹنے والا کتا۔' WHERE id = 1762;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے حکم نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ایک محرم شخص کے اونٹ نے حجۃ الوداع کے موقع پر اس کی گردن ( گرا کر ) توڑ دی اور اسے جان سے مار دیا، اس شخص کو رسول اللہ صلی اللہ علیہ وسلم کے سامنے لایا گیا تو آپ نے فرمایا کہ انہیں غسل اور کفن دے دو لیکن ان کا سر نہ ڈھکو اور نہ خوشبو لگاؤ کیونکہ ( قیامت میں ) یہ لبیک کہتے ہوئے اٹھے گا۔' WHERE id = 1772;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہا کہ میدان عرفات میں ایک شخص نبی کریم صلی اللہ علیہ وسلم کے ساتھ ٹھہرا ہوا تھا کہ اپنی اونٹنی سے گر پڑا اور اس اونٹنی نے اس کی گردن توڑ ڈالی، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پانی اور بیری کے پتوں سے اسے غسل دو اور احرام ہی کے دو کپڑوں کا کفن دو لیکن خوشبو نہ لگانا نہ اس کا سر چھپانا کیونکہ اللہ تعالیٰ قیامت میں اسے لبیک کہتے ہوئے اٹھائے گا۔' WHERE id = 1782;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن ذرارہ نے بیان کیا، کہا کہ ہمیں قاسم بن مالک نے خبر دی، انہیں جعید بن عبدالرحمٰن نے، انہوں نے کہا کہ میں نے عمر بن عبدالعزیز رحمہ اللہ سے سنا، وہ سائب بن یزید رضی اللہ عنہ سے کہہ رہے تھے سائب رضی اللہ عنہ کو نبی کریم صلی اللہ علیہ وسلم کے سامان کے ساتھ ( یعنی بال بچوں میں ) حج کرایا گیا تھا۔' WHERE id = 1792;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان بن بلال نے، ان سے عبیداللہ نے، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا مدینہ کے دونوں پتھریلے کناروں میں جو زمین ہے وہ میری زبان پر حرم ٹھہرائی گئی۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم بنو حارثہ کے پاس آئے اور فرمایا بنوحارثہ! میرا خیال ہے کہ تم لوگ حرم سے باہر ہو گئے ہو، پھر آپ صلی اللہ علیہ وسلم نے مڑ کر دیکھا اور فرمایا کہ نہیں بلکہ تم لوگ حرم کے اندر ہی ہو۔' WHERE id = 1802;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان سے ان کے دادا نے اور ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا مدینہ پر دجال کا رعب بھی نہیں پڑے گا اس دور میں مدینہ کے سات دروازے ہوں گے اور ہر دروازے پر دو فرشتے ہوں گے۔' WHERE id = 1812;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو ابوبکر اور بلال رضی اللہ عنہما بخار میں مبتلا ہو گئے، ابوبکر رضی اللہ عنہ جب بخار میں مبتلا ہوئے تو یہ شعر پڑھتے: ہر آدمی اپنے گھر والوں میں صبح کرتا ہے حالانکہ اس کی موت اس کی جوتی کے تسمہ سے بھی زیادہ قریب ہے۔ اور بلال رضی اللہ عنہ کا جب بخار اترتا تو آپ بلند آواز سے یہ اشعار پڑھتے: کاش! میں ایک رات مکہ کی وادی میں گزار سکتا اور میرے چاروں طرف اذخر اور جلیل ( گھاس ) ہوتیں۔ کاش! ایک دن میں مجنہ کے پانی پر پہنچتا اور کاش! میں شامہ اور طفیل ( پہاڑوں ) کو دیکھ سکتا۔ کہا کہ اے میرے اللہ! شیبہ بن ربیعہ، عتبہ بن ربیعہ اور امیہ بن خلف مردودوں پر لعنت کر۔ انہوں نے اپنے وطن سے اس وبا کی زمین میں نکالا ہے۔ رسول اللہ صلی اللہ علیہ وسلم نے یہ سن کر فرمایا اے اللہ! ہمارے دلوں میں مدینہ کی محبت اسی طرح پیدا کر دے جس طرح مکہ کی محبت ہے بلکہ اس سے بھی زیادہ! اے اللہ! ہمارے صاع اور ہمارے مد میں برکت عطا فرما اور مدینہ کی آب و ہوا ہمارے لیے صحت خیز کر دے یہاں کے بخار کو جحیفہ میں بھیج دے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب ہم مدینہ آئے تو یہ اللہ کی سب سے زیادہ وبا والی سر زمین تھی۔ انہوں نے کہا مدینہ میں بطحان نامی ایک نالہ سے ذرا ذرا بدمزہ اور بدبودار پانی بہا کرتا تھا۔' WHERE id = 1822;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، ان سے عقیل نے ان سے ابن شہاب زہری نے بیان کیا کہ مجھے بنو تمیم کے مولیٰ ابوسہیل بن ابی انس نے خبر دی، ان سے ان کے والد نے بیان کیا، اور انہوں نے ابوہریرہ رضی اللہ عنہ کو کہتے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جب رمضان کا مہینہ آتا ہے تو آسمان کے تمام دروازے کھول دیئے جاتے ہیں، جہنم کے دروازے بند کر دیئے جاتے ہیں اور شیاطین کو زنجیروں سے جکڑ دیا جاتا ہے۔' WHERE id = 1832;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محمد بن زیاد نے بیان کیا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، آپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، یا یوں کہا کہ ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا چاند ہی دیکھ کر روزے شروع کرو اور چاند ہی دیکھ کر روزہ موقوف کرو اور اگر بادل ہو جائے تو تیس دن پورے کر لو۔' WHERE id = 1842;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے اور ان سے زید بن ثابت رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ہم نے سحری کھائی، پھر آپ صلی اللہ علیہ وسلم صبح کی نماز کے لیے کھڑے ہوئے۔ میں نے پوچھا کہ سحری اور اذان میں کتنا فاصلہ ہوتا تھا تو انہوں نے کہا کہ پچاس آیتیں ( پڑھنے ) کے موافق فاصلہ ہوتا تھا۔' WHERE id = 1853;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن منیر نے بیان کیا، کہا کہ ہم نے یزید بن ہارون سے سنا، ان سے یحییٰ نے (جو سعید کے صاحبزادے ہیں) کہا، انہیں عبدالرحمٰن بن قاسم نے خبر دی، انہیں محمد بن جعفر بن زبیر بن عوام بن خویلد نے اور انہیں عباد بن عبداللہ بن زبیر رضی اللہ عنہما نے خبر دی کہ انہوں نے عائشہ رضی اللہ عنہا سے سنا، آپ نے کہا کہ ایک شخص رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کی کہ میں دوزخ میں جل چکا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہوئی؟ اس نے کہا کہ رمضان میں میں نے ( روزے کی حالت میں ) اپنی بیوی سے ہمبستری کر لی، تھوڑی دیر میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ( کھجور کا ) ایک تھیلہ جس کا نام عرق تھا، پیش کیا گیا، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ دوزخ میں جلنے والا شخص کہاں ہے؟ اس نے کہا کہ حاضر ہوں، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ لے تو اسے خیرات کر دے۔' WHERE id = 1865;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم سے یحییٰ بن حمزہ نے بیان کیا، ان سے ابوعبدالرحمٰن بن یزید بن جابر نے بیان کیا، ان سے اسماعیل بن عبیداللہ نے بیان کیا، اور ان سے ام الدرداء رضی اللہ عنہا نے بیان کیا کہ ابودرداء رضی اللہ عنہ نے کہا ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر کر رہے تھے۔ دن انتہائی گرم تھا۔ گرمی کا یہ عالم تھا کہ گرمی کی سختی سے لوگ اپنے سروں کو پکڑ لیتے تھے، نبی کریم صلی اللہ علیہ وسلم اور ابن رواحہ رضی اللہ عنہ کے سوا کوئی شخص روزہ سے نہیں تھا۔' WHERE id = 1875;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہمیں امام مالک نے خبر دی، انہیں ابوحازم سلمہ بن دینار نے، انہیں سہل بن سعد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، میری امت کے لوگوں میں اس وقت تک خیر باقی رہے گی، جب تک وہ افطار میں جلدی کرتے رہیں گے۔' WHERE id = 1887;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، کہا کہ ہم سے عبدالعزیز ابن ابی حازم نے بیان کیا، ان سے یزید بن ہاد نے، ان سے عبداللہ بن خباب نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا کہ آپ صلی اللہ علیہ وسلم فرما رہے تھے، صوم وصال نہ رکھو۔ اور اگر کسی کا ارادہ ہی وصال کا ہو تو سحری کے وقت تک وصال کر لے۔ صحابہ رضی اللہ عنہم نے عرض کی، یا رسول اللہ! آپ تو وصال کرتے ہیں آپ نے فرمایا کہ میں تمہاری طرح نہیں ہوں۔ رات کے وقت ایک کھلانے والا مجھے کھلاتا ہے اور ایک پلانے والا مجھے پلاتا ہے۔' WHERE id = 1897;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا کہ ہم کو ابوعاصم نے خبر دی، انہیں ابن جریج نے، انہوں نے عطاء سے سنا، انہیں ابوعباس شاعر نے خبر دی، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ میں مسلسل روزے رکھتا ہوں اور ساری رات عبادت کرتا ہوں۔ اب یا نبی کریم صلی اللہ علیہ وسلم نے کسی کو میرے پاس بھیجا یا خود میں نے آپ سے ملاقات کی۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا یہ خبر صحیح ہے کہ تو متواتر روزے رکھتا ہے اور ایک بھی نہیں چھوڑتا اور ( رات بھر ) نماز پڑھتا رہتا ہے؟ روزہ بھی رکھ اور بے روزہ بھی رہ، عبادت بھی کر اور سوؤ بھی کیونکہ تیری آنکھ کا بھی تجھ پر حق ہے، تیری جان کا بھی تجھ پر حق ہے اور تیری بیوی کا بھی تجھ پر حق ہے۔ عبداللہ رضی اللہ عنہ نے کہا کہ مجھ میں اس سے زیادہ کی طاقت ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر داؤد علیہ السلام کی طرح روزہ رکھا کر۔ انہوں نے کہا اور وہ کس طرح؟ فرمایا کہ داؤد علیہ السلام ایک دن روزہ رکھتے تھے اور ایک دن کا روزہ چھوڑ دیا کرتے تھے۔ اور جب دشمن سے مقابلہ ہوتا تو پیٹھ نہیں پھیرتے تھے۔ اس پر عبداللہ رضی اللہ عنہ نے عرض کی، اے اللہ کے نبی! میرے لیے یہ کیسے ممکن ہے کہ میں پیٹھ پھیر جاؤں۔ عطاء نے کہا کہ مجھے یاد نہیں ( اس حدیث میں ) صوم دہر کا کس طرح ذکر ہوا! ( البتہ انہیں اتنا دیا تھا کہ ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا، جو صوم دہر رکھتا ہے اس کا روزہ ہی نہیں، دو مرتبہ ( آپ صلی اللہ علیہ وسلم نے یہی فرمایا ) ۔' WHERE id = 1907;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے، ان سے منصور نے، ان سے ابراہیم نے، ان سے علقمہ نے، انہوں نے عائشہ رضی اللہ عنہا سے پوچھا کہ کیا رسول اللہ صلی اللہ علیہ وسلم نے ( روزہ وغیرہ عبادات کے لیے ) کچھ دن خاص طور پر مقرر کر رکھے تھے؟ انہوں نے کہا نہیں۔ بلکہ آپ کے ہر عمل میں ہمیشگی ہوتی تھی اور دوسرا کون ہے جو رسول اللہ صلی اللہ علیہ وسلم جتنی طاقت رکھتا ہو؟' WHERE id = 1917;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا کہ مجھے عروہ بن زبیر رضی اللہ عنہ نے خبر دی، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ( شروع اسلام میں ) رسول اللہ صلی اللہ علیہ وسلم نے عاشوراء کے دن کا روزہ رکھنے کا حکم دیا تھا۔ پھر جب رمضان کے روزے فرض ہو گئے تو جس کا دل چاہتا اس دن روزہ رکھتا اور جو نہ چاہتا نہیں رکھا کرتا تھا۔' WHERE id = 1929;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ بن زبیر رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک بار نماز ( تراویح ) پڑھی اور یہ رمضان میں ہوا تھا۔' WHERE id = 1939;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، کہا کہ ہم سے ایوب سختیانی نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، شب قدر کو رمضان کے آخری عشرہ میں تلاش کرو، جب نو راتیں باقی رہ جائیں یا پانچ راتیں باقی رہ جائیں۔ ( یعنی اکیسوئیں یا تئیسوئیں یا پچیسوئیں راتوں میں شب قدر کو تلاش کرو ) ۔' WHERE id = 1949;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل دوسی نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے یحییٰ قطان نے، ان سے عمرہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم رمضان کے آخری عشرہ میں اعتکاف کیا کرتے تھے۔ میں آپ صلی اللہ علیہ وسلم کے لیے ( مسجد میں ) ایک خیمہ لگا دیتی۔ اور آپ صلی اللہ علیہ وسلم صبح کی نماز پڑھ کے اس میں چلے جاتے تھے۔ پھر حفصہ رضی اللہ عنہا نے بھی عائشہ رضی اللہ عنہا سے خیمہ کھڑا کرنے کی ( اپنے اعتکاف کے لیے ) اجازت چاہی۔ عائشہ رضی اللہ عنہا نے اجازت دے دی اور انہوں نے ایک خیمہ کھڑا کر لیا جب زینب بنت جحش رضی اللہ عنہا نے دیکھا تو انہوں نے بھی ( اپنے لیے ) ایک خیمہ کھڑا کر لیا۔ صبح ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے کئی خیمے دیکھے تو فرمایا، یہ کیا ہے؟ آپ کو ان کی حقیقت کی خبر دی گئی۔ آپ صلی اللہ علیہ وسلم نے فرمایا، کیا تم سمجھتے ہو یہ خیمے ثواب کی نیت سے کھڑے کئے گئے ہیں۔ پس آپ صلی اللہ علیہ وسلم نے اس مہینہ ( رمضان ) کا اعتکاف چھوڑ دیا اور شوال کے عشرہ کا اعتکاف کیا۔' WHERE id = 1960;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا کہ ہم سے ابواسامہ نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے زمانہ جاہلیت میں مسجد الحرام میں اعتکاف کی نذر مانی تھی، عبید نے بیان کیا کہ میرا خیال ہے کہ انہوں نے رات بھر کا ذکر کیا تھا، تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اپنی نذر پوری کر۔' WHERE id = 1970;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ بن زبیر رضی اللہ عنہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ عتبہ بن ابی وقاص ( کافر ) نے اپنے بھائی سعد بن ابی وقاص ( مسلمان ) کو ( مرتے وقت ) وصیت کی تھی کہ زمعہ کی باندی کا لڑکا میرا ہے۔ اس لیے اسے تم اپنے قبضہ میں لے لینا۔ انہوں نے کہا کہ فتح مکہ کے سال سعد رضی اللہ عنہ بن ابی وقاص نے اسے لے لیا، اور کہا کہ یہ میرے بھائی کا لڑکا ہے اور وہ اس کے متعلق مجھے وصیت کر گئے ہیں، لیکن عبد بن زمعہ نے اٹھ کر کہا کہ میرے باپ کی لونڈی کا بچہ ہے، میرے باپ کے بستر پر پیدا ہوا ہے۔ آخر دونوں یہ مقدمہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لے گئے۔ سعد رضی اللہ عنہ نے عرض کیا یا رسول اللہ! یہ میرے بھائی کا لڑکا ہے اور مجھے اس کی انہوں نے وصیت کی تھی۔ اور عبد بن زمعہ نے عرض کیا، یہ میرا بھائی ہے اور میرے باپ کی لونڈی کا لڑکا ہے۔ انہیں کے بستر پر اس کی پیدائش ہوئی ہے۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، عبد بن زمعہ! لڑکا تو تمہارے ہی ساتھ رہے گا۔ اس کے بعد فرمایا، بچہ اسی کا ہوتا ہے جو جائز شوہر یا مالک ہو جس کے بستر پر وہ پیدا ہوا ہو۔ اور حرام کار کے حصہ میں پتھروں کی سزا ہے۔ پھر سودہ بنت زمعہ رضی اللہ عنہا سے جو نبی کریم صلی اللہ علیہ وسلم کی بیوی تھیں، فرمایا کہ اس لڑکے سے پردہ کیا کر، کیونکہ آپ صلی اللہ علیہ وسلم نے عتبہ کی شباہت اس لڑکے میں محسوس کر لی تھی۔ اس کے بعد اس لڑکے نے سودہ رضی اللہ عنہ کو کبھی نہ دیکھا یہاں تک کہ وہ اللہ تعالیٰ سے جا ملا۔' WHERE id = 1980;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا کہ ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے، ان سے مسروق نے، اور ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، جب عورت اپنے گھر کا کھانا ( غلہ وغیرہ ) بشرطیکہ گھر بگاڑنے کی نیت نہ ہو خرچ کرے تو اسے خرچ کرنے کا ثواب ملتا ہے اور اس کے شوہر کو کمانے کا اور خزانچی کو بھی ایسا ہی ثواب ملتا ہے ایک کا ثواب دوسرے کے ثواب کو کم نہیں کرتا۔' WHERE id = 1991;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا کہ ہم سے وکیع نے بیان کیا، کہا کہ ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے زبیر بن عوام رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر کوئی اپنی رسیوں کو سنبھال لے اور ان میں لکڑی باندھ کر لائے تو وہ اس سے بہتر ہے جو لوگوں سے مانگتا ہے پھرتا ہے۔' WHERE id = 2001;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے جریر بن حازم نے، کہا کہ ہم سے ابورجاء بصریٰ نے بیان کیا، ان سے سمرہ بن جندب رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، رات ( خواب میں ) میں نے دو آدمی دیکھے، وہ دونوں میرے پاس آئے اور مجھے بیت المقدس میں لے گئے، پھر ہم سب وہاں سے چلے یہاں تک کہ ہم ایک خون کی نہر پر آئے، وہاں ( نہر کے کنارے ) ایک شخص کھڑا ہوا تھا، اور نہر کے بیچ میں بھی ایک شخص کھڑا تھا۔ ( نہر کے کنارے پر ) کھڑے ہونے والے کے سامنے پتھر پڑے ہوئے تھے۔ بیچ نہر والا آدمی آتا اور جونہی وہ چاہتا کہ باہر نکل جائے فوراً ہی باہر والا شخص اس کے منہ پر پتھر کھینچ کر مارتا جو اسے وہیں لوٹا دیتا تھا جہاں وہ پہلے تھا۔ اسی طرح جب بھی وہ نکلنا چاہتا کنارے پر کھڑا ہوا شخص اس کے منہ پر پتھر کھینچ مارتا اور وہ جہاں تھا وہیں پھر لوٹ جاتا۔ میں نے ( اپنے ساتھیوں سے جو فرشتے تھے ) پوچھا کہ یہ کیا ہے، تو انہوں نے اس کا جواب یہ دیا کہ نہر میں تم نے جس شخص کو دیکھا وہ سود کھانے والا انسان ہے۔' WHERE id = 2011;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا کہ ہم سے عبدالواحد بن ایمن نے بیان کیا، ان سے ان کے والد نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ ایک انصاری عورت نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا، یا رسول اللہ! میں آپ کے لیے کوئی ایسی چیز کیوں نہ بنوا دوں جس پر آپ صلی اللہ علیہ وسلم وعظ کے وقت بیٹھا کریں۔ کیونکہ میرے پاس ایک غلام بڑھئی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا تمہاری مرضی۔ راوی نے بیان کیا کہ پھر جب منبر آپ صلی اللہ علیہ وسلم کے لیے اس نے تیار کیا۔ تو جمعہ کے دن جب نبی کریم صلی اللہ علیہ وسلم اس منبر پر بیٹھے تو اس کھجور کی لکڑی سے رونے کی آواز آنے لگی۔ جس پر ٹیک دے کر آپ صلی اللہ علیہ وسلم پہلے خطبہ دیا کرتے تھے۔ ایسا معلوم ہوتا تھا کہ وہ پھٹ جائے گی۔ یہ دیکھ کر نبی کریم صلی اللہ علیہ وسلم منبر پر سے اترے اور اسے پکڑ کر اپنے سینے سے لگا لیا۔ اس وقت بھی وہ لکڑی اس چھوٹے بچے کی طرح سسکیاں بھر رہی تھی جسے چپ کرانے کی کوشش کی جاتی ہے۔ اس کے بعد وہ چپ ہو گئی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، کہ اس کے رونے کی وجہ یہ تھی کہ یہ لکڑی خطبہ سنا کرتی تھی اس لیے روئی۔' WHERE id = 2021;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں نافع نے، انہیں قاسم بن محمد نے اور انہیں ام المؤمنین عائشہ رضی اللہ عنہا نے کہ انہوں نے ایک گدا خریدا جس پر مورتیں تھیں۔ رسول اللہ صلی اللہ علیہ وسلم کی نظر جوں ہی اس پر پڑی، آپ صلی اللہ علیہ وسلم دروازے پر ہی کھڑے ہو گئے اور اندر داخل نہیں ہوئے۔ ( عائشہ رضی اللہ عنہا نے بیان کیا کہ ) میں نے آپ صلی اللہ علیہ وسلم کے چہرہ مبارک پر ناپسندیدگی کے آثار دیکھے تو عرض کیا، یا رسول اللہ! میں اللہ کی بارگاہ میں توبہ کرتی ہوں اور اس کے رسول اللہ صلی اللہ علیہ وسلم سے معافی مانگتی ہوں، فرمائیے مجھ سے کیا غلطی ہوئی ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا، یہ گدا کیسا ہے؟ میں نے کہا کہ میں نے یہ آپ ہی کے لیے خریدا ہے تاکہ آپ اس پر بیٹھیں اور اس سے ٹیک لگائیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا، لیکن اس طرح کی مورتیں بنانے والے لوگ قیامت کے دن عذاب کئے جائیں گے۔ اور ان سے کہا جائے گا کہ تم لوگوں نے جس چیز کو بنایا اسے زندہ کر دکھاؤ۔ آپ صلی اللہ علیہ وسلم نے یہ بھی فرمایا کہ جن گھروں میں تصویریں ہوتی ہیں ( رحمت کے ) فرشتے ان میں داخل نہیں ہوتے۔' WHERE id = 2031;
UPDATE hadiths SET urdu = 'حمیدی نے کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو نے بیان کیا اور ان سے ابن عمر رضی اللہ عنہما نے کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے۔ میں عمر رضی اللہ عنہ کے ایک نئے اور سرکش اونٹ پر سوار تھا۔ اکثر وہ مجھے مغلوب کر کے سب سے آگے نکل جاتا، لیکن عمر رضی اللہ عنہ اسے ڈانٹ کر پیچھے واپس کر دیتے۔ وہ پھر آگے بڑھ جاتا۔ آخر نبی کریم صلی اللہ علیہ وسلم نے عمر رضی اللہ عنہ سے فرمایا کہ یہ اونٹ مجھے بیچ ڈال۔ عمر رضی اللہ عنہ نے کہا یا رسول اللہ! یہ تو آپ ہی کا ہے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں مجھے یہ اونٹ دیدے۔ چنانچہ عمر رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کو وہ اونٹ بیچ ڈالا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا، عبداللہ بن عمر! اب یہ اونٹ تیرا ہو گیا جس طرح تو چاہے اسے استعمال کر۔' WHERE id = 2041;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم سے ولید نے بیان کیا، ان سے ثور نے، ان سے خالد بن معدان نے اور ان سے مقدام بن معدیکرب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اپنے غلے کو ناپ لیا کرو۔ اس میں تمہیں برکت ہو گی۔' WHERE id = 2053;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، کوئی شخص اپنے بھائی کی خرید و فروخت میں دخل اندازی نہ کرے۔' WHERE id = 2064;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے معتمر نے بیان کیا، کہا کہ میں نے اپنے باپ سے سنا، وہ کہتے تھے کہ ہم سے ابوعثمان نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ جو شخص «مصراة» بکری خریدے اور اسے واپس کرنا چاہے تو ( اصل مالک کو ) اس کے ساتھ ایک صاع بھی دے۔ اور نبی کریم صلی اللہ علیہ وسلم نے قافلہ والوں سے ( جو مال بیچنے لائیں ) آگے بڑھ کر خریدنے سے منع فرمایا ہے۔' WHERE id = 2074;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ ہم سے معاذ بن معاذ نے بیان کیا، ان سے عبداللہ بن عون نے بیان کیا، ان سے محمد بن سیرین نے کہ انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ہمیں اس سے روکا گیا کہ کوئی شہری کسی دیہاتی کا مال تجارت بیچے۔' WHERE id = 2085;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ ہم سے امام مالک نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے مزابنہ سے منع فرمایا، مزابنہ یہ کہ درخت پر لگی ہوئی کھجور خشک کھجور کے بدلہ ماپ کر کے بیچی جائے۔ اسی طرح بیل پر لگے ہوئے انگور کو منقیٰ کے بدل بیچنا۔' WHERE id = 2095;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، انہیں ابن جریج نے خبر دی، انہیں عطاء اور ابوزبیر نے اور انہیں جابر رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے کھجور کے پکنے سے پہلے بیچنے سے منع کیا ہے اور یہ کہ اس میں سے ذرہ برابر بھی درہم و دینا کے سوا کسی اور چیز ( سوکھے پھل ) کے بدلے نہ بیچی جائے البتہ عریہ کی اجازت دی۔' WHERE id = 2109;
UPDATE hadiths SET urdu = 'لیث نے کہا کہ مجھے سے یونس نے بیان کیا انہوں نے کہا کہ ہم سے ابن شہاب نے بیان کیا، انہوں نے کہا کہ ایک شخص نے اگر پختہ ہونے سے پہلے ہی ( درخت پر ) پھل خریدے، پھر ان پر کوئی آفت آ گئی تو جتنا نقصان ہوا، وہ سب اصل مالک کو بھرنا پڑے گا۔ مجھے سالم بن عبداللہ نے خبر دی، اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، پختہ ہونے سے پہلے پھلوں کو نہ بیچو، اور نہ درخت پر لگی ہوئی کھجور کو ٹوٹی ہوئی کھجور کے بدلے میں بیچو۔' WHERE id = 2119;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا، ان سے ہشام نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ معاویہ رضی اللہ عنہ کی والدہ ہندہ رضی اللہ عنہا نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ ابوسفیان بخیل آدمی ہے۔ تو کیا اگر میں ان کے مال سے چھپا کر کچھ لے لیا کروں تو کوئی حرج ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم اپنے لیے اور اپنے بیٹوں کے لیے نیک نیتی کے ساتھ اتنا لے سکتی ہو جو تم سب کے لیے کافی ہو جایا کرے۔' WHERE id = 2130;
UPDATE hadiths SET urdu = 'ہم سے زہیر بن حرب نے بیان کیا، کہا کہ ہم سے یعقوب بن ابراہیم نے بیان کیا، ان سے ان کے باپ نے بیان کیا، ان سے صالح نے بیان کیا، کہ مجھ سے ابن شہاب نے بیان کیا، انہیں عبیداللہ بن عبداللہ نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم کا گزر ایک مردہ بکری پر ہوا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کے چمڑے سے تم لوگوں نے کیوں نہیں فائدہ اٹھایا؟ صحابہ نے عرض کیا، کہ وہ تو مردار ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مردار کا صرف کھانا منع ہے۔' WHERE id = 2141;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے عمرو نے، انہوں نے جابر بن عبداللہ رضی اللہ عنہما کو یہ کہتے سنا تھا کہ مدبر غلام کو رسول اللہ صلی اللہ علیہ وسلم نے بیچا تھا۔' WHERE id = 2151;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا کہ ہم سے یعلیٰ بن عبیداللہ نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے ابراہیم نے، ان سے اسود نے بیان کیا ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک یہودی سے ادھار غلہ خریدا اور اپنی ایک لوہے کی زرہ اس کے پاس گروی رکھی۔' WHERE id = 2169;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم کو ہشام بن عروہ نے خبر دی، انہیں معمر نے، انہیں زہری نے، انہیں عروہ بن زبیر نے اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ نے ( ہجرت کرتے وقت ) بنو دیل کے ایک مرد کو نوکر رکھا جو بنو عبد بن عدی کے خاندان سے تھا۔ اور اسے بطور ماہر راہبر مزدوری پر رکھا تھا ( حدیث کے لفظ ) «خريت» کے معنی راہبری میں ماہر کے ہیں۔ اس نے اپنا ہاتھ پانی وغیرہ میں ڈبو کر عاص بن وائل کے خاندان سے عہد کیا تھا اور وہ کفار قریش ہی کے دین پر تھا۔ لیکن نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ کو اس پر بھروسہ تھا۔ اسی لیے اپنی سواریاں انہوں نے اسے دے دیں اور غار ثور پر تین رات کے بعد اس سے ملنے کی تاکید کی تھی۔ وہ شخص تین راتوں کے گزرتے ہی صبح کو دونوں حضرات کی سواریاں لے کر وہاں حاضر ہو گیا۔ اس کے بعد یہ حضرات وہاں سے عامر بن فہیرہ اور اس دیلی راہبر کو ساتھ لے کر چلے۔ یہ شخص ساحل کے کنارے سے آپ کو لے کر چلا تھا۔' WHERE id = 2180;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے مسلم بن صبیح نے، ان سے مسروق نے، ان سے خباب بن ارت رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ میں لوہار تھا، میں نے عاص بن وائل ( مشرک ) کا کام کیا۔ جب میری بہت سی مزدوری اس کے سر چڑھ گئی تو میں اس کے پاس تقاضا کرنے آیا، وہ کہنے لگا کہ اللہ کی قسم! میں تمہاری مزدوری اس وقت تک نہیں دوں گا جب تک تم محمد صلی اللہ علیہ وسلم سے نہ پھر جاؤ۔ میں نے کہا، اللہ کی قسم! یہ تو اس وقت بھی نہ ہو گا جب تو مر کے دوبارہ زندہ ہو گا۔ اس نے کہا، کیا میں مرنے کے بعد پھر دوبارہ زندہ کیا جاؤں گا؟ میں نے کہا کہ ہاں! اس پر وہ بولا پھر کیا ہے۔ وہیں میرے پاس مال اور اولاد ہو گی اور وہیں میں تمہارا قرض ادا کر دوں گا۔ اس پر قرآن مجید کی یہ آیت نازل ہوئی «أفرأيت الذي كفر بآياتنا وقال لأوتين مالا وولدا‏» ”اے پیغمبر! کیا تو نے اس شخص کو دیکھا جس نے ہماری آیتوں کا انکار کیا، اور کہا کہ مجھے ضرور وہاں مال و اولاد دی جائے گی۔“' WHERE id = 2191;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ( قرض ادا کرنے میں ) مالدار کی طرف سے ٹال مٹول کرنا ظلم ہے۔ اور اگر تم میں سے کسی کا قرض کسی مالدار پر حوالہ دیا جائے تو اسے قبول کرے۔' WHERE id = 2202;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے کہ ابن شہاب نے بیان کیا، اور انہیں عروہ بن زبیر نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے جب سے ہوش سنبھالا تو اپنے والدین کو اسی دین اسلام کا پیروکار پایا۔ اور ابوصالح سلیمان نے بیان کیا کہ مجھ سے عبداللہ بن مبارک نے بیان کیا۔ ان سے یونس نے، اور ان سے زہری نے بیان کیا کہ مجھے عروہ بن زبیر نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے جب ہوش سنبھالا تو اپنے والدین کو دین اسلام کا پیروکار پایا۔ کوئی دن ایسا نہیں گزرتا تھا جب رسول اللہ صلی اللہ علیہ وسلم ہمارے یہاں صبح و شام دونوں وقت تشریف نہ لاتے ہوں۔ پھر جب مسلمانوں کو بہت زیادہ تکلیف ہونے لگی تو ابوبکر رضی اللہ عنہ نے بھی ہجرت حبشہ کا ارادہ کیا۔ جب آپ برک غماد پہنچے تو وہاں آپ کی ملاقات قارہ کے سردار مالک ابن الدغنہ سے ہوئی۔ اس نے پوچھا، ابوبکر! کہاں کا ارادہ ہے؟ ابوبکر رضی اللہ عنہ نے اس کا جواب یہ دیا کہ میری قوم نے مجھے نکال دیا ہے۔ اور اب تو یہی ارادہ ہے کہ اللہ کی زمین میں سیر کروں اور اپنے رب کی عبادت کرتا رہوں۔ اس پر مالک بن الدغنہ نے کہا کہ آپ جیسا انسان ( اپنے وطن سے ) نہیں نکل سکتا اور نہ اسے نکالا جا سکتا ہے۔ کہ آپ تو محتاجوں کے لیے کماتے ہیں، صلہ رحمی کرتے ہیں۔ مجبوروں کا بوجھ اپنے سر لیتے ہیں۔ مہمان نوازی کرتے ہیں۔ اور حادثوں میں حق بات کی مدد کرتے ہیں۔ آپ کو میں امان دیتا ہوں۔ آپ چلئے اور اپنے ہی شہر میں اپنے رب کی عبادت کیجئے۔ چنانچہ ابن الدغنہ اپنے ساتھ ابوبکر رضی اللہ عنہ کو لے کر آیا اور مکہ پہنچ کر کفار قریش کے تمام اشراف کے پاس گیا اور ان سے کہا کہ ابوبکر جیسا نیک آدمی ( اپنے وطن سے ) نہیں نکل سکتا۔ اور نہ اسے نکالا جا سکتا ہے۔ کیا تم ایسے شخص کو بھی نکال دو گے جو محتاجوں کے لیے کماتا ہے اور جو صلہ رحمی کرتا ہے اور جو مجبوروں اور کمزوروں کا بوجھ اپنے سر پر لیتا ہے۔ اور جو مہمان نوازی کرتا ہے اور جو حادثوں میں حق بات کی مدد کرتا ہے۔ چنانچہ قریش نے ابن الدغنہ کی امان کو مان لیا۔ اور ابوبکر رضی اللہ عنہ کو امان دے دی۔ پھر ابن الدغنہ سے کہا کہ ابوبکر کو اس کی تاکید کر دینا کہ اپنے رب کی عبادت اپنے گھر ہی میں کر لیا کریں۔ وہاں جس طرح چاہیں نماز پڑھیں، اور قرآن کی تلاوت کریں، لیکن ہمیں ان چیزوں کی وجہ سے کوئی ایذا نہ دیں اور نہ اس کا اظہار کریں، کیونکہ ہمیں اس کا ڈر ہے کہ کہیں ہمارے بچے اور ہماری عورتیں فتنہ میں نہ پڑ جائیں۔ ابن الدغنہ نے یہ باتیں جب ابوبکر رضی اللہ عنہ کو سنائیں تو آپ اپنے رب کی عبادت گھر کے اندر ہی کرنے لگے۔ نہ نماز میں کسی قسم کا اظہار کرتے اور نہ اپنے گھر کے سوا کسی دوسری جگہ تلاوت کرتے۔ پھر ابوبکر صدیق رضی اللہ عنہ نے کچھ دنوں بعد ایسا کیا کہ آپ نے اپنے گھر کے سامنے نماز کے لیے ایک جگہ بنا لی۔ اب آپ ظاہر ہو کر وہاں نماز پڑھنے لگے۔ اور اسی پر تلاوت قرآن کرنے لگے۔ پس پھر کیا تھا مشرکین کے بچوں اور ان کی عورتوں کا مجمع لگنے لگا۔ سب حیرت اور تعجب کی نگاہوں سے انہیں دیکھتے۔ ابوبکر رضی اللہ عنہ بڑے ہی رونے والے تھے۔ جب قرآن پڑھنے لگتے تو آنسوؤں پر قابو نہ رہتا۔ اس صورت حال سے اکابر مشرکین قریش گھبرائے اور سب نے ابن الدغنہ کو بلا بھیجا۔ ابن الدغنہ ان کے پاس آیا تو ان سب نے کہا کہ ہم نے تو ابوبکر کو اس لیے امان دی تھی کہ وہ اپنے رب کی عبادت گھر کے اندر ہی کریں گے، لیکن وہ تو زیادتی پر اتر آئے اور گھر کے سامنے نماز پڑھنے کی ایک جگہ بنا لی ہے۔ نماز بھی سب کے سامنے ہی پڑھنے لگے ہیں اور تلاوت بھی سب کے سامنے کرنے لگے ہیں۔ ڈر ہمیں اپنی اولاد اور عورتوں کا ہے کہ کہیں وہ فتنہ میں نہ پڑ جائیں۔ اس لیے اب تم ان کے پاس جاؤ۔ اگر وہ اس پر تیار ہو جائیں کہ اپنے رب کی عبادت صرف اپنے گھر کے اندر ہی کریں، پھر تو کوئی بات نہیں، لیکن اگر انہیں اس سے انکار ہو تو تم ان سے کہو کہ وہ تمہاری امان تمہیں واپس کر دیں۔ کیونکہ ہمیں یہ پسند نہیں کہ تمہاری امان کو ہم توڑ دیں۔ لیکن اس طرح انہیں اظہار اور اعلان بھی کرنے نہیں دیں گے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ اس کے بعد ابن الدغنہ ابوبکر صدیق رضی اللہ عنہ کے پاس آیا اور کہا کہ آپ کو معلوم ہے وہ شرط جس پر میرا آپ سے عہد ہوا تھا۔ اب یا تو آپ اس شرط کی حدود میں رہیں یا میری امان مجھے واپس کر دیں۔ کیونکہ یہ میں پسند نہیں کرتا کہ عرب کے کانوں تک یہ بات پہنچے کہ میں نے ایک شخص کو امان دی تھی لیکن وہ امان توڑ دی گئی۔ ابوبکر رضی اللہ عنہ نے فرمایا کہ میں تمہاری امان تمہیں واپس کرتا ہوں میں تو بس اپنے اللہ کی امان سے خوش ہوں۔ رسول اللہ صلی اللہ علیہ وسلم ان دنوں مکہ ہی میں موجود تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے تمہاری ہجرت کا مقام دکھلایا گیا ہے۔ میں نے ایک کھاری نمکین زمین دیکھی ہے۔ جہاں کھجور کے باغات ہیں اور وہ پتھریلے میدانوں کے درمیان میں ہے۔ جب رسول اللہ صلی اللہ علیہ وسلم نے اس کا اظہار فرما دیا تو جن مسلمانوں نے ہجرت کرنی چاہی وہ پہلے ہی مدینہ ہجرت کر کے چلے گئے۔ بلکہ بعض وہ صحابہ بھی جو حبشہ ہجرت کر کے چلے گئے تھے وہ بھی مدینہ آ گئے۔ ابوبکر صدیق رضی اللہ عنہ بھی ہجرت کی تیاریاں کرنے لگے تو رسول اللہ صلی اللہ علیہ وسلم نے ان سے فرمایا، جلدی نہ کرو، امید ہے کہ مجھے بھی جلد ہی اجازت مل جائے گی۔ ابوبکر رضی اللہ عنہ نے پوچھا میرے ماں باپ آپ پر فدا ہوں! کیا آپ کو اس کی امید ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں ضرور! چنانچہ ابوبکر صدیق رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کا انتظار کرنے لگے، تاکہ آپ صلی اللہ علیہ وسلم کے ساتھ ہجرت کریں۔ ان کے پاس دو اونٹ تھے، انہیں چار مہینے تک وہ ببول کے پتے کھلاتے رہے۔' WHERE id = 2212;
UPDATE hadiths SET urdu = 'اور عثمان بن ہیثم ابوعمرو نے بیان کیا کہ ہم سے عوف نے بیان کیا، ان سے محمد بن سیرین نے، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے رمضان کی زکوٰۃ کی حفاظت پر مقرر فرمایا۔ ( رات میں ) ایک شخص اچانک میرے پاس آیا اور غلہ میں سے لپ بھربھر کر اٹھانے لگا میں نے اسے پکڑ لیا اور کہا کہ قسم اللہ کی! میں تجھے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لے چلوں گا۔ اس پر اس نے کہا کہ اللہ کی قسم! میں بہت محتاج ہوں۔ میرے بال بچے ہیں اور میں سخت ضرورت مند ہوں۔ ابوہریرہ رضی اللہ عنہ نے کہا ( اس کے اظہار معذرت پر ) میں نے اسے چھوڑ دیا۔ صبح ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے پوچھا، اے ابوہریرہ! گذشتہ رات تمہارے قیدی نے کیا کیا تھا؟ میں نے کہا یا رسول اللہ! اس نے سخت ضرورت اور بال بچوں کا رونا رویا، اس لیے مجھے اس پر رحم آ گیا۔ اور میں نے اسے چھوڑ دیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ تم سے جھوٹ بول کر گیا ہے۔ اور وہ پھر آئے گا۔ رسول اللہ صلی اللہ علیہ وسلم کے اس فرمانے کی وجہ سے مجھ کو یقین تھا کہ وہ پھر ضرور آئے گا۔ اس لیے میں اس کی تاک میں لگا رہا۔ اور جب وہ دوسری رات آ کے پھر غلہ اٹھانے لگا تو میں نے اسے پھر پکڑا اور کہا کہ تجھے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر کروں گا، لیکن اب بھی اس کی وہی التجا تھی کہ مجھے چھوڑ دے، میں محتاج ہوں۔ بال بچوں کا بوجھ میرے سر پر ہے۔ اب میں کبھی نہ آؤں گا۔ مجھے رحم آ گیا اور میں نے اسے پھر چھوڑ دیا۔ صبح ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اے ابوہریرہ! تمہارے قیدی نے کیا کیا؟ میں نے کہا یا رسول اللہ! اس نے پھر اسی سخت ضرورت اور بال بچوں کا رونا رویا۔ جس پر مجھے رحم آ گیا۔ اس لیے میں نے اسے چھوڑ دیا۔ آپ صلی اللہ علیہ وسلم نے اس مرتبہ بھی یہی فرمایا کہ وہ تم سے جھوٹ بول کر گیا ہے اور وہ پھر آئے گا۔ تیسری مرتبہ میں پھر اس کے انتظار میں تھا کہ اس نے پھر تیسری رات آ کر غلہ اٹھانا شروع کیا، تو میں نے اسے پکڑ لیا، اور کہا کہ تجھے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں پہنچانا اب ضروری ہو گیا ہے۔ یہ تیسرا موقع ہے۔ ہر مرتبہ تم یقین دلاتے رہے کہ پھر نہیں آؤ گے۔ لیکن تم باز نہیں آئے۔ اس نے کہا کہ اس مرتبہ مجھے چھوڑ دے تو میں تمہیں ایسے چند کلمات سکھا دوں گا جس سے اللہ تعالیٰ تمہیں فائدہ پہنچائے گا۔ میں نے پوچھا وہ کلمات کیا ہیں؟ اس نے کہا، جب تم اپنے بستر پر لیٹنے لگو تو آیت الکرسی «الله لا إله إلا هو الحي القيوم» پوری پڑھ لیا کرو۔ ایک نگراں فرشتہ اللہ تعالیٰ کی طرف سے برابر تمہاری حفاظت کرتا رہے گا۔ اور صبح تک شیطان تمہارے پاس کبھی نہیں آ سکے گا۔ اس مرتبہ بھی پھر میں نے اسے چھوڑ دیا۔ صبح ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے دریافت فرمایا، گذشتہ رات تمہارے قیدی نے تم سے کیا معاملہ کیا؟ میں نے عرض کیا یا رسول اللہ! اس نے مجھے چند کلمات سکھائے اور یقین دلایا کہ اللہ تعالیٰ مجھے اس سے فائدہ پہنچائے گا۔ اس لیے میں نے اسے چھوڑ دیا۔ آپ نے دریافت کیا کہ وہ کلمات کیا ہیں؟ میں نے عرض کیا کہ اس نے بتایا تھا کہ جب بستر پر لیٹو تو آیت الکرسی پڑھ لو، شروع «الله لا إله إلا هو الحي القيوم» سے آخر تک۔ اس نے مجھ سے یہ بھی کہا کہ اللہ تعالیٰ کی طرف سے تم پر ( اس کے پڑھنے سے ) ایک نگراں فرشتہ مقرر رہے گا۔ اور صبح تک شیطان تمہارے قریب بھی نہیں آ سکے گا۔ صحابہ خیر کو سب سے آگے بڑھ کر لینے والے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے ( ان کی یہ بات سن کر ) فرمایا کہ اگرچہ وہ جھوٹا تھا۔ لیکن تم سے یہ بات سچ کہہ گیا ہے۔ اے ابوہریرہ! تم کو یہ بھی معلوم ہے کہ تین راتوں سے تمہارا معاملہ کس سے تھا؟ انہوں نے کہا نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ شیطان تھا۔' WHERE id = 2224;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہوں نے کہا کہ ہمیں یزید بن خصیفہ نے، ان سے سائب بن یزید نے بیان کیا کہ سفیان بن زہیر نے ازدشنوہ قبیلے کے ایک بزرگ سے سنا جو نبی کریم صلی اللہ علیہ وسلم کے صحابی تھے۔ انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا تھا کہ جس نے کتا پالا، جو نہ کھیتی کے لیے ہے اور نہ مویشی کے لیے، تو اس کی نیکیوں سے روزانہ ایک قیراط کم ہو جاتا ہے۔ میں نے پوچھا کہ کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے یہ سنا ہے؟ انہوں نے کہا ہاں ہاں! اس مسجد کے رب کی قسم! ( میں نے ضرور آپ صلی اللہ علیہ وسلم سے یہ سنا ہے ) ۔' WHERE id = 2235;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، ان سے ابوضمرہ نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، تین آدمی کہیں چلے جا رہے تھے کہ بارش نے ان کو آ لیا۔ تینوں نے ایک پہاڑ کی غار میں پناہ لے لی، اچانک اوپر سے ایک چٹان غار کے سامنے آ گری، اور انہیں ( غار کے اندر ) بالکل بند کر دیا۔ اب ان میں سے بعض لوگوں نے کہا کہ تم لوگ اب اپنے ایسے کاموں کو یاد کرو۔ جنہیں تم نے خالص اللہ تعالیٰ کے لیے کیا ہو اور اسی کام کا واسطہ دے کر اللہ تعالیٰ سے دعا کرو۔ ممکن ہے اس طرح اللہ تعالیٰ تمہاری اس مصیبت کو ٹال دے، چنانچہ ایک شخص نے دعا شروع کی۔ اے اللہ! میرے والدین بہت بوڑھے تھے اور میرے چھوٹے چھوٹے بچے بھی تھے۔ میں ان کے لیے ( جانور ) چرایا کرتا تھا۔ پھر جب واپس ہوتا تو دودھ دوہتا۔ سب سے پہلے، اپنی اولاد سے بھی پہلے، میں والدین ہی کو دودھ پلاتا تھا۔ ایک دن دیر ہو گئی اور رات گئے گھر واپس آیا، اس وقت میرے ماں باپ سو چکے تھے۔ میں نے معمول کے مطابق دودھ دوہا اور ( اس کا پیالہ لے کر ) میں ان کے سرہانے کھڑا ہو گیا۔ میں نے پسند نہیں کیا کہ انہیں جگاؤں۔ لیکن اپنے بچوں کو بھی ( والدین سے پہلے ) پلانا مجھے پسند نہیں تھا۔ بچے صبح تک میرے قدموں پر پڑے تڑپتے رہے۔ پس اگر تیرے نزدیک بھی میرا یہ عمل صرف تیری رضا کے لیے تھا تو ( غار سے اس چٹان کو ہٹا کر ) ہمارے لیے اتنا راستہ بنا دے کہ آسمان نظر آ سکے۔ چنانچہ اللہ تعالیٰ نے راستہ بنا دیا اور انہیں آسمان نظر آنے لگا۔ دوسرے نے کہا اے اللہ! میری ایک چچازاد بہن تھی۔ مرد عورتوں سے جس طرح کی انتہائی محبت کر سکتے ہیں، مجھے اس سے اتنی ہی محبت تھی۔ میں نے اسے اپنے پاس بلانا چاہا لیکن وہ سو دینار دینے کی صورت راضی ہوئی۔ میں نے کوشش کی اور وہ رقم جمع کی۔ پھر جب میں اس کے دونوں پاؤں کے درمیان بیٹھ گیا، تو اس نے مجھ سے کہا، اے اللہ کے بندے! اللہ سے ڈر اور اس کی مہر کو حق کے بغیر نہ توڑ۔ میں یہ سنتے ہی دور ہو گیا، اگر میرا یہ عمل تیرے علم میں بھی تیری رضا ہی کے لیے تھا تو ( اس غار سے ) پتھر کو ہٹا دے۔ پس غار کا منہ کچھ اور کھلا۔ اب تیسرا بولا کہ اے اللہ! میں نے ایک مزدور تین فرق چاول کی مزدوری پر مقرر کیا تھا جب اس نے اپنا کام پورا کر لیا تو مجھ سے کہا کہ اب میری مزدوری مجھے دیدے۔ میں نے پیش کر دی لیکن اس وقت وہ انکار کر بیٹھا۔ پھر میں برابر اس کی اجرت سے کاشت کرتا رہا اور اس کے نتیجہ میں بڑھنے سے بیل اور چرواہے میرے پاس جمع ہو گئے۔ اب وہ شخص آیا اور کہنے لگا کہ اللہ سے ڈر! میں نے کہا کہ بیل اور اس کے چرواہے کے پاس جا اور اسے لے لے۔ اس نے کہا اللہ سے ڈر! اور مجھ سے مذاق نہ کر، میں نے کہا کہ مذاق نہیں کر رہا ہوں۔ ( یہ سب تیرا ہی ہے ) اب تم اسے لے جاؤ۔ پس اس نے ان سب پر قبضہ کر لیا۔ الہٰی! اگر تیرے علم میں بھی میں نے یہ کام تیری خوشنودی ہی کے لیے کیا تھا تو تو اس غار کو کھول دے۔ اب وہ غار پورا کھل چکا تھا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ ابن عقبہ نے نافع سے ( اپنی روایت میں «فبغيت‏» کے بجائے ) «فسعيت‏» نقل کیا ہے۔' WHERE id = 2245;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم سلمہ بن دینار نے، ان سے سہل بن سعد رضی اللہ عنہ نے کہ جمعہ کے دن ہمیں بہت خوشی ( اس بات کی ) ہوتی تھی کہ ہماری ایک بوڑھی عورت تھیں جو اس چقندر کو اکھاڑ لاتیں جسے ہم اپنے باغ کی مینڈوں پر بو دیا کرتے تھے۔ وہ ان کو اپنی ہانڈی میں پکاتیں اور اس میں تھوڑے سے جَو بھی ڈال دیتیں۔ ابوحازم نے کہا میں نہیں جانتا کہ سہل نے یوں کہا نہ اس میں چربی ہوتی نہ چکنائی۔ پھر جب ہم جمعہ کی نماز پڑھ لیتے تو ان کی خدمت میں حاضر ہوتے۔ وہ اپنا پکوان ہمارے سامنے کر دیتیں۔ اور اس لیے ہمیں جمعہ کے دن کی خوشی ہوتی تھی۔ اور ہم دوپہر کا کھانا اور قیلولہ جمعہ کے بعد کیا کرتے تھے۔' WHERE id = 2258;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں سمی نے، انہیں ابوصالح نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، ایک شخص جا رہا تھا کہ اسے سخت پیاس لگی، اس نے ایک کنویں میں اتر کر پانی پیا۔ پھر باہر آیا تو دیکھا کہ ایک کتا ہانپ رہا ہے اور پیاس کی وجہ سے کیچڑ چاٹ رہا ہے۔ اس نے ( اپنے دل میں ) کہا، یہ بھی اس وقت ایسی ہی پیاس میں مبتلا ہے جیسے ابھی مجھے لگی ہوئی تھی۔ ( چنانچہ وہ پھر کنویں میں اترا اور ) اپنے چمڑے کے موزے کو ( پانی سے ) بھر کر اسے اپنے منہ سے پکڑے ہوئے اوپر آیا، اور کتے کو پانی پلایا۔ اللہ تعالیٰ نے اس کے اس کام کو قبول کیا اور اس کی مغفرت فرمائی۔ صحابہ نے عرض کیا یا رسول اللہ! کیا ہمیں چوپاؤں پر بھی اجر ملے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا، ہر جاندار میں ثواب ہے۔ اس روایت کی متابعت حماد بن سلمہ اور ربیع بن مسلم نے محمد بن زیاد سے کی ہے۔' WHERE id = 2270;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، ان سے ہاشم نے، ان سے ان کے والد نے اور ان سے زبیر بن عوام نے رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اگر کوئی شخص رسی لے کر لکڑیوں کا گھٹا لائے، پھر اسے بیچے اور اس طرح اللہ تعالیٰ اس کی آبرو محفوظ رکھے تو یہ اس سے بہتر ہے کہ وہ لوگوں کے سامنے ہاتھ پھیلائے اور ( بھیک ) اسے دی جائے یا نہ دی جائے۔ اس کی بھی کوئی امید نہ ہو۔' WHERE id = 2280;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا، کہا کہ ہم کو جریر نے خبر دی، انہیں مغیرہ نے، انہیں شعبی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک غزوہ میں شریک تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، اپنے اونٹ کے بارے میں تمہاری کیا رائے ہے۔ کیا تم اسے بیچو گے؟ میں نے کہا ہاں، چنانچہ اونٹ میں نے آپ صلی اللہ علیہ وسلم کو بیچ دیا۔ اور جب آپ صلی اللہ علیہ وسلم مدینہ پہنچے۔ تو صبح اونٹ کو لے کر میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو گیا۔ آپ صلی اللہ علیہ وسلم نے مجھے اس کی قیمت ادا کر دی۔' WHERE id = 2291;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی، انہیں زہری نے بیان کیا، ان سے کعب بن مالک نے بیان کیا، اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے خبر دی کہ ان کے والد ( عبداللہ رضی اللہ عنہ ) احد کے دن شہید کر دیئے گئے تھے۔ ان پر قرض چلا آ رہا تھا۔ قرض خواہوں نے اپنے حق کے مطالبے میں سختی اختیار کی تو میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آپ صلی اللہ علیہ وسلم نے ان سے دریافت فرما لیا کہ وہ میرے باغ کی کھجور لے لیں۔ اور میرے والد کو معاف کر دیں۔ لیکن قرض خواہوں نے اس سے انکار کیا تو نبی کریم صلی اللہ علیہ وسلم نے انہیں میرے باغ کا میوہ نہیں دیا۔ اور فرمایا کہ ہم صبح کو تمہارے باغ میں آئیں گے۔ چنانچہ جب صبح ہوئی تو آپ صلی اللہ علیہ وسلم ہمارے باغ میں تشریف لائے۔ آپ صلی اللہ علیہ وسلم درختوں میں پھرتے رہے۔ اور اس کے میوے میں برکت کی دعا فرماتے رہے۔ پھر میں نے کھجور توڑی اور ان کا تمام قرض ادا کرنے کے بعد بھی کھجور باقی بچ گئی۔' WHERE id = 2301;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا، انہوں نے عمر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے ایک شخص نے عرض کیا کہ خرید و فروخت میں مجھے دھوکا دے دیا جاتا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب خرید و فروخت کیا کرو، تو کہہ دیا کر کہ کوئی دھوکا نہ ہو۔ چنانچہ پھر وہ شخص اسی طرح کہا کرتا تھا۔' WHERE id = 2312;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عروہ بن زبیر رضی اللہ عنہ نے، انہیں عبدالرحمٰن بن عبدالقاری نے کہ انہوں نے عمر بن خطاب رضی اللہ عنہ سے سنا کہ وہ بیان کرتے تھے کہ میں نے ہشام بن حکیم بن حزام رضی اللہ عنہ کو سورۃ الفرقان ایک دفعہ اس قرآت سے پڑھتے سنا جو اس کے خلاف تھی جو میں پڑھتا تھا۔ حالانکہ میری قرآت خود رسول اللہ صلی اللہ علیہ وسلم نے مجھے سکھائی تھی۔ قریب تھا کہ میں فوراً ہی ان پر کچھ کر بیٹھوں، لیکن میں نے انہیں مہلت دی کہ وہ ( نماز سے ) فارغ ہو لیں۔ اس کے بعد میں نے ان کے گلے میں چادر ڈال کر ان کو گھسیٹا اور رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر کیا۔ میں نے آپ صلی اللہ علیہ وسلم سے کہا کہ میں نے انہیں اس قرآت کے خلاف پڑھتے سنا ہے جو آپ نے مجھے سکھائی ہے۔ آپ صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ پہلے انہیں چھوڑ دے۔ پھر ان سے فرمایا کہ اچھا اب تم قرآت سناؤ۔ انہوں نے وہی اپنی قرآت سنائی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسی طرح نازل ہوئی تھی۔ اس کے بعد مجھ سے آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب تم بھی پڑھو، میں نے بھی پڑھ کر سنایا۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اسی طرح نازل ہوئی۔ قرآن سات قراتوں میں نازل ہوا ہے۔ تم کو جس میں آسانی ہو اسی طرح سے پڑھ لیا کرو۔' WHERE id = 2323;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ربیعہ بن ابی عبدالرحمٰن نے، انہیں منبعث کے غلام یزید نے اور ان سے زید بن خالد رضی اللہ عنہ نے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ صلی اللہ علیہ وسلم سے لقطہٰ کے بارے میں سوال کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کے برتن کی بناوٹ اور اس کے بندھن کو ذہن میں یاد رکھ کر ایک سال تک اس کا اعلان کرتا رہ۔ اگر مالک مل جائے ( تو اسے دیدے ) ورنہ اپنی ضرورت میں خرچ کر۔ انہوں نے پوچھا اور اگر راستہ بھولی ہوئی بکری ملے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ تمہاری ہو گی یا تمہارے بھائی کی ہو گی۔ ورنہ پھر بھیڑیا اسے اٹھا لے جائے گا صحابی نے پوچھا اور اونٹ جو راستہ بھول جائے؟ آپ صلی اللہ علیہ وسلم نے فرمایا تمہیں اس سے کیا مطلب؟ اس کے ساتھ خود اس کا مشکیزہ ہے، اس کے کھر ہیں، پانی پر وہ خود ہی پہنچ جائے گا اور خود ہی درخت کے پتے کھا لے گا۔ اور اس طرح کسی نہ کسی دن اس کا مالک اسے خود پا لے گا۔' WHERE id = 2333;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا کہ ہم کو نضر نے خبر دی، کہا کہ ہم کو اسرائیل نے خبر دی ابواسحاق سے کہ مجھے براء بن عازب رضی اللہ عنہ نے ابوبکر رضی اللہ عنہ سے خبر دی (دوسری سند) ہم سے عبداللہ بن رجاء نے بیان کیا، کہا کہ ہم سے اسرائیل نے بیان کیا ابواسحاق سے، اور انہوں نے ابوبکر رضی اللہ عنہ سے کہ ( ہجرت کر کے مدینہ جاتے وقت ) میں نے تلاش کیا تو مجھے ایک چرواہا ملا جو اپنی بکریاں چرا رہا تھا۔ میں نے اس سے پوچھا کہ تم کس کے چرواہے ہو؟ اس نے کہا کہ قریش کے ایک شخص کا۔ اس نے قریشی کا نام بھی بتایا، جسے میں جانتا تھا۔ میں نے اس سے پوچھا کیا تمہارے ریوڑ کی بکریوں میں دودھ بھی ہے؟ اس نے کہا کہ ہاں! میں نے اس سے کہا کیا تم میرے لیے دودھ دوہ لو گے؟ اس نے کہا، ہاں ضرور! چنانچہ میں نے اس سے دوہنے کے لیے کہا۔ وہ اپنے ریوڑ سے ایک بکری پکڑ لایا۔ پھر میں نے اس سے بکری کا تھن گرد و غبار سے صاف کرنے کے لیے کہا۔ پھر میں نے اس سے اپنا ہاتھ صاف کرنے کے لیے کہا۔ اس نے ویسا ہی کیا۔ ایک ہاتھ کو دوسرے پر مار کر صاف کر لیا۔ اور ایک پیالہ دودھ دوہا۔ رسول اللہ صلی اللہ علیہ وسلم کے لیے میں نے ایک برتن ساتھ لیا تھا۔ جس کے منہ پر کپڑا بندھا ہوا تھا۔ میں نے پانی دودھ پر بہایا۔ جس سے اس کا نچلا حصہ ٹھنڈا ہو گیا پھر دودھ لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ اور عرض کیا کہ دودھ حاضر ہے۔ یا رسول اللہ! پی لیجئے، آپ صلی اللہ علیہ وسلم نے اسے پیا، یہاں تک کہ میں خوش ہو گیا۔' WHERE id = 2344;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے ابن ابی ذئب نے بیان کیا، انہوں نے کہا ہم سے سعید مقبری نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اگر کسی شخص کا ظلم کسی دوسرے کی عزت پر ہو یا کسی طریقہ ( سے ظلم کیا ہو ) تو آج ہی، اس دن کے آنے سے پہلے معاف کرا لے جس دن نہ دینار ہوں گے، نہ درہم، بلکہ اگر اس کا کوئی نیک عمل ہو گا تو اس کے ظلم کے بدلے میں وہی لے لیا جائے گا اور اگر کوئی نیک عمل اس کے پاس نہیں ہو گا تو اس کے ( مظلوم ) ساتھی کی برائیاں اس پر ڈال دی جائیں گی۔ ابوعبدللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ اسماعیل بن ابی اویس نے کہا سعید مقبری کا نام مقبری اس لیے ہوا کہ قبرستان کے قریب انہوں نے قیام کیا تھا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ سعید مقبری ہی بنی لیث کے غلام ہیں۔ پورا نام سعید بن ابی سعید ہے اور ( ان کے والد ) ابوسعید کا نام کیسان ہے۔' WHERE id = 2354;
UPDATE hadiths SET urdu = 'ہم سے بشر بن خالد نے بیان کیا کہا ہم کو محمد نے خبر دی شعبہ سے، انہیں سلیمان نے، انہیں عبداللہ بن مرہ نے، انہیں مسروق نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا چار خصلتیں ایسی ہیں کہ جس شخص میں بھی وہ ہوں گی، وہ منافق ہو گا۔ یا ان چار میں سے اگر ایک خصلت بھی اس میں ہے تو اس میں نفاق کی ایک خصلت ہے۔ یہاں تک کہ وہ اسے چھوڑ دے۔ جب بولے تو جھوٹ بولے، جب وعدہ کرے تو پورا نہ کرے، جب معاہدہ کرے تو بے وفائی کرے، اور جب جھگڑے تو بد زبانی پر اتر آئے۔' WHERE id = 2364;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، کہا ہم سے مروان بن معاویہ فزاری نے بیان کیا، ان سے حمید طویل نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی ازواج کے پاس ایک مہینہ تک نہ جانے کی قسم کھائی تھی، اور ( ایلاء کے واقعہ سے پہلے 5 ھ میں ) آپ صلی اللہ علیہ وسلم کے قدم مبارک میں موچ آ گئی تھی۔ اور آپ صلی اللہ علیہ وسلم اپنے بالا خانہ میں قیام پذیر ہوئے تھے۔ ( ایلاء کے موقع پر ) عمر رضی اللہ عنہ آئے اور عرض کیا، یا رسول اللہ! کیا آپ نے اپنی بیویوں کو طلاق دے دی ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ البتہ ایک مہینے کے لیے ان کے پاس نہ جانے کی قسم کھا لی ہے۔ چنانچہ آپ صلی اللہ علیہ وسلم انتیس دن تک بیویوں کے پاس نہیں گئے ( اور انتیس تاریخ کو ہی چاند ہو گیا تھا ) اس لیے آپ صلی اللہ علیہ وسلم بالاخانے سے اترے اور بیویوں کے پاس گئے۔' WHERE id = 2374;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے انس بن عیاض نے بیان کیا، ان سے عبیداللہ عمری نے، ان سے عبدالرحمٰن بن قاسم نے، ان سے ان کے والد قاسم نے اور ان سے عائشہ رضی اللہ عنہا نے کہ انہوں نے اپنے حجرے کے سائبان پر ایک پردہ لٹکا دیا جس میں تصویریں بنی ہوئی تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے ( جب دیکھا تو ) اسے اتار کر پھاڑ ڈالا۔ ( عائشہ رضی اللہ عنہا نے بیان کیا کہ ) پھر میں نے اس پردے سے دو گدے بنا ڈالے۔ وہ دونوں گدے گھر میں رہتے تھے اور نبی کریم صلی اللہ علیہ وسلم ان پر بیٹھا کرتے تھے۔' WHERE id = 2384;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا ہم سے سفیان ثوری نے بیان کیا، کہا ہم سے جبلہ بن سحیم نے بیان کیا، انہوں نے کہا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا۔ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے اس سے منع فرمایا تھا کہ کوئی شخص اپنے ساتھیوں کی اجازت کے بغیر ( دستر خوان پر ) دو دو کھجور ایک ساتھ ملا کر کھائے۔' WHERE id = 2394;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے جویریہ بن اسماء نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جس نے کسی ساجھے کے غلام کا اپنا حصہ آزاد کر دیا تو اس کے لیے ضروری ہے کہ اگر غلام کی انصاف کے موافق قیمت کے برابر اس کے پاس مال ہو تو وہ سارا غلام آزاد کرا دے۔ اس طرح دوسرے ساجھیوں کو ان کے حصے کی قیمت ادا کر دی جائے اور اس آزاد کیے ہوئے غلام کا پیچھا چھوڑ دیا جائے۔' WHERE id = 2406;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا کہ ہم سے عاصم بن محمد نے بیان کیا، انہوں نے کہا کہ مجھ سے واقد بن محمد نے بیان کیا، انہوں نے کہا کہ مجھ سے علی بن حسین کے ساتھی سعید بن مرجانہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جس شخص نے بھی کسی مسلمان ( غلام ) کو آزاد کیا تو اللہ تعالیٰ اس غلام کے جسم کے ہر عضو کی آزادی کے بدلے اس شخص کے جسم کے بھی ایک ایک عضو کو دوزخ سے آزاد کرے گا۔ سعید بن مرجانہ نے بیان کیا کہ پھر میں علی بن حسین ( زین العابدین رحمہ اللہ ) کے یہاں گیا ( اور ان سے حدیث بیان کی ) وہ اپنے ایک غلام کی طرف متوجہ ہوئے۔ جس کی عبداللہ بن جعفر دس ہزار درہم یا ایک ہزار دینار قیمت دے رہے تھے اور آپ نے اسے آزاد کر دیا۔' WHERE id = 2418;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے سعید بن ابی عروبہ نے، ان سے قتادہ نے ان سے نضر بن انس نے، ان سے بشیر بن نہیک نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے کسی ساجھے کے غلام کا اپنا حصہ آزاد کیا تو اس کی پوری آزادی اسی کے ذمہ ہے۔ بشرطیکہ اس کے پاس مال ہو۔ ورنہ غلام کی قیمت لگائی جائے گی اور ( اس سے اپنے بقیہ حصوں کی قیمت ادا کرنے کی ) کوشش کے لیے کہا جائے گا۔ لیکن اس پر کوئی سختی نہ کی جائے گی۔“ سعید کے ساتھ اس حدیث کو حجاج بن حجاج، ابان اور موسیٰ بن خلف نے بھی قتادہ سے روایت کیا۔ شعبہ نے اسے مختصر کر دیا ہے۔' WHERE id = 2428;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم بن عقبہ نے بیان کیا، ان سے موسیٰ نے، ان سے ابن شہاب نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ انصار کے بعض لوگوں نے رسول اللہ صلی اللہ علیہ وسلم سے ملاقات کی اور اجازت چاہی اور آ کر عرض کیا کہ آپ ہمیں اس کی اجازت دے دیجئیے کہ ہم اپنے بھانجے عباس کا فدیہ معاف کر دیں آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں ایک درہم بھی نہ چھوڑو۔' WHERE id = 2438;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، انہوں نے اعمش سے، ان سے ابوصالح نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کتنا اچھا ہے کسی کا وہ غلام جو اپنے رب کی عبادت تمام حسن و خوبی کے ساتھ بجا لائے اور اپنے مالک کی خیر خواہی بھی کرتا رہے۔“' WHERE id = 2449;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے لیث نے بیان کیا ابن شہاب سے، انہوں نے عروہ سے اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ بریرہ رضی اللہ عنہا ان کے پاس اپنے معاملہ مکاتبت میں مدد لینے آئیں، ابھی انہوں نے کچھ بھی ادا نہیں کیا تھا۔ عائشہ رضی اللہ عنہا نے ان سے کہا کہ تو اپنے مالکوں کے پاس جا، اگر وہ یہ پسند کریں کہ تیرے معاملہ مکاتبت کی پوری رقم میں ادا کر دوں اور تمہاری ولاء میرے ساتھ قائم ہو تو میں ایسا کر سکتی ہوں۔ بریرہ رضی اللہ عنہا نے یہ صورت اپنے مالکوں کے سامنے رکھی لیکن انہوں نے انکار کیا اور کہا کہ اگر وہ ( عائشہ رضی اللہ عنہا ) تمہارے ساتھ ثواب کی نیت سے یہ کام کرنا چاہتی ہیں تو انہیں اختیار ہے، لیکن تمہاری ولاء تو ہمارے ہی ساتھ رہے گی۔ عائشہ رضی اللہ عنہا نے اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو خرید کر انہیں آزاد کر دے۔ ولاء تو اسی کے ساتھ ہوتی ہے جو آزاد کر دے۔ راوی نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم نے لوگوں سے خطاب کیا اور فرمایا کہ کچھ لوگوں کو کیا ہو گیا ہے کہ وہ ایسی شرطیں لگاتے ہیں جن کی کوئی اصل ( دلیل، بنیاد ) کتاب اللہ میں نہیں ہے۔ پس جو بھی کوئی ایسی شرط لگائے جس کی اصل ( دلیل، بنیاد ) کتاب اللہ میں نہیں ہے تو اس کو ایسی شرطیں لگانا لائق نہیں خواہ وہ ایسی سو شرطیں کیوں نہ لگا لے۔ اللہ تعالیٰ کی شرط ہی سب سے زیادہ معقول اور مضبوط ہے۔' WHERE id = 2460;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان بن بلال نے، کہا کہ مجھ سے ابوطوالہ نے جن کا نام عبداللہ بن عبدالرحمٰن تھا کہ میں نے انس رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ ( ایک مرتبہ ) رسول اللہ صلی اللہ علیہ وسلم ہمارے اسی گھر میں تشریف لائے اور پانی طلب فرمایا۔ ہمارے پاس ایک بکری تھی، اسے ہم نے دوہا۔ پھر میں نے اسی کنویں کا پانی ملا کر آپ صلی اللہ علیہ وسلم کی خدمت میں ( لسی بنا کر ) پیش کیا، ابوبکر رضی اللہ عنہ آپ صلی اللہ علیہ وسلم کی بائیں طرف بیٹھے ہوئے تھے اور عمر رضی اللہ عنہ سامنے تھے اور ایک دیہاتی آپ صلی اللہ علیہ وسلم کے دائیں طرف تھا۔ جب آپ صلی اللہ علیہ وسلم پی کر فارغ ہوئے تو ( پیالے میں کچھ دودھ بچ گیا تھا اس لیے ) عمر رضی اللہ عنہ نے عرض کیا کہ یہ ابوبکر رضی اللہ عنہ ہیں۔ لیکن آپ صلی اللہ علیہ وسلم نے اسے دیہاتی کو عطا فرمایا۔ ( کیونکہ وہ دائیں طرف تھا ) پھر آپ صلی اللہ علیہ وسلم نے فرمایا، دائیں طرف بیٹھنے والے، دائیں طرف بیٹھنے والے ہی حق رکھتے ہیں۔ پس خبردار دائیں طرف ہی سے شروع کیا کرو۔ انس رضی اللہ عنہ نے کہا کہ یہی سنت ہے، یہی سنت ہے، تین مرتبہ ( آپ نے اس بات کو دہرایا ) ۔' WHERE id = 2470;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے میرے بھائی عبدالحمید بن ابی اویس نے، ان سے سلیمان نے ہشام بن عروہ سے، ان سے ان کے باپ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم کی ازواج دو گروہ میں تھیں۔ ایک میں عائشہ، حفصہ، صفیہ اور سودہ رضوان اللہ علیہن اور دوسری میں ام سلمہ اور بقیہ تمام ازواج مطہرات رضوان اللہ علیہن تھیں۔ مسلمانوں کو رسول اللہ صلی اللہ علیہ وسلم کی عائشہ رضی اللہ عنہا کے ساتھ محبت کا علم تھا اس لیے جب کسی کے پاس کوئی تحفہ ہوتا اور وہ اسے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں پیش کرنا چاہتا تو انتظار کرتا۔ جب رسول اللہ صلی اللہ علیہ وسلم کی عائشہ رضی اللہ عنہا کے گھر کی باری ہوتی تو تحفہ دینے والے صاحب اپنا تحفہ آپ صلی اللہ علیہ وسلم کی خدمت میں بھیجتے۔ اس پر ام سلمہ رضی اللہ عنہا کی جماعت کی ازواج مطہرات نے آپس میں مشورہ کیا اور ام سلمہ رضی اللہ عنہا سے کہا کہ وہ رسول اللہ صلی اللہ علیہ وسلم سے بات کریں تاکہ آپ صلی اللہ علیہ وسلم لوگوں سے فرما دیں کہ جسے آپ کے یہاں تحفہ بھیجنا ہو وہ جہاں بھی آپ صلی اللہ علیہ وسلم ہوں وہیں بھیجا کرے۔ چنانچہ ان ازواج کے مشورہ کے مطابق انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا لیکن آپ صلی اللہ علیہ وسلم نے انہیں کوئی جواب نہیں دیا۔ پھر ان خواتین نے پوچھا تو انہوں نے بتا دیا کہ مجھے آپ صلی اللہ علیہ وسلم نے کوئی جواب نہیں دیا۔ ازواج مطہرات نے کہا کہ پھر ایک مرتبہ کہو۔ انہوں نے بیان کیا پھر جب آپ کی باری آئی تو دوبارہ انہوں نے آپ صلی اللہ علیہ وسلم سے عرض کیا۔ اس مرتبہ بھی آپ صلی اللہ علیہ وسلم نے مجھے اس کا کوئی جواب ہی نہیں دیا۔ ازواج نے اس مرتبہ ان سے کہا کہ آپ صلی اللہ علیہ وسلم کو اس مسئلہ پر بلواؤ تو سہی۔ جب ان کی باری آئی تو انہوں نے پھر کہا۔ آپ صلی اللہ علیہ وسلم نے اس مرتبہ فرمایا۔ عائشہ کے بارے میں مجھے تکلیف نہ دو۔ عائشہ کے سوا اپنی بیویوں میں سے کسی کے کپڑے میں بھی مجھ پر وحی نازل نہیں ہوتی ہے۔ عائشہ رضی اللہ عنہا نے کہا کہ آپ صلی اللہ علیہ وسلم کے اس ارشاد پر انہوں نے عرض کیا، آپ کو ایذا پہنچانے کی وجہ سے میں اللہ کے حضور میں توبہ کرتی ہوں۔ پھر ان ازواج مطہرات نے رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی فاطمہ رضی اللہ عنہا کو بلایا اور ان کے ذریعہ آپ صلی اللہ علیہ وسلم کی خدمت میں یہ کہلوایا کہ آپ کی ازواج ابوبکر رضی اللہ عنہ کی بیٹی کے بارے میں اللہ کے لیے آپ سے انصاف چاہتی ہیں۔ چنانچہ انہوں نے بھی آپ صلی اللہ علیہ وسلم سے بات چیت کی۔ آپ صلی اللہ علیہ وسلم نے فرمایا، میری بیٹی! کیا تم وہ پسند نہیں کرتی جو میں پسند کروں؟ انہوں نے جواب دیا کہ کیوں نہیں، اس کے بعد وہ واپس آ گئیں اور ازواج کو اطلاع دی۔ انہوں نے ان سے پھر دوبارہ خدمت نبوی میں جانے کے لیے کہا۔ لیکن آپ نے دوبارہ جانے سے انکار کیا تو انہوں نے زینب بنت جحش رضی اللہ عنہا کو بھیجا۔ وہ خدمت نبوی میں حاضر ہوئیں تو انہوں نے سخت گفتگو کی اور کہا کہ آپ کی ازواج ابوقحافہ کی بیٹی کے بارے میں آپ سے اللہ کے لیے انصاف مانگتی ہیں اور ان کی آواز اونچی ہو گئی۔ عائشہ رضی اللہ عنہا وہیں بیٹھی ہوئی تھیں۔ انہوں نے ( ان کے منہ پر ) انہیں بھی برا بھلا کہا۔ رسول اللہ صلی اللہ علیہ وسلم عائشہ رضی اللہ عنہا کی طرف دیکھنے لگے کہ وہ کچھ بولتی ہیں یا نہیں۔ راوی نے بیان کیا کہ عائشہ رضی اللہ عنہا بھی بول پڑیں اور زینب رضی اللہ عنہا کی باتوں کا جواب دینے لگیں اور آخر انہیں خاموش کر دیا۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا کی طرف دیکھ کر فرمایا کہ یہ ابوبکر کی بیٹی ہے۔ امام بخاری رحمہ اللہ نے کہا کہ آخر کلام فاطمہ رضی اللہ عنہا کے واقعہ سے متعلق ہشام بن عروہ نے ایک اور شخص سے بیان کیا ہے۔ انہوں نے زہری سے روایت کی اور انہوں نے محمد بن عبدالرحمٰن سے اور ابومروان نے بیان کیا کہ ہشام سے اور انہوں نے عروہ سے کہ لوگ تحائف بھیجنے کے لیے عائشہ رضی اللہ عنہا کی باری کا انتظار کیا کرتے تھے اور ہشام کی ایک روایت قریش کے ایک صاحب اور ایک دوسرے صاحب سے جو غلاموں میں سے تھے، بھی ہے۔ وہ زہری سے نقل کرتے ہیں اور وہ محمد بن عبدالرحمٰن بن حارث بن ہشام سے کہ عائشہ رضی اللہ عنہا نے کہا جب فاطمہ رضی اللہ عنہا نے ( اندر آنے کی ) اجازت چاہی تو میں اس وقت آپ صلی اللہ علیہ وسلم ہی کی خدمت میں موجود تھی۔' WHERE id = 2480;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی زہری سے، وہ عروہ سے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم جب سفر کا ارادہ کرتے تو اپنی ازواج کے لیے قرعہ اندازی کرتے اور جن کا قرعہ نکل آتا انہیں کو اپنے ساتھ لے جاتے۔ آپ صلی اللہ علیہ وسلم کا یہ بھی طریقہ تھا کہ اپنی تمام ازواج کے لیے ایک ایک دن اور رات کی باری مقرر کر دی تھی، البتہ ( آخر میں ) سودہ بنت زمعہ رضی اللہ عنہا نے اپنی باری عائشہ رضی اللہ عنہا کو دے دی تھی، اس سے ان کا مقصد رسول اللہ صلی اللہ علیہ وسلم کی رضا حاصل کرنی تھی۔' WHERE id = 2491;
UPDATE hadiths SET urdu = 'اور ثابت بن محمد نے بیان کیا کہ ہم سے مسعر نے بیان کیا، ان سے محارب نے اور ان سے جابر رضی اللہ عنہ نے کہ اور ثابت بن محمد نے بیان کیا کہ ہم سے مسعر نے بیان کیا، ان سے محارب نے اور ان سے جابر رضی اللہ عنہ نے کہ' WHERE id = 2501;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے یونس بن محمد نے بیان کیا، ان سے شیبان نے بیان کیا قتادہ سے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں دبیز قسم کے ریشم کا ایک جبہ ہدیہ کے طور پر پیش کیا گیا۔ آپ صلی اللہ علیہ وسلم اس کے استعمال سے ( مردوں کو ) منع فرماتے تھے۔ صحابہ کو بڑی حیرت ہوئی ( کہ کتنا عمدہ ریشم ہے ) آپ صلی اللہ علیہ وسلم نے فرمایا ( تمہیں اس پر حیرت ہے ) اس ذات کی قسم جس کے ہاتھ میں محمد صلی اللہ علیہ وسلم کی جان ہے، جنت میں سعد بن معاذ رضی اللہ عنہ کے رومال اس سے بھی زیادہ خوبصورت ہیں۔' WHERE id = 2512;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے نضر بن انس نے بیان کیا، ان سے بشیر بن نہیک نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”عمریٰ جائز ہے۔“ اور عطاء نے کہا کہ مجھ سے جابر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح بیان کیا۔' WHERE id = 2522;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم کو سفیان نے خبر دی، کہا کہ میں نے مالک سے سنا، انہوں نے زید بن اسلم سے پوچھا تھا تو انہوں نے بیان کیا کہ میں نے اپنے باپ سے سنا وہ بیان کرتے تھے کہ عمر رضی اللہ عنہ نے کہا میں نے ایک گھوڑا اللہ کے راستے میں جہاد کے لیے ایک شخص کو دے دیا تھا، پھر میں نے دیکھا کہ وہ اسے بیچ رہا ہے۔ اس لیے میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ اسے واپس میں ہی خرید لوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”اس گھوڑے کو نہ خرید۔ اپنا دیا ہوا صدقہ واپس نہ لو۔“' WHERE id = 2532;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی عبداللہ بن ابی بکر سے، وہ عمرہ بنت عبدالرحمٰن سے اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ان کے یہاں تشریف فرما تھے۔ عائشہ صدیقہ رضی اللہ عنہا نے ایک صحابی کی آواز سنی جو ( ام المؤمنین ) حفصہ رضی اللہ عنہا کے گھر میں آنے کی اجازت چاہتا تھا۔ عائشہ رضی اللہ عنہا نے کہا کہ میں نے کہا، یا رسول اللہ! میرا خیال ہے یہ حفصہ رضی اللہ عنہا کے رضاعی چچا ہیں۔ انہوں نے عرض کیا، یا رسول اللہ! یہ صحابی آپ کے گھر میں ( جس میں حفصہ رضی اللہ عنہا رہتی ہیں ) آنے کی اجازت مانگ رہے ہیں۔ انہوں نے بیان کیا کہ آپ نے فرمایا، میرا خیال ہے یہ فلاں صاحب، حفصہ کے رضاعی چچا ہیں۔ پھر عائشہ رضی اللہ عنہا نے بھی اپنے ایک رضاعی چچا کے متعلق پوچھا کہ اگر فلاں زندہ ہوتے تو کیا وہ بے حجاب میرے پاس آ سکتے تھے؟ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ہاں! دودھ سے بھی وہ تمام رشتے حرام ہو جاتے ہیں جو نسب کی وجہ سے حرام ہوتے ہیں۔“' WHERE id = 2542;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی سلمہ نے بیان کیا، کہا ہم کو ابن شہاب نے خبر دی سالم بن عبداللہ سے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بلال رضی اللہ عنہ رات میں اذان دیتے ہیں۔ اس لیے تم لوگ سحری کھا پی سکتے ہو یہاں تک کہ ( فجر کے لیے ) دوسری اذان پکاری جائے۔“ یا ( یہ فرمایا ) یہاں تک کہ ”عبداللہ ابن ام مکتوم رضی اللہ عنہ کی اذان سن لو۔“ عبداللہ ابن ام مکتوم رضی اللہ عنہ نابینا تھے اور جب تک ان سے کہا نہ جاتا صبح ہو گئی ہے، وہ اذان نہیں دیتے تھے۔' WHERE id = 2552;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا کہا ہم کو ابومعاویہ نے خبر دی اور انہیں اعمش نے انہیں شقیق نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس شخص نے کوئی ایسی قسم کھائی جس میں وہ جھوٹا تھا، کسی مسلمان کا مال چھیننے کے لیے، تو وہ اللہ تعالیٰ سے اس طرح ملے گا کہ اللہ تعالیٰ اس پر غضبناک ہو گا۔“ انہوں نے بیان کیا کہ اس پر اشعث بن قیس رضی اللہ عنہ نے کہا کہ اللہ گواہ ہے، یہ حدیث میرے ہی متعلق آپ صلی اللہ علیہ وسلم نے فرمائی تھی۔ میرا ایک یہودی سے ایک زمین کا جھگڑا تھا۔ یہودی میرے حق کا انکار کر رہا تھا۔ اس لیے میں اسے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لایا۔ آپ صلی اللہ علیہ وسلم نے مجھ سے فرمایا ( کیونکہ میں مدعی تھا ) کہ گواہی پیش کرنا تمہارے ہی ذمہ ہے۔ انہوں نے بیان کیا کہ میں نے عرض کیا گواہ تو میرے پاس کوئی بھی نہیں۔ اس لیے آپ صلی اللہ علیہ وسلم نے یہودی سے فرمایا ”پھر تم قسم کھاؤ۔“ اشعث رضی اللہ عنہ نے بیان کیا کہ میں بول پڑا، یا رسول اللہ! پھر تو یہ قسم کھا لے گا اور میرا مال ہضم کر جائے گا۔ انہوں نے بیان کیا کہ اسی واقعہ پر اللہ تعالیٰ نے یہ آیت نازل فرمائی «إن الذين يشترون بعهد الله وأيمانهم ثمنا قليلا» ”جو لوگ اللہ کے عہد اور قسموں سے معمولی پونجی خریدتے ہیں آخر آیت تک۔“' WHERE id = 2562;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا امام مالک سے، ان سے ہشام بن عروہ نے، ان سے ان کے باپ نے، ان سے زینب نے اور ان سے ام سلمہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم لوگ میرے یہاں اپنے مقدمات لاتے ہو اور کبھی ایسا ہوتا ہے کہ ایک تم میں دوسرے سے دلیل بیان کرنے میں بڑھ کر ہوتا ہے ( قوت بیانیہ بڑھ کر رکھتا ہے ) پھر میں اس کو اگر اس کے بھائی کا حق ( غلطی سے ) دلا دوں، تو وہ حلال ( نہ سمجھے ) اس کو نہ لے، میں اس کو دوزخ کا ایک ٹکڑا دلا رہا ہوں۔“' WHERE id = 2573;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان نے بیان کیا، کہا کہ مجھ سے ابوحازم سلمہ بن دینار نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ ( قباء کے ) بنو عمرو بن عوف میں آپس میں کچھ تکرار ہو گئی تھی تو رسول اللہ صلی اللہ علیہ وسلم اپنے کئی اصحاب کو ساتھ لے کر ان کے یہاں ان میں صلح کرانے کے لیے گئے اور نماز کا وقت ہو گیا، لیکن آپ صلی اللہ علیہ وسلم تشریف نہ لا سکے۔ چنانچہ بلال رضی اللہ عنہ نے آگے بڑھ کر اذان دی، ابھی تک چونکہ آپ صلی اللہ علیہ وسلم تشریف نہیں لائے تھے اس لیے وہ ( آپ صلی اللہ علیہ وسلم ہی کی ہدایت کے مطابق ) ابوبکر رضی اللہ عنہ کے پاس آئے اور ان سے کہا کہ نبی کریم صلی اللہ علیہ وسلم وہیں رک گئے ہیں اور نماز کا وقت ہو گیا ہے، کیا آپ لوگوں کو نماز پڑھا دیں گے؟ انہوں نے کہا کہ ہاں اگر تم چاہو۔ اس کے بعد بلال رضی اللہ عنہ نے نماز کی تکبیر کہی اور ابوبکر رضی اللہ عنہ آگے بڑھے ( نماز کے درمیان ) نبی کریم صلی اللہ علیہ وسلم صفوں کے درمیان سے گزرتے ہوئے پہلی صف میں آ پہنچے۔ لوگ باربار ہاتھ پر ہاتھ مارنے لگے۔ مگر ابوبکر رضی اللہ عنہ نماز میں کسی دوسری طرف متوجہ نہیں ہوتے تھے ( مگر جب باربار ایسا ہوا تو ) آپ متوجہ ہوئے اور معلوم کیا کہ رسول اللہ صلی اللہ علیہ وسلم آپ کے پیچھے ہیں۔ آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ کے اشارے سے انہیں حکم دیا کہ جس طرح وہ نماز پڑھا رہے ہیں، اسے جاری رکھیں۔ لیکن ابوبکر رضی اللہ عنہ نے اپنا ہاتھ اٹھا کر اللہ کی حمد بیان کی اور الٹے پاؤں پیچھے آ گئے اور صف میں مل گئے۔ پھر نبی کریم صلی اللہ علیہ وسلم آگے بڑھے اور نماز پڑھائی۔ نماز سے فارغ ہو کر آپ صلی اللہ علیہ وسلم لوگوں کی طرف متوجہ ہوئے اور انہیں ہدایت کی کہ لوگو! جب نماز میں کوئی بات پیش آتی ہے تو تم ہاتھ پر ہاتھ مارنے لگتے ہو۔ ہاتھ پر ہاتھ مارنا عورتوں کے لیے ہے ( مردوں کو ) جس کی نماز میں کوئی بات پیش آئے تو اسے سبحان اللہ کہنا چاہئے، کیونکہ یہ لفظ جو بھی سنے گا وہ متوجہ ہو جائے گا۔ اے ابوبکر! جب میں نے اشارہ بھی کر دیا تھا تو پھر آپ لوگوں کو نماز کیوں نہیں پڑھاتے رہے؟ انہوں نے عرض کیا، ابوقحافہ کے بیٹے کے لیے یہ بات مناسب نہ تھی کہ وہ رسول اللہ صلی اللہ علیہ وسلم کے ہوتے ہوئے نماز پڑھائے۔' WHERE id = 2583;
UPDATE hadiths SET urdu = 'ہم سے محمد بن رافع نے بیان کیا، کہا ہم سے شریح بن نعمان نے بیان کیا، کہا ہم سے فلیح نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم عمرہ کا احرام باندھ کر نکلے، تو کفار قریش نے آپ صلی اللہ علیہ وسلم کو بیت اللہ جانے سے روک دیا۔ اس لیے آپ صلی اللہ علیہ وسلم نے قربانی کا جانور حدیبیہ میں ذبح کر دیا اور سر بھی وہیں منڈوا لیا اور کفار مکہ سے آپ صلی اللہ علیہ وسلم نے اس شرط پر صلح کی تھی کہ آپ صلی اللہ علیہ وسلم آئندہ سال عمرہ کر سکیں گے۔ تلواروں کے سوا اور کوئی ہتھیار ساتھ نہ لائیں گے۔ ( اور وہ بھی نیام میں ہوں گی ) اور قریش جتنے دن چاہیں گے اس سے زیادہ مکہ میں نہ ٹھہر سکیں گے۔ ( یعنی تین دن ) چنانچہ آپ صلی اللہ علیہ وسلم نے آئندہ سال عمرہ کیا اور شرائط کے مطابق آپ صلی اللہ علیہ وسلم مکہ میں داخل ہوئے، پھر جب تین دن گزر چکے تو قریش نے مکے سے چلے جانے کے لیے کہا اور آپ صلی اللہ علیہ وسلم وہاں سے واپس چلے آئے۔' WHERE id = 2593;
UPDATE hadiths SET urdu = 'عروہ نے کہا کہ مجھے عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ہجرت کرنے والی عورتوں کا اس آیت کی وجہ سے امتحان لیا کرتے تھے «{‏ يا أيها الذين آمنوا إذا جاءكم المؤمنات مهاجرات فامتحنوهن ‏}‏ إلى ‏ {‏ غفور رحيم‏ }‏‏.‏» ”اے مسلمانو! جب تمہارے یہاں مسلمان عورتیں ہجرت کر کے آئیں تو تم ان کا امتحان لے لو غفور رحیم تک۔“ عروہ نے کہا کہ عائشہ رضی اللہ عنہا نے کہا کہ ان عورتوں میں سے جو اس شرط کا اقرار کر لیتیں تو رسول اللہ صلی اللہ علیہ وسلم فرماتے کہ میں نے تم سے بیعت کی، آپ صلی اللہ علیہ وسلم صرف زبان سے بیعت کرتے تھے۔ قسم اللہ کی! بیعت کرتے وقت آپ صلی اللہ علیہ وسلم کے ہاتھ نے کسی بھی عورت کے ہاتھ کو کبھی نہیں چھوا، بلکہ آپ صلی اللہ علیہ وسلم صرف زبان سے بیعت لیا کرتے تھے۔' WHERE id = 2604;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے معمر نے بیان کیا، ان سے زہری نے، ان سے سعید نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کوئی شہری کسی دیہاتی کا مال تجارت نہ بیچے۔ کوئی شخص نجش نہ کرے اور نہ اپنے بھائی کی لگائی ہوئی قیمت پر بھاؤ بڑھائے۔ نہ کوئی شخص اپنے کسی بھائی کے پیغام نکاح کی موجودگی میں اپنا پیغام بھیجے اور نہ کوئی عورت ( کسی مرد سے ) اپنی بہن کی طلاق کا مطالبہ کرے ( جو اس مرد کے نکاح میں ہو ) تاکہ اس طرح اس کا حصہ بھی خود لے لے۔“' WHERE id = 2614;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا کہ ہم کو شعیب نے خبر دی ‘ ان سے ابوالزناد نے بیان کیا ‘ ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ کے ننانوے نام ہیں یعنی ایک کم سو۔ جو شخص ان سب کو محفوظ رکھے گا وہ جنت میں داخل ہو گا۔“' WHERE id = 2625;
UPDATE hadiths SET urdu = 'ہم سے حسان بن ابی عباد نے بیان کیا ‘ کہا ہم سے ہمام نے بیان کیا قتادہ سے اور ان سے انس رضی اللہ عنہ نے کہ ایک یہودی نے ایک ( انصاری ) لڑکی کا سر دو پتھروں کے درمیان میں رکھ کر کچل دیا تھا۔ لڑکی سے پوچھا گیا کہ تمہارا سر اس طرح کس نے کیا ہے؟ کیا فلاں شخص نے کیا؟ فلاں نے کیا؟ آخر یہودی کا بھی نام لیا گیا ( جس نے اس کا سر کچل دیا تھا ) تو لڑکی نے سر کے اشارے سے ہاں میں جواب دیا۔ پھر وہ یہودی بلایا گیا اور آخر اس نے بھی اقرار کر لیا اور نبی کریم صلی اللہ علیہ وسلم کے حکم سے اس کا بھی پتھر سے سر کچل دیا گیا۔' WHERE id = 2635;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو مخلد بن یزید نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے یعلیٰ بن مسلم نے خبر دی، انہوں نے عکرمہ سے سنا، وہ بیان کرتے تھے کہ ہمیں ابن عباس رضی اللہ عنہما نے خبر دی کہ سعد بن عبادہ رضی اللہ عنہ کی ماں عمرہ بنت مسعود کا انتقال ہوا تو وہ ان کی خدمت میں موجود نہیں تھے۔ انہوں نے آ کر رسول اللہ صلی اللہ علیہ وسلم سے پوچھا یا رسول اللہ! میری والدہ کا جب انتقال ہوا تو میں ان کی خدمت میں حاضر نہیں تھا۔ کیا اگر میں کوئی چیز صدقہ کروں تو اس سے انہیں فائدہ پہنچ سکتا ہے؟ آپ صلی اللہ علیہ وسلم نے اثبات میں جواب دیا تو انہوں نے کہا کہ میں آپ کو گواہ بناتا ہوں کہ میرا مخراف نامی باغ ان کی طرف سے صدقہ ہے۔' WHERE id = 2645;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے سلیمان بن بلال نے بیان کیا ‘ ان سے ثور بن زید مدنی نے بیان کیا ‘ ان سے ابوغیث نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سات گناہوں سے جو تباہ کر دینے والے ہیں بچتے رہو۔“ صحابہ رضی اللہ عنہم نے پوچھا یا رسول اللہ! وہ کون سے گناہ ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے ساتھ کسی کو شریک ٹھہرانا ‘ جادو کرنا ‘ کسی کی ناحق جان لینا کہ جسے اللہ تعالیٰ نے حرام قرار دیا ہے ‘ سود کھانا ‘ یتیم کا مال کھانا ‘ لڑائی میں سے بھاگ جانا ‘ پاک دامن بھولی بھالی ایمان والی عورتوں پر تہمت لگانا۔“' WHERE id = 2655;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ کہا ہم کو امام مالک نے خبر دی ‘ انہیں ابوالزناد نے ‘ انہیں اعرج نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو آدمی میرے وارث ہیں ‘ وہ روپیہ اشرفی اگر میں چھوڑ جاؤں تو وہ تقسیم نہ کریں ‘ وہ میری بیویوں کا خرچ اور جائیداد کا اہتمام کرنے والے کا خرچ نکالنے کے بعد صدقہ ہے۔“' WHERE id = 2665;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ انہوں نے کہا کہ ہم کو شعیب نے خبر دی ‘ انہیں زہری نے ‘ انہوں نے کہا کہ مجھ سے عطاء بن یزید لیثی نے کہا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ عرض کیا گیا یا رسول اللہ! کون شخص سب سے افضل ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”وہ مومن جو اللہ کے راستے میں اپنی جان اور مال سے جہاد کرے۔“ صحابہ رضی اللہ عنہم نے پوچھا اس کے بعد کون؟ فرمایا ”وہ مومن جو پہاڑ کی کسی گھاٹی میں رہنا اختیار کرے ‘ اللہ تعالیٰ کا خوف رکھتا ہو اور لوگوں کو چھوڑ کر اپنی برائی سے ان کو محفوظ رکھے۔“' WHERE id = 2675;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن یعقوب صفار نے بیان کیا، کہا ہم سے اسماعیل بن علیہ نے، ان سے ایوب نے، ان سے حمید بن ہلال نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے خطبہ دیا، آپ صلی اللہ علیہ وسلم نے فرمایا ”فوج کا جھنڈا اب زید نے اپنے ہاتھ میں لیا اور وہ شہید کر دیئے گئے پھر جعفر نے لے لیا اور وہ بھی شہید کر دیئے گئے پھر عبداللہ بن رواحہ نے لے لیا اور وہ بھی شہید کر دیئے گئے اور اب کسی ہدایت کا انتظار کئے بغیر خالد بن ولید نے جھنڈا اپنے ہاتھ میں لے لیا۔ اور ان کے ہاتھ پر اسلامی لشکر کو فتح ہوئی۔“ آپ صلی اللہ علیہ وسلم نے فرمایا ”اور ہمیں کوئی اس کی خوشی بھی نہیں تھی کہ یہ لوگ جو شہید ہو گئے ہیں ہمارے پاس زندہ رہتے کیونکہ وہ بہت عیش و آرام میں چلے گئے ہیں۔ ایوب نے بیان کیا یا آپ صلی اللہ علیہ وسلم نے یہ فرمایا ”انہیں کوئی اس کی خوشی بھی نہیں تھی کہ ہمارے ساتھ زندہ رہتے، اس وقت آپ صلی اللہ علیہ وسلم آنکھوں سے آنسو جاری تھے۔“' WHERE id = 2686;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا ‘ کہا ہم کو محمد بن مبارک نے خبر دی ‘ کہا ہم سے یحییٰ بن حمزہ نے بیان کیا ‘ کہا کہ مجھ سے یزید بن ابی مریم نے بیان کیا ‘ انہیں عبایہ بن رافع بن خدیج نے خبر دی ‘ کہا کہ مجھے ابوعبس رضی اللہ عنہ نے خبر دی ‘ آپ کا نام عبدالرحمٰن بن جبیر ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس بندے کے بھی قدم اللہ کے راستے میں غبار آلود ہو گئے ‘ انہیں ( جہنم کی ) آگ چھوئے؟ ( یہ نا ممکن ہے ) ۔“' WHERE id = 2697;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی ‘ ان سے زہری نے بیان کیا ‘ انہیں عمر بن جبیر بن مطعم نے خبر دی ‘ انہیں محمد بن جبیر نے خبر دی کہا کہ مجھے جبیر بن مطعم رضی اللہ عنہ نے خبر دی کہ وہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ چل رہے تھے، آپ کے ساتھ اور بہت سے صحابہ بھی تھے۔ وادی حنین سے واپس تشریف لا رہے تھے کہ کچھ ( بدو ) لوگ آپ صلی اللہ علیہ وسلم سے لپٹ گئے۔ بالآخر آپ کو مجبوراً ایک ببول کے درخت کے پاس جانا پڑا۔ وہاں آپ کی چادر مبارک ببول کے کانٹے میں الجھ گئی تو ان لوگوں نے اسے لے لیا ( تاکہ جب آپ صلی اللہ علیہ وسلم انہیں کچھ عنایت فرمائیں تو چادر واپس کریں ) آپ صلی اللہ علیہ وسلم وہاں کھڑے ہو گئے اور فرمایا میری چادر مجھے دے دو ‘ اگر میرے پاس درخت کے کانٹوں جتنے بھی اونٹ بکریاں ہوتیں تو میں تم میں تقسیم کر دیتا ‘ مجھے تم بخیل نہیں پاؤ گے اور نہ جھوٹا اور نہ بزدل پاؤ گے۔' WHERE id = 2707;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا ‘ انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا ابواسحاق سے کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا ‘ آپ کہتے تھے کہ جب آیت «لا يستوي القاعدون من المؤمنين‏» نازل ہوئی تو رسول اللہ صلی اللہ علیہ وسلم نے زید بن ثابت رضی اللہ عنہ ( جو کاتب وحی تھے ) کو بلایا ‘ آپ ایک چوڑی ہڈی ساتھ لے کر حاضر ہوئے اور اس آیت کو لکھا اور ابن ام مکتوم رضی اللہ عنہ نے جب اپنے نابینا ہونے کی شکایت کی تو آیت یوں نازل ہوئی «لا يستوي القاعدون من المؤمنين غير أولي الضرر» ۔' WHERE id = 2717;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا ‘ کہا ہم سے شیبان نے بیان کیا یحییٰ سے ‘ وہ ابوسلمہ سے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس شخص نے اللہ کے راستے میں ایک جوڑا ( کسی چیز کا ) خرچ کیا تو اسے جنت کے داروغہ بلائیں گے۔ جنت کے ہر دروازے کا داروغہ ( اپنی طرف ) بلائے گا کہ اے فلاں! اس دروازے سے آ، اس پر ابوبکر رضی اللہ عنہ بولے۔ یا رسول اللہ! پھر اس شخص کو کوئی خوف نہیں رہے گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا مجھے امید ہے کہ تم بھی انہیں میں سے ہو گے۔' WHERE id = 2727;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، ان سے ابوالتیاح نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”گھوڑے کی پیشانی میں برکت بندھی ہوئی ہے۔“' WHERE id = 2737;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ابوعقیل و بشر بن عقبہ نے بیان کیا، انہوں نے کہا ہم سے ابوالمتوکل ناجی (علی بن داود) نے بیان کیا، انہوں نے کہا میں جابر بن عبداللہ انصاری رضی اللہ عنہما کی خدمت میں حاضر ہوا اور عرض کیا کہ آپ نے رسول اللہ صلی اللہ علیہ وسلم سے جو کچھ سنا ہے، ان میں سے مجھ سے بھی کوئی حدیث بیان کیجئے۔ انہوں نے بیان فرمایا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھا۔ ابوعقیل راوی نے کہا کہ مجھے معلوم نہیں ( یہ سفر ) جہاد کے لیے تھا یا عمرہ کے لیے ( واپس ہوتے ہوئے ) جب ( مدینہ منورہ ) دکھائی دینے لگا تو آپ صلی اللہ علیہ وسلم نے فرمایا جو شخص اپنے گھر جلدی جانا چاہے وہ جا سکتا ہے۔ جابر رضی اللہ عنہ نے بیان کیا کہ پھر ہم آگے بڑھے۔ میں اپنے ایک سیاہی مائل سرخ اونٹ بےداغ پر سوار تھا دوسرے لوگ میرے پیچھے رہ گئے، میں اسی طرح چل رہا تھا کہ اونٹ رک گیا ( تھک کر ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا جابر! اپنا اونٹ تھام لے، آپ صلی اللہ علیہ وسلم نے اپنے کوڑے سے اونٹ کو مارا، اونٹ کود کر چل نکلا پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا یہ اونٹ بیچو گے؟ میں نے کہا ہاں! جب مدینہ پہنچے اور نبی کریم صلی اللہ علیہ وسلم اپنے اصحاب کے ساتھ مسجد نبوی میں داخل ہوئے تو میں بھی آپ صلی اللہ علیہ وسلم کی خدمت میں پہنچا اور ”بلاط“ کے ایک کونے میں، میں نے اونٹ کو باندھ دیا اور نبی کریم صلی اللہ علیہ وسلم سے عرض کیا یہ آپ کا اونٹ ہے۔ پھر آپ صلی اللہ علیہ وسلم باہر تشریف لائے اور اونٹ کو گھمانے لگے اور فرمایا کہ اونٹ تو ہمارا ہی ہے، اس کے بعد آپ صلی اللہ علیہ وسلم نے چند اوقیہ سونا مجھے دلوایا اور دریافت فرمایا تم کو قیمت پوری مل گئی۔ میں نے عرض کیا جی ہاں۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا اب قیمت اور اونٹ ( دونوں ہی ) تمہارے ہیں۔' WHERE id = 2747;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے معاویہ بن عمرو نے بیان کیا، ان سے ابواسحاق ابراہیم نے بیان کیا، ان سے حمید نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، آپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی اونٹنی کا نام عضباء تھا۔' WHERE id = 2757;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے بشر بن مفضل نے بیان کیا، ان سے خالد بن ذکوان نے اور ان سے ربیع بنت معوذ رضی اللہ عنہا نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ جہاد میں شریک ہوتیں تھیں مجاہد مسلمانوں کو پانی پلاتیں، ان کی خدمت کرتیں اور زخمیوں اور شہیدوں کو اٹھا کر مدینہ لے جاتیں تھیں۔' WHERE id = 2768;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے کہا، ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے عمرو بن عمرو نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ابوطلحہ رضی اللہ عنہ سے فرمایا کہ اپنے بچوں میں سے کوئی بچہ میرے ساتھ کر دو جو خیبر کے غزوے میں میرے کام کر دیا کرے، جب کہ میں خیبر کا سفر کروں۔ ابوطلحہ اپنی سواری پر اپنے پیچھے بٹھا کر مجھے ( انس رضی اللہ عنہ کو ) لے گئے، میں اس وقت ابھی لڑکا تھا۔ بالغ ہونے کے قریب۔ جب بھی آپ صلی اللہ علیہ وسلم کہیں قیام فرماتے تو میں آپ صلی اللہ علیہ وسلم کی خدمت کرتا۔ اکثر میں سنتا کہ آپ صلی اللہ علیہ وسلم یہ دعا کرتے۔ «اللهم إني أعوذ بك من الهم والحزن والعجز والكسل والبخل والجبن وضلع الدين وغلبة الرجال» ”اے اللہ! میں تیری پناہ مانگتا ہوں غم، عاجزی، سستی، بخل، بزدلی، قرض داری کے بوجھ اور ظالم کے اپنے اوپر غلبہ سے، آخر ہم خیبر پہنچے اور جب اللہ تعالیٰ نے خیبر کے قلعہ پر آپ صلی اللہ علیہ وسلم کو فتح دی تو آپ صلی اللہ علیہ وسلم کے سامنے صفیہ بنت حی بن اخطب رضی اللہ عنہا کے جمال ( ظاہری و باطنی ) کا ذکر کیا گیا ان کا شوہر ( یہودی ) لڑائی میں کام آ گیا تھا اور وہ ابھی دلہن ہی تھیں ( اور چونکہ قبیلہ کے سردار کی لڑکی تھیں ) اس لیے رسول اللہ صلی اللہ علیہ وسلم نے ( ان کا اکرام کرنے کے لیے کہا ) انہیں اپنے لیے پسند فرما لیا۔ پھر آپ صلی اللہ علیہ وسلم انہیں ساتھ لے کر وہاں سے چلے۔ جب ہم سدا الصبہاء پر پہنچے تو وہ حیض سے پاک ہوئیں، تو آپ صلی اللہ علیہ وسلم نے ان سے خلوت کی۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے حیس ( کھجور، پنیر اور گھی سے تیار کیا ہوا ایک کھانا ) تیار کرا کر ایک چھوٹے سے دستر خوان پر رکھوایا اور مجھ سے فرمایا کہ اپنے آس پاس کے لوگوں کو دعوت دے دو اور یہی آپ صلی اللہ علیہ وسلم کا سیدہ صفیہ رضی اللہ عنہا کے ساتھ نکاح کا ولیمہ تھا۔ آخر ہم مدینہ کی طرف چلے، انس رضی اللہ عنہ نے کہا کہ میں نے دیکھا کہ آپ صلی اللہ علیہ وسلم صفیہ رضی اللہ عنہا کی وجہ سے اپنے پیچھے ( اونٹ کے کوہان کے اردگرد ) اپنی عباء سے پردہ کئے ہوئے تھے ( سواری پر جب صفیہ رضی اللہ عنہا سوار ہوتیں ) تو آپ صلی اللہ علیہ وسلم اپنے اونٹ کے پاس بیٹھ جاتے اور اپنا گھٹنا کھڑا رکھتے اور صفیہ رضی اللہ عنہا اپنا پاؤں نبی کریم صلی اللہ علیہ وسلم کے گھٹنے پر رکھ کر سوار ہو جاتیں۔ اس طرح ہم چلتے رہے اور جب مدینہ منورہ کے قریب پہنچے تو آپ صلی اللہ علیہ وسلم نے احد پہاڑ کو دیکھا اور فرمایا یہ پہاڑ ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں، اس کے بعد آپ صلی اللہ علیہ وسلم نے مدینہ کی طرف نگاہ اٹھائی اور فرمایا: اے اللہ! میں اس کے دونوں پتھریلے میدانوں کے درمیان کے خطے کو حرمت والا قرار دیتا ہوں جس طرح ابراہیم علیہ السلام نے مکہ معظمہ کو حرمت والا قرار دیا تھا اے اللہ! مدینہ کے لوگوں کو ان کی مد اور صاع میں برکت دیجئیے' WHERE id = 2778;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، کہا مجھ سے سعد بن ابراہیم نے بیان کیا، ان سے عبداللہ بن شداد نے اور ان سے علی رضی اللہ عنہ نے (دوسری سند) ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے سعد بن ابراہیم نے بیان کیا، کہا مجھ سے عبداللہ بن شداد نے بیان کیا، کہا کہ میں نے علی رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ سعد بن ابی وقاص رضی اللہ عنہ کے بعد میں نے کسی کے متعلق نبی کریم صلی اللہ علیہ وسلم سے نہیں سنا کہ آپ نے خود کو ان پر صدقے کیا ہو۔ میں نے سنا کہ آپ صلی اللہ علیہ وسلم فرما رہے تھے: ”تیر برساؤ ( سعد ) تم پر میرے ماں باپ قربان ہوں۔“' WHERE id = 2789;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسمٰعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بخیل ( جو زکوٰۃ نہیں دیتا ) اور زکوٰۃ دینے والے ( سخی ) کی مثال دو آدمیوں جیسی ہے، دونوں لوہے کے کرتے ( زرہ ) پہنے ہوئے ہیں، دونوں کے ہاتھ گردن سے بندھے ہوئے ہیں زکوٰۃ دینے والا ( سخی ) جب بھی زکوٰۃ کا ارادہ کرتا ہے تو اس کا کرتہ اتنا کشادہ ہو جاتا ہے کہ زمین پر چلتے میں گھسٹتا جاتا ہے لیکن جب بخیل صدقہ کا ارادہ کرتا ہے تو اس کی زرہ کا ایک ایک حلقہ اس کے بدن پر تنگ ہو جاتا ہے اور اس طرح سکڑ جاتا ہے کہ اس کے ہاتھ اس کی گردن سے جڑ جاتے ہیں۔“ ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے سنا ”پھر بخیل اسے ڈھیلا کرنا چاہتا ہے لیکن وہ ڈھیلا نہیں ہوتا۔“' WHERE id = 2800;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، ان سے جریر بن حازم نے بیان کیا، کہا میں نے حسن سے سنا، انہوں نے کہا کہ ہم سے عمرو بن تغلب رضی اللہ عنہ نے بیان کیا، کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کی نشانیوں میں سے ہے کہ تم ایسی قوم سے جنگ کرو گے جو بالوں کی جوتیاں پہنے ہوں گے ( یا ان کے بال بہت لمبے ہوں گے ) اور قیامت کی ایک نشانی یہ ہے کہ ان لوگوں سے لڑو گے جن کے منہ چوڑے چوڑے ہوں گے گویا ڈھالیں ہیں چمڑا جمی ہوئی ( یعنی بہت موٹے منہ والے ہوں گے ) ۔' WHERE id = 2810;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ طفیل بن عمرو دوسی رضی اللہ عنہ اپنے ساتھیوں کے ساتھ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ یا رسول اللہ! قبیلہ دوس کے لوگ سرکشی پر اتر آئے ہیں اور اللہ کا کلام سننے سے انکار کرتے ہیں۔ آپ ان پر بددعا کیجئے! بعض صحابہ رضی اللہ عنہم نے کہا کہ اب دوس کے لوگ برباد ہو جائیں گے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا: «اللهم اهد دوسا وائت بهم» ”اے اللہ! دوس کے لوگوں کو ہدایت دے اور انہیں ( دائرہ اسلام میں ) کھینچ لا۔“' WHERE id = 2820;
UPDATE hadiths SET urdu = 'یونس سے روایت ہے، ان سے زہری نے بیان کیا، انہوں نے کہا کہ مجھے عبدالرحمٰن بن کعب بن مالک نے خبر دی کہ کعب بن مالک رضی اللہ عنہ کہا کرتے تھے کہ کم ایسا ہوتا کہ رسول اللہ صلی اللہ علیہ وسلم کسی سفر میں جمعرات کے سوا اور کسی دن نکلیں۔' WHERE id = 2831;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا ہم سے یزید بن ابی عبید نے بیان کیا، اور ان سے سلمہ بن الاکوع نے بیان کیا ( حدیبیہ کے موقع پر ) میں نے رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی۔ پھر ایک درخت کے سائے میں آ کر کھڑا ہو گیا۔ جب لوگوں کا ہجوم کم ہوا تو نبی کریم صلی اللہ علیہ وسلم نے دریافت کیا، ابن الاکوع کیا بیعت نہیں کرو گے؟ انہوں نے کہا کہ میں نے عرض کیا، یا رسول اللہ! میں تو بیعت کر چکا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا، دوبارہ اور بھی! چنانچہ میں نے دوبارہ بیعت کی ( یزید بن ابی عبیداللہ کہتے ہیں کہ ) میں نے سلمہ بن الاکوع رضی اللہ عنہ سے پوچھا، ابومسلم اس دن آپ حضرات نے کس بات پر بیعت کی تھی؟ کہا کہ موت پر۔' WHERE id = 2841;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا کہ مجھ سے لیث نے بیان کیا، کہا کہ مجھے عقیل نے خبر دی، ان سے ابن شہاب نے بیان کیا، انہیں ثعلبہ بن ابی مالک قرظی نے خبر دی کہ قیس بن سعد انصاری رضی اللہ عنہ نے، جو جہاد میں رسول اللہ صلی اللہ علیہ وسلم کے علمبردار تھے، جب حج کا ارادہ کیا تو ( احرام باندھنے سے پہلے ) کنگھی کی۔' WHERE id = 2853;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے ابوعاصم نے بیان کیا، کہا ہم سے عثمان بن اسود نے بیان کیا، کہا ہم سے ابن ابی ملیکہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ انہوں نے عرض کیا، یا رسول اللہ! آپ کے اصحاب حج اور عمرہ دونوں کر کے واپس جا رہے ہیں اور میں صرف حج کر پائی ہوں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر جاؤ ( عمرہ کر آؤ ) عبدالرحمٰن رضی اللہ عنہ ( عائشہ رضی اللہ عنہا کے بھائی ) تمہیں اپنی سواری کے پیچھے بٹھا لیں گے۔ چنانچہ آپ نے عبدالرحمٰن رضی اللہ عنہ کو حکم دیا کہ تنعیم سے ( احرام باندھ کر ) عائشہ رضی اللہ عنہا کو عمرہ کرا لائیں۔ رسول اللہ صلی اللہ علیہ وسلم نے اس عرصہ میں مکہ کے بالائی علاقہ پر ان کا انتظار کیا۔ یہاں تک کہ وہ آ گئیں۔' WHERE id = 2863;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے ابن عدی نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے حصین نے، ان سے سالم نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ جب ہم بلندی پر چڑھتے تو «الله اكبر» کہتے اور نشیب میں اترتے تو «سبحان الله» کہتے تھے۔' WHERE id = 2873;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے کہا، ہم سے حبیب بن ابی ثابت نے بیان کیا، کہا کہ میں نے ابوالعباس (شاعر ہونے کے ساتھ) روایت حدیث میں بھی ثقہ اور قابل اعتماد تھے، انہوں نے بیان کیا کہ میں نے عبداللہ بن عمرو رضی اللہ عنہما سے سنا، آپ بیان کرتے تھے کہ ایک صحابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ صلی اللہ علیہ وسلم سے جہاد میں شرکت کی اجازت چاہی۔ آپ صلی اللہ علیہ وسلم نے ان سے دریافت فرمایا ”کیا تمہارے ماں باپ زندہ ہیں؟“ انہوں نے کہا کہ جی ہاں! آپ صلی اللہ علیہ وسلم نے فرمایا ”پھر انہیں میں جہاد کرو۔ ( یعنی ان کو خوش رکھنے کی کوشش کرو ) ۔“' WHERE id = 2883;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا ‘ کہا ہم کو لیث نے خبر دی ‘ انہیں نافع نے اور انہیں عبداللہ رضی اللہ عنہ نے خبر دی کہ ہم سے احمد بن یونس نے بیان کیا ‘ کہا ہم کو لیث نے خبر دی ‘ انہیں نافع نے اور انہیں عبداللہ رضی اللہ عنہ نے خبر دی کہ' WHERE id = 2893;
UPDATE hadiths SET urdu = 'ابوعامر نے کہا ‘ ہم سے مغیرہ بن عبدالرحمٰن نے بیان کیا ‘ ان سے ابوالزناد نے ‘ ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”دشمن سے لڑنے بھڑنے کی تمنا نہ کرو ‘ ہاں! اگر جنگ شروع ہو جائے تو پھر صبر سے کام لو۔“' WHERE id = 2904;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے حماد نے بیان کیا ‘ ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم سب سے زیادہ حسین ‘ سب سے زیادہ سخی اور سب سے زیادہ بہادر تھے۔ انہوں نے کہا کہ ایک مرتبہ رات کے وقت اہل مدینہ گھبرا گئے تھے ‘ کیونکہ ایک آواز سنائی دی تھی۔ پھر ابوطلحہ رضی اللہ عنہ کے ایک گھوڑے پر جس کی پیٹھ ننگی تھی رسول اللہ صلی اللہ علیہ وسلم حقیقت حال معلوم کرنے کے لیے تنہا اطراف مدینہ میں سب سے آگے تشریف لے گئے۔ پھر آپ صلی اللہ علیہ وسلم واپس آ کر صحابہ رضی اللہ عنہم سے ملے تو تلوار آپ صلی اللہ علیہ وسلم کی گردن میں لٹک رہی تھی اور آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ گھبرانے کی کوئی بات نہیں ‘ گھبرانے کی کوئی بات نہیں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تو اسے دریا کی طرح پایا۔ ( تیز دوڑنے میں ) آپ صلی اللہ علیہ وسلم کا اشارہ گھوڑے کی طرف تھا۔' WHERE id = 2916;
UPDATE hadiths SET urdu = 'مجھ سے محمود بن غیلان نے بیان کیا ‘ کہا ہم سے عبدالرزاق نے بیان کیا ‘ کہا ہم کو معمر نے خبر دی ‘ انہیں زہری نے ‘ انہیں محمد بن جبیر نے ‘ انہیں ان کے باپ (جبیر بن مطعم رضی اللہ عنہ) نے وہ بدر کے قیدیوں کو چھڑانے نبی کریم صلی اللہ علیہ وسلم کے پاس آئے ( وہ ابھی اسلام نہیں لائے تھے ) انہوں نے بیان کیا کہ میں نے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے مغرب کی نماز میں سورۃ الطور پڑھی۔' WHERE id = 2926;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے سفیان نے بیان کیا ‘ ان سے ابن جریج نے ‘ ان سے عمرو بن دینار نے ‘ ان سے ابومعبد نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا یا رسول اللہ! میرا نام فلاں جہاد میں جانے کے لیے لکھا گیا ہے۔ ادھر میری بیوی حج کرنے جا رہی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر جا اور اپنی بیوی کے ساتھ حج کر آ۔' WHERE id = 2936;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا ‘ کہ ہم کو عبداللہ بن مبارک نے خبر دی ‘ انہیں خالد بن سعید نے ‘ انہیں ان کے والد نے اور ان سے ام خالد بنت خالد بن سعید رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں اپنے والد کے ساتھ حاضر ہوئی ‘ میں اس وقت ایک زرد رنگ کی قمیص پہنے ہوئے تھی۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا ”سنہ سنہ“ عبداللہ نے کہا یہ لفظ حبشی زبان میں عمدہ کے معنے میں بولا جاتا ہے۔ انہوں نے بیان کیا کہ پھر میں مہر نبوت کے ساتھ ( جو آپ کے پشت پر تھی ) کھیلنے لگی تو میرے والد نے مجھے ڈانٹا ‘ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے مت ڈانٹو ‘ پھر آپ صلی اللہ علیہ وسلم نے ام خالد کو ( درازی عمر کی ) دعا دی کہ اس قمیص کو خوب پہن اور پرانی کر ‘ پھر پہن اور پرانی کر ‘ اور پھر پہن اور پرانی کر ‘ عبداللہ نے کہا کہ چنانچہ یہ قمیص اتنے دنوں تک باقی رہی کہ زبانوں پر اس کا چرچا آ گیا۔' WHERE id = 2946;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا ‘ کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے زہری نے بیان کیا کہ سائب بن یزید رضی اللہ عنہ نے کہا ‘ ( جب رسول اللہ صلی اللہ علیہ وسلم غزوہ تبوک سے واپس تشریف لا رہے تھے تو ) ہم سب بچے ثنیۃ الوداع تک آپ صلی اللہ علیہ وسلم کا استقبال کرنے گئے تھے۔' WHERE id = 2957;
UPDATE hadiths SET urdu = 'ہم سے ابونعمان نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ابوحمزہ ضبعی نے بیان کیا ‘ انہوں نے ابن عباس رضی اللہ عنہما سے سنا ‘ وہ بیان کرتے تھے کہ قبیلہ عبدالقیس کا وفد ( دربار رسالت میں ) حاضر ہوا اور عرض کی یا رسول اللہ! ہمارا تعلق قبیلہ ربیعہ سے ہے اور قبیلہ مضر کے کفار ہمارے اور آپ کے بیچ میں بستے ہیں۔ ( اس لیے ان کے خطرے کی وجہ سے ہم لوگ ) آپ کی خدمت میں صرف ادب والے مہینوں میں حاضر ہو سکتے ہیں۔ آپ ہمیں کوئی ایسا واضح حکم فرما دیں جس پر ہم خود بھی مضبوطی سے قائم رہیں اور جو لوگ ہمارے ساتھ نہیں آ سکے ہیں انہیں بھی بتا دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا میں تمہیں چار چیزوں کا حکم دیتا ہوں اور چار چیزوں سے روکتا ہوں ( میں تمہیں حکم دیتا ہوں ) اللہ پر ایمان لانے کا کہ اللہ کے سوا اور کوئی معبود نہیں اور آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ کو گرہ لگائی ‘ نماز قائم کرنے کا ‘ زکوٰۃ دینے کا ‘ رمضان کے روزے رکھنے کا ‘ اور اس بات کا کہ جو کچھ بھی تمہیں غنیمت کا مال ملے۔ اس میں پانچواں حصہ ( خمس ) اللہ کے لیے نکال دو اور تمہیں میں دبا ‘ نقیر ‘ حنتم اور مزفت کے استعمال سے روکتا ہوں۔' WHERE id = 2968;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم کو امام مالک بن انس نے خبر دی ‘ انہیں عبداللہ بن ابی بکر نے ‘ انہیں عمرہ بنت عبدالرحمٰن نے اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ان کے گھر میں موجود تھے۔ اچانک انہوں نے سنا کہ کوئی صاحب حفصہ رضی اللہ عنہا کے گھر میں اندر آنے کی اجازت مانگ رہے ہیں۔ ( عائشہ رضی اللہ عنہا نے بیان کیا کہ ) میں نے عرض کیا: یا رسول اللہ! آپ دیکھتے نہیں، یہ شخص گھر میں جانے کی اجازت مانگ رہا ہے۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ میرا خیال ہے یہ فلاں صاحب ہیں، حفصہ رضی اللہ عنہا کے رضاعی چچا! رضاعت بھی ان تمام چیزوں کو حرام کر دیتی ہے جنہیں ولادت حرام کرتی ہے۔' WHERE id = 2978;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا ‘ ان سے اعمش نے ‘ ان سے ابوسالم نے ‘ ان سے ابوالجعد نے اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ ہمارے قبیلہ میں ایک شخص کے یہاں بچہ پیدا ہوا ‘ تو انہوں نے اس کا نام قاسم رکھا ‘ انصار کہنے لگے کہ ہم تمہیں ابوالقاسم کہہ کر کبھی نہیں پکاریں گے اور ہم تمہاری آنکھ ٹھنڈی نہیں کریں گے یہ سن کر وہ انصاری آپ صلی اللہ علیہ وسلم کے پاس آیا اور عرض کی یا رسول اللہ! میرے گھر ایک بچہ پیدا ہوا ہے۔ میں نے اس کا نام قاسم رکھا ہے تو انصار کہتے ہیں ہم تیری کنیت ابوالقاسم نہیں پکاریں گے اور تیری آنکھ ٹھنڈی نہیں کریں گے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”انصار نے ٹھیک کہا ہے میرے نام پر نام رکھو ‘ لیکن میری کنیت مت رکھو ‘ کیونکہ قاسم میں ہوں۔“' WHERE id = 2988;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا ‘ کہا ہم کو عبدالرحمٰن بن مہدی نے خبر دی ‘ انہیں امام مالک نے ‘ انہیں زید بن اسلم نے ‘ انہیں ان کے والد نے کہ عمر رضی اللہ عنہ نے فرمایا ”اگر مسلمانوں کی آنے والی نسلوں کا خیال نہ ہوتا تو جو شہر بھی فتح ہوتا میں اسے فاتحوں میں اسی طرح تقسیم کر دیا کرتا جس طرح نبی کریم صلی اللہ علیہ وسلم نے خیبر کی تقسیم کی تھی۔“' WHERE id = 2998;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے ‘ کہا ہم سے محمد بن منکدر نے ‘ اور انہوں نے جابر رضی اللہ عنہ سے سنا ‘ آپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ جب بحرین سے وصول ہو کر میرے پاس مال آئے گا تو میں تمہیں اس طرح اس طرح ‘ اس طرح ( تین لپ ) دوں گا اس کے بعد آپ صلی اللہ علیہ وسلم کی وفات ہو گئی اور بحرین کا مال اس وقت تک نہ آیا۔ پھر جب وہاں سے مال آیا تو ابوبکر رضی اللہ عنہ کے حکم سے منادی نے اعلان کیا کہ جس کا بھی نبی کریم صلی اللہ علیہ وسلم پر کوئی قرض ہو یا آپ کا کوئی وعدہ ہو تو ہمارے پاس آئے۔ میں ابوبکر رضی اللہ عنہ کی خدمت میں گیا اور عرض کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے یہ فرمایا تھا۔ چنانچہ انہوں نے تین لپ بھر کر مجھے دیا۔ سفیان بن عیینہ نے اپنے دونوں ہاتھوں سے اشارہ کر کے ( لپ بھرنے کی ) کیفیت بتائی پھر ہم سے سفیان نے بیان کیا کہ ابن منکدر نے بھی ہم سے اسی طرح بیان کیا تھا۔ اور ایک مرتبہ سفیان نے ( سابقہ سند کے ساتھ ) بیان کیا کہ جابر رضی اللہ عنہ نے کہا کہ میں ابوبکر رضی اللہ عنہ کی خدمت میں حاضر ہوا تو انہوں نے مجھے کچھ نہیں دیا۔ پھر میں حاضر ہوا ‘ اور اس مرتبہ بھی مجھے انہوں نے کچھ نہیں دیا۔ پھر میں تیسری مرتبہ حاضر ہوا اور عرض کیا کہ میں نے ایک مرتبہ آپ سے مانگا اور آپ نے عنایت نہیں فرمایا۔ دوبارہ مانگا ‘ پھر بھی آپ نے عنایت نہیں فرمایا اور پھر مانگا لیکن آپ نے عنایت نہیں فرمایا۔ اب یا آپ مجھے دیجئیے یا پھر میرے بارے میں بخل سے کام لیجئے، ابوبکر رضی اللہ عنہ نے فرمایا کہ تم کہتے ہو کہ میرے معاملے میں بخل سے کام لیتا ہے۔ حالانکہ تمہیں دینے سے جب بھی میں نے منہ پھیرا تو میرے دل میں یہ بات ہوتی تھی کہ تمہیں کبھی نہ کبھی دینا ضرور ہے۔، سفیان نے بیان کیا کہ ہم سے عمرو نے بیان کیا ‘ ان سے محمد بن علی نے اور ان سے جابر نے ‘ پھر ابوبکر رضی اللہ عنہ نے مجھے ایک لپ بھر کر دیا اور فرمایا کہ اسے شمار کر میں نے شمار کیا تو پانچ سو کی تعداد تھی ‘ اس کے بعد ابوبکر رضی اللہ عنہ نے فرمایا کہ اتنا ہی دو مرتبہ اور لے لے۔ اور ابن المنکدر نے بیان کیا ( کہ ابوبکر رضی اللہ عنہ نے فرمایا تھا ) بخل سے زیادہ بدترین اور کیا بیماری ہو سکتی ہے۔' WHERE id = 3009;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے زہری نے بیان کیا، کہا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ جب اللہ تعالیٰ نے اپنے رسول کو قبیلہ ہوازن کے اموال میں سے غنیمت دی اور آپ صلی اللہ علیہ وسلم قریش کے بعض آدمیوں کو ( تالیف قلب کی غرض سے ) سو سو اونٹ دینے لگے تو بعض انصاری لوگوں نے کہا اللہ تعالیٰ رسول اللہ صلی اللہ علیہ وسلم کی بخشش کرے۔ آپ قریش کو تو دے رہے ہیں اور ہمیں چھوڑ دیا۔ حالانکہ ان کا خون ابھی تک ہماری تلواروں سے ٹپک رہا ہے۔ ( قریش کے لوگوں کو حال ہی میں ہم نے مارا، ان کے شہر کو ہم ہی نے فتح کیا ) انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو جب یہ خبر پہنچی تو آپ صلی اللہ علیہ وسلم نے انصار کو بلایا اور انہیں چمڑے کے ایک ڈیرے میں جمع کیا، ان کے سوا کسی دوسرے صحابی کو آپ صلی اللہ علیہ وسلم نے نہیں بلایا۔ جب سب انصاری لوگ جمع ہو گئے تو آپ صلی اللہ علیہ وسلم بھی تشریف لائے اور دریافت فرمایا کہ آپ لوگوں کے بارے میں جو بات مجھے معلوم ہوئی وہ کہاں تک صحیح ہے؟ انصار کے سمجھ دار لوگوں نے عرض کیا: یا رسول اللہ! ہم میں جو عقل والے ہیں، وہ تو کوئی ایسی بات زبان پر نہیں لائے ہیں، ہاں چند نوعمر لڑکے ہیں، انہوں نے یہ کہا ہے کہ اللہ رسول اللہ صلی اللہ علیہ وسلم کی بخشش کرے، آپ صلی اللہ علیہ وسلم قریش کو تو دے رہے ہیں اور ہم کو نہیں دیتے حالانکہ ہماری تلواروں سے ابھی تک ان کے خون ٹپک رہے ہیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں بعض ایسے لوگوں کو دیتا ہوں جن کا کفر کا زمانہ ابھی گزرا ہے۔ ( اور ان کو دے کر ان کا دل ملاتا ہوں ) کیا تم اس پر خوش نہیں ہو کہ جب دوسرے لوگ مال و دولت لے کر واپس جا رہے ہوں گے، تو تم لوگ اپنے گھروں کو رسول اللہ کو لے کر واپس جا رہے ہو گے۔ اللہ کی قسم! تمہارے ساتھ جو کچھ واپس جا رہا ہے وہ اس سے بہتر ہے جو دوسرے لوگ اپنے ساتھ واپس لے جائیں گے۔ سب انصاریوں نے کہا: بیشک یا رسول اللہ! ہم اس پر راضی اور خوش ہیں۔ پھر آپ صلی اللہ علیہ وسلم نے ان سے فرمایا ”میرے بعد تم یہ دیکھو گے کہ تم پر دوسرے لوگوں کو مقدم کیا جائے گا، اس وقت تم صبر کرنا، ( دنگا فساد نہ کرنا ) یہاں تک کہ اللہ تعالیٰ سے جا ملو اور اس کے رسول سے حوض کوثر پر۔“ انس رضی اللہ عنہ نے بیان کیا، پھر ہم سے صبر نہ ہو سکا۔' WHERE id = 3019;
UPDATE hadiths SET urdu = 'ہم سے سہل بن بکار نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، ان سے عمرو بن یحییٰ نے، ان سے عباس ساعدی نے اور ان سے ابو حمید ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہم غزوہ تبوک میں شریک تھے۔ ایلہ کے حاکم ( یوحنا بن روبہ ) نے نبی کریم صلی اللہ علیہ وسلم کو ایک سفید خچر بھیجا اور آپ صلی اللہ علیہ وسلم نے اسے ایک چادر بطور خلعت کے اور ایک تحریر کے ذریعہ اس کے ملک پر اسے ہی حاکم باقی رکھا۔' WHERE id = 3031;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا، کہا ہم کو وکیع نے خبر دی، انہیں اعمش نے، انہیں ابراہیم تیمی نے، ان سے ان کے باپ (یزید بن شریک تیمی) نے بیان کیا کہ علی رضی اللہ عنہ نے ہمارے سامنے خطبہ دیا، جس میں فرمایا کہ کتاب اللہ اور اس ورق میں جو کچھ ہے، اس کے سوا اور کوئی کتاب ( احکام شریعت کی ) ایسی ہمارے پاس نہیں جسے ہم پڑھتے ہوں، پھر آپ نے فرمایا کہ اس میں زخموں کے قصاص کے احکام ہیں اور دیت میں دئیے جانے والے کی عمر کے احکام ہیں اور یہ کہ مدینہ حرم ہے عیر پہاڑی سے فلاں ( احد پہاڑی ) تک۔ اس لیے جس شخص نے کوئی نئی بات ( شریعت کے اندر داخل کی ) یا کسی ایسے شخص کو پناہ دی تو اس پر اللہ، ملائکہ اور انسان سب کی لعنت ہے، نہ اس کی کوئی فرض عبادت قبول ہو گی اور نہ نفل۔ اور یہ بیان ہے جو لونڈی غلام اپنے مالک کے سوا کسی دوسرے کو مالک بنائے اس پر بھی اس طرح ( لعنت ) ہے۔ اور مسلمان مسلمان سب برابر ہیں ہر ایک کا ذمہ یکساں ہے۔ پس جس شخص نے کسی مسلمان کی پناہ میں ( جو کسی کافر کو دی گئی ہو ) دخل اندازی کی تو اس پر بھی اسی طرح لعنت ہے۔' WHERE id = 3041;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے یحییٰ بن آدم نے، ان سے یزید بن عبدالعزیز نے، ان سے ان کے باپ عبدالعزیز بن سیاہ نے، ان سے حبیب بن ابی ثابت نے بیان کیا، کہا کہ مجھ سے ابووائل نے بیان کیا کہ ہم مقام صفین میں ڈیرے ڈالے ہوئے تھے۔ پھر سہل بن حنیف رضی اللہ عنہ کھڑے ہوئے اور فرمایا اے لوگو! تم خود اپنی رائے کو غلط سمجھو۔ ہم صلح حدیبیہ کے موقع پر رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے، اگر ہمیں لڑنا ہوتا تو اس وقت ضرور لڑتے۔ عمر رضی اللہ عنہ اس موقع پر آئے ( یعنی حدیبیہ میں ) اور عرض کیا، یا رسول اللہ! کیا ہم حق پر اور وہ باطل پر نہیں ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیوں نہیں! عمر رضی اللہ عنہ نے کہا کیا ہمارے مقتول جنت میں اور ان کے مقتول جہنم میں نہیں جائیں گے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، کہ کیوں نہیں! پھر عمر رضی اللہ عنہ نے کہا کہ پھر ہم اپنے دین کے معاملے میں کیوں دبیں؟ کیا ہم ( مدینہ ) واپس چلے جائیں گے، اور ہمارے اور ان کے درمیان اللہ کوئی فیصلہ نہیں کرے گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ابن خطاب! میں اللہ کا رسول ہوں اور اللہ مجھے کبھی برباد نہیں کرے گا۔“ اس کے بعد عمر رضی اللہ عنہ ابوبکر رضی اللہ عنہ کے پاس گئے اور ان سے وہی سوالات کئے، جو نبی کریم صلی اللہ علیہ وسلم سے ابھی کر چکے تھے۔ انہوں نے بھی یہی کہا کہ آپ صلی اللہ علیہ وسلم اللہ کے رسول ہیں، اور اللہ انہیں کبھی برباد نہیں ہونے دے گا۔ پھر سورۃ فتح نازل ہوئی اور آپ صلی اللہ علیہ وسلم نے عمر رضی اللہ عنہ کو اسے آخر تک پڑھ کر سنایا، تو عمر رضی اللہ عنہ نے عرض کیا کیا یہی فتح ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں! بلا شک یہی فتح ہے۔' WHERE id = 3051;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے مغیرہ بن عبدالرحمٰن قرشی نے بیان کیا، انہوں نے کہا کہ ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی ‌اللہ ‌علیہ ‌وسلم نے فرمایا ” جب اللہ تعالیٰ مخلوق کو پیدا کر چکا تو اپنی کتاب (لوح محفوظ) میں ، جو اس کے پاس عرش پر موجود ہے ، اس نے لکھا کہ میری رحمت میرے غصہ پر غالب ہے ۔ “' WHERE id = 3062;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے اسماعیل ابی خالد نے بیان کیا، کہا کہ ہم سے قیس بن ابی حازم نے بیان کیا اور ان سے ابومسعود انصاری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سورج اور چاند میں کسی کی موت یا حیات پر گرہن نہیں لگتا۔ بلکہ یہ اللہ کی نشانیوں میں سے نشانی ہیں اس لیے جب تم ان میں گرہن دیکھو تو نماز پڑھو۔“' WHERE id = 3072;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم کو وہب بن جریر نے خبر دی، ان سے میرے والد نے بیان کیا، انہوں نے کہا کہ میں نے حمید بن ہلال سے سنا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جیسے وہ غبار میری نظروں کے سامنے ہے۔ موسیٰ نے روایت میں یوں زیادتی کی کہ جبرائیل علیہ السلام کے ( ساتھ آنے والے ) سوار فرشتوں کی وجہ سے۔ جو غبار خاندان بنو غنم کی گلی سے اٹھا تھا۔' WHERE id = 3082;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو مخلد بن یزید نے خبر دی، کہا ہم کو ابن جریج نے خبر دی، انہیں اسماعیل بن امیہ نے، ان سے نافع نے بیان کیا، ان سے قاسم بن محمد نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے ایک تکیہ بھرا، جس پر تصویریں بنی ہوئی تھیں۔ وہ ایسا ہو گیا جیسے نقشی تکیہ ہوتا ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو دروازے پر کھڑے ہو گئے اور آپ کے چہرے کا رنگ بدلنے لگا۔ میں نے عرض کیا، یا رسول اللہ صلی اللہ علیہ وسلم ! ہم سے کیا غلطی ہوئی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ تکیہ کیسا ہے؟ میں نے عرض کیا، یہ تو میں نے آپ کے لیے بنایا ہے تاکہ آپ اس پر ٹیک لگا سکیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا، کیا تمہیں نہیں معلوم کہ فرشتے اس گھر میں داخل نہیں ہوتے جس میں کوئی تصویر ہوتی ہے اور یہ کہ جو شخص بھی تصویر بنائے گا، قیامت کے دن اسے اس پر عذاب دیا جائے گا۔ اس سے کہا جائے گا کہ جس کی مورت تو نے بنائی، اب اسے زندہ بھی کر کے دکھا۔' WHERE id = 3092;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن اسماعیل نے بیان کیا، کہا ہم سے محمد بن عبداللہ انصاری نے بیان کیا، ان سے ابن عون نے، کہا ہم کو قاسم نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جس نے یہ گمان کیا کہ محمد صلی اللہ علیہ وسلم نے اپنے رب کو دیکھا تھا تو اس نے بڑی جھوٹی بات زبان سے نکالی، لیکن آپ صلی اللہ علیہ وسلم نے جبرائیل علیہ السلام کو ( معراج کی رات میں ) ان کی اصل صورت میں دیکھا تھا۔ ان کے وجود نے آسمان کا کنارہ ڈھانپ لیا تھا۔' WHERE id = 3102;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ کا ارشاد ہے کہ میں نے اپنے نیک بندوں کے لیے وہ چیزیں تیار کر رکھی ہیں، جنہیں نہ آنکھوں نے دیکھا، نہ کانوں نے سنا اور نہ کسی انسان کے دل میں ان کا کبھی خیال گزرا ہے۔ اگر جی چاہے تو یہ آیت پڑھ لو «فلا تعلم نفس ما أخفي لهم من قرة أعين» ”پس کوئی شخص نہیں جانتا کہ اس کی آنکھوں کی ٹھنڈک کے لیے کیا کیا چیزیں چھپا کر رکھی گئی ہیں۔“' WHERE id = 3112;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھ سے امام مالک بن انس نے بیان کیا، ان سے صفوان بن سلیم نے، ان سے عطاء بن یسار نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جنتی لوگ اپنے سے بلند کمرے والوں کو اوپر اسی طرح دیکھیں گے جیسے چمکتے ستارے کو جو صبح کے وقت رہ گیا ہو، آسمان کے کنارے پورب یا پچھم میں دیکھتے ہیں۔ ان میں ایک دوسرے سے افضل ہو گا۔“ لوگوں نے عرض کیا: یا رسول اللہ! یہ تو انبیاء کے محل ہوں گے جنہیں ان کے سوار اور کوئی نہ پا سکے گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں، اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے۔ یہ ان لوگوں کے لیے ہوں گے جو اللہ تعالیٰ پر ایمان لائے اور انبیاء کی تصدیق کی۔' WHERE id = 3123;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، انہوں نے عطاء سے سنا، انہوں نے صفوان بن یعلیٰ سے خبر دی۔ انہوں نے اپنے والد کے واسطہ سے انہوں نے نبی کریم صلی اللہ علیہ وسلم کو منبر پر اس طرح آیت پڑھتے سنا «ونادوا يا مالك» ( اور وہ دوزخی پکاریں گے، اے مالک! ) ۔' WHERE id = 3133;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، کہا ہم سے عمرو بن دینار نے، کہا کہ مجھے سعید بن جبیر نے خبر دی، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا ( نوف بکالی کہتا ہے کہ خضر کے پاس جو موسیٰ گئے تھے وہ دوسرے موسیٰ تھے ) تو انہوں نے کہا کہ ہم سے ابی بن کعب نے بیان کیا، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ موسیٰ علیہ السلام نے اپنے رفیق سفر ( یوشع بن نون ) سے فرمایا کہ ہمارا کھانا لا، اس پر انہوں نے بتایا کہ آپ کو معلوم بھی ہے جب ہم نے چٹان پر پڑاؤ ڈالا تھا تو میں مچھلی وہیں بھول گیا ( اور اپنے ساتھ نہ لا سکا ) اور مجھے اسے یاد رکھنے سے صرف شیطان نے غافل رکھا اور موسیٰ علیہ السلام نے اس وقت تک کوئی تھکن معلوم نہیں کی جب تک اس حد سے نہ گزر لیے، جہاں کا اللہ تعالیٰ نے حکم دیا تھا۔' WHERE id = 3144;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا کہ لیث بن سعد نے کہا کہ مجھ سے خالد بن یزید نے بیان کیا، ان سے سعید بن ابی ہلال نے، ان سے ابوالاسود نے، انہیں عروہ نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ فرشتے بادل میں آپس میں کسی امر میں جو زمین میں ہونے والا ہوتا ہے باتیں کرتے ہیں۔ «عنان» سے مراد بادل ہے۔ تو شیاطین اس میں سے کوئی ایک کلمہ سن لیتے ہیں اور وہی کاہنوں کے کان میں اس طرح لا کر ڈالتے ہیں جیسے شیشے کا منہ ملا کر اس میں کچھ چھوڑتے ہیں اور وہ کاہن اس میں سو جھوٹ اپنی طرف سے ملاتے ہیں۔' WHERE id = 3154;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عبدالرحمٰن بن عبداللہ بن عبدالرحمٰن بن ابی صعصعہ نے، ان سے ان کے والد نے، اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ایک زمانہ آئے گا جب مسلمان کا سب سے عمدہ مال اس کی وہ بکریاں ہوں گی جنہیں وہ پہاڑ کی چوٹیوں اور بارش کی وادیوں میں لے کر چلا جائے گا تاکہ اس طرح اپنے دین و ایمان کو فتنوں سے بچا لے۔“' WHERE id = 3165;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے معمر نے بیان کیا، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پانچ جانور موذی ہیں، انہیں حرم میں بھی مارا جا سکتا ہے چوہا، بچھو، چیل، کوا اور کاٹ لینے والا کتا۔“' WHERE id = 3177;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے یحییٰ نے بیان کیا، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص کتا پالے، اس کے عمل نیک میں سے روزانہ ایک قیراط ( ثواب ) کم کر دیا جاتا ہے، کھیت کے لیے یا مویشی کے لیے جو کتے پالے جائیں وہ اس سے الگ ہیں۔“' WHERE id = 3187;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، کہا ہم سے خالد بن حارث نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوعمران جونی نے اور ان سے انس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کہ اللہ تعالیٰ ( قیامت کے دن ) اس شخص سے پوچھے گا جسے دوزخ کا سب سے ہلکا عذاب کیا گیا ہو گا۔ اگر دنیا میں تمہاری کوئی چیز ہوتی تو کیا تو اس عذاب سے نجات پانے کے لیے اسے بدلے میں دے سکتا تھا؟ وہ شخص کہے گا کہ جی ہاں اس پر اللہ تعالیٰ فرمائے گا کہ جب تو آدم کی پیٹھ میں تھا تو میں نے تجھ سے اس سے بھی معمولی چیز کا مطالبہ کیا تھا ( روز ازل میں ) کہ میرا کسی کو بھی شریک نہ ٹھہرانا، لیکن ( جب تو دنیا میں آیا تو ) اسی شرک کا عمل اختیار کیا۔' WHERE id = 3197;
UPDATE hadiths SET urdu = '(امام بخاری رحمہ اللہ نے کہا) کہ ابن کثیر نے بیان کیا، ان سے سفیان ثوری نے، ان سے ان کے والد نے، ان سے ابن ابی نعیم نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ علی رضی اللہ عنہ نے ( یمن سے ) نبی کریم صلی اللہ علیہ وسلم کی خدمت میں کچھ سونا بھیجا تو آپ صلی اللہ علیہ وسلم نے اسے چار آدمیوں میں تقسیم کر دیا، اقرع بن حابس حنظلی ثم المجاشعی، عیینہ بن بدر فزاری، زید طائی بنی نبہان والے اور علقمہ بن علاثہ عامری بنو کلاب والے، اس پر قریش اور انصار کے لوگوں کو غصہ آیا اور کہنے لگے کہ آپ صلی اللہ علیہ وسلم نے نجد کے بڑوں کو تو دیا لیکن ہمیں نظر انداز کر دیا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں صرف ان کے دل ملانے کے لیے انہیں دیتا ہوں ( کیونکہ ابھی حال ہی میں یہ لوگ مسلمان ہوئے ہیں ) پھر ایک شخص سامنے آیا، اس کی آنکھیں دھنسی ہوئی تھیں، کلے پھولے ہوئے تھے، پیشانی بھی اٹھی ہوئی، ڈاڑھی بہت گھنی تھی اور سر منڈا ہوا تھا۔ اس نے کہا اے محمد! اللہ سے ڈرو آپ صلی اللہ علیہ وسلم نے فرمایا، اگر میں ہی اللہ کی نافرمانی کروں گا تو پھر اس کی فرمانبرداری کون کرے گا؟ اللہ تعالیٰ نے مجھے روئے زمین پر دیانت دار بنا کر بھیجا ہے۔ کیا تم مجھے امین نہیں سمجھتے؟ اس شخص کی اس گستاخی پر ایک صحابی نے اس کے قتل کی اجازت چاہی، میرا خیال ہے کہ یہ خالد بن ولید تھے، لیکن آپ صلی اللہ علیہ وسلم نے انہیں اس سے روک دیا، پھر وہ شخص وہاں سے چلنے لگا تو آپ صلی اللہ علیہ وسلم نے فرمایا اس شخص کی نسل سے یا ( آپ صلی اللہ علیہ وسلم نے فرمایا کہ ) اس شخص کے بعد اسی کی قوم سے ایسے لوگ جھوٹے مسلمان پیدا ہوں گے، جو قرآن کی تلاوت تو کریں گے، لیکن قرآن مجید ان کے حلق سے نیچے نہیں اترے گا، دین سے وہ اس طرح نکل جائیں گے جیسے تیر کمان سے نکل جاتاہے، یہ مسلمانوں کو قتل کریں گے اور بت پرستوں کو چھوڑ دیں گے، اگر میری زندگی اس وقت تک باقی رہے تو میں ان کو اس طرح قتل کروں گا جیسے قوم عاد کا ( عذاب الٰہی سے ) قتل ہوا تھا کہ ایک بھی باقی نہ بچا۔' WHERE id = 3207;
UPDATE hadiths SET urdu = 'ہم سے مؤمل نے بیان کیا، کہا ہم سے اسماعیل نے بیان کیا، کہا ہم سے عوف نے، کہا ہم سے ابورجاء نے، کہا ہم سے سمرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”آج کی رات میرے پاس ( خواب میں ) دو فرشتے ( جبرائیل و میکائیل علیہما السلام ) آئے۔ پھر یہ دونوں فرشتے مجھے ساتھ لے کر ایک لمبے قد کے بزرگ کے پاس گئے، وہ اتنے لمبے تھے کہ ان کا سر میں نہیں دیکھ پاتا تھا اور یہ ابراہیم علیہ السلام تھے۔“' WHERE id = 3217;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے ابراہیم تیمی نے، ان سے ان کے والد یزید بن شریک نے بیان کیا کہ میں نے ابوذر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! سب سے پہلے روئے زمین پر کون سی مسجد بنی ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مسجد الحرام۔ انہوں نے بیان کیا کہ پھر میں نے عرض کیا اور اور اس کے بعد؟ فرمایا کہ مسجد الاقصیٰ ( بیت المقدس ) میں نے عرض کیا، ان دونوں کی تعمیر کے درمیان کتنا فاصلہ رہا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ چالیس سال۔ پھر فرمایا اب جہاں بھی تجھ کو نماز کا وقت ہو جائے وہاں نماز پڑھ لے۔ بڑی فضیلت نماز پڑھنا ہے۔' WHERE id = 3228;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا ‘ کہا ہم سے ابواحمد نے بیان کیا ‘ ان سے سفیان نے بیان کیا ‘ ان سے ابواسحاق نے ‘ ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے «فهل من مدكر‏» پڑھا تھا۔' WHERE id = 3238;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ انہوں نے کہا ہم کو شعیب نے خبر دی ‘ انہوں نے کہا ہم سے ابوالزناد نے بیان کیا ‘ ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے دعا فرمائی «اللهم أنج عياش بن أبي ربيعة،‏‏‏‏ ‏‏‏‏ اللهم أنج سلمة بن هشام،‏‏‏‏ ‏‏‏‏ اللهم أنج الوليد بن الوليد اللهم أنج المستضعفين من المؤمنين،‏‏‏‏ ‏‏‏‏ اللهم اشدد وطأتك على مضر،‏‏‏‏ ‏‏‏‏ اللهم اجعلها سنين كسني يوسف» ”اے اللہ! عیاش بن ابی ربیعہ کو نجات دے ‘ اے اللہ! سلمہ بن ہشام کو نجات دے ‘ اے اللہ! ولید بن ولید کو نجات دے ‘ اے اللہ تمام ضعیف اور کمزور مسلمانوں کو نجات دے۔ اے اللہ! قبیلہ مضر کو سخت گرفت میں پکڑ لے۔ اے اللہ! یوسف علیہ السلام کے زمانے کی سی قحط سالی ان ( ظالموں ) پر نازل فرما۔“' WHERE id = 3248;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے ‘ ان سے عمرو بن یحییٰ نے ‘ ان سے ان کے والد یحییٰ بن عمارہ نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن سب لوگ بیہوش ہو جائیں گے ‘ پھر سب سے پہلے میں ہوش میں آؤں گا اور دیکھوں گا کہ موسیٰ علیہ السلام عرش کے پایوں میں سے ایک پایہ تھامے ہوئے ہیں۔ اب مجھے یہ معلوم نہیں کہ وہ مجھ سے پہلے ہوش میں آ گئے ہوں گے یا ( بیہوش ہی نہیں کئے گئے ہوں گے بلکہ ) انہیں کوہ طور کی بے ہوشی کا بدلہ ملا ہو گا۔“' WHERE id = 3259;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی ‘ ان سے زہری نے بیان کیا ‘ انہیں ابوسلمہ بن عبدالرحمٰن اور سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ مسلمانوں کی جماعت کے ایک آدمی اور یہودیوں میں سے ایک شخص کا جھگڑا ہوا۔ مسلمان نے کہا کہ اس ذات کی قسم جس نے محمد صلی اللہ علیہ وسلم کو ساری دنیا میں برگذیدہ بنایا ‘ قسم کھاتے ہوئے انہوں نے یہ کہا۔ اس پر یہودی نے کہا: قسم ہے اس ذات کی جس نے موسیٰ علیہ السلام کو ساری دنیا میں برگزیدہ بنایا۔ اس پر مسلمان نے اپنا ہاتھ اٹھا کر یہودی کو تھپڑ مار دیا۔ وہ یہودی ‘ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آیا اور اپنے اور مسلمان کے جھگڑے کی آپ صلی اللہ علیہ وسلم کو خبر دی۔ آپ صلی اللہ علیہ وسلم نے اسی موقع پر فرمایا کہ مجھے موسیٰ علیہ السلام پر ترجیح نہ دیا کرو۔ لوگ قیامت کے دن بیہوش کر دئیے جائیں گے اور سب سے پہلے میں ہوش میں آؤں گا پھر دیکھوں گا کہ موسیٰ علیہ السلام عرش کا پایہ پکڑے ہوئے کھڑے ہیں۔ اب مجھے معلوم نہیں کہ وہ بھی بیہوش ہونے والوں میں تھے اور مجھ سے پہلے ہی ہوش میں آ گئے یا انہیں اللہ تعالیٰ نے بیہوش ہونے والوں میں ہی نہیں رکھا تھا۔' WHERE id = 3269;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے ‘ ان سے عمرو بن دینار نے ‘ ان سے عمرو بن اوس ثقفی نے ‘ انہوں نے عبداللہ بن عمرو رضی اللہ عنہما سے سنا ‘ انہوں نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا ”اللہ تعالیٰ کے نزدیک روزے کا سب سے پسندیدہ طریقہ داؤد علیہ السلام کا طریقہ تھا۔ آپ ایک دن روزہ رکھتے اور ایک دن بغیر روزے کے رہتے تھے۔ اسی طرح اللہ تعالیٰ کے نزدیک نماز کا سب سے زیادہ پسندیدہ طریقہ داؤد علیہ السلام کی نماز کا طریقہ تھا ‘ آپ آدھی رات تک سوتے اور ایک تہائی حصے میں عبادت کیا کرتے تھے ‘ پھر بقیہ چھٹے حصے میں بھی سوتے تھے۔“' WHERE id = 3280;
UPDATE hadiths SET urdu = 'ہم سے ابولیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا انہوں نے کہا کہ مجھ سے سعید بن مسیب نے بیان کیا، کہا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”ہر ایک بنی آدم جب پیدا ہوتا ہے تو پیدائش کے وقت شیطان اسے چھوتا ہے اور بچہ شیطان کے چھونے سے زور سے چیختا ہے۔ سوائے مریم اور ان کے بیٹے عیسیٰ علیہما السلام کے۔“ پھر ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ( اس کی وجہ مریم علیہما السلام کی والدہ کی دعا ہے کہ اے اللہ! ) میں اسے ( مریم کو ) اور اس کی اولاد کو شیطان رجیم سے تیری پناہ میں دیتی ہوں۔' WHERE id = 3290;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، کہا ہم سے فلیح بن سلیمان نے بیان کیا، کہا ہم سے ہلال بن علی نے بیان کیا، ان سے عبدالرحمٰن بن ابی عمرہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں عیسیٰ بن مریم علیہما السلام سے اور لوگوں کی بہ نسبت زیادہ قریب ہوں، دنیا میں بھی اور آخرت میں بھی اور انبیاء علیہم السلام علاتی بھائیوں ( کی طرح ) ہیں۔ ان کے مسائل میں اگرچہ اختلاف ہے لیکن دین سب کا ایک ہی ہے۔“ اور ابراہیم بن طہمان نے بیان کیا، ان سے موسیٰ بن عقبہ نے، ان سے صفوان بن سلیم نے، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا۔' WHERE id = 3301;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابوالضحیٰ نے بیان کیا، ان سے مسروق نے بیان کیا کہ عائشہ رضی اللہ عنہا کوکھ پر ہاتھ رکھنے کو ناپسند کرتی تھیں اور فرماتی تھیں کہ اس طرح یہود کرتے ہیں۔' WHERE id = 3313;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے حمید بن عبدالرحمٰن نے اور انہوں نے معاویہ بن ابی سفیان رضی اللہ عنہما سے سنا ایک سال جب وہ حج کے لیے گئے ہوئے تھے تو منبرنبوی پر کھڑے ہو کر انہوں نے پیشانی کے بالوں کا ایک کچھا لیا جو ان کے چوکیدار کے ہاتھ میں تھا اور فرمایا: اے مدینہ والو! تمہارے علماء کدھر گئے میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے۔ آپ صلی اللہ علیہ وسلم نے اس طرح ( بال جوڑنے کی ) ممانعت فرمائی تھی اور فرمایا تھا کہ بنی اسرائیل پر بربادی اس وقت آئی جب ( شریعت کے خلاف ) ان کی عورتوں نے اس طرح بال سنوارنے شروع کر دیئے تھے۔' WHERE id = 3323;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے قتادہ نے ان سے عقبہ بن عبدالغافر نے ان سے ابو سعید خدری رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے کہ گزشتہ امتوں میں ایک آدمی کو اللہ تعالیٰ نے خوب دولت دی تھی۔ جب اس کی موت کا وقت آیا تو اس نے اپنے بیٹوں سے پوچھا میں تمہارے حق میں کیسا باپ ثابت ہوا؟ بیٹوں نے کہا کہ آپ ہمارے بہترین باپ تھے۔ اس شخص نے کہا لیکن میں نے عمر بھر کوئی نیک کام نہیں کیا۔ اس لیے جب میں مر جاؤں تو مجھے جلا ڈالنا، پھر میری ہڈیوں کو پیس ڈالنا اور ( راکھ کو ) کسی سخت آندھی کے دن ہوا میں اڑا دینا۔ بیٹوں نے ایسا ہی کیا۔ لیکن اللہ پاک نے اسے جمع کیا اور پوچھا کہ تو نے ایسا کیوں کیا؟ اس شخص نے عرض کیا کہ پروردگار تیرے ہی خوف سے چنانچہ اللہ تعالیٰ نے اسے اپنے سایہ رحمت میں جگہ دی۔ اس حدیث کو معاذ عنبری نے بیان کیا کہ ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، انہوں نے عقبہ بن عبدالغافر سے سنا، انہوں نے ابو سعید خدری رضی اللہ عنہ سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 3333;
UPDATE hadiths SET urdu = 'ہم سے خالد بن یزید الکاہلی نے بیان کیا، کہا ہم سے ابوبکر بن عیاش نے بیان کیا، ان سے ابوحصین (عثمان بن عاصم) نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے آیت «وجعلناكم شعوبا وقبائل‏» کے متعلق فرمایا کہ «شعوب» بڑے قبیلوں کے معنی میں ہے اور «قبائل» سے کسی بڑے قبیلے کی شاخیں مراد ہیں۔' WHERE id = 3343;
UPDATE hadiths SET urdu = 'اور لیث نے بیان کیا کہ مجھ سے ابوالاسود محمد نے بیان کیا اور ان سے عروہ بن زبیر نے بیان کیا کہ عبداللہ بن زبیر رضی اللہ عنہما بنی زہرہ کے چند لوگوں کے ساتھ عائشہ رضی اللہ عنہا کے پاس گئے۔ عائشہ رضی اللہ عنہا بنی زہرہ کے ساتھ بہت اچھی طرح پیش آتی تھیں کیونکہ ان لوگوں کی رسول اللہ صلی اللہ علیہ وسلم سے قرابت تھی۔' WHERE id = 3355;
UPDATE hadiths SET urdu = 'ہم سے محمد بن غریر زہری نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، ان سے ان کے والد نے، ان سے صالح نے، ان سے نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے منبر پر فرمایا ”قبیلہ غفار کی اللہ تعالیٰ نے مغفرت فرما دی اور قبیلہ اسلم کو اللہ تعالیٰ نے سلامت رکھا اور قبیلہ عصیہ نے اللہ تعالیٰ کی اور اس کے رسول کی نافرمانی کی۔“' WHERE id = 3365;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے ایوب نے، ان سے محمد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قبیلہ اسلم، غفار اور مزینہ اور جہنیہ کے کچھ لوگ یا انہوں نے بیان کیا کہ مزینہ کے کچھ لوگ یا ( بیان کیا کہ ) جہینہ کے کچھ لوگ اللہ تعالیٰ کے نزدیک یا بیان کیا کہ قیامت کے دن قبیلہ اسد، تمیم، ہوازن اور غطفان سے بہتر ہوں گے۔“' WHERE id = 3375;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، کہا ہم سے سلیم نے بیان کیا، کہا ہم سے سعید بن میناء نے بیان کیا اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میری اور دوسرے انبیاء کی مثال ایسی ہے جیسی کسی شخص نے کوئی گھر بنایا، اسے خوب آراستہ پیراستہ کر کے مکمل کر دیا۔ صرف ایک اینٹ کی جگہ خالی چھوڑ دی۔ لوگ اس گھر میں داخل ہوتے اور تعجب کرتے اور کہتے کاش یہ ایک اینٹ کی جگہ خالی نہ رہتی تو کیسا اچھا مکمل گھر ہوتا۔“' WHERE id = 3385;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن علی فلاس نے بیان کیا، کہا ہم سے ابن فضیل نے بیان کیا، کہا ہم سے اسماعیل بن ابی خالد نے بیان کیا، کہا کہ میں نے ابوجحیفہ رضی اللہ عنہ سے سنا۔ وہ بیان کرتے تھے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا ہے، حسن بن علی رضی اللہ عنہما میں آپ کی شباہت پوری طرح موجود تھی۔ اسماعیل بن ابی خالد نے کہا، میں نے ابوجحیفہ رضی اللہ عنہ سے عرض کیا کہ آپ نبی کریم صلی اللہ علیہ وسلم کی صفت بیان کریں۔ انہوں نے کہا آپ سفید رنگ کے تھے، کچھ بال سفید ہو گئے تھے اور آپ نے ہمیں تیرہ اونٹنیوں کے دیئے جانے کا حکم کیا تھا۔ لیکن ابھی ہم نے ان اونٹنیوں کو اپنے قبضہ میں بھی نہیں لیا تھا کہ آپ کی وفات ہو گئی۔' WHERE id = 3395;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے عبداللہ نے بیان کیا، کہا ہم کو یونس نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ سے عبیداللہ بن عبداللہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سب سے زیادہ سخی تھے اور رمضان میں جب آپ صلی اللہ علیہ وسلم سے جبرائیل علیہ السلام کی ملاقات ہوتی تو آپ کی سخاوت اور بھی بڑھ جایا کرتی تھی۔ جبرائیل علیہ السلام رمضان کی ہر رات میں آپ صلی اللہ علیہ وسلم سے ملاقات کے لیے تشریف لاتے اور آپ صلی اللہ علیہ وسلم کے ساتھ قرآن مجید کا دور کرتے۔ اس وقت رسول اللہ صلی اللہ علیہ وسلم خیر و بھلائی کے معاملے میں تیز چلنے والی ہوا سے بھی زیادہ سخی ہو جاتے تھے۔' WHERE id = 3405;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے بکر بن مضر نے بیان کیا، ان سے جعفر بن ربیعہ نے، ان سے اعرج نے، ان سے عبداللہ بن مالک بن بحینہ اسدی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب سجدہ کرتے تو دونوں ہاتھ پیٹ سے الگ رکھتے یہاں تک کہ آپ صلی اللہ علیہ وسلم کی بغلیں ہم لوگ دیکھ لیتے، ابن بکیر نے بکر سے روایت کی اس میں یوں ہے، یہاں تک کہ آپ کی بغلوں کی سفیدی دکھائی دیتی تھی۔' WHERE id = 3416;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالعزیز بن مسلم نے بیان کیا، ان سے حصین نے بیان کیا، ان سے سالم بن ابی الجعد نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ صلح حدیبیہ کے دن لوگوں کو پیاس لگی ہوئی تھی نبی کریم صلی اللہ علیہ وسلم کے سامنے ایک چھاگل رکھا ہوا تھا آپ صلی اللہ علیہ وسلم نے فرمایا کیا بات ہے؟ لوگوں نے کہا کہ جو پانی آپ کے سامنے ہے، اس پانی کے سوا نہ تو ہمارے پاس وضو کے لیے کوئی دوسرا پانی ہے اور نہ پینے کے لیے۔ آپ صلی اللہ علیہ وسلم نے اپنا ہاتھ چھاگل میں رکھ دیا اور پانی آپ صلی اللہ علیہ وسلم کی انگلیوں کے درمیان میں سے چشمے کی طرح پھوٹنے لگا اور ہم سب لوگوں نے اس پانی کو پیا بھی اور اس سے وضو بھی کیا۔ میں نے پوچھا آپ لوگ کتنی تعداد میں تھے؟ کہا کہ اگر ہم ایک لاکھ بھی ہوتے تو وہ پانی کافی ہوتا۔ ویسے ہماری تعداد اس وقت پندرہ سو تھی۔' WHERE id = 3427;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے ابن ابی عدی نے بیان کیا، ان سے شعبہ نے، (دوسری سند) کہا مجھ سے بشر بن خالد نے بیان کیا، کہا ہم سے محمد بن جعفر نے، ان سے شعبہ نے، ان سے سلیمان نے، انہوں نے ابووائل سے سنا، وہ حذیفہ رضی اللہ عنہ سے بیان کرتے تھے کہ عمر بن خطاب رضی اللہ عنہ نے پوچھا: فتنہ کے بارے میں رسول اللہ صلی اللہ علیہ وسلم کی حدیث کس کو یاد ہے؟ حذیفہ رضی اللہ عنہ بولے کہ مجھے زیادہ یاد ہے جس طرح رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا۔ عمر رضی اللہ عنہ نے کہا پھر بیان کرو ( ماشاء اللہ ) تم تو بہت جری ہو۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا: انسان کی ایک آزمائش ( فتنہ ) تو اس کے گھر، مال اور پڑوس میں ہوتا ہے جس کا کفارہ، نماز، روزہ، صدقہ اور امر بالمعروف اور نہی عن المنکر جیسی نیکیاں بن جاتی ہیں۔ عمر رضی اللہ عنہ نے کہا کہ میں اس کے متعلق نہیں پوچھتا، بلکہ میری مراد اس فتنہ سے ہے جو سمندر کی طرح ( ٹھاٹھیں مارتا ) ہو گا۔ انہوں نے کہا اس فتنہ کا آپ پر کوئی اثر نہیں پڑے گا۔ آپ کے اور اس فتنہ کے درمیان بند دروازہ ہے۔ عمر رضی اللہ عنہ نے پوچھا وہ دروازہ کھولا جائے گا یا توڑا جائے گا۔ انہوں نے کہا کہ نہیں بلکہ توڑ دیا جائے گا۔ عمر رضی اللہ عنہ نے اس پر فرمایا کہ پھر تو بند نہ ہو سکے گا۔ ہم نے حذیفہ رضی اللہ عنہ سے پوچھا، کیا عمر رضی اللہ عنہ اس دروازے کے متعلق جانتے تھے؟ انہوں نے فرمایا کہ اسی طرح جانتے تھے جیسے دن کے بعد رات کے آنے کو ہر شخص جانتا ہے۔ میں نے ایسی حدیث بیان کی جو غلط نہیں تھی۔ ہمیں حذیفہ رضی اللہ عنہ سے ( دروازہ کے متعلق ) پوچھتے ہوئے ڈر معلوم ہوا۔ اس لیے ہم نے مسروق سے کہا تو انہوں نے پوچھا کہ وہ دروازہ کون ہیں؟ تو انہوں نے بتایا کہ وہ خود عمر رضی اللہ عنہ ہی ہیں۔' WHERE id = 3437;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم سے شعیب نے خبر دی، انہیں زہری نے، کہا کہ مجھ سے عروہ بن زبیر نے بیان کیا، ان سے زینب بنت ابی سلمہ نے بیان کیا، ان سے ام حبیبہ بنت ابی سفیان رضی اللہ عنہا نے بیان کیا کہ ہم کو زینب بنت ابی جحش رضی اللہ عنہا نے خبر دی کہ ایک دن نبی کریم صلی اللہ علیہ وسلم ان کے گھر تشریف لائے تو آپ صلی اللہ علیہ وسلم بہت پریشان نظر آ رہے تھے اور یہ فرما رہے تھے کہ اللہ تعالیٰ کے سوا اور کوئی معبود نہیں، عرب کے لیے تباہی اس شر سے آئے گی جس کے واقع ہونے کا زمانہ قریب آ گیا ہے۔ آج یاجوج ماجوج کی دیوار میں اتنا شگاف پیدا ہو گیا ہے اور آپ صلی اللہ علیہ وسلم نے انگلیوں سے حلقہ بنا کر اس کی وضاحت کی۔ ام المؤمنین زینب رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! ہم میں نیک لوگ ہوں گے پھر بھی ہم ہلاک کر دیئے جائیں گے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں جب خباثتیں بڑھ جائیں گی ( تو ایسا ہو گا ) ۔' WHERE id = 3448;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ کو ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں موجود تھے اور آپ صلی اللہ علیہ وسلم ( جنگ حنین کا مال غنیمت ) تقسیم فرما رہے تھے اتنے میں بنی تمیم کا ایک شخص ذوالخویصرہ نامی آیا اور کہنے لگا کہ یا رسول اللہ! انصاف سے کام لیجئے۔ یہ سن کر آپ صلی اللہ علیہ وسلم نے فرمایا ”افسوس! اگر میں ہی انصاف نہ کروں تو دنیا میں پھر کون انصاف کرے گا۔ اگر میں ظالم ہو جاؤں تب تو میری بھی تباہی اور بربادی ہو جائے۔“ عمر رضی اللہ عنہ نے عرض کیا یا رسول اللہ! اس کے بارے میں مجھے اجازت دیں میں اس کی گردن مار دوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے چھوڑ دو۔ اس کے جوڑ کے کچھ لوگ پیدا ہوں گے کہ تم اپنے روزوں کو ان کے روزوں کے مقابل ناچیز سمجھو گے۔ وہ قرآن کی تلاوت کریں گے لیکن وہ ان کے حلق کے نیچے نہیں اترے گا۔ یہ لوگ دین سے اس طرح نکل جائیں گے جیسے زور دار تیر جانور سے پار ہو جاتا ہے۔ اس تیر کے پھل کو اگر دیکھا جائے تو اس میں کوئی چیز ( خون وغیرہ ) نظر نہ آئے گی پھر اس کے پٹھے کو اگر دیکھا جائے تو چھڑ میں اس کے پھل کے داخل ہونے کی جگہ سے اوپر جو لگایا جاتا ہے تو وہاں بھی کچھ نہ ملے گا۔ اس کے نفی ( نفی تیر میں لگائی جانے والی لکڑی کو کہتے ہیں ) کو دیکھا جائے تو وہاں بھی کچھ نشان نہیں ملے گا۔ اسی طرح اگر اس کے پر کو دیکھا جائے تو اس میں بھی کچھ نہیں ملے گا۔ حالانکہ گندگی اور خون سے وہ تیر گزرا ہے۔ ان کی علامت ایک کالا شخص ہو گا۔ اس کا ایک بازو عورت کے پستان کی طرح ( اٹھا ہوا ) ہو گا یا گوشت کے لوتھڑے کی طرح ہو گا اور حرکت کر رہا ہو گا۔ یہ لوگ مسلمانوں کے بہترین گروہ سے بغاوت کریں گے۔ ابو سعید خدری رضی اللہ عنہ نے کہا کہ میں گواہی دیتا ہوں کہ میں نے یہ حدیث رسول اللہ صلی اللہ علیہ وسلم سے سنی تھی اور میں گواہی دیتا ہوں کہ علی بن ابی طالب رضی اللہ عنہ نے ان سے جنگ کی تھی ( یعنی خوارج سے ) اس وقت میں بھی علی رضی اللہ عنہ کے ساتھ تھا۔ اور انہوں نے اس شخص کو تلاش کرایا ( جسے آپ صلی اللہ علیہ وسلم نے اس گروہ کی علامت کے طور پر بتلایا تھا ) آخر وہ لایا گیا۔ میں نے اسے دیکھا تو اس کا پورا حلیہ بالکل آپ صلی اللہ علیہ وسلم کے بیان کئے ہوئے اوصاف کے مطابق تھا۔' WHERE id = 3459;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن علاء نے بیان کیا، کہا ہم سے حماد بن اسامہ نے بیان کیا، ان سے برید بن عبداللہ بن ابی بردہ نے، ان سے ان کے دادا ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے، میں سمجھتا ہوں (یہ امام بخاری رحمہ اللہ کا قول ہے کہ) محمد بن علاء نے یوں کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں نے خواب میں دیکھا تھا کہ میں مکہ سے ایک ایسی زمین کی طرف ہجرت کر رہا ہوں جہاں کھجور کے باغات ہیں۔ اس پر میرا ذہن ادھر گیا کہ یہ مقام یمامہ یا ہجر ہو گا۔ لیکن وہ یثرب مدینہ منورہ ہے اور اسی خواب میں میں نے دیکھا کہ میں نے تلوار ہلائی تو وہ بیچ میں سے ٹوٹ گئی۔ یہ اس مصیبت کی طرف اشارہ تھا جو احد کی لڑائی میں مسلمانوں کو اٹھانی پڑی تھی۔ پھر میں نے دوسری مرتبہ اسے ہلایا تو وہ پہلے سے بھی اچھی صورت میں ہو گئی۔ یہ اس واقعہ کی طرف اشارہ تھا کہ اللہ تعالیٰ نے مکہ کی فتح دی اور مسلمان سب اکٹھے ہو گئے۔ میں نے اسی خواب میں گائیں دیکھیں اور اللہ تعالیٰ کا جو کام ہے وہ بہتر ہے۔ ان گایوں سے ان مسلمانوں کی طرف اشارہ تھا جو احد کی لڑائی میں شہید کئے گئے اور خیر و بھلائی وہ تھی جو ہمیں اللہ تعالیٰ نے خیر و سچائی کا بدلہ بدر کی لڑائی کے بعد عطا فرمایا تھا۔“' WHERE id = 3470;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، انہوں نے کہا ہم کو سفیان بن عیینہ نے خبر دی، انہیں ابن ابی نجیح نے، انہیں مجاہد نے، انہیں ابومعمر نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں چاند کے پھٹ کر دو ٹکڑے ہو گئے تھے اور آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ لوگو اس پر گواہ رہنا۔' WHERE id = 3482;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، کہا مجھ سے محمد بن اسماعیل ابن ابی الفدیک نے بیان کیا، ان سے محمد بن عبدالرحمٰن ابن ابی ذئب نے، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! میں نے آپ سے بہت سی احادیث اب تک سنی ہیں لیکن میں انہیں بھول جاتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنی چادر پھیلاؤ، میں نے چادر پھیلا دی اور آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ سے اس میں ایک لپ بھر کر ڈال دی اور فرمایا کہ اسے اپنے بدن سے لگا لو۔ چنانچہ میں نے لگا لیا اور اس کے بعد کبھی کوئی حدیث نہیں بھولا۔' WHERE id = 3493;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم کو حماد بن زید نے خبر دی، انہیں ایوب نے، ان سے عبداللہ بن ابی ملیکہ نے بیان کیا کہ کوفہ والوں نے عبداللہ بن زبیر رضی اللہ عنہما کو دادا (کی میراث کے سلسلے میں) سوال لکھا تو آپ نے انہیں جواب دیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ اگر اس امت میں کسی کو میں اپنا جانی دوست بنا سکتا تو ابوبکر کو بناتا۔ ( وہی ) ابوبکر رضی اللہ عنہ یہ فرماتے تھے کہ دادا، باپ کی طرح ہے ( یعنی جب میت کا باپ زندہ نہ ہو تو باپ کا حصہ دادا کی طرف لوٹ جائے گا۔ یعنی باپ کی جگہ دادا وارث ہو گا ) ۔' WHERE id = 3503;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے مالک نے، ان سے عبدالرحمٰن بن قاسم نے بیان کیا، ان سے ان کے والد نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک سفر میں ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ چلے جب ہم مقام بیداء یا مقام ذات الجیش پر پہنچے تو میرا ایک ہار ٹوٹ کر گر گیا، اس لیے نبی کریم صلی اللہ علیہ وسلم اس کی تلاش کے لیے وہاں ٹھہر گئے اور صحابہ بھی آپ کے ساتھ ٹھہرے لیکن نہ اس جگہ پانی تھا اور نہ ان کے پاس پانی تھا۔ لوگ ابوبکر رضی اللہ عنہ کے پاس آ کر کہنے لگے کہ آپ ملاحظہ نہیں فرماتے، عائشہ رضی اللہ عنہا نے کیا کیا، نبی کریم صلی اللہ علیہ وسلم کو یہیں روک لیا ہے۔ اتنے صحابہ آپ کے ساتھ ہیں۔ نہ تو یہاں پانی ہے اور نہ لوگ اپنے ساتھ ( پانی ) لیے ہوئے ہیں۔ اس کے بعد ابوبکر رضی اللہ عنہ اندر آئے۔ رسول اللہ صلی اللہ علیہ وسلم اس وقت اپنا سر مبارک میری ران پر رکھے ہوئے سو رہے تھے۔ وہ کہنے لگے، تمہاری وجہ سے آپ صلی اللہ علیہ وسلم کو اور سب لوگوں کو رکنا پڑا۔ اب نہ یہاں کہیں پانی ہے اور نہ لوگوں کے پاس پانی ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے مجھ پر غصہ کیا اور جو کچھ اللہ کو منظور تھا انہوں نے کہا اور اپنے ہاتھ سے میری کوکھ میں کچوکے لگانے لگے۔ میں ضرور تڑپ اٹھتی مگر آپ صلی اللہ علیہ وسلم کا سر مبارک میری ران پر تھا۔ آپ صلی اللہ علیہ وسلم سوئے رہے۔ جب صبح ہوئی تو پانی نہیں تھا اور اسی موقع پر اللہ تعالیٰ نے تیمم کا حکم نازل فرمایا اور سب نے تیمم کیا۔ اس پر اسید بن حضیر رضی اللہ عنہ نے کہا کہ اے آل ابوبکر! یہ تمہاری کوئی پہلی برکت نہیں ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر ہم نے جب اس اونٹ کو اٹھایا جس پر میں سوار تھی تو ہار اسی کے نیچے ہمیں ملا۔' WHERE id = 3515;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن نمیر نے بیان کیا، کہا ہم سے محمد بن بشر نے بیان کیا، کہا ہم سے عبیداللہ نے بیان کیا، کہا کہ مجھ سے ابوبکر بن سالم نے بیان کیا، ان سے سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے خواب میں دیکھا کہ میں ایک کنویں سے ایک اچھا بڑا ڈول کھینچ رہا ہوں، جس پر ”لکڑی کا چرخ“ لگا ہوا ہے، پھر ابوبکر آئے اور انہوں نے بھی ایک یا دو ڈول کھینچے مگر کمزوری کے ساتھ اور اللہ ان کی مغفرت کرے۔ پھر عمر آئے اور ان کے ہاتھ میں وہ ڈول ایک بہت بڑے ڈول کی صورت اختیار کر گیا۔ میں نے ان جیسا مضبوط اور باعظمت شخص نہیں دیکھا جو اتنی مضبوطی کے ساتھ کام کر سکتا ہو۔ انہوں نے اتنا کھینچا کہ لوگ سیراب ہو گئے اور اپنے اونٹوں کو پلا کر ان کے ٹھکانوں پر لے گئے۔ ابن جبیر نے کہا کہ «عبقري» کا معنی عمدہ اور «زرابي» اور «عبقري» سردار کو بھی کہتے ہیں ( حدیث میں «عبقري» سے یہی مراد ہے ) یحییٰ بن زیاد فری نے کہا، «زرابي» ان بچھونوں کو کہتے ہیں جن کے حاشیے باریک، پھیلے ہوئے بہت کثرت سے ہوتے ہیں۔' WHERE id = 3525;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا کہا ہم سے اسماعیل بن ابراہیم نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے مسور بن مخرمہ نے بیان کیا کہ جب عمر رضی اللہ عنہ زخمی کر دیئے گئے تو آپ نے بڑی بے چینی کا اظہار کیا۔ اس موقع پر ابن عباس رضی اللہ عنہما نے آپ سے تسلی کے طور پر کہا کہ اے امیرالمؤمنین! آپ اس درجہ گھبرا کیوں رہے ہیں۔ آپ رسول اللہ صلی اللہ علیہ وسلم کی صحبت میں رہے اور نبی کریم صلی اللہ علیہ وسلم کی صحبت کا پورا حق ادا کیا اور پھر جب آپ نبی کریم صلی اللہ علیہ وسلم سے جدا ہوئے تو نبی کریم صلی اللہ علیہ وسلم آپ سے خوش اور راضی تھے، اس کے بعد ابوبکر رضی اللہ عنہ کی صحبت اٹھائی اور ان کی صحبت کا بھی آپ نے پورا حق ادا کیا اور جب جدا ہوئے تو وہ بھی آپ سے راضی اور خوش تھے۔ آخر میں مسلمانوں کی صحبت آپ کو حاصل رہی۔ ان کی صحبت کا بھی آپ نے پورا حق ادا کیا اور اگر آپ ان سے جدا ہوئے تو اس میں کوئی شبہ نہیں کہ انہیں بھی آپ اپنے سے خوش اور راضی ہی چھوڑیں گے۔ اس پر عمر رضی اللہ عنہ نے فرمایا: ابن عباس! تم نے جو رسول اللہ صلی اللہ علیہ وسلم کی صحبت کا اور آپ صلی اللہ علیہ وسلم کی رضا و خوشی کا ذکر کیا ہے تو یقیناً یہ صرف اللہ تعالیٰ کا ایک فضل اور احسان ہے جو اس نے مجھ پر کیا ہے۔ اسی طرح جو تم نے ابوبکر رضی اللہ عنہ کی صحبت اور ان کی خوشی کا ذکر کیا ہے تو یہ بھی اللہ تعالیٰ کا مجھ پر فضل و احسان تھا۔ لیکن جو گھبراہٹ اور پریشانی مجھ پر تم طاری دیکھ رہے ہو وہ تمہاری وجہ سے اور تمہارے ساتھیوں کی فکر کی وجہ سے ہے۔ اور اللہ کی قسم! اگر میرے پاس زمین بھر سونا ہوتا تو اللہ تعالیٰ کے عذاب کا سامنا کرنے سے پہلے اس کا فدیہ دے کر اس سے نجات کی کوشش کرتا۔ حماد بن زید نے بیان کیا، ان سے ایوب نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ میں عمر رضی اللہ عنہ کی خدمت میں حاضر ہوا۔ پھر آخر تک یہی حدیث بیان کی۔' WHERE id = 3535;
UPDATE hadiths SET urdu = '(ہم سے قتیبہ بن سعید نے بیان کیا، ان سے حاتم نے بیان کیا، ان سے یزید بن ابی عبید نے بیان کیا، ان سے سلمہ بن اکوع رضی اللہ عنہ نے بیان کیا کہ علی رضی اللہ عنہ غزوہ خیبر کے موقع پر نبی کریم صلی اللہ علیہ وسلم کے ساتھ بوجہ آنکھ دکھنے کے نہیں آ سکے تھے، پھر انہوں نے سوچا میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ میں شریک نہ ہو سکوں! چنانچہ گھر سے نکلے اور آپ کے لشکر سے جا ملے، جب اس رات کی شام آئی جس کی صبح کو اللہ تعالیٰ نے فتح عنایت فرمائی تھی تو آپ صلی اللہ علیہ وسلم نے فرمایا: کل میں ایک ایسے شخص کو عَلم دوں گا یا آپ صلی اللہ علیہ وسلم نے یوں فرمایا کہ کل ) ایک ایسا شخص عَلم کو لے گا جس سے اللہ اور اس کے رسول کو محبت ہے یا آپ نے یہ فرمایا کہ جو اللہ اور اس کے رسول سے محبت رکھتا ہے اور اللہ تعالیٰ اس کے ہاتھ پر فتح عنایت فرمائے گا، اتفاق سے علی رضی اللہ عنہ آ گئے، حالانکہ ان کے آنے کی ہمیں امید نہیں تھی لوگوں نے بتایا کہ یہ ہیں علی رضی اللہ عنہ۔ آپ صلی اللہ علیہ وسلم نے عَلم انہیں دے دیا، اور اللہ تعالیٰ نے ان کے ہاتھ پر خیبر کو فتح کرا دیا۔' WHERE id = 3545;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے ابن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے ان سے ابن ابی ملیکہ نے ان سے مسور بن مخرمہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ فاطمہ میرے جسم کا ٹکرا ہے، اس لیے جس نے اسے ناحق ناراض کیا، اس نے مجھے ناراض کیا۔' WHERE id = 3556;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ابن ابی زائدہ نے خبر دی، کہا ہم سے ہاشم بن ہاشم بن عتبہ بن ابی وقاص نے بیان کیا، کہا کہ میں نے سعید بن مسیب سے سنا، کہا کہ میں نے سعد بن ابی وقاص سے سنا، انہوں نے کہا کہ جس دن میں اسلام لایا، اسی دن دوسرے ( سب سے پہلے اسلام میں داخل ہونے والے حضرات صحابہ ) بھی اسلام میں داخل ہوئے ہیں اور میں سات دن تک اسی طور پر رہا کہ میں اسلام کا تیسرا فرد تھا۔ ابن ابی زائدہ کے ساتھ اس حدیث کو ابواسامہ نے بھی روایت کیا۔' WHERE id = 3567;
UPDATE hadiths SET urdu = 'ابوعبداللہ (امام بخاری رحمہ اللہ) نے کہا کہ مجھ سے سلیمان بن عبدالرحمٰن نے بیان کیا، کہا ہم سے ولید نے بیان کیا، کہا ہم سے عبدالرحمٰن بن نمر نے بیان کیا، ان سے زہری نے، ان سے اسامہ بن زید رضی اللہ عنہما کے مولیٰ حرملہ نے بیان کیا کہ وہ عبداللہ بن عمر رضی اللہ عنہما کی خدمت میں حاضر تھے کہ حجاج بن ایمن ( مسجد کے ) اندر آئے نہ انہوں نے رکوع پوری طرح ادا کیا تھا اور نہ سجدہ۔ ابن عمر رضی اللہ عنہما نے ان سے فرمایا کہ نماز دوبارہ پڑھ لو۔ پھر جب وہ جانے لگے تو انہوں نے مجھ سے پوچھا کہ یہ کون ہیں؟ میں نے عرض کیا حجاج بن ایمن ابن ام ایمن ہیں۔ اس پر آپ نے کہا اگر انہیں رسول اللہ صلی اللہ علیہ وسلم دیکھتے تو بہت عزیز رکھتے، پھر آپ نے نبی کریم صلی اللہ علیہ وسلم کی اسامہ رضی اللہ عنہ اور ام ایمن رضی اللہ عنہا کی تمام اولاد سے محبت کا ذکر کیا۔ امام بخاری رحمہ اللہ نے بیان کیا کہ مجھ سے میرے بعض اساتذہ نے بیان کیا اور ان سے سلیمان نے کہ ام ایمن رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم کو گود لیا تھا۔' WHERE id = 3577;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن معین اور صدقہ نے بیان کیا، کہا کہ ہمیں محمد بن جعفر نے خبر دی، انہیں شعبہ نے، انہیں واقد بن محمد نے، انہیں ان کے والد نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم ( کی خوشنودی ) کو آپ کے اہل بیت کے ساتھ ( محبت و خدمت کے ذریعہ ) تلاش کرو۔' WHERE id = 3589;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن علاء نے بیان کیا، کہا ہم سے ابراہیم بن یوسف بن ابی اسحٰق نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے ابواسحٰق نے، کہا کہ مجھ سے اسود بن یزید نے بیان کیا، کہا کہ میں نے ابوموسیٰ اشعری رضی اللہ عنہ سے سنا: انہوں نے بیان کیا کہ میں اور میرے بھائی یمن سے ( مدینہ طیبہ ) حاضر ہوئے اور ایک زمانے تک یہاں قیام کیا، ہم اس پورے عرصہ میں یہی سمجھتے رہے کہ عبداللہ بن مسعود رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے گھرانے ہی کے ایک فرد ہیں، کیونکہ نبی کریم صلی اللہ علیہ وسلم کے گھر میں عبداللہ بن مسعود رضی اللہ عنہ اور ان کی والدہ کا ( بکثرت ) آنا جانا ہم خود دیکھا کرتے تھے۔' WHERE id = 3601;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ( نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک غزوہ میں جانے کے لیے ) آپ نے ( اپنی بہن ) اسماء رضی اللہ عنہا سے ایک ہار عاریتاً لے لیا تھا، اتفاق سے وہ راستے میں کہیں گم ہو گیا، نبی کریم صلی اللہ علیہ وسلم نے اسے تلاش کرنے کے لیے چند صحابہ کو بھیجا، اس دوران میں نماز کا وقت ہو گیا تو ان حضرات نے بغیر وضو کے نماز پڑھ لی، پھر جب آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو آپ سے صورت حال کے متعلق عرض کیا۔ اس کے بعد تیمم کی آیت نازل ہوئی۔ اس پر اسید بن حضیر رضی اللہ عنہ نے کہا: تمہیں اللہ تعالیٰ جزائے خیر دے، اللہ کی قسم! تم پر جب بھی کوئی مرحلہ آیا تو اللہ تعالیٰ نے اس سے نکلنے کی سبیل تمہارے لیے پیدا کر دی، اور تمام مسلمانوں کے لیے بھی اس میں برکت پیدا فرمائی۔' WHERE id = 3611;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، مجھے عدی بن ثابت نے خبر دی، کہا کہ میں نے براء رضی اللہ عنہ سے سنا وہ کہتے تھے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا یا یوں بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا انصار سے صرف مومن ہی محبت رکھے گا اور ان سے صرف منافق ہی بغض رکھے گا۔ پس جو شخص ان سے محبت کرے اس سے اللہ محبت کرے گا اور جو ان سے بغض رکھے گا اس سے اللہ تعالیٰ اس سے بغض رکھے گا ( معلوم ہوا کہ انصار کی محبت نشان ایمان ہے اور ان سے دشمنی رکھنا بے ایمان لوگوں کا کام ہے ) ۔' WHERE id = 3621;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ہشام نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے انصار سے فرمایا ”میرے بعد تم دیکھو گے کہ تم پر دوسروں کو فوقیت دی جائے گی، پس تم صبر کرنا یہاں تک کہ مجھ سے آ ملو اور میری تم سے ملاقات حوض پر ہو گی۔“' WHERE id = 3631;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے ابوعوانہ کے داماد فضل بن مساور نے بیان کیا، کہا ہم سے اعمش نے، ان سے ابوسفیان نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ سعد بن معاذ رضی اللہ عنہ کی موت پر عرش ہل گیا اور اعمش سے روایت ہے، ان سے ابوصالح نے بیان کیا اور ان سے جابر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح روایت کیا، ایک صاحب نے جابر رضی اللہ عنہ سے کہا کہ براء رضی اللہ عنہ تو اس طرح بیان کرتے ہیں کہ چارپائی جس پر معاذ رضی اللہ عنہ کی نعش رکھی ہوئی تھی، ہل گئی تھی، جابر رضی اللہ عنہ نے کہا ان دونوں قبیلوں ( اوس اور خزرج ) کے درمیان ( زمانہ جاہلیت میں ) دشمنی تھی، میں نے خود نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے سنا ہے کہ سعد بن معاذ رضی اللہ عنہ کی موت پر عرش رحمن ہل گیا تھا۔' WHERE id = 3641;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ازہر سمان نے بیان کیا، ان سے ابوعوانہ نے، ان سے محمد نے اور ان سے قیس بن عباد نے بیان کیا کہ میں مسجد نبوی میں بیٹھا ہوا تھا کہ ایک بزرگ مسجد میں داخل ہوئے جن کے چہرے پر خشوع و خضوع کے آثار ظاہر تھے لوگوں نے کہا کہ یہ بزرگ جنتی لوگوں میں سے ہیں، پھر انہوں نے دو رکعت نماز مختصر طریقہ پر پڑھی اور باہر نکل گئے میں بھی ان کے پیچھے ہو لیا اور عرض کیا کہ جب آپ مسجد میں داخل ہوئے تھے تو لوگوں نے کہا کہ یہ بزرگ جنت والوں میں سے ہیں، اس پر انہوں نے کہا: اللہ کی قسم! کسی کے لیے ایسی بات زبان سے نکالنا مناسب نہیں ہے جسے وہ نہ جانتا ہو اور میں تمہیں بتاؤں گا کہ ایسا کیوں ہے۔ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں، میں نے ایک خواب دیکھا اور نبی کریم صلی اللہ علیہ وسلم سے اسے بیان کیا میں نے خواب یہ دیکھا تھا کہ جیسے میں ایک باغ میں ہوں، پھر انہوں نے اس کی وسعت اور اس کے سبزہ زاروں کا ذکر کیا اس باغ کے درمیان میں ایک لوہے کا ستون ہے جس کا نچلا حصہ زمین میں ہے اور اوپر کا آسمان پر اور اس کی چوٹی پر ایک گھنا درخت ہے «العروة» مجھ سے کہا گیا کہ اس پر چڑھ جاؤ میں نے کہا کہ مجھ میں تو اتنی طاقت نہیں ہے اتنے میں ایک خادم آیا اور پیچھے سے میرے کپڑے اس نے اٹھائے تو میں چڑھ گیا اور جب میں اس کی چوٹی پر پہنچ گیا تو میں نے اس گھنے درخت کو پکڑ لیا مجھ سے کہا گیا کہ اس درخت کو پوری مضبوطی کے ساتھ پکڑ لے، ابھی میں اسے اپنے ہاتھ سے پکڑے ہوئے تھا کہ میری آنکھ کھل گئی۔ یہ خواب جب میں نے نبی کریم صلی اللہ علیہ وسلم سے بیان کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو باغ تم نے دیکھا ہے، وہ تو اسلام ہے اور اس میں ستون اسلام کا ستون ہے اور «العروة» ( گھنا درخت ) «عروة الوثقى» ہے اس لیے تم اسلام پر مرتے دم تک قائم رہو گے۔ یہ بزرگ عبداللہ بن سلام تھے اور مجھ سے خلیفہ نے بیان کیا ان سے معاذ نے بیان کیا ان سے ابن عون نے بیان کیا ان سے محمد نے ان سے قیس بن عباد نے بیان کیا عبداللہ بن سلام رضی اللہ عنہ سے انہوں نے «منصف‏.» ( خادم ) کے بجائے «وصيف» کا لفظ ذکر کیا۔' WHERE id = 3651;
UPDATE hadiths SET urdu = 'اور قیس سے روایت ہے کہ جریر بن عبداللہ رضی اللہ عنہ نے فرمایا زمانہ جاہلیت میں ”ذوالخلصہ“ نامی ایک بت کدہ تھا اسے «الكعبة اليمانية» یا «الكعبة الشأمية» بھی کہتے تھے، نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا ”ذی الخلصہ کے وجود سے میں جس اذیت میں مبتلا ہوں، کیا تم مجھے اس سے نجات دلا سکتے ہو؟“ انہوں نے بیان کیا کہ پھر قبیلہ احمس کے ڈیڑھ سو سواروں کو میں لے کر چلا، انہوں نے بیان کیا اور ہم نے بت کدے کو ڈھا دیا اور اس میں جو تھے ان کو قتل کر دیا، پھر ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ صلی اللہ علیہ وسلم کو خبر دی تو آپ نے ہمارے لیے اور قبیلہ احمس کے لیے دعا فرمائی۔' WHERE id = 3661;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے کہا کہ عمرو بن دینار بیان کیا کرتے تھے کہ ہم سے سعید بن مسیب نے اپنے والد سے بیان کیا، انہوں نے سعید کے دادا حزن سے بیان کیا کہ زمانہ جاہلیت میں ایک مرتبہ سیلاب آیا کہ ( مکہ کی ) دونوں پہاڑیوں کے درمیان پانی ہی پانی ہو گیا۔ سفیان نے بیان کیا کہ بیان کرتے تھے کہ اس حدیث کا ایک بہت بڑا قصہ ہے۔' WHERE id = 3671;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے کہا، مجھ کو نافع نے خبر دی اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ زمانہ جاہلیت کے لوگ «حبل الحبلة» تک قیمت کی ادائیگی کے وعدہ پر، اونٹ کا گوشت ادھار بیچا کرتے تھے۔ عبداللہ رضی اللہ عنہ نے بیان کیا کہ «حبل الحبلة» کا مطلب یہ ہے کہ کوئی حاملہ اونٹنی اپنا بچہ جنے پھر وہ نوزائیدہ بچہ ( بڑھ کر ) حاملہ ہو، نبی کریم صلی اللہ علیہ وسلم نے اس طرح کی خرید و فروخت ممنوع قرار دے دی تھی۔' WHERE id = 3681;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعیب نے بیان کیا، ان سے ابواسحاق نے، ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے سورۃ النجم پڑھی اور سجدہ کیا اس وقت آپ صلی اللہ علیہ وسلم کے ساتھ تمام لوگوں نے سجدہ کیا صرف ایک شخص کو میں نے دیکھا کہ اپنے ہاتھ میں اس نے کنکریاں اٹھا کر اس پر اپنا سر رکھ دیا اور کہنے لگا کہ میرے لیے بس اتنا ہی کافی ہے۔ میں نے پھر اسے دیکھا کہ کفر کی حالت میں وہ قتل کیا گیا۔' WHERE id = 3691;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن کثیر نے بیان کیا، انہوں نے کہا ہم کو سفیان ثوری نے خبر دی، انہیں اسماعیل بن ابی خالد نے، انہیں قیس بن ابی حازم نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ عمر رضی اللہ عنہ کے اسلام لانے کے بعد ہم لوگ ہمیشہ عزت سے رہے۔' WHERE id = 3701;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، کہا ہم سے ہمارے والد (عروہ بن زبیر) نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ام حبیبہ رضی اللہ عنہا اور ام سلمہ رضی اللہ عنہا نے ایک گرجے کا ذکر کیا جسے انہوں نے حبشہ میں دیکھا تھا اس کے اندر تصویریں تھیں۔ انہوں نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم کے سامنے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا ”جب ان میں کوئی نیک مرد ہوتا اور اس کی وفات ہو جاتی تو اس کی قبر کو وہ لوگ مسجد بناتے اور پھر اس میں اس کی تصویریں رکھتے۔ یہ لوگ قیامت کے دن اللہ تعالیٰ کی بارگاہ میں بدترین مخلوق ہوں گے۔“' WHERE id = 3711;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے، ان سے سفیان ثوری نے، کہا ہم سے عبدالملک بن عمیر نے، ان سے عبداللہ بن حارث نے بیان کیا ان سے عباس بن عبدالمطلب رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا آپ اپنے چچا ( ابوطالب ) کے کیا کام آئے کہ وہ آپ کی حمایت کیا کرتے تھے اور آپ صلی اللہ علیہ وسلم کے لیے غصہ ہوتے تھے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ” ( اسی وجہ سے ) وہ صرف ٹخنوں تک جہنم میں ہیں اگر میں ان کی سفارش نہ کرتا تو وہ دوزخ کی تہ میں بالکل نیچے ہوتے۔“' WHERE id = 3721;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعید نے، ان سے یزید بن ابی حبیب نے، ان سے ابوالخیر مرثد بن عبداللہ نے، ان سے عبدالرحمٰن صنابحی نے اور ان سے عبادہ بن صامت رضی اللہ عنہ نے بیان کیا کہ میں ان نقیبوں میں سے تھا جنہوں نے ( عقبہ کی رات میں ) رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تھی۔ آپ نے بیان کیا کہ ہم نے نبی کریم صلی اللہ علیہ وسلم سے اس کا عہد کیا تھا کہ ہم اللہ کے ساتھ کسی کو شریک نہیں ٹھہرائیں گے، چوری نہیں کریں گے، زنا نہیں کریں گے، کسی ایسے شخص کو قتل نہیں کریں گے جس کا قتل اللہ تعالیٰ نے حرام قرار دیا ہے، لوٹ مار نہیں کریں گے اور نہ اللہ کی نافرمانی کریں گے جنت کے بدلے میں، اگر ہم اپنے عہد میں پورے اترے۔ لیکن اگر ہم نے اس میں کچھ خلاف کیا تو اس کا فیصلہ اللہ پر ہے۔' WHERE id = 3731;
UPDATE hadiths SET urdu = 'مجھ سے مطر بن فضل نے بیان کیا، کہا ہم سے روح بن عبادہ نے بیان کیا، کہا ہم سے زکریا بن اسحاق نے بیان کیا، ان سے عمرو بن دینار نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے نبوت کے بعد مکہ میں تیرہ سال قیام کیا اور جب آپ صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ کی عمر تریسٹھ سال کی تھی۔' WHERE id = 3741;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی انہیں اعمش نے، انہیں ابووائل شقیق بن سلمہ نے اور ان سے خباب رضی اللہ عنہ نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہجرت کی تھی۔' WHERE id = 3751;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ولید بن مسلم دمشقی نے بیان کیا، کہا ہم سے امام اوزاعی نے بیان کیا، (دوسری سند) اور محمد بن یوسف نے بیان کیا کہ ہم سے امام اوزاعی نے بیان کیا، کہا مجھ سے زہری نے بیان کیا، کہا کہ مجھ سے عطاء بن یزید لیثی نے بیان کیا، کہا کہ مجھ سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہا کہ ایک اعرابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ صلی اللہ علیہ وسلم سے ہجرت کا حال پوچھنے لگا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”تجھ پر افسوس! ہجرت تو بہت مشکل ہے۔ تمہارے پاس کچھ اونٹ بھی ہیں؟“ اس نے کہا جی ہاں ہیں۔ فرمایا ”تم اس کی زکوٰۃ ادا کرتے ہو؟“ اس نے عرض کیا جی ہاں ادا کرتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”اونٹنیوں کا دودھ دوسرے ( محتاجوں ) کو بھی دوہنے کے لیے دے دیا کرتے ہو؟“ اس نے عرض کیا کہ ایسا بھی کرتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”انہیں گھاٹ پر لے جا کر ( محتاجوں کے لیے ) دوہتے ہو؟“ اس نے عرض کیا ایسا بھی کرتا ہوں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا ”پھر تم سات سمندر پار عمل کرو، اللہ تعالیٰ تمہارے کسی عمل کا بھی ثواب کم نہیں کرے گا۔“' WHERE id = 3761;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن حمزہ نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے بیان کیا، ان سے عبدالرحمٰن بن حمید زہری نے بیان کیا، انہوں نے خلیفہ عمر بن عبدالعزیز سے سنا، وہ نمر کندی کے بھانجے سائب بن یزید سے دریافت کر رہے تھے کہ تم نے مکہ میں ( مہاجر کے ) ٹھہرنے کے مسئلہ میں کیا سنا ہے؟ انہوں نے بیان کیا کہ میں نے علاء بن حضرمی رضی اللہ عنہ سے سنا وہ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مہاجر کو ( حج میں ) طواف وداع کے بعد تین دن ٹھہرنے کی اجازت ہے۔“' WHERE id = 3771;
UPDATE hadiths SET urdu = 'مجھ سے زیاد بن ایوب نے بیان کیا کہا، ہم سے ہشیم نے بیان کیا کہا، ہم کو ابوبشر (جابر بن ابی وحشیہ) نے خبر دی، انہیں سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہا کہ وہ اہل کتاب ہی تو ہیں جنہوں نے آسمانی کتاب کو ٹکڑے ٹکڑے کر ڈالا، بعض باتوں پر ایمان لائے اور بعض باتوں کا انکار کیا۔' WHERE id = 3782;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہما نے بیان کیا کہ ( بدر کی لڑائی کے موقع پر ) مجھے اور ابن عمر رضی اللہ عنہما کو نابالغ قرار دے دیا گیا تھا۔' WHERE id = 3792;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبداللہ رقاشی نے بیان کیا، ہم سے معتمر نے بیان کیا، کہا کہ میں نے اپنے والد سے سنا، انہوں نے بیان کیا کہ ہم سے ابومجلز نے، ان سے قیس بن عباد نے اور ان سے علی بن ابی طالب رضی اللہ عنہ نے بیان کیا کہ قیامت کے دن میں سب سے پہلا شخص ہوں گا جو اللہ تعالیٰ کے دربار میں جھگڑا چکانے کے لیے دو زانو ہو کر بیٹھے گا۔ قیس بن عباد نے بیان کیا کہ انہیں حضرات ( حمزہ، علی اور عبیدہ رضی اللہ عنہم ) کے بارے میں سورۃ الحج کی یہ آیت نازل ہوئی تھی «هذان خصمان اختصموا في ربهم‏» ”یہ دو فریق ہیں جنہوں نے اللہ کے بارے میں لڑائی کی۔“ بیان کیا کہ یہ وہی ہیں جو بدر کی لڑائی میں لڑنے نکلے تھے، مسلمانوں کی طرف سے حمزہ، علی اور عبیدہ یا ابوعبیدہ بن حارث رضوان اللہ علیہم ( اور کافروں کی طرف سے ) شیبہ بن ربیعہ، عتبہ بن ربیعہ اور ولید بن عتبہ تھے۔' WHERE id = 3803;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا ‘ ہم سے عبداللہ بن مبارک نے بیان کیا ‘ انہیں ہشام بن عروہ نے خبر دی ‘ انہیں ان کے والد نے کہ رسول اللہ صلی اللہ علیہ وسلم کے صحابہ نے زبیر رضی اللہ عنہ سے یرموک کی جنگ میں کہا آپ حملہ کرتے تو ہم بھی آپ کے ساتھ حملہ کرتے انہوں نے کہا کہ اگر میں نے ان پر زور کا حملہ کر دیا تو پھر تم لوگ پیچھے رہ جاؤ گے سب بولے کہ ہم ایسا نہیں کریں گے۔ چنانچہ زبیر رضی اللہ عنہ نے دشمن ( رومی فوج ) پر حملہ کیا اور ان کی صفوں کو چیرتے ہوئے آگے نکل گئے۔ اس وقت ان کے ساتھ کوئی ایک بھی ( مسلمان ) نہیں رہا پھر ( مسلمان فوج کی طرف ) آنے لگے تو رومیوں نے ان کے گھوڑے کی لگام پکڑ لی اور مونڈھے پر دو کاری زخم لگائے، جو زخم بدر کی لڑائی کے موقع پر ان کو لگا تھا وہ ان دونوں زخموں کے درمیان میں پڑ گیا تھا۔ عروہ بن زبیر نے بیان کیا کہ جب میں چھوٹا تھا تو ان زخموں میں اپنی انگلیاں ڈال کر کھیلا کرتا تھا۔ عروہ نے بیان کیا کہ یرموک کی لڑائی کے موقع پر عبداللہ بن زبیر رضی اللہ عنہ بھی ان کے ساتھ گئے تھے، اس وقت ان کی عمر کل دس سال کی تھی اس لیے ان کو ایک گھوڑے پر سوار کر کے ایک صاحب کی حفاظت میں دے دیا تھا۔' WHERE id = 3813;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ہم سے ابراہیم نے بیان کیا، انہیں ابن شہاب نے خبر دی، کہا کہ مجھے عمر بن اسید بن جاریہ ثقفی نے خبر دی جو بنی زہرہ کے حلیف تھے اور ابوہریرہ رضی اللہ عنہ کے شاگردوں میں شامل تھے کہ ابوہریرہ رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے دس جاسوس بھیجے اور ان کا امیر عاصم بن ثابت انصاری رضی اللہ عنہ کو بنایا جو عاصم بن عمر بن خطاب رضی اللہ عنہ کے نانا ہوتے ہیں۔ جب یہ لوگ عسفان اور مکہ کے درمیان مقام ہدہ پر پہنچے تو بنی ہذیل کے ایک قبیلہ کو ان کے آنے کی اطلاع مل گئی۔ اس قبیلہ کا نام بنی لحیان تھا۔ اس کے سو تیرانداز ان صحابہ رضی اللہ عنہم کی تلاش میں نکلے اور ان کے نشان قدم کے اندازے پر چلنے لگے۔ آخر اس جگہ پہنچ گئے جہاں بیٹھ کر ان صحابہ رضی اللہ عنہم نے کھجور کھائی تھی۔ انہوں نے کہا کہ یہ یثرب ( مدینہ ) کی کھجور ( کی گٹھلیاں ) ہیں۔ اب پھر وہ ان کے نشان قدم کے اندازے پر چلنے لگے۔ جب عاصم بن ثابت رضی اللہ عنہ اور ان کے ساتھیوں نے ان کے آنے کو معلوم کر لیا تو ایک ( محفوظ ) جگہ پناہ لی۔ قبیلہ والوں نے انہیں اپنے گھیرے میں لے لیا اور کہا کہ نیچے اتر آؤ اور ہماری پناہ خود قبول کر لو تو تم سے ہم وعدہ کرتے ہیں کہ تمہارے کسی آدمی کو بھی ہم قتل نہیں کریں گے۔ عاصم بن ثابت رضی اللہ عنہ نے کہا۔ مسلمانو! میں کسی کافر کی پناہ میں نہیں اتر سکتا۔ پھر انہوں نے دعا کی، اے اللہ! ہمارے حالات کی خبر اپنے نبی کو کر دے آخر قبیلہ والوں نے مسلمانوں پر تیر اندازی کی اور عاصم رضی اللہ عنہ کو شہید کر دیا۔ بعد میں ان کے وعدہ پر تین صحابہ اتر آئے۔ یہ حضرات خبیب، زید بن دثنہ اور ایک تیسرے صحابی تھے۔ قبیلہ والوں نے جب ان تینوں صحابیوں پر قابو پا لیا تو ان کی کمان سے تانت نکال کر اسی سے انہیں باندھ دیا۔ تیسرے صحابی نے کہا، یہ تمہاری پہلی دغا بازی ہے میں تمہارے ساتھ کبھی نہیں جا سکتا۔ میرے لیے تو انہیں کی زندگی نمونہ ہے۔ آپ کا اشارہ ان صحابہ کی طرف تھا جو ابھی شہید کئے جا چکے تھے۔ کفار نے انہیں گھسیٹنا شروع کیا اور زبردستی کی لیکن وہ کسی طرح ان کے ساتھ جانے پر تیار نہ ہوئے۔ ( تو انہوں نے ان کو بھی شہید کر دیا ) اور خبیب رضی اللہ عنہ اور زید بن دثنہ رضی اللہ عنہ کو ساتھ لے گئے اور ( مکہ میں لے جا کر ) انہیں بیچ دیا۔ یہ بدر کی لڑائی کے بعد کا واقعہ ہے۔ حارث بن عامر بن نوفل کے لڑکوں نے خبیب رضی اللہ کو خرید لیا۔ انہوں ہی نے بدر کی لڑائی میں حارث بن عامر کو قتل کیا تھا۔ کچھ دنوں تک تو وہ ان کے یہاں قید رہے آخر انہوں نے ان کے قتل کا ارادہ کیا۔ انہیں دنوں حارث کی کسی لڑکی سے انہوں نے زیر ناف بال صاف کرنے کے لیے استرہ مانگا۔ اس نے دے دیا۔ اس وقت اس کا ایک چھوٹا سا بچہ ان کے پاس ( کھیلتا ہوا ) اس عورت کی بےخبری میں چلا گیا۔ پھر جب وہ ان کی طرف آئی تو دیکھا کہ بچہ ان کی ران پر بیٹھا ہوا ہے۔ اور استرہ ان کے ہاتھ میں ہے انہوں نے بیان کیا کہ یہ دیکھتے ہی وہ اس درجہ گھبرا گئی کہ خبیب رضی اللہ عنہ نے اس کی گھبراہٹ کو دیکھ لیا اور بولے، کیا تمہیں اس کا خوف ہے کہ میں اس بچے کو قتل کر دوں گا؟ یقین رکھو کہ ایسا ہرگز نہیں کر سکتا۔ ان خاتون نے بیان کیا کہ اللہ کی قسم! میں نے کبھی کوئی قیدی خبیب رضی اللہ عنہ سے بہتر نہیں دیکھا۔ اللہ کی قسم! میں نے ایک دن انگور کے ایک خوشہ سے انہیں انگور کھاتے دیکھا جو ان کے ہاتھ میں تھا حالانکہ وہ لوہے کی زنجیروں میں جکڑے ہوئے تھے اور مکہ میں اس وقت کوئی پھل بھی نہیں تھا۔ وہ بیان کرتی تھیں کہ وہ تو اللہ کی طرف سے بھیجی ہوئی روزی تھی جو اس نے خبیب رضی اللہ عنہ کے لیے بھیجی تھی۔ پھر بنو حارثہ انہیں قتل کرنے کے لیے حرم سے باہر لے جانے لگے تو خبیب رضی اللہ عنہ نے ان سے کہا کہ مجھے دو رکعت نماز پڑھنے کی اجازت دے دو۔ انہوں نے اس کی اجازت دی تو انہوں نے دو رکعت نماز پڑھی اور فرمایا: اللہ کی قسم! اگر تمہیں یہ خیال نہ ہونے لگتا کہ مجھے گھبراہٹ ہے ( موت سے ) تو اور زیادہ دیر تک پڑھتا۔ پھر انہوں نے دعا کی کہ اے اللہ! ان میں سے ہر ایک کو الگ الگ ہلاک کر اور ایک کو بھی باقی نہ چھوڑ اور یہ اشعار پڑھے ”جب میں اسلام پر قتل کیا جا رہا ہوں تو مجھے کوئی پرواہ نہیں کہ اللہ کی راہ میں مجھے کس پہلو پر پچھاڑا جائے گا اور یہ تو صرف اللہ کی رضا حاصل کرنے کے لیے ہے۔ اگر وہ چاہے گا تو میرے جسم کے ایک ایک جوڑ پر ثواب عطا فرمائے گا۔“ اس کے بعد ابوسروعہ عقبہ بن حارث ان کی طرف بڑھا اور اس نے انہیں شہید کر دیا۔ خبیب رضی اللہ عنہ نے اپنے عمل حسن سے ہر اس مسلمان کے لیے جسے قید کر کے قتل کیا جائے ( قتل سے پہلے دو رکعت ) نماز کی سنت قائم کی ہے۔ ادھر جس دن ان صحابہ رضی اللہ عنہم پر مصیبت آئی تھی آپ صلی اللہ علیہ وسلم نے اپنے صحابہ رضی اللہ عنہم کو اسی دن اس کی خبر دے دی تھی۔ قریش کے کچھ لوگوں کو جب معلوم ہوا کہ عاصم بن ثابت رضی اللہ عنہ شہید کر دئیے گئے ہیں تو ان کے پاس اپنے آدمی بھیجے تاکہ ان کے جسم کا کوئی ایسا حصہ لائیں جس سے انہیں پہچانا جا سکے۔ کیونکہ انہوں نے بھی ( بدر میں ) ان کے ایک سردار ( عقبہ بن ابی معیط ) کو قتل کیا تھا لیکن اللہ تعالیٰ نے ان کی لاش پر بادل کی طرح بھڑوں کی ایک فوج بھیج دی اور انہوں نے آپ کی لاش کو کفار قریش کے ان آدمیوں سے بچا لیا اور وہ ان کے جسم کا کوئی حصہ بھی نہ کاٹ سکے اور کعب بن مالک رضی اللہ عنہ نے بیان کیا کہ میرے سامنے لوگوں نے مرارہ بن ربیع عمری رضی اللہ عنہ اور ہلال بن امیہ واقفی رضی اللہ عنہ کا ذکر کیا۔ ( جو غزوہ تبوک میں نہیں جا سکے تھے ) کہ وہ صالح صحابیوں میں سے ہیں اور بدر کی لڑائی میں شریک ہوئے تھے۔' WHERE id = 3825;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، ہم کو شعیب نے خبر دی، انہیں زہری نے کہا کہ مجھے ابوادریس عائذ اللہ بن عبداللہ نے خبر دی اور انہیں عبادہ بن صامت رضی اللہ عنہ نے، وہ بدر کی لڑائی میں شریک ہوئے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ مجھ سے بیعت کرو۔' WHERE id = 3835;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں محمود بن ربیع نے خبر دی کہ عتبان بن مالک رضی اللہ عنہ جو نبی کریم صلی اللہ علیہ وسلم کے صحابی تھے اور وہ بدر میں شریک ہوئے تھے اور انصار میں سے تھے، نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔' WHERE id = 3845;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن منصور نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں محمد بن جبیر نے، ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے میں نے سنا، آپ مغرب کی نماز میں سورۃ والطور کی تلاوت کر رہے تھے، یہ پہلا موقع تھا جب میرے دل میں ایمان نے قرار پکڑا۔' WHERE id = 3857;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے کہا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا کہ میں نے جابر بن عبداللہ انصاری رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کعب بن اشرف کا کام کون تمام کرے گا؟ وہ اللہ اور اس کے رسول کو بہت ستا رہا ہے۔“ اس پر محمد بن مسلمہ انصاری رضی اللہ عنہ کھڑے ہوئے اور عرض کیا: یا رسول اللہ! کیا آپ اجازت دیں گے کہ میں اسے قتل کر آؤں؟ آپ نے فرمایا ”ہاں مجھ کو یہ پسند ہے۔“ انہوں نے عرض کیا، پھر آپ مجھے اجازت عنایت فرمائیں کہ میں اس سے کچھ باتیں کہوں آپ نے انہیں اجازت دے دی۔ اب محمد بن مسلمہ رضی اللہ عنہ کعب بن اشرف کے پاس آئے اور اس سے کہا، یہ شخص ( اشارہ آپ صلی اللہ علیہ وسلم کی طرف تھا ) ہم سے صدقہ مانگتا رہتا ہے اور اس نے ہمیں تھکا مارا ہے۔ اس لیے میں تم سے قرض لینے آیا ہوں۔ اس پر کعب نے کہا، ابھی آگے دیکھنا، خدا کی قسم! بالکل اکتا جاؤ گے۔ محمد بن مسلمہ رضی اللہ عنہ نے کہا، چونکہ ہم نے بھی اب ان کی اتباع کر لی ہے۔ اس لیے جب تک یہ نہ کھل جائے کہ ان کا انجام کیا ہوتا ہے، انہیں چھوڑنا بھی مناسب نہیں۔ تم سے ایک وسق یا ( راوی نے بیان کیا کہ ) دو وسق غلہ قرض لینے آیا ہوں۔ اور ہم سے عمرو بن دینار نے یہ حدیث کئی دفعہ بیان کی لیکن ایک وسق یا دو وسق غلے کا کوئی ذکر نہیں کیا۔ میں نے ان سے کہا کہ حدیث میں ایک یا دو وسق کا ذکر ہے؟ انہوں نے کہا کہ میرا بھی خیال ہے کہ حدیث میں ایک یا دو وسق کا ذکر آیا ہے۔ کعب بن اشرف نے کہا، ہاں، میرے پاس کچھ گروی رکھ دو۔ انہوں نے پوچھا، گروی میں تم کیا چاہتے ہو؟ اس نے کہا، اپنی عورتوں کو رکھ دو۔ انہوں نے کہا کہ تم عرب کے بہت خوبصورت مرد ہو۔ ہم تمہارے پاس اپنی عورتیں کس طرح گروی رکھ سکتے ہیں۔ اس نے کہا، پھر اپنے بچوں کو گروی رکھ دو۔ انہوں نے کہا، ہم بچوں کو کس طرح گروی رکھ سکتے ہیں۔ کل انہیں اسی پر گالیاں دی جائیں گی کہ ایک یا دو وسق غلے پر اسے رہن رکھ دیا گیا تھا، یہ تو بڑی بے غیرتی ہو گی۔ البتہ ہم تمہارے پاس اپنے «اللأمة» گروی رکھ سکتے ہیں۔ سفیان نے کہا کہ مراد اس سے ہتھیار تھے۔ محمد بن مسلمہ رضی اللہ عنہ نے اس سے دوبارہ ملنے کا وعدہ کیا اور رات کے وقت اس کے یہاں آئے۔ ان کے ساتھ ابونائلہ بھی موجود تھے وہ کعب بن اشرف کے رضاعی بھائی تھے۔ پھر اس کے قلعہ کے پاس جا کر انہوں نے آواز دی۔ وہ باہر آنے لگا تو اس کی بیوی نے کہا کہ اس وقت ( اتنی رات گئے ) کہاں باہر جا رہے ہو؟ اس نے کہا، وہ تو محمد بن مسلمہ اور میرا بھائی ابونائلہ ہے۔ عمرو کے سوا ( دوسرے راوی ) نے بیان کیا کہ اس کی بیوی نے اس سے کہا تھا کہ مجھے تو یہ آواز ایسی لگتی ہے جیسے اس سے خون ٹپک رہا ہو۔ کعب نے جواب دیا کہ میرے بھائی محمد بن مسلمہ اور میرے رضاعی بھائی ابونائلہ ہیں۔ شریف کو اگر رات میں بھی نیزہ بازی کے لیے بلایا جائے تو وہ نکل پڑتا ہے۔ راوی نے بیان کیا کہ جب محمد بن مسلمہ اندر گئے تو ان کے ساتھ دو آدمی اور تھے۔ سفیان سے پوچھا گیا کہ کیا عمرو بن دینار نے ان کے نام بھی لیے تھے؟ انہوں نے بتایا کہ بعض کا نام لیا تھا۔ عمرو نے بیان کیا کہ وہ آئے تو ان کے ساتھ دو آدمی اور تھے اور عمرو بن دینار کے سوا ( راوی نے ) ابوعبس بن جبر، حارث بن اوس اور عباد بن بشر نام بتائے تھے۔ عمرو نے بیان کیا کہ وہ اپنے ساتھ دو آدمیوں کو لائے تھے اور انہیں یہ ہدایت کی تھی کہ جب کعب آئے تو میں اس کے ( سر کے ) بال ہاتھ میں لے لوں گا اور اسے سونگھنے لگوں گا۔ جب تمہیں اندازہ ہو جائے کہ میں نے اس کا سر پوری طرح اپنے قبضہ میں لے لیا ہے تو پھر تم تیار ہو جانا اور اسے قتل کر ڈالنا۔ عمرو نے ایک مرتبہ بیان کیا کہ پھر میں اس کا سر سونگھوں گا۔ آخر کعب چادر لپیٹے ہوئے باہر آیا۔ اس کے جسم سے خوشبو پھوٹی پڑتی تھی۔ محمد بن مسلمہ رضی اللہ عنہ نے کہا، آج سے زیادہ عمدہ خوشبو میں نے کبھی نہیں سونگھی تھی۔ عمرو کے سوا ( دوسرے راوی ) نے بیان کیا کہ کعب اس پر بولا، میرے پاس عرب کی وہ عورت ہے جو ہر وقت عطر میں بسی رہتی ہے اور حسن و جمال میں بھی اس کی کوئی نظیر نہیں۔ عمرو نے بیان کیا کہ محمد بن مسلمہ رضی اللہ عنہ نے اس سے کہا، کیا تمہارے سر کو سونگھنے کی مجھے اجازت ہے؟ اس نے کہا، سونگھ سکتے ہو۔ راوی نے بیان کیا کہ محمد بن مسلمہ رضی اللہ عنہ نے اس کا سر سونگھا اور ان کے بعد ان کے ساتھیوں نے بھی سونگھا۔ پھر انہوں نے کہا، کیا دوبارہ سونگھنے کی اجازت ہے؟ اس نے اس مرتبہ بھی اجازت دے دی۔ پھر جب محمد بن مسلمہ رضی اللہ عنہ نے اسے پوری طرح اپنے قابو میں کر لیا تو اپنے ساتھیوں کو اشارہ کیا کہ تیار ہو جاؤ۔ چنانچہ انہوں نے اسے قتل کر دیا اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر اس کی اطلاع دی۔' WHERE id = 3869;
UPDATE hadiths SET urdu = 'ہم سے حسان بن حسان نے بیان کیا، کہا ہم سے محمد بن طلحہ نے بیان کیا، کہا ہم سے حمید طویل نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ ان کے چچا ( انس بن نضر ) بدر کی لڑائی میں شریک نہ ہو سکے تھے، پھر انہوں نے کہا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ پہلی ہی لڑائی میں غیر حاضر رہا۔ اگر نبی کریم صلی اللہ علیہ وسلم کے ساتھ اللہ تعالیٰ نے مجھے کسی اور لڑائی میں شرکت کا موقع دیا تو اللہ دیکھے گا کہ میں کتنی بے جگری سے لڑتا ہوں۔ پھر غزوہ احد کے موقع پر جب مسلمانوں کی جماعت میں افراتفری پیدا ہو گئی تو انہوں نے کہا: اے اللہ! مسلمانوں نے آج جو کچھ کیا میں تیرے حضور میں اس کے لیے معذرت خواہ ہوں اور مشرکین نے جو کچھ کیا میں تیرے حضور میں اس سے اپنی بیزاری ظاہر کرتا ہوں۔ پھر وہ اپنی تلوار لے کر آگے بڑھے۔ راستے میں سعد بن معاذ رضی اللہ عنہ سے ملاقات ہوئی تو انہوں نے ان سے کہا، سعد! کہاں جا رہے ہو؟ میں تو احد پہاڑی کے دامن میں جنت کی خوشبو سونگھ رہا ہوں۔ اس کے بعد وہ آگے بڑھے اور شہید کر دیئے گئے۔ ان کی لاش پہچانی نہیں جا رہی تھی۔ آخر ان کی بہن نے ایک تل یا ان کی انگلیوں کے پور سے ان کی لاش کو پہچانا۔ انکو اسّی ( 80 ) سے زیادہ زخم بھالے اور تلوار اور تیروں کے لگے تھے۔' WHERE id = 3879;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے مسعر نے بیان کیا، ان سے سعد نے، ان سے ابن شداد نے بیان کیا، انہوں نے علی رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ سعد رضی اللہ عنہ کے سوا میں نے نبی کریم صلی اللہ علیہ وسلم سے نہیں سنا کہ آپ اس کے لیے دعا میں ماں باپ دونوں کو بایں طور جمع کر رہے ہوں۔' WHERE id = 3889;
UPDATE hadiths SET urdu = 'اور حنظلہ بن ابی سفیان سے روایت ہے، انہوں نے بیان کیا کہ میں نے سالم بن عبداللہ سے سنا، وہ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم صفوان بن امیہ، سہیل بن عمرو اور حارث بن ہشام کے لیے بددعا کرتے تھے اس پر یہ آیت «ليس لك من الأمر شىء‏» سے «فإنهم ظالمون‏» تک نازل ہوئی۔' WHERE id = 3900;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے یزید بن عبداللہ بن ابی بردہ نے، ان سے ان کے دادا ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں نے خواب میں دیکھا کہ میں نے تلوار کو ہلایا اور اس سے اس کی دھار ٹوٹ گئی۔ اس کی تعبیر مسلمانوں کے اس نقصان کی شکل میں ظاہر ہوئی جو غزوہ احد میں انہیں اٹھانا پڑا تھا۔ پھر میں نے دوبارہ اس تلوار کو ہلایا، تو پھر وہ اس سے بھی زیادہ عمدہ ہو گئی جیسی پہلے تھی۔ اس کی تعبیر اللہ تعالیٰ نے فتح اور مسلمانوں کے پھر از سر نو اجتماع کی صورت میں ظاہر کی۔ میں نے اسی خواب میں ایک گائے دیکھی تھی ( جو ذبح ہو رہی تھی ) اور اللہ تعالیٰ کے تمام کام خیر و برکت لیے ہوتے ہیں۔ اس کی تعبیر وہ مسلمان تھے ( جو ) احد کی لڑائی میں ( شہید ہوئے ) ۔' WHERE id = 3910;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا ٰ، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے ماموں، ام سلیم ( انس کی والدہ ) کے بھائی کو بھی ان ستر سواروں کے ساتھ بھیجا تھا۔ اس کی وجہ یہ ہوئی تھی کہ مشرکوں کے سردار عامر بن طفیل نے نبی کریم صلی اللہ علیہ وسلم کے سامنے ( شرارت اور تکبر سے ) تین صورتیں رکھی تھیں۔ اس نے کہا کہ یا تو یہ کیجئے کہ دیہاتی آبادی پر آپ کی حکومت ہو اور شہری آبادی پر میری ہو یا پھر مجھے آپ کا جانشیں مقرر کیا جائے ورنہ پھر میں ہزاروں غطفانیوں کو لے کر آپ پر چڑھائی کر دوں گا۔ ( اس پر نبی کریم صلی اللہ علیہ وسلم نے اس کے لیے بددعا کی ) اور ام فلاں کے گھر میں وہ مرض طاعون میں گرفتار ہوا۔ کہنے لگا کہ اس فلاں کی عورت کے گھر کے جوان اونٹ کی طرح مجھے بھی غدود نکل آیا ہے۔ میرا گھوڑا لاؤ۔ چنانچہ وہ اپنے گھوڑے کی پشت پر ہی مر گیا۔ بہرحال ام سلیم کے بھائی حرام بن ملحان ایک اور صحابی جو لنگڑے تھے اور تیسرے صحابی جن کا تعلق بنی فلاں سے تھا، آگے بڑھے۔ حرام نے ( اپنے دونوں ساتھیوں سے بنو عامر تک پہنچ کر پہلے ہی ) کہہ دیا کہ تم دونوں میرے قریب ہی کہیں رہنا۔ میں ان کے پاس پہلے جاتا ہوں اگر انہوں نے مجھے امن دے دیا تو تم لوگ قریب ہی ہو اور اگر انہوں نے قتل کر دیا تو آپ حضرات اپنے ساتھیوں کے پاس چلے جانا۔ چنانچہ قبیلہ میں پہنچ کر انہوں نے ان سے کہا، کیا تم مجھے امان دیتے ہو کہ میں رسول اللہ صلی اللہ علیہ وسلم کا پیغام تمہیں پہنچا دوں؟ پھر وہ آپ صلی اللہ علیہ وسلم کا پیغام انہیں پہنچانے لگے تو قبیلہ والوں نے ایک شخص کو اشارہ کیا اور اس نے پیچھے سے آ کر ان پر نیزہ سے وار کیا۔ ہمام نے بیان کیا، میرا خیال ہے کہ نیزہ آر پار ہو گیا تھا۔ حرام کی زبان سے اس وقت نکلا ”اللہ اکبر، کعبہ کے رب کی قسم! میں نے تو اپنی مراد حاصل کر لی۔“ اس کے بعد ان میں سے ایک صحابی کو بھی مشرکین نے پکڑ لیا ( جو حرام رضی اللہ عنہ کے ساتھ تھے اور انہیں بھی شہید کر دیا ) پھر اس مہم کے تمام صحابہ کو شہید کر دیا۔ صرف لنگڑے صحابی بچ نکلنے میں کامیاب ہو گئے وہ پہاڑ کی چوٹی پر چڑھ گئے تھے۔ ان شہداء کی شان میں اللہ تعالیٰ نے آیت نازل فرمائی، بعد میں وہ آیت منسوخ ہو گئی ( آیت یہ تھی ) «إنا قد لقينا ربنا فرضي عنا وأرضانا‏.‏» ۔ نبی کریم صلی اللہ علیہ وسلم نے ان قبائل رعل، ذکوان، بنو لحیان اور عصیہ کے لیے جنہوں نے اللہ اور اس کے رسول کی نافرمانی کی تھی تیس دن تک صبح کی نماز میں بددعا کی۔' WHERE id = 3920;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے عبدالواحد بن ایمن نے بیان کیا، ان سے ان کے والد ایمن حبشی نے بیان کیا کہ میں جابر رضی اللہ عنہ کی خدمت میں حاضر ہوا تو انہوں نے بیان کیا کہ ہم غزوہ خندق کے موقع پر خندق کھود رہے تھے کہ ایک بہت سخت قسم کی چٹان نکلی ( جس پر کدال اور پھاوڑے کا کوئی اثر نہیں ہوتا تھا اس لیے خندق کی کھدائی میں رکاوٹ پیدا ہو گئی ) صحابہ رضی اللہ عنہم رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ سے عرض کیا کہ خندق میں ایک چٹان ظاہر ہو گئی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں اندر اترتا ہوں۔ چنانچہ آپ کھڑے ہوئے اور اس وقت ( بھوک کی شدت کی وجہ سے ) آپ کا پیٹ پتھر سے بندھا ہوا تھا۔ آپ صلی اللہ علیہ وسلم نے کدال اپنے ہاتھ میں لی اور چٹان پر اس سے مارا۔ چٹان ( ایک ہی ضرب میں ) بالو کے ڈھیر کی طرح بہہ گئی۔ میں نے عرض کیا: یا رسول اللہ! مجھے گھر جانے کی اجازت دیجئیے۔ ( گھر آ کر ) میں نے اپنی بیوی سے کہا کہ آج میں نے نبی کریم صلی اللہ علیہ وسلم کو ( فاقوں کی وجہ سے ) اس حالت میں دیکھا کہ صبر نہ ہو سکا۔ کیا تمہارے پاس ( کھانے کی ) کوئی چیز ہے؟ انہوں نے بتایا کہ ہاں کچھ جَو ہیں اور ایک بکری کا بچہ۔ میں نے بکری کے بچہ کو ذبح کیا اور میری بیوی نے جَو پیسے۔ پھر گوشت کو ہم نے چولھے پر ہانڈی میں رکھا اور میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آٹا گوندھا جا چکا تھا اور گوشت چولھے پر پکنے کے قریب تھا۔ نبی کریم صلی اللہ علیہ وسلم سے میں نے عرض کیا گھر کھانے کے لیے مختصر کھانا تیار ہے۔ یا رسول اللہ! آپ اپنے ساتھ ایک دو آدمیوں کو لے کر تشریف لے چلیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کتنا ہے؟ میں نے آپ کو سب کچھ بتا دیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو بہت ہے اور نہایت عمدہ و طیب ہے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنی بیوی سے کہہ دو کہ چولھے سے ہانڈی نہ اتاریں اور نہ تنور سے روٹی نکالیں میں ابھی آ رہا ہوں۔ پھر صحابہ سے فرمایا کہ سب لوگ چلیں۔ چنانچہ تمام انصار و مہاجرین تیار ہو گئے۔ جب جابر رضی اللہ عنہ گھر پہنچے تو اپنی بیوی سے انہوں نے کہا اب کیا ہو گا؟ رسول اللہ صلی اللہ علیہ وسلم تو تمام مہاجرین و انصار کو ساتھ لے کر تشریف لا رہے ہیں۔ انہوں نے پوچھا، نبی کریم صلی اللہ علیہ وسلم نے آپ سے کچھ پوچھا بھی تھا؟ جابر رضی اللہ عنہ نے کہا کہ ہاں۔ آپ صلی اللہ علیہ وسلم نے صحابہ سے فرمایا کہ اندر داخل ہو جاؤ لیکن اژدہام نہ ہونے پائے۔ اس کے بعد آپ صلی اللہ علیہ وسلم روٹی کا چورا کرنے لگے اور گوشت اس پر ڈالنے لگے۔ ہانڈی اور تنور دونوں ڈھکے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے اسے لیا اور صحابہ کے قریب کر دیا۔ پھر آپ نے گوشت اور روٹی نکالی۔ اس طرح آپ صلی اللہ علیہ وسلم برابر روٹی چورا کرتے جاتے اور گوشت اس میں ڈالتے جاتے۔ یہاں تک کہ تمام صحابہ شکم سیر ہو گئے اور کھانا بچ بھی گیا۔ آخر میں آپ صلی اللہ علیہ وسلم نے ( جابر رضی اللہ عنہ کی بیوی سے ) فرمایا کہ اب یہ کھانا تم خود کھاؤ اور لوگوں کے یہاں ہدیہ میں بھیجو کیونکہ لوگ آج کل فاقہ میں مبتلا ہیں۔' WHERE id = 3930;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا ‘ کہا ہم سے روح بن عبادہ نے بیان کیا ‘ ان سے ہشام بن حسان نے بیان کیا ‘ ان سے محمد بن سیرین نے ‘ ان سے عبیدہ سلمانی نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے غزوہ خندق کے موقع پر فرمایا کہ جس طرح ان کفار نے ہمیں صلوٰۃ وسطیٰ ( نماز عصر ) نہیں پڑھنے دی اور سورج غروب ہو گیا ‘ اللہ تعالیٰ بھی ان کی قبروں اور گھروں کو آگ سے بھر دے۔' WHERE id = 3940;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے غندر نے ‘ ان سے شعبہ نے ‘ ان سے سعد بن ابراہیم نے ‘ انہوں نے ابوامامہ سے سنا ‘ انہوں نے کہا کہ میں نے ابو سعید خدری رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ بنو قریظہ نے سعد بن معاذ رضی اللہ عنہ کو ثالث مان کر ہتھیار ڈال دیئے تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں بلانے کے لیے آدمی بھیجا۔ وہ گدھے پر سوار ہو کر آئے۔ جب اس جگہ کے قریب آئے جسے نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھنے کے لیے منتخب کر رکھا تھا تو آپ صلی اللہ علیہ وسلم نے انصار سے فرمایا کہ اپنے سردار کے لینے کے لیے کھڑے ہو جاؤ۔ یا ( آپ صلی اللہ علیہ وسلم نے یوں فرمایا ) اپنے سے بہتر شخص کے لیے کھڑے ہو جاؤ۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ بنو قریظہ نے تم کو ثالث مان کر ہتھیار ڈال دیئے ہیں۔ چنانچہ سعد رضی اللہ عنہ نے یہ فیصلہ کیا کہ جتنے لوگ ان میں جنگ کے قابل ہیں انہیں قتل کر دیا جائے اور ان کے بچوں اور عورتوں کو قیدی بنا لیا جائے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ تم نے اللہ کے فیصلہ کے مطابق فیصلہ کیا یا یہ فرمایا کہ جیسے بادشاہ ( یعنی اللہ ) کا حکم تھا۔' WHERE id = 3950;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا ‘ ان سے یحییٰ بن سعید انصاری نے ‘ ان سے قاسم بن محمد نے ‘ ان سے صالح بن خوات نے ‘ ان سے سہل بن ابی حثمہ نے بیان کیا کہ ( نماز خوف میں ) امام قبلہ رو ہو کر کھڑا ہو گا اور مسلمانوں کی ایک جماعت اس کے ساتھ نماز میں شریک ہو گی۔ اس دوران میں مسلمانوں کی دوسری جماعت دشمن کے مقابلہ پر کھڑی ہو گی۔ انہیں کی طرف منہ کیے ہوئے۔ امام اپنے ساتھ والی جماعت کو پہلے ایک رکعت نماز پڑھائے گا ( ایک رکعت پڑھنے کے بعد پھر ) یہ جماعت کھڑی ہو جائے گی اور خود ( امام کے بغیر ) اسی جگہ ایک رکوع اور دو سجدے کر کے دشمن کے مقابلہ پر جا کر کھڑی ہو جائے گی۔ جہاں دوسری جماعت پہلے سے موجود تھی۔ اس کے بعد امام دوسری جماعت کو ایک رکعت نماز پڑھائے گا۔ اس طرح امام کی دو رکعتیں پوری ہو جائیں گی اور یہ دوسری جماعت ایک رکوع اور دو سجدے خود کرے گی۔' WHERE id = 3960;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا ‘ کہا ہم سے ابراہیم بن سعد نے بیان کیا ‘ ان سے صالح بن کیسان نے ‘ ان سے ابن شہاب نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے عروہ بن زبیر ‘ سعید بن مسیب ‘ علقمہ بن وقاص اور عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہ جب اہل افک ( یعنی تہمت لگانے والوں ) نے ان کے متعلق وہ سب کچھ کہا جو انہیں کہنا تھا ( ابن شہاب نے بیان کیا کہ ) تمام حضرات نے ( جن چار حضرات کے نام انہوں نے روایت کے سلسلے میں لیے ہیں ) مجھ سے عائشہ رضی اللہ عنہا کی حدیث کا ایک ایک ٹکڑا بیان کیا۔ یہ بھی تھا کہ ان میں سے بعض کو یہ قصہ زیادہ بہتر طریقہ پر یاد تھا اور عمدگی سے یہ قصہ بیان کرتا تھا اور میں نے ان میں سے ہر ایک کی روایت یاد رکھی جو اس نے عائشہ رضی اللہ عنہا سے یاد رکھی تھی۔ اگرچہ بعض لوگوں کو دوسرے لوگوں کے مقابلے میں روایت زیادہ بہتر طریقہ پر یاد تھی۔ پھر بھی ان میں باہم ایک کی روایت دوسرے کی روایت کی تصدیق کرتی ہے۔ ان لوگوں نے بیان کیا کہ عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم جب سفر کا ارادہ کرتے تو ازواج مطہرات رضی اللہ عنہن کے درمیان قرعہ ڈالا کرتے تھے اور جس کا نام آتا تو نبی کریم صلی اللہ علیہ وسلم انہیں اپنے ساتھ سفر میں لے جاتے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک غزوہ کے موقع پر جب آپ نے قرعہ ڈالا تو میرا نام نکلا اور میں آپ صلی اللہ علیہ وسلم کے ساتھ سفر میں روانہ ہوئی۔ یہ واقعہ پردہ کے حکم کے نازل ہونے کے بعد کا ہے۔ چنانچہ مجھے ہودج سمیت اٹھا کر سوار کر دیا جاتا اور اسی کے ساتھ اتارا جاتا۔ اس طرح ہم روانہ ہوئے۔ پھر جب نبی کریم صلی اللہ علیہ وسلم اپنے اس غزوہ سے فارغ ہو گئے تو واپس ہوئے۔ واپسی میں اب ہم مدینہ کے قریب تھے ( اور ایک مقام پر پڑاؤ تھا ) جہاں سے آپ صلی اللہ علیہ وسلم نے کوچ کا رات کے وقت اعلان کیا۔ کوچ کا اعلان ہو چکا تھا تو میں کھڑی ہوئی اور تھوڑی دور چل کر لشکر کے حدود سے آگے نکل گئی۔ پھر قضائے حاجت سے فارغ ہو کر میں اپنی سواری کے پاس پہنچی۔ وہاں پہنچ کر جو میں نے اپنا سینہ ٹٹولا تو ظفار ( یمن کا ایک شہر ) کے مہرہ کا بنا ہوا میرا ہار غائب تھا۔ اب میں پھر واپس ہوئی اور اپنا ہار تلاش کرنے لگی۔ اس تلاش میں دیر ہو گئی۔ انہوں نے بیان کیا کہ جو لوگ مجھے سوار کیا کرتے تھے وہ آئے اور میرے ہودج کو اٹھا کر انہوں نے میرے اونٹ پر رکھ دیا۔ جس پر میں سوار ہوا کرتی تھی۔ انہوں نے سمجھا کہ میں ہودج کے اندر ہی موجود ہوں۔ ان دنوں عورتیں بہت ہلکی پھلکی ہوتی تھیں۔ ان کے جسم میں زیادہ گوشت نہیں ہوتا تھا کیونکہ بہت معمولی خوراک انہیں ملتی تھی۔ اس لیے اٹھانے والوں نے جب اٹھایا تو ہودج کے ہلکے پن میں انہیں کوئی فرق معلوم نہیں ہوا۔ یوں بھی اس وقت میں ایک کم عمر لڑکی تھی۔ غرض اونٹ کو اٹھا کر وہ بھی روانہ ہو گئے۔ جب لشکر گزر گیا تو مجھے بھی اپنا ہار مل گیا۔ میں ڈیرے پر آئی تو وہاں کوئی بھی نہ تھا۔ نہ پکارنے والا نہ جواب دینے والا۔ اس لیے میں وہاں آئی جہاں میرا اصل ڈیرہ تھا۔ مجھے یقین تھا کہ جلد ہی میرے نہ ہونے کا انہیں علم ہو جائے گا اور مجھے لینے کے لیے وہ واپس لوٹ آئیں گے۔ اپنی جگہ پر بیٹھے بیٹھے میری آنکھ لگ گئی اور میں سو گئی۔ صفوان بن معطل سلمی الذکوانی رضی اللہ عنہ لشکر کے پیچھے پیچھے آ رہے تھے۔ ( تاکہ لشکر کی کوئی چیز گم ہو گئی ہو تو وہ اٹھا لیں ) انہوں نے ایک سوئے انسان کا سایہ دیکھا اور جب ( قریب آ کر ) مجھے دیکھا تو پہچان گئے پردہ سے پہلے وہ مجھے دیکھ چکے تھے۔ مجھے جب وہ پہچان گئے تو اناللہ پڑھنا شروع کیا اور ان کی آواز سے میں جاگ اٹھی اور فوراً اپنی چادر سے میں نے اپنا چہرہ چھپا لیا۔ اللہ کی قسم! میں نے ان سے ایک لفظ بھی نہیں کہا اور نہ سوا اناللہ کے میں نے ان کی زبان سے کوئی لفظ سنا۔ وہ سواری سے اتر گئے اور اسے انہوں نے بٹھا کر اس کی اگلی ٹانگ کو موڑ دیا ( تاکہ بغیر کسی مدد کے ام المؤمنین اس پر سوار ہو سکیں ) میں اٹھی اور اس پر سوار ہو گئی۔ اب وہ سواری کو آگے سے پکڑے ہوئے لے کر چلے۔ جب ہم لشکر کے قریب پہنچے تو ٹھیک دوپہر کا وقت تھا۔ لشکر پڑاؤ کئے ہوئے تھا۔ ام المؤمنین رضی اللہ عنہا نے بیان کیا کہ پھر جسے ہلاک ہونا تھا وہ ہلاک ہوا۔ اصل میں تہمت کا بیڑا عبداللہ بن ابی ابن سلول ( منافق ) نے اٹھا رکھا تھا۔ عروہ نے بیان کیا کہ مجھے معلوم ہوا کہ وہ اس تہمت کا چرچا کرتا اور اس کی مجلسوں میں اس کا تذکرہ ہوا کرتا۔ وہ اس کی تصدیق کرتا ‘ خوب غور اور توجہ سے سنتا اور پھیلانے کے لیے خوب کھود کرید کرتا۔ عروہ نے پہلی سند کے حوالے سے یہ بھی کہا کہ حسان بن ثابت ‘ مسطح بن اثاثہ اور حمنہ بنت جحش کے سوا تہمت لگانے میں شریک کسی کا بھی نام نہیں لیا کہ مجھے ان کا علم ہوتا۔ اگرچہ اس میں شریک ہونے والے بہت سے تھے۔ جیسا کہ اللہ تعالیٰ نے ارشاد فرمایا ( کہ جن لوگوں نے تہمت لگائی ہے وہ بہت سے ہیں ) لیکن اس معاملہ میں سب سے بڑھ چڑھ کر حصہ لینے والا عبداللہ بن ابی ابن سلول تھا۔ عروہ نے بیان کیا کہ عائشہ اس پر بڑی خفگی کا اظہار کرتی تھیں۔ اگر ان کے سامنے حسان بن ثابت رضی اللہ عنہ کو برا بھلا کہا جاتا ‘ آپ فرماتیں کہ یہ شعر حسان ہی نے کہا ہے کہ ”میرے والد اور میرے والد کے والد اور میری عزت ‘ محمد صلی اللہ علیہ وسلم کی عزت کی حفاظت کے لیے تمہارے سامنے ڈھال بنی رہیں گی۔“ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر ہم مدینہ پہنچ گئے اور وہاں پہنچتے ہی میں بیمار ہو گئی تو ایک مہینے تک بیمار ہی رہی۔ اس عرصہ میں لوگوں میں تہمت لگانے والوں کی افواہوں کا بڑا چرچا رہا لیکن میں ایک بات بھی نہیں سمجھ رہی تھی البتہ اپنے مرض کے دوران ایک چیز سے مجھے بڑا شبہ ہوتا کہ رسول اللہ صلی اللہ علیہ وسلم کی وہ محبت و عنایت میں نہیں محسوس کرتی تھی جس کو پہلے جب بھی بیمار ہوتی میں دیکھ چکی تھی۔ آپ میرے پاس تشریف لاتے ‘ سلام کرتے اور دریافت فرماتے کیسی طبیعت ہے؟ صرف اتنا پوچھ کر واپس تشریف لے جاتے۔ آپ صلی اللہ علیہ وسلم کے اس طرز عمل سے مجھے شبہ ہوتا تھا۔ لیکن شر ( جو پھیل چکا تھا ) اس کا مجھے کوئی احساس نہیں تھا۔ مرض سے جب افاقہ ہوا تو میں ام مسطح کے ساتھ مناصع کی طرف گئی۔ مناصع ( مدینہ کی آبادی سے باہر ) ہمارے رفع حاجت کی جگہ تھی۔ ہم یہاں صرف رات کے وقت جاتے تھے۔ یہ اس سے پہلے کی بات ہے۔ جب بیت الخلاء ہمارے گھروں کے قریب بن گئے تھے۔ ام المؤمنین نے بیان کیا کہ ابھی ہم عرب قدیم کے طریقے پر عمل کرتے اور میدان میں رفع حاجت کے لیے جایا کرتے تھے اور ہمیں اس سے تکلیف ہوتی تھی کہ بیت الخلاء ہمارے گھروں کے قریب بنائے جائیں۔ انہوں نے بیان کیا کہ الغرض میں اور ام مسطح ( رفع حاجت کے لیے ) گئے۔ ام مسطح ابی رہم بن عبدالمطلب بن عبد مناف کی بیٹی ہیں۔ ان کی والدہ صخر بن عامر کی بیٹی ہیں اور وہ ابوبکر رضی اللہ عنہ کی خالہ تھیں۔ انہی کے بیٹے مسطح بن اثاثہ بن عباد بن مطلب رضی اللہ عنہ ہیں۔ پھر میں اور ام مسطح حاجت سے فارغ ہو کر اپنے گھر کی طرف واپس آ رہے تھے کہ ام مسطح اپنی چادر میں الجھ گئیں اور ان کی زبان سے نکلا کہ مسطح ذلیل ہو۔ میں نے کہا ‘ آپ نے بری بات زبان سے نکالی ‘ ایک ایسے شخص کو آپ برا کہہ رہی ہیں جو بدر کی لڑائی میں شریک ہو چکا ہے۔ انہوں نے اس پر کہا کیوں مسطح کی باتیں تم نے نہیں سنیں؟ ام المؤمنین نے بیان کیا کہ میں نے پوچھا کہ انہوں نے کیا کہا ہے؟ بیان کیا ‘ پھر انہوں نے تہمت لگانے والوں کی باتیں سنائیں۔ بیان کیا کہ ان باتوں کو سن کر میرا مرض اور بڑھ گیا۔ جب میں اپنے گھر واپس آئی تو نبی کریم صلی اللہ علیہ وسلم میرے پاس تشریف لائے اور سلام کے بعد دریافت فرمایا کہ کیسی طبیعت ہے؟ میں نے آپ صلی اللہ علیہ وسلم سے عرض کیا کہ کیا آپ مجھے اپنے والدین کے گھر جانے کی اجازت مرحمت فرمائیں گے؟ ام المؤمنین نے بیان کیا کہ میرا ارادہ یہ تھا کہ ان سے اس خبر کی تصدیق کروں گی۔ انہوں نے بیان کیا کہ آپ صلی اللہ علیہ وسلم نے مجھے اجازت دے دی۔ میں نے اپنی والدہ سے ( گھر جا کر ) پوچھا کہ آخر لوگوں میں کس طرح کی افواہیں ہیں؟ انہوں نے فرمایا کہ بیٹی! فکر نہ کر ‘ اللہ کی قسم! ایسا شاید ہی کہیں ہوا ہو کہ ایک خوبصورت عورت کسی ایسے شوہر کے ساتھ ہو جو اس سے محبت بھی رکھتا ہو اور اس کی سوکنیں بھی ہوں اور پھر اس پر تہمتیں نہ لگائی گئی ہوں۔ اس کی عیب جوئی نہ کی گئی ہو۔ ام المؤمنین نے بیان کیا کہ میں نے اس پر کہا کہ سبحان اللہ ( میری سوکنوں سے اس کا کیا تعلق ) اس کا تو عام لوگوں میں چرچا ہے۔ انہوں نے بیان کیا کہ ادھر پھر جو میں نے رونا شروع کیا تو رات بھر روتی رہی اسی طرح صبح ہو گئی اور میرے آنسو کسی طرح نہ تھمتے تھے اور نہ نیند ہی آتی تھی۔ بیان کیا کہ ادھر رسول اللہ صلی اللہ علیہ وسلم نے علی بن ابی طالب رضی اللہ عنہ اور اسامہ بن زید رضی اللہ عنہما کو اپنی بیوی کو علیحدہ کرنے کے متعلق مشورہ کرنے کے لیے بلایا کیونکہ اس سلسلے میں اب تک آپ پر وحی نازل نہیں ہوئی تھی۔ بیان کیا کہ اسامہ رضی اللہ عنہ نے تو نبی کریم صلی اللہ علیہ وسلم کو اسی کے مطابق مشورہ دیا جو وہ آپ صلی اللہ علیہ وسلم کی بیوی ( مراد خود اپنی ذات سے ہے ) کی پاکیزگی اور آپ صلی اللہ علیہ وسلم کی ان سے محبت کے متعلق جانتے تھے۔ چنانچہ انہوں نے کہا کہ آپ کی بیوی میں مجھے خیر و بھلائی کے سوا اور کچھ معلوم نہیں ہے لیکن علی رضی اللہ عنہ نے کہا: یا رسول اللہ! اللہ تعالیٰ نے آپ پر کوئی تنگی نہیں رکھی ہے اور عورتیں بھی ان کے علاوہ بہت ہیں۔ آپ ان کی باندی ( بریرہ رضی اللہ عنہا ) سے بھی دریافت فرما لیں وہ حقیقت حال بیان کر دے گی۔ بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے بریرہ رضی اللہ عنہا کو بلایا اور ان سے دریافت فرمایا کہ کیا تم نے کوئی ایسی بات دیکھی ہے جس سے تمہیں ( عائشہ پر ) شبہ ہوا ہو۔ بریرہ رضی اللہ عنہا نے کہا: اس ذات کی قسم! جس نے آپ کو حق کے ساتھ مبعوث کیا۔ میں نے ان کے اندر کوئی ایسی چیز نہیں دیکھی جو بری ہو۔ اتنی بات ضرور ہے کہ وہ ایک نوعمر لڑکی ہیں ‘ آٹا گوندھ کر سو جاتی ہیں اور بکری آ کر اسے کھا جاتی ہے۔ انہوں نے بیان کیا کہ اس دن رسول اللہ صلی اللہ علیہ وسلم نے صحابہ رضی اللہ عنہم کو خطاب کیا اور منبر پر کھڑے ہو کر عبداللہ بن ابی ( منافق ) کا معاملہ رکھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا۔ اے گروہ مسلمین! اس شخص کے بارے میں میری کون مدد کرے گا جس کی اذیتیں اب میری بیوی کے معاملے تک پہنچ گئی ہیں۔ اللہ کی قسم کہ میں نے اپنی بیوی میں خیر کے سوا اور کوئی چیز نہیں دیکھی اور نام بھی ان لوگوں نے ایک ایسے شخص ( صفوان بن معطل رضی اللہ عنہ جو ام المؤمنین کو اپنے اونٹ پر لائے تھے ) کا لیا ہے جس کے بارے میں بھی میں خیر کے سوا اور کچھ نہیں جانتا۔ وہ جب بھی میرے گھر آئے تو میرے ساتھ ہی آئے۔ ام المؤمنین رضی اللہ عنہا نے بیان کیا کہ اس پر سعد بن معاذ رضی اللہ عنہ قبیلہ بنو اسہل کے ہم رشتہ کھڑے ہوئے اور عرض کیا میں، یا رسول اللہ! آپ کی مدد کروں گا۔ اگر وہ شخص قبیلہ اوس کا ہوا تو میں اس کی گردن مار دوں گا اور اگر وہ ہمارے قبیلہ کا ہوا آپ کا اس کے متعلق بھی جو حکم ہو گا ہم بجا لائیں گے۔ ام المؤمنین نے بیان کیا کہ اس پر قبیلہ خزرج کے ایک صحابی کھڑے ہوئے۔ حسان کی والدہ ان کی چچا زاد بہن تھیں یعنی سعد بن عبادہ رضی اللہ عنہ وہ قبیلہ خزرج کے سردار تھے اور اس سے پہلے بڑے صالح اور مخلصین میں تھے لیکن آج قبیلہ کی حمیت ان پر غالب آ گئی۔ انہوں نے سعد رضی اللہ عنہ کو مخاطب کر کے کہا: اللہ کی قسم! تم جھوٹے ہو ‘ تم اسے قتل نہیں کر سکتے، اور نہ تمہارے اندر اتنی طاقت ہے۔ اگر وہ تمہارے قبیلہ کا ہوتا تو تم اس کے قتل کا نام نہ لیتے۔ اس کے بعد اسید بن حضیر رضی اللہ عنہ جو سعد بن عبادہ رضی اللہ عنہ کے چچیرے بھائی تھے کھڑے ہوئے اور سعد بن عبادہ رضی اللہ عنہ کو مخاطب کر کے کہا: اللہ کی قسم! تم جھوٹے ہو ‘ ہم اسے ضرور قتل کریں گے۔ اب اس میں شبہ نہیں رہا کہ تم بھی منافق ہو ‘ تم منافقوں کی طرف سے مدافعت کرتے ہو۔ اتنے میں اوس و خزرج کے دونوں قبیلے بھڑک اٹھے اور ایسا معلوم ہوتا تھا کہ آپس ہی میں لڑ پڑیں گے۔ اس وقت تک رسول اللہ صلی اللہ علیہ وسلم منبر پر ہی تشریف فرما تھے۔ ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم سب کو خاموش کرانے لگے۔ سب حضرات چپ ہو گئے اور آپ صلی اللہ علیہ وسلم بھی خاموش ہو گئے۔ ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ میں اس روز پورا دن روتی رہی۔ نہ میرا آنسو تھمتا تھا اور نہ آنکھ لگتی تھی۔ بیان کیا کہ صبح کے وقت میرے والدین میرے پاس آئے۔ دو راتیں اور ایک دن میرا روتے ہوئے گزر گیا تھا۔ اس پورے عرصہ میں نہ میرا آنسو رکا اور نہ نیند آئی۔ ایسا معلوم ہوتا تھا کہ روتے روتے میرا کلیجہ پھٹ جائے گا۔ ابھی میرے والدین میرے پاس ہی بیٹھے ہوئے تھے اور میں روئے جا رہی تھی کہ قبیلہ انصار کی ایک خاتون نے اندر آنے کی اجازت چاہی۔ میں نے انہیں اجازت دے دی اور وہ بھی میرے ساتھ بیٹھ کر رونے لگیں۔ بیان کیا کہ ہم ابھی اسی حالت میں تھے کہ رسول اللہ صلی اللہ علیہ وسلم تشریف لائے۔ آپ نے سلام کیا اور بیٹھ گئے۔ بیان کیا کہ جب سے مجھ پر تہمت لگائی گئی تھی ‘ آپ صلی اللہ علیہ وسلم میرے پاس نہیں بیٹھے تھے۔ ایک مہینہ گزر گیا تھا اور میرے بارے میں آپ کو وحی کے ذریعہ کوئی اطلاع نہیں دی گئی تھی۔ بیان کیا کہ بیٹھنے کے بعد آپ صلی اللہ علیہ وسلم نے کلمہ شہادت پڑھا پھر فرمایا ”امابعد“ اے عائشہ! مجھے تمہارے بارے میں اس اس طرح کی خبریں ملی ہیں ‘ اگر تم واقعی اس معاملہ میں پاک و صاف ہو تو اللہ تمہاری پاکی خود بیان کر دے گا لیکن اگر تم نے کسی گناہ کا قصد کیا تھا تو اللہ کی مغفرت چاہو اور اس کے حضور میں توبہ کرو کیونکہ بندہ جب ( اپنے گناہوں کا ) اعتراف کر لیتا ہے اور پھر اللہ کی بارگاہ میں توبہ کرتا ہے تو اللہ تعالیٰ اس کی توبہ قبول کر لیتا ہے۔ ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ جب آپ صلی اللہ علیہ وسلم اپنا کلام پورا کر چکے تو میرے آنسو اس طرح خشک ہو گئے کہ ایک قطرہ بھی محسوس نہیں ہوتا تھا۔ میں نے پہلے اپنے والد سے کہا کہ میری طرف سے رسول اللہ صلی اللہ علیہ وسلم کو ان کے کلام کا جواب دیں۔ والد نے فرمایا: اللہ کی قسم! میں کچھ نہیں جانتا کہ آپ صلی اللہ علیہ وسلم سے مجھے کیا کہنا چاہیے۔ پھر میں نے اپنی والدہ سے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے جو کچھ فرمایا ہے وہ اس کا جواب دیں۔ والدہ نے بھی یہی کہا۔ اللہ کی قسم! مجھے کچھ نہیں معلوم کہ آپ صلی اللہ علیہ وسلم سے مجھے کیا کہنا چاہیے۔ اس لیے میں نے خود ہی عرض کیا۔ حالانکہ میں بہت کم عمر لڑکی تھی اور قرآن مجید بھی میں نے زیادہ نہیں پڑھا تھا کہ اللہ کی قسم! مجھے بھی معلوم ہوا ہے کہ آپ لوگوں نے اس طرح کی افوہوں پر کان دھرا اور بات آپ لوگوں کے دلوں میں اتر گئی اور آپ لوگوں نے اس کی تصدیق کی۔ اب اگر میں یہ کہوں کہ میں اس تہمت سے بری ہوں تو آپ لوگ میری تصدیق نہیں کریں گے اگر اور اس گناہ کا اقرار کر لوں اور اللہ تعالیٰ خوب جانتا ہے کہ میں اس سے بری ہوں تو آپ لوگ اس کی تصدیق کرنے لگ جائیں گے۔ پس اللہ کی قسم! میری اور لوگوں کی مثال یوسف علیہ السلام کے والد جیسی ہے۔ جب انہوں نے کہا تھا «فصبر جميل والله المستعان على ما تصفون‏» ( یوسف: 18 ) ”پس صبر جمیل بہتر ہے اور اللہ ہی کی مدد درکار ہے اس بارے میں جو کچھ تم کہہ رہے ہو“ پھر میں نے اپنا رخ دوسری طرف کر لیا اور اپنے بستر پر لیٹ گئی۔ اللہ خوب جانتا تھا کہ میں اس معاملہ میں قطعاً بری تھی اور وہ خود میری برات ظاہر کرے گا۔ کیونکہ میں واقعی بری تھی لیکن اللہ کی قسم! مجھے اس کا کوئی وہم و گمان بھی نہ تھا کہ اللہ تعالیٰ وحی کے ذریعہ قرآن مجید میں میرے معاملے کی صفائی اتارے گا کیونکہ میں اپنے کو اس سے بہت کمتر سمجھتی تھی کہ اللہ تعالیٰ میرے معاملہ میں خود کوئی کلام فرمائے ‘ مجھے تو صرف اتنی امید تھی کہ آپ صلی اللہ علیہ وسلم کوئی خواب دیکھیں گے جس کے ذریعہ اللہ تعالیٰ میری برات کر دے گا لیکن اللہ کی قسم! ابھی نبی کریم صلی اللہ علیہ وسلم مجلس سے اٹھے بھی نہیں تھے اور نہ اور کوئی گھر کا آدمی وہاں سے اٹھا تھا کہ آپ صلی اللہ علیہ وسلم پر وحی نازل ہونی شروع ہوئی اور آپ پر وہ کیفیت طاری ہوئی جو وحی کی شدت میں طاری ہوتی تھی۔ موتیوں کی طرح پسینے کے قطرے آپ کے چہرے سے گرنے لگے۔ حالانکہ سردی کا موسم تھا۔ یہ اس وحی کی وجہ سے تھا جو آپ پر نازل ہو رہی تھی۔ ام المؤمنین رضی اللہ عنہا نے بیان کیا کہ پھر آپ کی وہ کیفیت ختم ہوئی تو آپ تبسم فرما رہے تھے۔ سب سے پہلا کلمہ جو آپ کی زبان مبارک سے نکلا وہ یہ تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا: اے عائشہ! اللہ نے تمہاری برات نازل کر دی ہے۔ انہوں نے بیان کیا کہ اس پر میری والدہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے کھڑی ہو جاؤ۔ میں نے کہا ‘ نہیں اللہ کی قسم! میں آپ کے سامنے نہیں کھڑی ہوں گی۔ میں اللہ عزوجل کے سوا اور کسی کی حمد و ثنا نہیں کروں گی ( کہ اسی نے میری برات نازل کی ہے ) بیان کیا کہ اللہ تعالیٰ نے نازل فرمایا «إن الذين جاءوا بالإفك‏» ”جو لوگ تہمت تراشی میں شریک ہوئے ہیں“ دس آیتیں اس سلسلہ میں نازل فرمائیں۔ جب اللہ تعالیٰ نے ( سورۃ النور میں ) یہ آیتیں میری برات کے لیے نازل فرمائیں تو ابوبکر صدیق رضی اللہ عنہ ( جو مسطح بن اثاثہ کے اخراجات ‘ ان سے قرابت اور ان کی محتاجی کی وجہ سے خود اٹھاتے تھے ) نے کہا: اللہ کی قسم! مسطح نے جب عائشہ کے متعلق اس طرح کی تہمت تراشی میں حصہ لیا تو میں اس پر اب کبھی کچھ خرچ نہیں کروں گا۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «ولا يأتل أولو الفضل منكم‏» یعنی ”اہل فضل اور اہل ہمت قسم نہ کھائیں“ سے «غفور رحيم‏» تک ( کیونکہ مسطح رضی اللہ عنہ یا دوسرے مومنین کی اس میں شرکت محض غلط فہمی کی بنا پر تھی ) ۔ چنانچہ ابوبکر صدیق رضی اللہ عنہ نے کہا کہ اللہ کی قسم! میری تمنا ہے کہ اللہ تعالیٰ مجھے اس کہنے پر معاف کر دے اور مسطح کو جو کچھ دیا کرتے تھے ‘ اسے پھر دینے لگے اور کہا کہ اللہ کی قسم! اب اس وظیفہ کو میں کبھی بند نہیں کروں گا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میرے معاملے میں آپ صلی اللہ علیہ وسلم نے ام المؤمنین زینب بنت جحش رضی اللہ عنہا سے بھی مشورہ کیا تھا۔ آپ نے ان سے پوچھا کہ عائشہ کے متعلق کیا معلومات ہیں تمہیں یا ان میں تم نے کیا چیز دیکھی ہے؟ انہوں نے عرض کیا: یا رسول اللہ! میں اپنی آنکھوں اور کانوں کو محفوظ رکھتی ہوں ( کہ ان کی طرف خلاف واقعہ نسبت کروں ) اللہ کی قسم! میں ان کے بارے میں خیر کے سوا اور کچھ نہیں جانتی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ زینب ہی تمام ازواج مطہرات میں میرے مقابل کی تھیں لیکن اللہ تعالیٰ نے ان کے تقویٰ اور پاکبازی کی وجہ سے انہیں محفوظ رکھا۔ بیان کیا کہ البتہ ان کی بہن حمنہ نے غلط راستہ اختیار کیا اور ہلاک ہونے والوں کے ساتھ وہ بھی ہلاک ہوئی تھیں۔ ابن شہاب نے بیان کیا کہ یہی تھی وہ تفصیل اس حدیث کی جو ان اکابر کی طرف سے مجھ تک پہنچی تھی۔ پھر عروہ نے بیان کیا کہ عائشہ رضی اللہ عنہا نے بیان کیا کہ اللہ کی قسم! جن صحابی کے ساتھ یہ تہمت لگائی گئی تھی وہ ( اپنے پر اس تہمت کو سن کر ) کہتے ‘ سبحان اللہ ‘ اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے ‘ میں نے آج تک کسی عورت کا پردہ نہیں کھولا۔ ام المؤمنین رضی اللہ عنہا نے بیان کیا کہ پھر اس واقعہ کے بعد وہ اللہ کے راستے میں شہید ہو گئے تھے۔' WHERE id = 3970;
UPDATE hadiths SET urdu = 'مجھ سے فضل بن یعقوب نے بیان کیا ‘ ہم سے حسن بن محمد بن اعین ابوعلی حرانی نے بیان کیا ‘ کہا ہم سے زہیر بن معاویہ نے بیان کیا ‘ کہا ہم سے ابواسحاق سبیعی نے بیان کیا کہ ہمیں براء بن عازب رضی اللہ عنہ نے خبر دی کہ وہ لوگ غزوہ حدیبیہ کے موقع پر رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک ہزار چار سو کی تعداد میں تھے یا اس سے بھی زیادہ۔ ایک کنویں پر پڑاؤ ہوا لشکر نے اس کا ( سارا ) پانی کھینچ لیا اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ نبی کریم صلی اللہ علیہ وسلم کنویں کے پاس تشریف لائے اور اس کی منڈیر پر بیٹھ گئے۔ پھر فرمایا کہ ایک ڈول میں اسی کنویں کا پانی لاؤ۔ پانی لایا گیا تو آپ صلی اللہ علیہ وسلم نے اس میں کلی کی اور دعا فرمائی۔ پھر فرمایا کہ کنویں کو یوں ہی تھوڑی دیر کے لیے رہنے دو۔ اس کے بعد سارا لشکر خود بھی سیراب ہوتا رہا اور اپنی سواریوں کو بھی خوب پلاتا رہا۔ یہاں تک کہ وہاں سے انہوں نے کوچ کیا۔' WHERE id = 3980;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا ‘ ان سے طارق بن عبدالرحمٰن نے بیان کیا کہ سعید بن مسیب کی مجلس میں «الشجرة» کا ذکر ہوا تو وہ ہنسے اور کہا کہ میرے والد نے مجھے بتایا کہ وہ بھی اس درخت کے تلے بیعت میں شریک تھے۔' WHERE id = 3992;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے ابن ابی عدی نے ‘ ان سے شعبہ نے ان سے یحییٰ بن سعید نے ‘ ان سے بشیر بن یسار نے اور ان سے سوید بن نعمان رضی اللہ عنہ نے بیان کیا ‘ وہ بیعت رضوان میں شریک تھے کہ گویا اب بھی وہ منظر میری آنکھوں کے سامنے ہے جب رسول اللہ صلی اللہ علیہ وسلم اور آپ کے صحابہ رضی اللہ عنہم کے سامنے ستو لایا گیا۔ جسے ان حضرات نے پیا۔ اس روایت کی متابعت معاذ نے شعبہ سے کی ہے۔' WHERE id = 4002;
UPDATE hadiths SET urdu = 'ہم سے حسن بن اسحاق نے بیان کیا ‘ کہا ہم سے محمد بن سابق نے بیان کیا ‘ کہا ہم سے مالک بن مغول نے بیان کیا ‘ کہا کہ میں نے ابوحصین سے سنا ‘ ان سے ابووائل نے بیان کیا کہ سہل بن حنیف رضی اللہ عنہ جب جنگ صفین ( جو علی رضی اللہ عنہ اور معاویہ رضی اللہ عنہ میں ہوئی تھی ) سے واپس آئے تو ہم ان کی خدمت میں حالات معلوم کرنے کے لیے حاضر ہوئے۔ انہوں نے کہا کہ اس جنگ کے بارے میں تم لوگ اپنی رائے اور فکر پر نازاں مت ہو۔ میں یوم ابوجندل ( صلح حدیبیہ ) میں بھی موجود تھا۔ اگر میرے لیے رسول اللہ صلی اللہ علیہ وسلم کے حکم کو ماننے سے انکار ممکن ہوتا تو میں اس دن ضرور حکم عدولی کرتا۔ اللہ اور اس کا رسول خوب جانتے ہیں کہ جب ہم نے کسی مشکل کام کے لیے اپنی تلواروں کو اپنے کاندھوں پر رکھا تو صورت حال آسان ہو گئی اور ہم نے مشکل حل کر لی۔ لیکن اس جنگ کا کچھ عجیب حال ہے ‘ اس میں ہم ( فتنے کے ) ایک کونے کو بند کرتے ہیں تو دوسرا کونا کھل جاتا ہے۔ ہم نہیں جانتے کہ ہم کو کیا تدبیر کرنی چاہئے۔' WHERE id = 4014;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا ‘ کہا ہم سے عبدالوہاب نے بیان کیا ‘ کہا ہم سے ایوب نے بیان کیا ‘ ان سے محمد نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک آنے والے نے حاضر ہو کر عرض کیا کہ گدھے کا گوشت کھایا جا رہا ہے۔ اس پر آپ نے خاموشی اختیار کی پھر دوبارہ وہ حاضر ہوئے اور عرض کیا کہ گدھے کا گوشت کھایا جا رہا ہے۔ نبی کریم صلی اللہ علیہ وسلم اس مرتبہ بھی خاموش رہے ‘ پھر وہ تیسری مرتبہ آئے اور عرض کیا کہ گدھے ختم ہو گئے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے ایک منادی سے اعلان کرایا کہ اللہ اور اس کے رسول تمہیں پالتو گدھوں کے گوشت کے کھانے سے منع کرتے ہیں۔ چنانچہ تمام ہانڈیاں الٹ دی گئیں حالانکہ وہ گوشت کے ساتھ جوش مار رہی تھیں۔' WHERE id = 4024;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا ‘ کہا ہم سے حاتم نے بیان کیا ‘ ان سے یزید بن ابی عبید نے اور ان سے سلمہ رضی اللہ عنہ نے بیان کیا کہ علی رضی اللہ عنہ غزوہ خیبر میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نہ جا سکے تھے کیونکہ وہ آشوب چشم میں مبتلا تھے۔ ( جب آپ صلی اللہ علیہ وسلم جا چکے ) تو انہوں نے کہا میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ سے پیچھے رہوں ( ایسا نہیں ہو سکتا ) ؟ چنانچہ وہ بھی آ گئے۔ جس دن خیبر فتح ہونا تھا ‘ جب اس کی رات آئی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ کل میں ( اسلامی ) عَلم اس شخص کو دوں گا یا فرمایا کہ عَلم وہ شخص لے گا جسے اللہ اور اس کا رسول عزیز رکھتے ہیں اور جس کے ہاتھ پر فتح حاصل ہو گی۔ ہم سب ہی اس سعادت کے امیدوار تھے لیکن کہا گیا کہ یہ ہیں علی رضی اللہ عنہ اور آپ صلی اللہ علیہ وسلم نے انہیں کو جھنڈا دیا اور انہیں کے ہاتھ پر خیبر فتح ہوا۔' WHERE id = 4034;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا ہم سے حماد بن زید نے ‘ ان سے عمرو نے ان سے محمد بن علی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے غزوہ خیبر کے موقع پر گدھے کے گوشت کھانے کی ممانعت کی تھی اور گھوڑوں کے گوشت کھانے کی اجازت دی تھی۔' WHERE id = 4044;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم نے بیان کیا ‘ کہا ہم نے حفص بن غیاث سے سنا ‘ ان سے برید بن عبداللہ نے بیان کیا ‘ ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ خیبر کی فتح کے بعد ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پہنچے لیکن نبی کریم صلی اللہ علیہ وسلم نے ( مال غنیمت میں ) ہمارا بھی حصہ لگایا۔ آپ نے ہمارے سوا کسی بھی ایسے شخص کا حصہ مال غنیمت میں نہیں لگایا جو فتح کے وقت ( اسلامی لشکر کے ساتھ ) موجود نہ رہا ہو۔' WHERE id = 4056;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ ان سے سعید نے بیان کیا ‘ ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ خیبر کی فتح کے بعد نبی کریم صلی اللہ علیہ وسلم کو ( ایک یہودی عورت کی طرف سے ) بکری کے گوشت کا ہدیہ پیش کیا گیا جس میں زہر ملا ہوا تھا۔' WHERE id = 4069;
UPDATE hadiths SET urdu = 'ہمیں احمد بن ابی بکر نے خبر دی ‘ انہوں نے کہا ہم سے مغیرہ بن عبدالرحمٰن نے بیان کیا ‘ ان سے عبداللہ نے بیان کیا ‘ ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے غزوہ موتہ کے لشکر کا امیر زید بن حارثہ رضی اللہ عنہ کو بنایا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے یہ بھی فرما دیا تھا کہ اگر زید شہید ہو جائیں تو جعفر امیر ہوں اور اگر جعفر بھی شہید ہو جائیں تو عبداللہ بن رواحہ امیر ہوں۔ عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ اس غزوہ میں ‘ میں بھی شریک تھا۔ بعد میں جب ہم نے جعفر رضی اللہ عنہ کو تلاش کیا تو ان کی لاش ہمیں شہداء میں ملی اور ان کے جسم پر کچھ اوپر نوے زخم نیزوں اور تیروں کے تھے۔' WHERE id = 4080;
UPDATE hadiths SET urdu = 'اور عمر بن حفص بن غیاث نے (جو امام بخاری رحمہ اللہ کے شیخ ہیں) بیان کیا کہا ہم سے ہمارے والد نے بیان کیا ‘ ان سے یزید بن ابی عبید نے بیان کیا اور انہوں نے سلمہ بن اکوع رضی اللہ عنہ سے سنا ‘ وہ بیان کرتے تھے کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ سات غزووں میں شریک رہا ہوں اور نو ایسی لڑائیوں میں گیا ہوں جن کو خود نبی کریم صلی اللہ علیہ وسلم نے بھیجا تھا۔ کبھی ہمارے امیر ابوبکر رضی اللہ عنہ ہوتے اور کبھی اسامہ رضی اللہ عنہ ہوتے۔' WHERE id = 4090;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے معاویہ بن قرہ نے بیان کیا ‘ انہوں نے عبداللہ بن مغفل رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم فتح مکہ کے موقع پر اپنے اونٹ پر سوار ہیں اور خوش الحانی کے ساتھ سورۃ الفتح کی تلاوت فرما رہے ہیں۔ معاویہ بن قرہ رضی اللہ عنہ نے کہا کہ اگر اس کا خطرہ نہ ہوتا کہ لوگ مجھے گھیر لیں گے تو میں بھی اسی طرح تلاوت کر کے دکھاتا جیسے عبداللہ بن مغفل رضی اللہ عنہ نے پڑھ کر سنایا تھا۔' WHERE id = 4100;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے غندر نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے منصور نے ‘ ان سے ابوالضحیٰ نے ‘ ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اپنے رکوع اور سجدہ میں یہ پڑھتے تھے «سبحانك اللهم،‏‏‏‏ ربنا وبحمدك،‏‏‏‏ اللهم اغفر لي» ۔' WHERE id = 4111;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا، نبی کریم صلی اللہ علیہ وسلم سے (دوسری سند اور لیث بن سعد نے کہا مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، انہیں عروہ بن زبیر نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ عتبہ بن ابی وقاص نے (مرتے وقت زمانہ جاہلیت میں) اپنے بھائی (سعد بن ابی وقاص رضی اللہ عنہ) کو وصیت کی تھی کہ وہ زمعہ بن لیثی کی باندی سے پیدا ہونے والے بچے کو اپنے قبضے میں لے لیں۔ عتبہ نے کہا تھا کہ وہ میرا لڑکا ہو گا۔ چنانچہ جب فتح مکہ کے موقع پر رسول اللہ صلی اللہ علیہ وسلم مکہ میں داخل ہوئے تو سعد بن ابی وقاص رضی اللہ عنہ اس بچے کو لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور ان کے ساتھ عبد بن زمعہ بھی آئے۔ سعد بن ابی وقاص رضی اللہ عنہ نے تو یہ کہا کہ یہ میرے بھائی کا لڑکا ہے۔ لیکن عبد بن زمعہ نے کہا: یا رسول اللہ! یہ میرا بھائی ہے (میرے والد) زمعہ کا بیٹا ہے کیونکہ انہیں کے بستر پر پیدا ہوا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے زمعہ کی باندی کے لڑکے کو دیکھا تو وہ واقعی (سعد کے بھائی) عتبہ بن ابی وقاص کی شکل پر تھا لیکن نبی کریم صلی اللہ علیہ وسلم نے (قانون شریعت کے مطابق) فیصلے میں یہ کہا کہ اے عبد بن زمعہ! تمہیں اس بچے کو رکھو، یہ تمہارا بھائی ہے، کیونکہ یہ تمہارے والد کے فراش پر (اس کی باندی کے بطن سے پیدا ہوا ہے۔ لیکن دوسری طرف ام المؤمنین سودہ رضی اللہ عنہا سے جو زمعہ کی بیٹی تھیں فرمایا سودہ! اس لڑکے سے پردا کیا کرنا کیونکہ آپ نے اس لڑکے میں عتبہ بن ابی وقاص رضی اللہ عنہ کی شباہت پائی تھی۔ ابن شہاب نے کہا ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ لڑکا اس کا ہوتا ہے جس کی جورو یا لونڈی کے پیٹ سے پیدا ہوا ہو اور زنا کرنے والے کے حصے میں سنگ ہی ہیں۔ ابن شہاب نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ اس حدیث کو پکار پکار کر بیان کیا کرتے تھے۔)' WHERE id = 4121;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے ابواسحاق نے، انہوں نے براء رضی اللہ عنہ سے سنا اور ان سے قبیلہ قیس کے ایک آدمی نے پوچھا کہ کیا تم لوگ نبی کریم صلی اللہ علیہ وسلم کو غزوہ حنین میں چھوڑ کر بھاگ نکلے تھے؟ انہوں نے کہا: لیکن نبی کریم صلی اللہ علیہ وسلم اپنی جگہ سے نہیں ہٹے تھے۔ قبیلہ ہوازن کے لوگ تیرانداز تھے، جب ان پر ہم نے حملہ کیا تو وہ پسپا ہو گئے پھر ہم لوگ مال غنیمت میں لگ گئے۔ آخر ہمیں ان کے تیروں کا سامنا کرنا پڑا۔ میں نے خود دیکھا تھا کہ نبی کریم صلی اللہ علیہ وسلم اپنے سفید خچر پر سوار تھے اور ابوسفیان بن حارث رضی اللہ عنہ اس کی لگام تھامے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم فرما رہے تھے «أنا النبي لا كذب‏» ”میں نبی ہوں، اس میں جھوٹ نہیں۔“ اسرائیل اور زہیر نے بیان کیا کہ بعد میں آپ صلی اللہ علیہ وسلم اپنے خچر سے اتر گئے۔' WHERE id = 4133;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، انہیں معمر نے خبر دی، ان سے زہری نے بیان کیا اور انہیں انس بن مالک رضی اللہ عنہ نے خبر دی، بیان کیا کہ جب قبیلہ ہوازن کے مال میں سے اللہ تعالیٰ نے اپنے رسول کو جو دینا تھا وہ دیا تو انصار کے کچھ لوگوں کو رنج ہوا کیونکہ آپ صلی اللہ علیہ وسلم نے کچھ لوگوں کو سو سو اونٹ دے دئیے تھے۔ کچھ لوگوں نے کہا کہ اللہ اپنے رسول کی مغفرت کرے، قریش کو تو آپ عنایت فرما رہے ہیں اور ہم کو آپ نے چھوڑ دیا ہے حالانکہ ہماری تلواروں سے ان کا خون ٹپک رہا ہے۔ انس رضی اللہ عنہ نے بیان کیا کہ انصار کی یہ بات نبی کریم صلی اللہ علیہ وسلم کے کانوں میں آئی تو آپ نے انہیں بلا بھیجا اور چمڑے کے ایک خیمے میں انہیں جمع کیا، ان کے ساتھ ان کے علاوہ کسی کو بھی آپ نے نہیں بلایا تھا۔ جب سب لوگ جمع ہو گئے تو آپ صلی اللہ علیہ وسلم کھڑے ہوئے اور آپ نے فرمایا تمہاری جو بات مجھے معلوم ہوئی ہے کیا وہ صحیح ہے؟ انصار کے جو سمجھدار لوگ تھے انہوں نے عرض کیا: یا رسول اللہ! جو لوگ ہمارے معزز اور سردار ہیں، انہوں نے ایسی کوئی بات نہیں کہی۔ البتہ ہمارے کچھ لوگ جو ابھی نوعمر ہیں، انہوں نے کہا ہے کہ اللہ، رسول اللہ صلی اللہ علیہ وسلم کی مغفرت کرے، قریش کو آپ دے رہے ہیں اور ہمیں آپ نے چھوڑ دیا ہے حالانکہ ہماری تلواروں سے ان کا خون ٹپک رہا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ میں ایسے لوگوں کو دیتا ہوں جو ابھی نئے نئے اسلام میں داخل ہوئے ہیں، اس طرح میں ان کی دلجوئی کرتا ہوں۔ کیا تم اس پر راضی نہیں ہو کہ دوسرے لوگ تو مال و دولت لے جائیں اور تم نبی کو اپنے ساتھ اپنے گھر لے جاؤ۔ اللہ کی قسم! جو چیز تم اپنے ساتھ لے جاؤ گے وہ اس سے بہتر ہے جو وہ لے جا رہے ہیں۔ انصار نے عرض کیا: یا رسول اللہ! ہم اس پر راضی ہیں۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرے بعد تم دیکھو گے کہ تم پر دوسروں کو ترجیح دی جائے گی۔ اس وقت صبر کرنا، یہاں تک کہ اللہ اور اس کے رسول سے آ ملو۔ میں حوض کوثر پر ملوں گا۔ انس رضی اللہ عنہ نے کہا لیکن انصار نے صبر نہیں کیا۔' WHERE id = 4145;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم سے خالد نے، ان سے شیبانی نے، ان سے سعید بن ابی بردہ نے، ان سے ان کے والد نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں یمن بھیجا۔ ابوموسیٰ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے ان شربتوں کا مسئلہ پوچھا جو یمن میں بنائے جاتے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ وہ کیا ہیں؟ ابوموسیٰ رضی اللہ عنہ نے بتایا کہ ”بتع“ اور ”مزر“ ( سعید بن ابی بردہ نے کہا کہ ) میں نے ابوبردہ ( اپنے والد ) سے پوچھا ”بتع“ کیا چیز ہے؟ انہوں نے بتایا کہ شہد سے تیاری کی ہوئی شراب اور ”مزر“ جَو سے تیار کی ہوئی شراب۔ نبی کریم صلی اللہ علیہ وسلم نے جواب میں فرمایا کہ ہر نشہ آور چیز پینا حرام ہے۔ اس کی روایت جریر اور عبدالواحد نے شیبانی سے کی ہے اور انہوں نے ابوبردہ سے کی ہے۔' WHERE id = 4156;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم کو خبر دی ابواسامہ نے، انہیں اسماعیل بن ابی خالد نے، انہیں قیس بن ابی حازم نے اور ان سے جریر بن عبداللہ بجلی رضی اللہ عنہ نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ذوالخلصہ سے مجھے کیوں نہیں بےفکری دلاتے! میں نے عرض کیا میں حکم کی تعمیل کروں گا۔ چنانچہ قبیلہ احمس کے ڈیڑھ سو سواروں کو ساتھ لے کر میں روانہ ہوا۔ یہ سب اچھے سوار تھے، لیکن میں سواری اچھی طرح نہیں کر پاتا تھا۔ میں نے اس کے متعلق نبی کریم صلی اللہ علیہ وسلم سے ذکر کیا تو آپ نے اپنا ہاتھ میرے سینے پر مارا جس کا اثر میں نے اپنے سینہ میں دیکھا اور نبی کریم صلی اللہ علیہ وسلم نے دعا فرمائی ”اے اللہ! اسے اچھا سوار بنا دے اور اسے ہدایت کرنے والا اور خود ہدایت پایا ہوا بنا دے۔“ راوی نے بیان کیا کہ پھر اس کے بعد میں کبھی کسی گھوڑے سے نہیں گرا۔ راوی نے بیان کیا کہ ذوالخلصہ ایک ( بت خانہ ) تھا، یمن میں قبیلہ خثعم اور بجیلہ کا، اس میں بت تھے جن کی پوجا کی جاتی تھی اور اسے کعبہ بھی کہتے تھے۔ بیان کیا کہ پھر جریر وہاں پہنچے اور اسے آگ لگا دی اور منہدم کر دیا۔ بیان کیا کہ جب جریر رضی اللہ عنہ یمن پہنچے تو وہاں ایک شخص تھا جو تیروں سے فال نکالا کرتا تھا۔ اس سے کسی نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کے ایلچی یہاں آ گئے ہیں۔ اگر انہوں نے تمہیں پا لیا تو تمہاری گردن مار دیں گے۔ بیان کیا کہ ابھی وہ فال نکال ہی رہے تھے کہ جریر رضی اللہ عنہ وہاں پہنچ گئے۔ آپ نے اس سے فرمایا کہ یہ فال کے تیر توڑ کر کلمہ لا الٰہ الا اللہ پڑھ لے ورنہ میں تیری گردن مار دوں گا۔ راوی نے بیان کیا اس شخص نے تیر وغیرہ توڑ ڈالے اور کلمہ ایمان کی گواہی دی۔ اس کے بعد جریر رضی اللہ عنہ نے قبیلہ احمس کے ایک صحابی ابوارطاط رضی اللہ عنہ نامی کو نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بھیجا جب وہ خدمت میں حاضر ہوئے تو انہوں نے عرض کیا: یا رسول اللہ! اس ذات کی قسم جس نے آپ کو حق کے ساتھ مبعوث کیا ہے۔ میں آپ کی خدمت میں حاضر ہونے کے لیے اس وقت تک نہیں چلا جب تک اس بت کدہ کو خارش زدہ اونٹ کی طرح جلا کر سیاہ نہیں کر دیا۔ بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے قبیلہ احمس کے گھوڑوں اور سواروں کے لیے پانچ مرتبہ برکت کی دعا فرمائی۔' WHERE id = 4168;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہیں ابن جریج نے خبر دی، انہیں ابن ابی ملیکہ نے اور انہیں عبداللہ بن زبیر رضی اللہ عنہما نے خبر دی کہ بنو تمیم کے چند سوار نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور انہوں نے عرض کیا کہ آپ ہمارا کوئی امیر منتخب کر دیجئیے۔ ابوبکر رضی اللہ عنہ نے کہا کہ قعقاع بن معبد بن زرارہ رضی اللہ عنہ کو امیر منتخب کر دیجئیے۔ عمر رضی اللہ عنہ نے عرض کیا کہ یا رسول اللہ! بلکہ آپ اقرع بن حابس رضی اللہ عنہ کو ان کا امیر منتخب فرما دیجئیے۔ اس پر ابوبکر رضی اللہ عنہ نے عمر رضی اللہ عنہ سے کہا کہ تمہارا مقصد صرف مجھ سے اختلاف کرنا ہے۔ عمر رضی اللہ عنہ نے کہا کہ نہیں میری غرض مخالفت کی نہیں ہے۔ دونوں اتنا جھگڑے کی آواز بلند ہو گئی۔ اسی پر سورۃ الحجرات کی یہ آیت نازل ہوئی «يا أيها الذين آمنوا لا تقدموا‏» آخر آیت تک۔' WHERE id = 4178;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ میں نے ابواسحاق سے سنا، انہوں نے صلہ بن زفر سے اور ان سے ابوحذیفہ رضی اللہ عنہ نے بیان کیا کہ اہل نجران نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ ہمارے ساتھ کوئی امانت دار آدمی بھیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہارے ساتھ ایسا آدمی بھیجوں گا جو ہر حیثیت سے امانت دار ہو گا۔ صحابہ رضی اللہ عنہم منتظر تھے، آخر آپ صلی اللہ علیہ وسلم نے ابوعبیدہ بن الجراح رضی اللہ عنہ کو بھیجا۔' WHERE id = 4189;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ محمد بن میمون نے، ان سے اعمش نے، ان سے ابراہیم نخعی نے اور ان سے علقمہ نے بیان کیا کہ ہم عبداللہ بن مسعود رضی اللہ عنہ کے پاس بیٹھے ہوئے تھے۔ اتنے میں خباب بن ارت رضی اللہ عنہ مشہور صحابی تشریف لائے اور کہا: ابوعبدالرحمٰن! کیا یہ نوجوان لوگ ( جو تمہارے شاگرد ہیں ) اسی طرح قرآن پڑھ سکتے ہیں جیسے آپ پڑھتے ہیں؟ ابن مسعود رضی اللہ عنہ نے کہا کہ اگر آپ چاہیں تو میں کسی سے تلاوت کے لیے کہوں؟ انہوں نے فرمایا کہ ضرور۔ اس پر ابن مسعود رضی اللہ عنہ نے کہا: علقمہ! تم پڑھو، زید بن حدیر، زیاد بن حدیر کے بھائی، بولے آپ علقمہ سے تلاوت قرآن کے لیے فرماتے ہیں حالانکہ وہ ہم سب سے اچھے قاری نہیں ہیں۔ ابن مسعود رضی اللہ عنہ نے کہا اگر تم چاہو تو میں تمہیں وہ حدیث سنا دوں جو رسول اللہ صلی اللہ علیہ وسلم نے تمہاری قوم کے حق میں فرمائی تھی۔ خیر علقمہ کہتے ہیں کہ میں نے سورۃ مریم کی پچاس آیتیں پڑھ کر سنائیں۔ عبداللہ بن مسعود رضی اللہ عنہ نے خباب رضی اللہ عنہ سے پوچھا کہو کیسا پڑھتا ہے؟ خباب رضی اللہ عنہ نے کہا بہت خوب پڑھا۔ عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ جو آیت بھی میں جس طرح پڑھتا ہوں علقمہ بھی اسی طرح پڑھتا ہے، پھر انہوں نے خباب رضی اللہ عنہ کو دیکھا، ان کے ہاتھ میں سونے کی انگوٹھی تھی، تو کہا: کیا ابھی وقت نہیں آیا ہے کہ یہ انگوٹھی پھینک دی جائے۔ خباب رضی اللہ عنہ نے کہا کہ آج کے بعد آپ یہ انگوٹھی میرے ہاتھ میں نہیں دیکھیں گے۔ چنانچہ انہوں نے انگوٹھی اتار دی۔ اسی حدیث کو غندر نے شعبہ سے روایت کیا ہے۔' WHERE id = 4199;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا کہ ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا مجھ سے عروہ بن زبیر اور ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ صفیہ رضی اللہ عنہا حجۃ الوداع کے موقع پر حائضہ ہو گئی تھیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا ابھی ہمیں ان کی وجہ سے رکنا پڑے گا؟ میں نے عرض کیا: یا رسول اللہ! یہ تو مکہ لوٹ کر طواف زیارت کر چکی ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر اسے چلنا چاہئیے ( طواف وداع کی ضرورت نہیں ) ۔' WHERE id = 4209;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا کہ مجھ سے میرے والد عروہ نے بیان کیا، انہوں نے کہا کہ اسامہ رضی اللہ عنہ سے حجۃ الوداع کے موقع پر نبی کریم صلی اللہ علیہ وسلم کی ( سفر میں ) رفتار کے متعلق پوچھا گیا تو انہوں نے کہا کہ بیچ کی چال چلتے تھے اور جب کشادہ جگہ ملتی تو اس سے تیز چلتے تھے۔' WHERE id = 4220;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو حمید طویل نے خبر دی اور انہیں انس بن مالک رضی اللہ عنہ نے کہ جب رسول اللہ صلی اللہ علیہ وسلم غزوہ تبوک سے واپس ہوئے۔ اور مدینہ کے قریب پہنچے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ مدینہ میں بہت سے ایسے لوگ ہیں کہ جہاں بھی تم چلے اور جس وادی کو بھی تم نے قطع کیا وہ ( اپنے دل سے ) تمہارے ساتھ ساتھ تھے۔ صحابہ رضی اللہ عنہم نے عرض کیا: یا رسول اللہ! اگرچہ ان کا قیام اس وقت بھی مدینہ میں ہی رہا ہو؟ آپ صلی اللہ علیہ وسلم نے فرمایا: ہاں، وہ مدینہ میں رہتے ہوئے بھی ( اپنے دل سے تمہارے ساتھ تھے ) وہ کسی عذر کی وجہ سے رک گئے تھے۔' WHERE id = 4230;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سعد نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں سنتی آئی تھی کہ ہر نبی کو وفات سے پہلے دنیا اور آخرت کے رہنے میں اختیار دیا جاتا ہے، پھر میں نے رسول اللہ صلی اللہ علیہ وسلم سے بھی سنا، آپ اپنے مرض الموت میں فرما رہے تھے۔ آپ صلی اللہ علیہ وسلم کی آواز بھاری ہو چکی تھی۔ آپ آیت «مع الذين أنعم الله عليهم‏» کی تلاوت فرما رہے تھے ( یعنی ان لوگوں کے ساتھ جن پر اللہ نے انعام کیا ہے ) مجھے یقین ہو گیا کہ آپ کو بھی اختیار دے دیا گیا ہے۔' WHERE id = 4241;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو بشر بن شعیب بن ابی حمزہ نے خبر دی، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے زہری نے بیان کیا، انہیں عبداللہ بن کعب بن مالک انصاری نے خبر دی اور کعب بن مالک رضی اللہ عنہ ان تین صحابہ میں سے ایک تھے جن کی ( غزوہ تبوک میں شرکت نہ کرنے کی ) توبہ قبول ہوئی تھی۔ انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ علی بن ابی طالب رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کے پاس سے باہر آئے۔ یہ اس مرض کا واقعہ ہے جس میں آپ صلی اللہ علیہ وسلم نے وفات پائی تھی۔ صحابہ رضی اللہ عنہم نے آپ سے پوچھا: ابوالحسن! نبی کریم صلی اللہ علیہ وسلم کا آج مزاج کیا ہے؟ صبح انہوں نے بتایا کہ الحمدللہ اب آپ کو افاقہ ہے۔ پھر عباس بن عبدالمطلب رضی اللہ عنہ نے علی رضی اللہ عنہ کا ہاتھ پکڑ کے کہا کہ تم، اللہ کی قسم تین دن کے بعد زندگی گزارنے پر تم مجبور ہو جاؤ گے۔ اللہ کی قسم، مجھے تو ایسے آثار نظر آ رہے ہیں کہ نبی کریم صلی اللہ علیہ وسلم اس مرض سے صحت نہیں پا سکیں گے۔ موت کے وقت بنو عبدالمطلب کے چہروں کی مجھے خوب شناخت ہے۔ اب ہمیں آپ کے پاس چلنا چاہئیے اور آپ سے پوچھنا چاہئیے کہ ہمارے بعد خلافت کسے ملے گی۔ اگر ہم اس کے مستحق ہیں تو ہمیں معلوم ہو جائے گا اور اگر کوئی دوسرا مستحق ہو گا تو وہ بھی معلوم ہو جائے گا اور آپ صلی اللہ علیہ وسلم ہمارے متعلق اپنے خلیفہ کو ممکن ہے کچھ وصیتیں کر دیں لیکن علی رضی اللہ عنہ نے کہا کہ اللہ کی قسم! اگر ہم نے اس وقت آپ سے اس کے متعلق کچھ پوچھا اور آپ نے انکار کر دیا تو پھر لوگ ہمیں ہمیشہ کے لیے اس سے محروم کر دیں گے۔ میں تو ہرگز آپ صلی اللہ علیہ وسلم سے اس کے متعلق کچھ نہیں پوچھوں گا۔' WHERE id = 4252;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم سے عبداللہ بن مبارک نے بیان کیا، ان سے یونس نے بیان کیا، ان سے زہری نے بیان کیا، انہیں سعید بن مسیب نے کئی اہل علم کی موجودگی میں خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم حالت صحت میں فرمایا کرتے تھے کہ ہر نبی کی روح قبض کرنے سے پہلے انہیں جنت میں ان کی قیام گاہ دکھائی گئی، پھر اختیار دیا گیا۔ پھر جب آپ صلی اللہ علیہ وسلم بیمار ہوئے اور آپ کا سر مبارک میری ران پر تھا۔ اس وقت آپ پر غشی طاری ہو گئی۔ جب ہوش میں آئے تو آپ نے اپنی نظر گھر کی چھت کی طرف اٹھا لی اور فرمایا «اللهم الرفيق الأعلى» ”اے اللہ! مجھے اپنی بارگاہ میں انبیاء اور صدیقین سے ملا دے۔“ میں اسی وقت سمجھ گئی کہ اب آپ ہمیں پسند نہیں کر سکتے اور مجھے وہ حدیث یاد آ گئی جو آپ حالت صحت میں ہم سے بیان کیا کرتے تھے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ آخری کلمہ جو زبان مبارک سے نکلا وہ یہی تھا کہ «اللهم الرفيق الأعلى» ۔' WHERE id = 4264;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں سمی نے، انہیں ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب امام «غير المغضوب عليهم ولا الضالين‏» کہے تو تم «آمين‏.‏» کہو کیونکہ جس کا یہ کہنا ملائکہ کے کہنے کے ساتھ ہو جائے اس کی تمام پچھلی خطائیں معاف ہو جاتی ہیں۔“' WHERE id = 4275;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے عثمان بن عمر نے بیان کیا، انہیں علی بن مبارک نے خبر دی، انہیں یحییٰ بن ابی کثیر نے، انہیں ابوسلمہ نے کہ ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ اہل کتاب ( یہودی ) توراۃ کو خود عبرانی زبان میں پڑھتے ہیں لیکن مسلمانوں کے لیے اس کی تفسیر عربی میں کرتے ہیں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم اہل کتاب کی نہ تصدیق کرو اور نہ تم تکذیب کرو بلکہ یہ کہا کرو «آمنا بالله وما أنزل إلينا» یعنی ہم ایمان لائے اللہ پر اور اس چیز پر جو ہماری طرف نازل کی گئی ہے۔“' WHERE id = 4285;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ہشام بن عروہ نے، ان سے ان کے والد نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا سے پوچھا ( ان دنوں میں نوعمر تھا ) کہ اللہ تبارک و تعالیٰ کے اس ارشاد کے بارے میں آپ کا کیا خیال ہے «إن الصفا والمروة من شعائر الله فمن حج البيت أو اعتمر فلا جناح عليه أن يطوف بهما‏» ”صفا اور مروہ بیشک اللہ کی یادگار چیزوں میں سے ہیں۔ پس جو کوئی بیت اللہ کا حج کرے یا عمرہ کرے تو اس پر کوئی گناہ نہیں کہ ان دونوں کے درمیان آمدورفت ( یعنی سعی ) کرے۔“ میرا خیال ہے کہ اگر کوئی ان کی سعی نہ کرے تو اس پر بھی کوئی گناہ نہیں ہونا چاہئیے۔ عائشہ رضی اللہ عنہا نے کہا کہ ہرگز نہیں جیسا کہ تمہارا خیال ہے۔ اگر مسئلہ یہی ہوتا تو پھر واقعی ان کے سعی نہ کرنے میں کوئی گناہ نہ تھا۔ لیکن یہ آیت انصار کے بارے میں نازل ہوئی تھی ( اسلام سے پہلے ) انصار منات بت کے نام سے احرام باندھتے تھے، یہ بت مقام قدید میں رکھا ہوا تھا اور انصار صفا اور مروہ کی سعی کو اچھا نہیں سمجھتے تھے۔ جب اسلام آیا تو انہوں نے سعی کے متعلق آپ صلی اللہ علیہ وسلم سے پوچھا: اس پر اللہ تعالیٰ نے یہ آیت نازل کی «إن الصفا والمروة من شعائر الله فمن حج البيت أو اعتمر فلا جناح عليه أن يطوف بهما‏» ”صفا اور مروہ بیشک اللہ کی یادگار چیزوں میں سے ہیں، سو جو کوئی بیت اللہ کا حج کرے یا عمرہ کرے تو اس پر کوئی بھی گناہ نہیں کہ ان دونوں کے درمیان ( سعی ) کرے۔“' WHERE id = 4295;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، انہوں نے کہا ہم کو روح نے خبر دی، انہوں نے کہا ہم سے زکریا بن اسحاق نے بیان کیا، انہوں نے کہا ہم سے عمرو بن دینار نے بیان کیا، ان سے عطاء نے اور انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا وہ یوں قرآت کر رہے تھے «وعلى الذين يطوقونه فدية طَعام مسكين» ( تفعیل سے ) «فدية طَعام مسكين» ۔“ ابن عباس رضی اللہ عنہما نے کہا کہ یہ آیت منسوخ نہیں ہے۔ اس سے مراد بہت بوڑھا مرد یا بہت بوڑھی عورت ہے۔ جو روزے کی طاقت نہ رکھتی ہو، انہیں چاہئیے کہ ہر روزہ کے بدلے ایک مسکین کو کھانا کھلا دیں۔' WHERE id = 4305;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے بیان کیا، ان سے عمران ابی بکر نے، ان سے ابورجاء نے بیان کیا اور ان سے عمران بن حصین رضی اللہ عنہما نے بیان کیا کہ ( حج میں ) تمتع کا حکم قرآن میں نازل ہوا اور ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تمتع کے ساتھ ( حج ) کیا، پھر اس کے بعد قرآن نے اس سے نہیں روکا اور نہ اس سے نبی کریم صلی اللہ علیہ وسلم نے روکا، یہاں تک کہ آپ کی وفات ہو گئی ( لہٰذا تمتع اب بھی جائز ہے ) یہ تو ایک صاحب نے اپنی رائے سے جو چاہا کہہ دیا ہے۔' WHERE id = 4316;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ مروزی نے بیان کیا، کہا ہم سے عبداللہ بن مبارک نے، کہا ہم کو عبداللہ بن عون نے خبر دی، ان سے محمد بن سیرین نے بیان کیا کہ میں انصار کی ایک مجلس میں حاضر ہوا۔ بڑے بڑے انصاری وہاں موجود تھے اور عبدالرحمٰن بن ابی لیلیٰ بھی موجود تھے۔ میں نے وہاں سبیعہ بنت حارث کے باب سے متعلق عبداللہ بن عتبہ کی حدیث کا ذکر کیا۔ عبدالرحمٰن نے کہا لیکن عبداللہ بن عتبہ کے چچا ( عبداللہ بن مسعود رضی اللہ عنہ ) ایسا نہیں کہتے تھے۔ ( محمد بن سیرین نے کہا ) کہ میں نے کہا کہ پھر تو میں نے ایک ایسے بزرگ عبداللہ بن عتبہ کے متعلق جھوٹ بولنے میں دلیری کی ہے کہ جو کوفہ میں ابھی زندہ موجود ہیں۔ میری آواز بلند ہو گئی تھی۔ ابن سیرین نے کہا کہ پھر جب میں باہر نکلا تو راستے میں مالک بن عامر یا مالک بن عوف سے ملاقات ہو گئی۔ ( راوی کو شک ہے کہ یہ ابن مسعود رضی اللہ عنہ کے رفیقوں میں سے تھے ) میں نے ان سے پوچھا کہ جس عورت کے شوہر کا انتقال ہو جائے اور وہ حمل سے ہو تو ابن مسعود رضی اللہ عنہ اس کی عدت کے متعلق کیا فتویٰ دیتے تھے؟ انہوں نے کہا کہ ابن مسعود رضی اللہ عنہ کہتے تھے کہ تم لوگ اس حاملہ پر سختی کے متعلق کیوں سوچتے ہو اس پر آسانی نہیں کرتے ( اس کو لمبی ) عدت کا حکم دیتے ہو۔ سورۃ نساء چھوٹی ( سورۃ الطلاق ) لمبی سورۃ نساء کے بعد نازل ہوئی ہے اور ایوب سختیانی نے بیان کیا، ان سے محمد بن سیرین نے کہ میں ابوعطیہ مالک بن عامر سے ملا۔' WHERE id = 4328;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے منصور نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب سورۃ البقرہ کی آخری آیتیں نازل ہوئیں تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں مسجد میں پڑھ کر سنایا اور شراب کی تجارت حرام قرار دی گئی۔' WHERE id = 4338;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ مدینہ میں ابوطلحہ رضی اللہ عنہ کے پاس انصار میں سب سے زیادہ کھجوروں کے درخت تھے اور بیرحاء کا باغ اپنی تمام جائیداد میں انہیں سب سے زیادہ عزیز تھا۔ یہ باغ مسجد نبوی کے سامنے ہی تھا اور نبی کریم صلی اللہ علیہ وسلم بھی اس میں تشریف لے جاتے اور اس کے میٹھے اور عمدہ پانی کو پیتے، پھر جب آیت «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”جب تک تم اپنی عزیز ترین چیزوں کو نہ خرچ کرو گے نیکی کے مرتبہ کو نہ پہنچ سکو گے۔“ نازل ہوئی تو ابوطلحہ رضی اللہ عنہ اٹھے اور عرض کیا: یا رسول اللہ! اللہ تعالیٰ فرماتا ہے کہ جب تک تم اپنی عزیز چیزوں کو خرچ نہ کرو گے نیکی کے مرتبہ کو نہ پہنچ سکو گے اور میرا سب سے زیادہ عزیز مال بیرحاء ہے اور یہ اللہ کی راہ میں صدقہ ہے۔ اللہ ہی سے میں اس کے ثواب و اجر کی توقع رکھتا ہوں، پس یا رسول اللہ! جہاں آپ مناسب سمجھیں اسے استعمال کریں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ خوب یہ فانی ہی دولت تھی، یہ فانی ہی دولت تھی۔ جو کچھ تم نے کہا ہے وہ میں نے سن لیا اور میرا خیال ہے کہ تم اپنے عزیز و اقرباء کو اسے دے دو۔ ابوطلحہ رضی اللہ عنہ نے کہا کہ میں ایسا ہی کروں گا، یا رسول اللہ! چنانچہ انہوں نے وہ باغ اپنے عزیزوں اور اپنے ناطہٰ والوں میں بانٹ دیا۔ عبداللہ بن یوسف اور روح بن عبادہ نے «ذلك مال رايح» ( «ربح» سے ) بیان کیا ہے۔ یعنی یہ مال بہت نفع دینے والا ہے۔ مجھ سے یحییٰ بن یحییٰ نے بیان کیا، کہا کہ میں نے امام مالک کے سامنے «مال رايح» ( «رواح» سے ) پڑھا تھا۔' WHERE id = 4349;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابوحصین نے، ان سے ابوالضحیٰ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب ابراہیم علیہ السلام کو آگ میں ڈالا گیا تو آخری کلمہ جو آپ کی زبان مبارک سے نکلا «حسبي الله ونعم الوكيل‏.‏» تھا یعنی میری مدد کے لیے اللہ کافی ہے اور وہی بہترین کام بنانے والا ہے۔' WHERE id = 4359;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے، انہوں نے کہا مجھ کو عروہ بن زبیر نے خبر دی انہوں نے عائشہ رضی اللہ عنہا سے آیت «وإن خفتم أن لا تقسطوا في اليتامى‏» کا مطلب پوچھا۔ انہوں نے کہا میرے بھانجے اس کا مطلب یہ ہے کہ ایک یتیم لڑکی اپنے ولی کی پرورش میں ہو اور اس کی جائیداد کی حصہ دار ہو ( ترکے کی رو سے اس کا حصہ ہو ) اب اس ولی کو اس کی مالداری خوبصورتی پسند آئے۔ اس سے نکاح کرنا چاہے پر انصاف کے ساتھ پورا مہر جتنا مہر اس کو دوسرے لوگ دیں، نہ دینا چاہے، تو اللہ تعالیٰ نے اس آیت میں لوگوں کو ایسی یتیم لڑکیوں کے ساتھ جب تک ان کا پورا مہر انصاف کے ساتھ نہ دیں، نکاح کرنے سے منع فرمایا اور ان کو یہ حکم دیا کہ تم دوسری عورتوں سے جو تم کو بھلی لگیں نکاح کر لو۔ ( یتیم لڑکی کا نقصان نہ کرو ) عروہ نے کہا عائشہ رضی اللہ عنہا کہتی تھیں، اس آیت کے اترنے کے بعد لوگوں نے پھر نبی کریم صلی اللہ علیہ وسلم سے اس بارے میں مسئلہ پوچھا، اس وقت اللہ نے یہ آیت «ويستفتونك في النساء‏» اتاری۔ عائشہ رضی اللہ عنہا نے کہا دوسری آیت میں یہ جو فرمایا «وترغبون أن تنكحوهن‏» یعنی وہ یتیم لڑکیاں جن کا مال و جمال کم ہو اور تم ان کے ساتھ نکاح کرنے سے نفرت کرو۔ اس کا مطلب یہ ہے کہ جب تم ان یتیم لڑکیوں سے جن کا مال و جمال کم ہو نکاح کرنا نہیں چاہتے تو مال اور جمال والی یتیم لڑکیوں سے بھی جن سے تم کو نکاح کرنے کی رغبت ہے نکاح نہ کرو، مگر جب انصاف کے ساتھ ان کا مہر پورا ادا کرو۔' WHERE id = 4369;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، انہوں نے کہا ہم کو حجاج بن محمد نے خبر دی، انہیں ابن جریج نے، انہیں یعلیٰ بن مسلم نے، انہیں سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ آیت «أطيعوا الله وأطيعوا الرسول وأولي الأمر منكم‏» ”اللہ کی اطاعت کرو اور رسول ( صلی اللہ علیہ وسلم ) کی اور اپنے میں سے حاکموں کی۔“ عبداللہ بن حذافہ بن قیس بن عدی رضی اللہ عنہ کے بارے میں نازل ہوئی تھی۔ جب رسول اللہ صلی اللہ علیہ وسلم نے انہیں ایک مہم پر بطور افسر کے روانہ کیا تھا۔' WHERE id = 4379;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، ان سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے بیان کیا اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ جب آیت «لا يستوي القاعدون من المؤمنين‏» نازل ہوئی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ فلاں ( یعنی زید بن ثابت رضی اللہ عنہ ) کو بلاؤ۔ وہ اپنے ساتھ دوات اور تختی یا شانہ کی ہڈی لے کر حاضر ہوئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا لکھو «لا يستوي القاعدون من المؤمنين والمجاهدون في سبيل الله» ۔ ابن ام مکتوم رضی اللہ عنہ نے جو نبی کریم صلی اللہ علیہ وسلم کے پیچھے موجود تھے، عرض کیا: یا رسول اللہ! میں نابینا ہوں۔ چنانچہ وہیں اس طرح آیت نازل ہوئی «لا يستوي القاعدون من المؤمنين غير أولي الضرر والمجاهدون في سبيل الله» ۔' WHERE id = 4389;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، انہوں نے کہا ہم سے فلیح نے بیان کیا، ان سے ہلال نے بیان کیا، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص یہ کہتا ہے میں یونس بن متی سے بہتر ہوں اس نے جھوٹ کہا۔“' WHERE id = 4399;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی رجاء نے بیان کیا، کہا ہم سے نضر بن شمیل نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، کہا مجھ کو میرے والد نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ان کے والد ابوبکر صدیق رضی اللہ عنہ اپنی قسم کے خلاف کبھی نہیں کیا کرتے تھے۔ لیکن جب اللہ تعالیٰ نے قسم کے کفارہ کا حکم نازل کر دیا تو ابوبکر رضی اللہ عنہ نے کہا کہ اب اگر اس کے ( یعنی جس کے لیے قسم کھا رکھی تھی ) سوا دوسری چیز مجھے اس سے بہتر معلوم ہوتی ہے تو میں اللہ تعالیٰ کی دی ہوئی رخصت پر عمل کرتا ہوں اور وہی کام کرتا ہوں جو بہتر ہوتا ہے۔' WHERE id = 4409;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ابی یعقوب ابوعبداللہ کرمانی نے بیان کیا، کہا ہم سے حسان بن ابراہیم نے بیان کیا، کہا ہم سے یونس نے بیان کیا، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے جہنم کو دیکھا کہ اس کے بعض حصے بعض دوسرے حصوں کو کھائے جا رہے ہیں اور میں نے عمرو بن عامر خزاعی کو دیکھا کہ وہ اپنی آنتیں اس میں گھسیٹا پھر رہا تھا۔ یہی وہ شخص ہے جس نے سب سے پہلے سانڈ چھوڑنے کی رسم ایجاد کی تھی۔' WHERE id = 4419;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو نے، ان سے ابووائل نے اور ان سے عبداللہ رضی اللہ عنہ نے کہا کہ اللہ سے زیادہ اور کوئی غیرت مند نہیں، یہی وجہ ہے کہ اس نے بےحیائیوں کو حرام قرار دیا ہے۔ خواہ وہ ظاہر ہوں خواہ پوشیدہ اور اللہ کو اپنی تعریف سے زیادہ اور کوئی چیز پسند نہیں، یہی وجہ ہے کہ اس نے اپنی خود مدح کی ہے۔ ( عمرو بن مرہ نے بیان کیا کہ ) میں نے پوچھا آپ نے یہ حدیث خود عبداللہ بن مسعود رضی اللہ عنہ سے سنی تھی انہوں نے بیان کیا کہ ہاں، میں نے پوچھا اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم کے حوالہ سے حدیث بیان کی تھی؟ کہا کہ ہاں۔' WHERE id = 4429;
UPDATE hadiths SET urdu = 'اور عبداللہ بن براد نے بیان کیا، ان سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عبداللہ بن زبیر رضی اللہ عنہما نے کہ اللہ تعالیٰ نے اپنے نبی کریم صلی اللہ علیہ وسلم کو حکم دیا ہے کہ لوگوں کے اخلاق ٹھیک کرنے کے لیے درگزر اختیار کریں یا کچھ ایسا ہی کہا۔' WHERE id = 4439;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا۔ انہوں نے کہا کہ سب سے آخر میں یہ آیت نازل ہوئی تھی «يستفتونك قل الله يفتيكم في الكلالة‏» اور سب سے آخر میں سورۃ برات نازل ہوئی۔' WHERE id = 4449;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن جعفی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابن جریج نے، ان سے ابن ابی ملیکہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب میرا عبداللہ بن زبیر رضی اللہ عنہما سے اختلاف ہو گیا تھا تو میں نے کہا کہ ان کے والد زبیر بن عوام رضی اللہ عنہ تھے، ان کی والدہ اسماء بنت ابوبکر رضی اللہ عنہا تھیں، ان کی خالہ عائشہ رضی اللہ عنہا تھیں۔ ان کے نانا ابوبکر رضی اللہ عنہ تھے اور ان کی دادی ( نبی کریم صلی اللہ علیہ وسلم کی پھوپھی ) صفیہ رضی اللہ عنہا تھیں۔ ( عبداللہ بن محمد نے بیان کیا کہ ) میں نے سفیان ( ابن عیینہ ) سے پوچھا کہ اس روایت کی سند کیا ہے؟ تو انہوں نے کہنا شروع کیا «حدثنا» ہم سے حدیث بیان کی لیکن ابھی اتنا ہی کہنے پائے تھے کہ انہیں ایک دوسرے شخص نے دوسری باتوں میں لگا دیا اور ( راوی کا نام ) ابن جریج وہ نہ بیان کر سکے۔' WHERE id = 4459;
UPDATE hadiths SET urdu = 'ہم سے مؤمل بن ہشام نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم نے بیان کیا، کہا ہم سے عوف نے بیان کیا، کہا ہم سے ابورجاء نے بیان کیا، کہا ہم سے سمرہ بن جندب نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہم سے فرمایا کہ رات ( خواب میں ) میرے پاس دو فرشتے آئے اور مجھے اٹھا کر ایک شہر میں لے گئے جو سونے اور چاندی کی اینٹوں سے بنایا گیا تھا، وہاں ہمیں ایسے لوگ ملے جن کا آدھا بدن نہایت خوبصورت، اتنا کہ کسی دیکھنے والے نے ایسا حسن نہ دیکھا ہو گا اور بدن کا دوسرا آدھا حصہ نہایت بدصورت تھا، اتنا کہ کسی نے بھی ایسی بدصورتی نہیں دیکھی ہو گی۔ دونوں فرشتوں نے ان لوگوں سے کہا جاؤ اور اس نہر میں غوطہٰ لگاؤ۔ وہ گئے اور نہر میں غوطہٰ لگا آئے۔ جب وہ ہمارے پاس آئے تو ان کی بدصورتی جاتی رہی اور اب وہ نہایت خوبصورت نظر آتے تھے پھر فرشتوں نے مجھ سے کہا کہ یہ ”جنت عدن“ ہے اور آپ کا مکان یہیں ہے۔ جن لوگوں کو ابھی آپ نے دیکھا کہ جسم کا آدھا حصہ خوبصورت تھا اور آدھا بدصورت، تو یہ وہ لوگ تھے جنہوں نے دنیا میں اچھے اور برے سب کام کئے تھے اور اللہ تعالیٰ نے انہیں معاف کر دیا تھا۔' WHERE id = 4469;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ فرماتا ہے کہ بندو! ( میری راہ میں ) خرچ کرو تو میں بھی تم پر خرچ کروں گا اور فرمایا، اللہ کا ہاتھ بھرا ہوا ہے۔ رات اور دن مسلسل کے خرچ سے بھی اس میں کم نہیں ہوتا اور فرمایا تم نے دیکھا نہیں جب سے اللہ نے آسمان و زمین کو پیدا کیا ہے، مسلسل خرچ کئے جا رہا ہے لیکن اس کے ہاتھ میں کوئی کمی نہیں ہوئی، اس کا عرش پانی پر تھا اور اس کے ہاتھ میں میزان عدل ہے جسے وہ جھکاتا اور اٹھاتا رہتا ہے۔ «اعتراك‏» باب «افتعال» سے ہے «عروته» سے یعنی میں نے اس کو پکڑ پایا اسی سے ہے۔ «يعروه» مضارع کا صیغہ اور «اعتراني آخذ بناصيتها‏» یعنی اس کی حکومت اور قبضہ قدرت میں ہیں۔ «عنيد»،‏‏‏‏ «عنود» اور «عاند» سب کے معنی ایک ہی ہیں یعنی سرکش مخالف اور یہ «جبار» کی تاکید ہے۔ «استعمركم‏» تم کو بسایا، آباد کیا۔ عرب لوگ کہتے ہیں «أعمرته الدار فهى عمرى» یعنی یہ گھر میں نے اس کو عمر بھر کے لیے دے ڈالا۔ «نكرهم‏»،‏‏‏‏ «أنكرهم» اور «استنكرهم» سب کے ایک ہی معنی ہیں۔ یعنی ان کو پردیسی سمجھا۔ «حميد»،‏‏‏‏ «فعيل» کے وزن پر ہے بہ معنی «محمود» میں سراہا گیا اور «مجيد‏»،‏‏‏‏ «ماجد‏.‏» کے معنی میں ہے ( یعنی کرم کرنے والا ) ۔ «سجيل» اور «سجين» دونوں کے معنی سخت اور بڑا کے ہیں۔ «لام» اور «نون» بہنیں ہیں ( ایک دوسرے سے بدلی جاتی ہیں ) ۔ تمیم بن مقبل شاعر کہتا ہے۔ بعضے پیدل دن دھاڑے خود پر ضرب لگاتے ہیں ایسی ضرب جس کی سختی کے لیے بڑے بڑے پہلوان اپنے شاگردوں کو وصیت کیا کرتے ہیں۔' WHERE id = 4479;
UPDATE hadiths SET urdu = 'ہم سے سعید بن تلید نے بیان کیا، انہوں نے کہا ہم سے عبدالرحمٰن بن قاسم نے بیان کیا، ان سے بکر بن مضر نے، ان سے عمرو بن حارث نے، ان سے یونس بن یزید نے، ان سے ابن شہاب نے، ان سے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ لوط علیہ السلام پر اپنی رحمت نازل فرمائے کہ انہوں نے ایک زبردست سہارے کی پناہ لینے کے لیے کہا تھا اور اگر میں قید خانے میں اتنے دنوں تک رہ چکا ہوتا جتنے دن یوسف علیہ السلام رہے تھے تو بلانے والے کی بات رد نہ کرتا اور ہم کو تو ابراہیم علیہ السلام کے بہ نسبت شک ہونا زیادہ سزاوار ہے۔ جب اللہ پاک نے ان سے فرمایا «أولم تؤمن قال بلى ولكن ليطمئن قلبي‏» کہ کیا تجھ کو یقین نہیں؟ انہوں نے کہا کیوں نہیں یقین تو ہے پر میں چاہتا ہوں کہ اور اطمینان ہو جائے۔' WHERE id = 4489;
UPDATE hadiths SET urdu = 'مجھ سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابوظبیان حصین بن جندب نے بیان کیا، اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ آیت «كما أنزلنا على المقتسمين‏» میں سے یہود و نصاریٰ مراد ہیں کچھ قرآن انہوں نے مانا کچھ نہ مانا۔' WHERE id = 4501;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ آیت «وما جعلنا الرؤيا التي أريناك إلا فتنة للناس‏» میں «رؤيا» سے آنکھ کا دیکھنا مراد ہے ( بیداری میں نہ کہ خواب میں ) یعنی وہ جو نبی کریم صلی اللہ علیہ وسلم کو شب معراج میں دکھایا گیا اور «شجرة الملعونة‏» سے تھوہڑ کا درخت مراد ہے۔' WHERE id = 4511;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسی نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں ابن جریر نے خبر دی، کہا کہ مجھے یعلیٰ بن مسلم اور عمرو بن دینار نے خبر دی سعید بن جبیر سے، دونوں میں سے ایک اپنے ساتھی اور دیگر راوی کے مقابلہ میں بعض الفاظ زیادہ کہتا ہے اور ان کے علاوہ ایک اور صاحب نے بھی سعید بن جبیر سے سن کر بیان کیا کہ انہوں نے کہا ہم ابن عباس رضی اللہ عنہما کی خدمت میں ان کے گھر حاضر تھے۔ انہوں نے فرمایا کہ دین کی باتیں مجھ سے کچھ پوچھو۔ میں نے عرض کیا: اے ابوعباس! اللہ آپ پر مجھے قربان کرے کوفہ میں ایک واعظ شخص نوف نامی ( نوف بکالی ) ہے اور وہ کہتا ہے کہ موسیٰ، خضر علیہ السلام سے ملنے والے وہ نہیں تھے جو بنی اسرائیل کے پیغمبر موسیٰ علیہ السلام ہوئے ہیں ( ابن جریج نے بیان کیا کہ ) عمرو بن دینار نے تو روایت اس طرح بیان کی کہ ابن عباس نے کہا دشمن خدا جھوٹی بات کہتا ہے اور یعلیٰ بن مسلم نے اپنی روایت میں اس طرح مجھ سے بیان کیا کہ ابن عباس رضی اللہ عنہما نے کہا کہ مجھ سے ابی بن کعب رضی اللہ عنہ نے بیان کیا، کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام اللہ کے رسول تھے ایک دن آپ نے لوگوں ( بنی اسرائیل ) کو ایسا وعظ فرمایا کہ لوگوں کی آنکھوں سے آنسو نکل پڑے اور دل پسیج گئے تو آپ واپس جانے کے لیے مڑے۔ اس وقت ایک شخص نے ان سے پوچھا: اے اللہ کے رسول! کیا دنیا میں آپ سے بڑا کوئی عالم ہے؟ انہوں نے کہا کہ نہیں، اس پر اللہ نے موسیٰ علیہ السلام پر عتاب نازل کیا، کیونکہ انہوں نے علم کی نسبت اللہ تعالیٰ کی طرف نہیں کی تھی۔ ( ان کو یوں کہنا چاہئے تھا کہ اللہ ہی جانتا ہے ) ۔ ان سے کہا گیا کہ ہاں تم سے بھی بڑا عالم ہے۔ موسیٰ علیہ السلام نے عرض کیا، اے پروردگار! وہ کہاں ہے۔ اللہ نے فرمایا جہاں ( فارس اور روم کے ) دو دریا ملے ہیں۔ موسیٰ علیہ السلام نے عرض کیا: اے پروردگار! میرے لیے ان کی کوئی نشانی ایسی بتلا دے کہ میں ان تک پہنچ جاؤں۔ اب عمرو بن دینار نے مجھ سے اپنی روایت اس طرح بیان کی ہے کہ اللہ تعالیٰ نے فرمایا، جہاں تم سے مچھلی تمہاری زنبیل سے چل دے ( وہیں وہ ملیں گے ) اور یعلیٰ نے حدیث اس طرح بیان کی کہ ایک مردہ مچھلی ساتھ لے لو، جہاں اس مچھلی میں جان پڑ جائے ( وہیں وہ ملیں گے ) موسیٰ علیہ السلام نے مچھلی ساتھ لے لی اور اسے ایک زنبیل میں رکھ لیا۔ آپ نے اپنے ساتھی یوشع سے فرمایا کہ میں بس تمہیں اتنی تکلیف دیتا ہوں کہ جب یہ مچھلی زنبیل سے نکل کر چل دے تو مجھے بتانا۔ انہوں نے عرض کیا کہ یہ کون سی بڑی تکلیف ہے۔ اسی کی طرف اشارہ ہے اللہ تعالیٰ کے ارشاد «وإذ قال موسى لفتاه‏» میں وہ «فتي» ( رفیق سفر ) یوشع ابن نون تھے۔ سعید بن جبیر ( راوی حدیث ) نے اپنی روایت میں یوشع بن نون کا نام نہیں لیا۔ بیان کیا کہ پھر موسیٰ علیہ السلام ایک چٹان کے سایہ میں ٹھہر گئے جہاں نمی اور ٹھنڈ تھی۔ اس وقت مچھلی تڑپی اور دریا میں کود گئی۔ موسیٰ علیہ السلام سو رہے تھے اس لیے یوشع نے سوچا کہ آپ کو جگانا نہ چاہئے۔ لیکن جب موسیٰ علیہ السلام بیدار ہوئے تو مچھلی کا حال کہنا بھول گئے۔ اسی عرصہ میں مچھلی تڑپ کر پانی میں چلی گئی۔ اللہ تعالیٰ نے مچھلی کی جگہ پانی کے بہاؤ کو روک دیا اور مچھلی کا نشان پتھر پر جس پر سے گئی تھی بن گیا۔ عمرو بن دینار نے مجھ ( ابن جریج ) سے بیان کیا کہ اس کا نشان پتھر پہ بن گیا اور دونوں انگوٹھوں اور کلمہ کی انگلیوں کو ملا کر ایک حلقہ کی طرح اس کو بتایا۔ بیدار ہونے کے بعد موسیٰ علیہ السلام باقی دن اور باقی رات چلتے رہے۔ آخر کہنے لگے۔ ہمیں اب اس سفر میں تھکن ہو رہی ہے۔ ان کے خادم نے عرض کیا۔ اللہ نے آپ کی تھکن کو دور کر دیا ہے ( اور مچھلی زندہ ہو گئی ہے ) ۔ ابن جریج نے بیان کیا کہ یہ ٹکڑا سعید بن جبیر کی روایت میں نہیں ہے۔ پھر موسیٰ علیہ السلام اور یوشع دونوں واپس لوٹے اور خضر علیہ السلام سے ملاقات ہوئی ( ابن جریج نے کہا ) مجھ سے عثمان بن ابی سلیمان نے بیان کیا کہ خضر علیہ السلام دریا کے بیچ میں ایک چھوٹے سے سبز زین پوش پر تشریف رکھتے تھے۔ اور سعید بن جبیر نے یوں بیان کیا کہ وہ اپنے کپڑے سے تمام جسم لپیٹے ہوئے تھے۔ کپڑے کا ایک کنارہ ان کے پاؤں کے نیچے تھا اور دوسرا سر کے تلے تھا۔ موسیٰ علیہ السلام نے پہنچ کو سلام کیا تو خضر علیہ السلام نے اپنا چہرہ کھولا اور کہا، میری اس زمین میں سلام کا رواج کہاں سے آ گیا۔ آپ کون ہیں؟ موسیٰ علیہ السلام نے فرمایا کہ میں موسیٰ ہوں۔ پوچھا، موسیٰ بنی اسرائیل؟ فرمایا کہ ہاں! پوچھا، آپ کیوں آئے ہیں؟ فرمایا کہ میرے آنے کا مقصد یہ ہے کہ جو ہدایت کا علم آپ کو اللہ نے دیا ہے وہ مجھے بھی سکھا دیں۔ اس پر خضر علیہ السلام نے فرمایا کہ موسیٰ کیا آپ کے لیے یہ کافی نہیں ہے اس کا پورا سیکھنا آپ کے لیے مناسب نہیں ہے۔ اسی طرح آپ کو جو علم حاصل ہے اس کا پورا سیکھنا میرے لیے مناسب نہیں۔ اس عرصہ میں ایک چڑیا نے اپنی چونچ سے دریا کا پانی لیا تو خضر علیہ السلام نے فرمایا: اللہ کی قسم! میرا اور آپ کا علم اللہ کے علم کے مقابلے میں اس سے زیادہ نہیں ہے۔ جتنا اس چڑیا نے دریا کا پانی اپنی چونچ میں لیا ہے۔ کشتی پر چڑھنے کے وقت انہوں نے چھوٹی چھوٹی کشتیاں دیکھیں جو ایک کنارے والوں کو دوسرے کنارے پر لے جا کر چھوڑ آتی تھیں۔ کشتی والوں نے خضر علیہ السلام کو پہچان لیا اور کہا کہ یہ اللہ کے صالح بندے ہیں ہم ان سے کرایہ نہیں لیں گے۔ لیکن خضر علیہ السلام نے کشتی میں شگاف کر دیئے اور اس میں ( تختوں کی جگہ ) کیلیں گاڑ دیں۔ موسیٰ علیہ السلام نے کہا آپ نے اس لیے اسے پھاڑ ڈالا کہ اس کے مسافروں کو ڈبو دیں۔ بلاشبہ آپ نے ایک بڑا ناگوار کام کیا ہے۔ مجاہد نے آیت میں «إمرا» کا ترجمہ «منكرا» کیا ہے۔ خضر علیہ السلام نے فرمایا میں نے پہلے ہی نہ کہا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے۔ موسیٰ علیہ السلام کا پہلا سوال تو بھولنے کی وجہ سے تھا لیکن دوسرا بطور شرط تھا اور تیسرا قصداً انہوں نے کیا تھا۔ موسیٰ علیہ السلام نے اس پہلے سوال پر کہا کہ جو میں بھول گیا اس پر مجھ سے مؤاخذہ نہ کیجئے اور میرے معاملہ میں تنگی نہ کیجئے۔ پھر انہیں ایک بچہ ملا تو خضر علیہ السلام نے اسے قتل کر دیا۔ یعلیٰ نے بیان کیا کہ سعید بن جبیر نے کہا کہ خضر علیہ السلام کو چند بچے ملے جو کھیل رہے تھے آپ نے ان میں سے ایک بچہ کو پکڑا جو کافر اور چالاک تھا اور اسے لٹا کر چھری سے ذبح کر دیا۔ موسیٰ علیہ السلام نے فرمایا، آپ نے بلا کسی خون کے ایک بےگناہ جان کو جس نے کہ برا کام نہیں کیا تھا، قتل کر ڈالا۔ ابن عباس رضی اللہ عنہما آیت میں «زكية» کی جگہ «زاكية» پڑھا کرتے تھے۔ بمعنی «مسلمة» جیسے «غلاما زكيا» میں ہے۔ پھر وہ دونوں بزرگ آگے بڑھے تو ایک دیوار پر نظر پڑی جو بس گرنے ہی والی تھی۔ خضر علیہ السلام نے اسے ٹھیک کر دیا۔ سعید بن جبیر نے اپنے ہاتھ سے اشارہ کر کے بتایا کہ اس طرح۔ یعلیٰ بن مسلم نے بیان کیا میرا خیال ہے کہ سعید بن جبیر نے بیان کیا کہ خضر نے دیوار پر ہاتھ پھیر کر اسے ٹھیک کر دیا۔ موسیٰ علیہ السلام نے فرمایا کہ اگر آپ چاہتے تو اس پر اجرت لے سکتے تھے۔ سعید بن جبیر نے اس کی تشریح کی کہ اجرت جسے ہم کھا سکتے۔ آیت «وكان وراءهم» کی ابن عباس رضی اللہ عنہما نے قرآت «وكان أمامهم» کی یعنی کشتی جہاں جا رہی تھی اس ملک میں ایک بادشاہ تھا۔ سعید کے سوا دوسرے راوی سے اس بادشاہ کا نام ہدد بن بدد نقل کرتے ہیں اور جس بچہ کو خضر علیہ السلام نے قتل کیا تھا اس کا نام لوگ جیسور بیان کرتے ہیں۔ وہ بادشاہ ہر ( نئی ) کشتی کو زبردستی چھین لیا کرتا تھا۔ اس لیے میں نے چاہا کہ جب یہ کشتی اس کے سامنے سے گزرے تو اس کے اس عیب کی وجہ سے اسے نہ چھینے۔ جب کشتی والے اس بادشاہ کی سلطنت سے گزر جائیں گے تو وہ خود اسے ٹھیک کر لیں گے اور اسے کام میں لاتے رہیں گے۔ بعض لوگوں کا تو یہ خیال ہے کہ انہوں نے کشتی کو پھر سیسہ لگا کر جوڑا تھا اور بعض کہتے ہیں کہ تار کول سے جوڑا تھا ( اور جس بچہ کو قتل کر دیا تھا ) تو اس کے والدین مومن تھے اور وہ بچہ ( اللہ کی تقدیر میں ) کافر تھا۔ اس لیے ہمیں ڈر تھا کہ کہیں ( بڑا ہو کر ) وہ انہیں بھی کفر میں مبتلا نہ کر دے کہ اپنے لڑکے سے انتہائی محبت انہیں اس کے دین کی اتباع پر مجبور کر دے۔ اس لیے ہم نے چاہا کہ اللہ اس کے بدلے میں انہیں کوئی نیک اور اس سے بہتر اولاد دے۔ «وأقرب رحما» یعنی اس کے والدین اس بچہ پر جو اب اللہ تعالیٰ انہیں دے گا پہلے سے زیادہ بہتر مہربان ہوں جسے خضر علیہ السلام نے قتل کر دیا ہے۔ سعید بن جبیر رضی اللہ عنہ نے کہا کہ ان والدین کو اس بچے کے بدلے ایک لڑکی دی گئی تھی۔ داود بن ابی عاصم رحمہ اللہ کئی راویوں سے نقل کرتے ہیں کہ وہ لڑکی ہی تھی۔' WHERE id = 4521;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، کہا ہم سے مہدی بن میمون نے، ان سے محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ( عالم مثال میں ) آدم علیہ السلام اور موسیٰ علیہ السلام کی ملاقات ہوئی تو موسیٰ علیہ السلام نے آدم علیہ السلام سے کہا کہ آپ ہی نے لوگوں کو پریشانی میں ڈالا اور انہیں جنت سے نکالا۔ آدم علیہ السلام نے جواب دیا کہ آپ وہی ہیں جنہیں اللہ تعالیٰ نے اپنی رسالت کے لیے پسند کیا اور خود اپنے لیے پسند کیا اور آپ پر توریت نازل کی۔ موسیٰ علیہ السلام نے کہا کہ جی ہاں۔ اس پر آدم علیہ السلام نے فرمایا کہ پھر آپ نے تو دیکھا ہی ہو گا کہ میری پیدائش سے پہلے ہی یہ سب کچھ میرے لیے لکھ دیا گیا تھا۔ موسیٰ علیہ السلام نے فرمایا کہ جی ہاں معلوم ہے۔ چنانچہ آدم علیہ السلام موسیٰ علیہ السلام پر غالب آ گئے۔ «اليم» کے معنی دریا کے ہیں۔' WHERE id = 4531;
UPDATE hadiths SET urdu = 'مجھ سے ابوالربیع سلیمان بن داؤد نے بیان کیا، کہا ہم سے فلیح نے، ان سے زہری نے، ان سے سہل بن سعد نے کہ ایک صاحب ( یعنی عویمر ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! ایسے شخص کے متعلق آپ کا کیا ارشاد ہے جس نے اپنی بیوی کے ساتھ ایک غیر مرد کو دیکھا ہو کیا وہ اسے قتل کر دے؟ لیکن پھر آپ قصاص میں قاتل کو قتل کر دیں گے۔ پھر اسے کیا کرنا چاہئے؟ انہیں کے متعلق اللہ تعالیٰ نے دو آیات نازل کیں جن میں لعان کا ذکر ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تمہارے اور تمہاری بیوی کے بارے میں فیصلہ کیا جا چکا ہے۔ راوی نے بیان کیا کہ پھر دونوں میاں بیوی نے لعان کیا اور میں اس وقت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھا۔ پھر آپ نے دونوں میں جدائی کرا دی اور دو لعان کرنے والوں میں اس کے بعد یہی طریقہ قائم ہو گیا کہ ان میں جدائی کرا دی جائے۔ ان کی بیوی حاملہ تھیں، لیکن انہوں نے اس کا بھی انکار کر دیا۔ چنانچہ جب بچہ پیدا ہوا تو اسے ماں ہی کے نام سے پکارا جانے لگا۔ میراث کا یہ طریقہ ہوا کہ بیٹا ماں کا وارث ہوتا ہے اور ماں اللہ کے مقرر کئے ہوئے حصہ کے مطابق بیٹے کی وارث ہوتی ہے۔' WHERE id = 4541;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے ابن ابی عدی نے بیان کیا، کہا کہ ہم کو شعبہ نے خبر دی، انہیں اعمش نے، انہیں ابوالضحیٰ نے اور ان سے مسروق نے بیان کیا، کہ حسان بن ثابت رضی اللہ عنہ عائشہ رضی اللہ عنہا کے پاس آئے اور یہ شعر پڑھا۔ عفیفہ اور بڑی عقلمند ہیں، ان کے متعلق کسی کو شبہ بھی نہیں گزر سکتا۔ آپ غافل اور پاک دامن عورتوں کا گوشت کھانے سے کامل پرہیز کرتی ہیں۔“ اس پر عائشہ رضی اللہ عنہا نے فرمایا کہ لیکن اے حسان! تو ایسا نہیں ہے۔ بعد میں، میں نے عرض کیا آپ ایسے شخص کو اپنے پاس آنے دیتی ہیں؟ اللہ تعالیٰ تو یہ آیت بھی نازل کر چکا ہے «والذي تولى كبره منهم‏» کہ ”اور جس نے ان میں سے سب سے بڑا حصہ لیا۔“ الخ۔ عائشہ رضی اللہ عنہا نے کہا کہ نابینا ہو جانے سے بڑھ کر اور کیا عذاب ہو گا، پھر انہوں نے کہا کہ حسان رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کی طرف سے کفار کی ہجو کا جواب دیا کرتے تھے ( کیا یہ شرف ان کے لیے کم ہے ) ۔' WHERE id = 4551;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا مجھ کو میرے والد نے خبر دی، انہیں شعبہ نے، انہیں منصور نے، ان سے سعید بن جبیر نے بیان کیا کہ مجھے عبدالرحمٰن بن ابزیٰ نے حکم دیا کہ میں ابن عباس رضی اللہ عنہما سے دو آیتوں کے بارے میں پوچھوں یعنی «ومن يقتل مؤمنا متعمدا‏» ”اور جس نے کسی مومن کو جان بوجھ کر قتل کیا“ الخ۔ میں نے ان سے پوچھا تو انہوں نے فرمایا کہ یہ آیت کسی چیز سے بھی منسوخ نہیں ہوئی ہے۔ ( اور دوسری آیت جس کے ) بارے میں مجھے انہوں نے پوچھنے کا حکم دیا وہ یہ تھی «والذين لا يدعون مع الله إلها آخر‏» ”اور جو لوگ کسی معبود کو اللہ کے ساتھ نہیں پکارتے“ آپ نے اس کے متعلق فرمایا کہ یہ مشرکین کے بارے میں نازل ہوئی تھی۔' WHERE id = 4561;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ جب آیت «الذين آمنوا ولم يلبسوا إيمانهم بظلم‏» کہ ”جو لوگ ایمان لائے اور اپنے ایمان کے ساتھ ظلم کی آمیزش نہیں کی۔“ نازل ہوئی تو اصحاب رسول صلی اللہ علیہ وسلم بہت گھبرائے اور کہنے لگے کہ ہم میں کون ایسا ہو گا جس نے اپنے ایمان کے ساتھ ظلم کی ملاوٹ نہیں کی ہو گی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ آیت میں ظلم سے یہ مراد نہیں ہے۔ تم نے لقمان علیہ السلام کی وہ نصیحت نہیں سنی جو انہوں نے اپنے بیٹے کو کی تھی «إن الشرك لظلم عظيم‏» کہ ”بیشک شرک کرنا بڑا بھاری ظلم ہے۔“' WHERE id = 4571;
UPDATE hadiths SET urdu = 'اور لیث نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، کہا مجھے ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کو حکم ہوا کہ اپنی ازواج کو اختیار دیں تو آپ صلی اللہ علیہ وسلم میرے پاس تشریف لائے اور فرمایا کہ میں تم سے ایک معاملہ کے متعلق کہنے آیا ہوں، ضروری نہیں کہ تم جلدی کرو، اپنے والدین سے بھی مشورہ لے سکتی ہو۔ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو تو معلوم ہی تھا کہ میرے والدین آپ سے جدائی کا کبھی مشورہ نہیں دے سکتے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے ( وہ آیت جس میں یہ حکم تھا ) پڑھی کہ اللہ پاک کا ارشاد ہے «يا أيها النبي قل لأزواجك إن كنتن تردن الحياة الدنيا وزينتها‏» ”اے نبی! اپنی بیویوں سے فرما دیجئیے کہ اگر تم دنیوی زندگی اور اس کی زینت کو چاہتی ہو سے «أجرا عظيما‏» تک۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا لیکن اپنے والدین سے مشورہ کی کس بات کے لیے ضرورت ہے، ظاہر ہے کہ میں اللہ اور اس کے رسول اور عالم آخرت کو چاہتی ہوں۔ بیان کیا کہ پھر دوسری ازواج مطہرات نے بھی وہی کہا جو میں کہہ چکی تھی۔ اس کی متابعت موسیٰ بن اعین نے معمر سے کی ہے کہ ان سے زہری نے بیان کیا کہ انہیں ابوسلمہ نے خبر دی اور عبدالرزاق اور ابوسفیان معمری نے معمر سے بیان کیا، ان سے زہری نے، اور ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے۔' WHERE id = 4581;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، ان سے عروہ بن زبیر نے بیان کیا، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ پردہ کا حکم نازل ہونے کے بعد ابوالقعیس کے بھائی افلح رضی اللہ عنہ نے مجھ سے ملنے کی اجازت چاہی، لیکن میں نے کہلوا دیا کہ جب تک اس سلسلے میں رسول اللہ صلی اللہ علیہ وسلم سے اجازت حاصل نہ لے لوں، ان سے نہیں مل سکتی۔ میں نے سوچا کہ ان کے بھائی ابوالقعیس نے مجھے تھوڑا ہی دودھ پلایا تھا، دودھ پلانے والی تو ابوالقعیس کی بیوی تھی۔ پھر نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ سے عرض کیا کہ یا رسول اللہ! ابوالقعیس کے بھائی افلح رضی اللہ عنہ نے مجھ سے ملنے کی اجازت چاہی، لیکن میں نے یہ کہلوا دیا کہ جب تک نبی کریم صلی اللہ علیہ وسلم سے اجازت نہ لے لوں ان سے ملاقات نہیں کر سکتی۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اپنے چچا سے ملنے سے تم نے کیوں انکار کر دیا۔ میں نے عرض کیا: یا رسول اللہ! ابوالقعیس نے مجھے تھوڑا ہی دودھ پلایا تھا، دودھ پلانے والی تو ان کی بیوی تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا انہیں اندر آنے کی اجازت دے دو وہ تمہارے چچا ہیں۔ عروہ نے بیان کیا کہ اسی وجہ سے عائشہ رضی اللہ عنہا فرماتی تھیں کہ رضاعت سے بھی وہ چیز یں ( مثلاً نکاح وغیرہ ) حرام ہو جاتی ہیں جو نسب کی وجہ سے حرام ہوتی ہیں۔' WHERE id = 4591;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عوام بن حوشب نے کہ میں نے مجاہد سے سورۃ ص میں سجدہ کے متعلق پوچھا تو انہوں نے کہا کہ یہ سوال ابن عباس رضی اللہ عنہما سے بھی کیا گیا تھا تو انہوں نے اس آیت کی تلاوت کی «أولئك الذين هدى الله فبهداهم اقتده‏» ”یہی وہ لوگ ہیں جنہیں اللہ نے ہدایت دی تھی پس آپ بھی انہی کی ہدایت کی اتباع کریں۔“ اور ابن عباس رضی اللہ عنہما اس میں سجدہ کیا کرتے تھے۔' WHERE id = 4601;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا، ان سے روح بن قاسم نے، ان سے مجاہد نے، ان سے ابومعمر نے اور ان سے ابن مسعود رضی اللہ عنہ نے آیت «وما كنتم تستترون أن يشهد،‏‏‏‏ عليكم سمعكم‏» ”اور تم اس بات سے اپنے کو چھپا نہیں سکتے تھے کہ تمہارے کان گواہی دیں گے۔“ الخ کے متعلق کہا کہ قریش کے دو آدمی اور بیوی کی طرف سے ان کے قبیلہ ثقیب کا کوئی رشتہ دار یا ثقیف کے دو افراد تھے اور بیوی کی طرف قریش کا کوئی رشتہ دار، یہ خانہ کعبہ کے پاس بیٹھے ہوئے تھے ان میں سے بعض نے کہا کہ کیا تمہارا خیال ہے کہ اللہ تعالیٰ ہماری باتیں سنتا ہو گا ایک نے کہا کہ بعض باتیں سنتا ہے۔ دوسرے نے کہا کہ اگر بعض باتیں سن سکتا ہے تو سب سنتا ہو گا۔ اس پر یہ آیت نازل ہوئی «وما كنتم تستترون أن يشهد عليكم سمعكم ولا أبصاركم‏» ”اور تم اس بات سے اپنے کو چھپا ہی نہیں سکتے کہ تمہارے خلاف تمہارے کان اور تمہاری آنکھیں گواہی دیں گی۔“ آخر آیت «وذلكم ظنكم‏» تک۔' WHERE id = 4611;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ فرماتا ہے کہ ابن آدم مجھے تکلیف پہنچاتا ہے وہ زمانہ کو گالی دیتا ہے حالانکہ میں ہی زمانہ ہوں، میرے ہی ہاتھ میں سب کچھ ہے۔ میں رات اور دن کو ادلتا بدلتا رہتا ہوں۔' WHERE id = 4621;
UPDATE hadiths SET urdu = 'ہم سے حسن بن عبدالعزیز نے بیان کیا، کہا ہم سے عبداللہ بن یحییٰ نے بیان کیا، انہیں حیوہ نے خبر دی، انہیں ابوالاسود نے، انہوں نے عروہ سے سنا اور انہوں نے عائشہ رضی اللہ عنہا سے کہ نبی کریم صلی اللہ علیہ وسلم رات کی نماز میں اتنا طویل قیام کرتے کہ آپ کے قدم پھٹ جاتے۔ عائشہ رضی اللہ عنہا نے ایک مرتبہ عرض کیا کہ یا رسول اللہ! آپ اتنی زیادہ مشقت کیوں اٹھاتے ہیں۔ اللہ تعالیٰ نے تو آپ کی اگلی پچھلی خطائیں معاف کر دی ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کیا پھر میں شکر گزار بندہ بننا پسند نہ کروں۔ عمر کے آخری حصہ میں ( جب طویل قیام دشوار ہو گیا تو ) آپ صلی اللہ علیہ وسلم بیٹھ کر رات کی نماز پڑھتے اور جب رکوع کا وقت آتا تو کھڑے ہو جاتے ( اور تقریباً تیس یا چالیس آیتیں اور پڑھتے ) پھر رکوع کرتے۔' WHERE id = 4631;
UPDATE hadiths SET urdu = 'ہم سے حسن بن محمد نے بیان کیا، انہوں نے کہا ہم سے حجاج نے بیان کیا، ان سے ابن جریج نے بیان کیا، انہیں ابن ابی ملیکہ نے خبر دی اور انہیں عبداللہ بن زبیر رضی اللہ عنہما نے خبر دی کہ قبیلہ بنی تمیم کے سواروں کا وفد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آیا۔ ابوبکر رضی اللہ عنہ نے کہا کہ ان کا امیر آپ قعقاع بن معبد کو بنا دیں اور عمر رضی اللہ عنہ نے کہا بلکہ اقرع بن حابس کو امیر بنائیں۔ ابوبکر رضی اللہ عنہ نے اس پر کہا کہ مقصد تو صرف میری مخالفت ہی کرنا ہے۔ عمر نے کہا کہ میں نے آپ کے خلاف کرنے کی غرض سے یہ نہیں کہا ہے۔ اس پر دونوں میں بحث چلی گئی اور آواز بھی بلند ہو گئی۔ اسی کے متعلق یہ آیت نازل ہوئی «يا أيها الذين آمنوا لا تقدموا بين يدى الله ورسوله‏» کہ ”اے ایمان والو! تم اللہ اور اس کے رسول سے پہلے کسی کام میں جلدی مت کیا کرو۔“ آخر آیت تک۔' WHERE id = 4641;
UPDATE hadiths SET urdu = 'ہم سے طلق بن غنام نے بیان کیا، ان سے زائدہ بن قدامہ کوفی نے بیان کیا، ان سے سلیمان شیبانی نے بیان کیا کہ میں نے زر بن حبیش سے اس آیت کے بارے میں پوچھا «فكان قاب قوسين أو أدنى * فأوحى إلى عبده ما أوحى‏» الخ یعنی سو دو کمانوں کا فاصلہ رہ گیا بلکہ اور بھی کم۔ پھر اللہ نے اپنے بندے پر وحی کی جو کچھ بھی نازل کیا تو انہوں نے بیان کیا کہ ہمیں عبداللہ بن مسعود رضی اللہ عنہ نے خبر دی کہ محمد صلی اللہ علیہ وسلم نے جبرائیل علیہ السلام کو دیکھا تھا جن کے چھ سو پر تھے۔' WHERE id = 4651;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے یونس بن محمد نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ مکہ والوں نے نبی کریم صلی اللہ علیہ وسلم سے معجزہ دکھانے کو کہا تو نبی کریم صلی اللہ علیہ وسلم نے انہیں چاند کے پھٹ جانے کا معجزہ دکھایا۔' WHERE id = 4661;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن شاہین واسطی نے بیان کیا، کہا ہم سے خالد بن عبداللہ طحان نے، کہا ان سے خالد بن مہران حذاء نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم جبکہ آپ بدر کی لڑائی کے موقع پر میدان میں ایک خیمے میں یہ دعا کر رہے تھے کہ ”اے اللہ! میں تجھے تیرا عہد اور وعدہ نصرت یاد دلاتا ہوں۔ اے اللہ! اگر تو چاہے کہ ( مسلمانوں کو فنا کر دے ) تو آج کے بعد پھر کبھی تیری عبادت نہیں کی جائے گی۔“ اور اس پر ابوبکر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کا ہاتھ پکڑ کر عرض کیا: بس یا رسول اللہ! آپ اپنے رب سے خوب الحاح و زاری کے ساتھ دعا کر چکے ہیں۔ نبی کریم اس وقت زرہ پہنے ہوئے تھے۔ آپ باہر تشریف لائے تو آپ کی زبان مبارک پر یہ آیت تھی «سيهزم الجمع ويولون الدبر * بل الساعة موعدهم والساعة أدهى وأمر‏» یعنی ”عنقریب کافروں کی یہ جماعت ہار جائے گی اور یہ سب پیٹھ پھیر کر بھاگیں گے۔ لیکن ان کا اصل وعدہ تو قیامت کے دن کا ہے اور قیامت بڑی سخت اور بہت ہی کڑوی چیز ہے۔“' WHERE id = 4671;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس بیان کیا، کہا ہم سے ابوبکر نے بیان کیا، ان سے حصین نے، ان سے عمرو بن میمون نے بیان کیا کہ عمر بن خطاب رضی اللہ عنہ نے ( زخمی ہونے کے بعد انتقال سے پہلے ) فرمایا تھا میں اپنے بعد ہونے والے خلیفہ کو مہاجرین اولین کے بارے میں وصیت کرتا ہوں کہ وہ ان کا حق پہچانے اور میں اپنے بعد ہونے والے خلیفہ کو انصار کے بارے میں وصیت کرتا ہوں جو دارالسلام اور ایمان میں نبی کریم صلی اللہ علیہ وسلم کی ہجرت سے پہلے ہی سے قرار پکڑے ہوئے ہیں یہ کہ ان میں جو نیکوکار ہیں ان کی عزت کرے اور ان کے غلط کاروں سے درگزر کرے۔' WHERE id = 4681;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبدالوہاب نے بیان کیا، کہا ہم سے عبدالعزیز نے بیان کیا، انہیں ثور نے اور ان سے ابوالغیث نے، انہیں ابوہریرہ رضی اللہ عنہ نے اور انہیں نبی کریم صلی اللہ علیہ وسلم نے کہ ان کی قوم کے کچھ لوگ اسے پا لیں گے۔' WHERE id = 4691;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، کہا مجھ کو سالم نے خبر دی اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ انہوں نے اپنی بیوی آمنہ بنت غفار کو جبکہ وہ حائضہ تھیں طلاق دے دی۔ عمر رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے اس کا ذکر کیا۔ آپ اس پر بہت غصہ ہوئے اور فرمایا کہ وہ ان سے ( اپنی بیوی سے ) رجوع کر لیں اور اپنے نکاح میں رکھیں یہاں تک کہ وہ ماہواری سے پاک ہو جائے پھر ماہواری آئے اور پھر وہ اس سے پاک ہو، اب اگر وہ طلاق دینا مناسب سمجھیں تو اس کی پاکی ( طہر ) کے زمانہ میں ان کے ساتھ ہمبستری سے پہلے طلاق دے سکتے ہیں بس یہی وہ وقت ہے جس میں اللہ تعالیٰ نے ( مردوں کو ) حکم دیا ہے کہ اس میں یعنی حالت طہر میں طلاق دیں۔' WHERE id = 4701;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے عبد بن خالد سے بیان کیا، کہا کہ میں نے حارثہ بن وہب خزاعی رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ میں تمہیں بہشتی آدمی کے متعلق نہ بتا دوں۔ وہ دیکھنے میں کمزور ناتواں ہوتا ہے ( لیکن اللہ کے یہاں اس کا مرتبہ یہ ہے کہ ) اگر کسی بات پر اللہ کی قسم کھا لے تو اللہ اسے ضرور پوری کر دیتا ہے اور کیا میں تمہیں دوزخ والوں کے متعلق نہ بتا دوں ہر بدخو، بھاری جسم والا اور تکبر کرنے والا۔' WHERE id = 4711;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن موسیٰ نے بیان کیا، کہا ہم سے اسرائیل نے، ان سے موسیٰ بن ابی عائشہ نے کہ انہوں نے سعید بن جبیر سے اللہ تعالیٰ کے ارشاد «لا تحرك به لسانك‏» الایۃ یعنی ”آپ قرآن کو لینے کے لیے زبان نہ ہلایا کریں“ کے متعلق پوچھا تو انہوں نے بیان کیا کہ ابن عباس رضی اللہ عنہما نے کہا جب نبی کریم صلی اللہ علیہ وسلم پر وحی نازل ہوئی تو آپ صلی اللہ علیہ وسلم اپنے ہونٹ ہلایا کرتے تھے اس لیے آپ سے کہا گیا «لا تحرك به لسانك‏» الخ یعنی وحی پر اپنی زبان نہ ہلایا کریں، اس کا تمہارے دل میں جما دینا اور اس کا پڑھا دینا ہمارا کام ہے۔ جب ہم اس کو پڑھ چکیں یعنی جبرائیل تجھ کو سنا چکیں تو جیسا جبرائیل نے پڑھ کر سنایا تو بھی اس طرح پڑھ۔ پھر یہ بھی ہمارا ہی کام ہے کہ ہم تیری زبان سے اس کو پڑھوا دیں گے۔' WHERE id = 4721;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا ہم سے معن نے بیان کیا، انہوں نے کہا کہ مجھ سے مالک نے بیان کیا، ان سے نافع اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس دن لوگ دونوں جہان کے پالنے والے کے سامنے حساب دینے کے لیے کھڑے ہوں گے تو کانوں کی لو تک پسینہ میں ڈوب جائیں گے۔' WHERE id = 4732;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے منصور نے، ان سے سعد بن عبیدہ نے بیان کیا، ان سے ابوعبدالرحمٰن سلمی نے بیان کیا، اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ ہم بقیع الغرقد میں ایک جنازہ کے ساتھ تھے۔ پھر رسول اللہ صلی اللہ علیہ وسلم بھی تشریف لائے۔ آپ بیٹھ گئے اور ہم بھی آپ کے چاروں طرف بیٹھ گئے۔ آپ کے ہاتھ میں چھڑی تھی۔ آپ نے سر جھکا لیا پھر چھڑی سے زمین کو کریدنے لگے۔ پھر فرمایا کہ تم میں کوئی شخص ایسا نہیں، کوئی پیدا ہونے والی جان ایسی نہیں جس کا جنت اور جہنم کا ٹھکانا لکھا نہ جا چکا ہو۔ یہ لکھا جا چکا ہے کہ کون نیک ہے اور کون برا ہے۔ ایک صاحب نے عرض کیا: یا رسول اللہ! پھر کیا حرج ہے اگر ہم اپنی اسی تقدیر پر بھروسہ کر لیں اور نیک عمل کرنا چھوڑ دیں جو ہم میں نیک ہو گا، وہ نیکیوں کے ساتھ جا ملے گا اور جو برا ہو گا اس سے بروں کے سے اعمال ہو جائیں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو لوگ نیک ہوتے ہیں انہیں نیکوں ہی کے عمل کی توفیق حاصل ہوتی ہے اور جو برے ہوتے ہیں انہیں بروں ہی جیسے عمل کرنے کی توفیق ہوتی ہے۔ پھر آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی «فأما من أعطى واتقى * وصدق بالحسنى‏» یعنی ”سو جس نے دیا اور اللہ سے ڈرا اور اچھی بات کو سچا سمجھا سو ہم اس کے لیے نیک کاموں کو آسان کر دیں گے۔“' WHERE id = 4743;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے عبدالکریم جزری نے، ان سے عکرمہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا ابوجہل نے کہا تھا کہ اگر میں نے محمد صلی اللہ علیہ وسلم کو کعبہ کے پاس نماز پڑھتے دیکھ لیا تو اس کی گردن میں کچل دوں گا۔ نبی کریم صلی اللہ علیہ وسلم کو جب یہ بات پہنچی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر اس نے ایسا کیا ہوتا تو اسے فرشتے پکڑ لیتے۔ عبدالرزاق کے ساتھ اس حدیث کو عمرو بن خالد نے روایت کیا ہے، ان سے عبیداللہ نے، ان سے عبدالکریم نے بیان کیا۔' WHERE id = 4753;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ( سورۃ الفتح نازل ہونے کے بعد ) اپنے رکوع اور سجدوں میں بکثرت یہ دعا پڑھتے تھے «سبحانك اللهم ربنا وبحمدك،‏‏‏‏ اللهم اغفر لي» یعنی ”پاک ہے تیری ذات، اے اللہ! اے ہمارے رب! اور تیرے ہی لیے تعریف ہے، اے اللہ! میری مغفرت فرما دے۔“ قرآن مجید کے حکم مذکور پر اس طرح آپ عمل کرتے تھے۔' WHERE id = 4763;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے معتمر بن سلیمان نے ‘ کہا کہ میں نے اپنے والد سے سنا ‘ ان سے ابوعثمان مہدی نے بیان کیا کہ مجھے معلوم ہوا ہے کہ جبرائیل علیہ السلام نبی کریم صلی اللہ علیہ وسلم کے پاس آئے اور آپ صلی اللہ علیہ وسلم سے بات کرنے لگے۔ اس وقت ام المؤمنین ام سلمہ رضی اللہ عنہا آپ کے پاس موجود تھیں نبی کریم صلی اللہ علیہ وسلم نے ان سے پوچھا کہ جانتی ہو یہ کون ہیں؟ یا اسی طرح کے الفاظ آپ صلی اللہ علیہ وسلم نے فرمائے۔ ام المؤمنین نے کہا کہ دحیہ الکلبی ہیں۔ جب آپ صلی اللہ علیہ وسلم کھڑے ہوئے ام سلمہ رضی اللہ عنہا نے بیان کیا: اللہ کی قسم! اس وقت ( تک ) بھی میں انہیں دحیہ الکلبی سمجھتی رہی۔ آخر جب میں نے نبی کریم صلی اللہ علیہ وسلم کا خطبہ سنا جس میں آپ صلی اللہ علیہ وسلم نے جبرائیل علیہ السلام کے آنے کی خبر سنائی تب مجھے حال معلوم ہوا یا اسی طرح کے الفاظ بیان کئے۔ معتمر نے بیان کیا کہ میرے والد ( سلیمان ) نے کہا ‘ میں نے ابوعثمان مہدی سے کہا کہ آپ نے یہ حدیث کس سے سنی تھی؟ انہوں نے بتایا کہ اسامہ بن زید رضی اللہ عنہا سے۔' WHERE id = 4774;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے، ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ جب آیت «لا يستوي القاعدون من المؤمنين والمجاهدون في سبيل الله‏» نازل ہوئی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ زید کو میرے پاس بلاؤ اور ان سے کہو کہ تختی، دوات اور مونڈھے کی ہڈی ( لکھنے کا سامان ) لے کر آئیں، یا راوی نے اس کی بجائے ہڈی اور دوات ( کہا ) پھر ( جب وہ آ گئے تو ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ لکھو «لا يستوي القاعدون‏ ‏» الخ۔ نبی کریم صلی اللہ علیہ وسلم کے پیچھے عمرو ابن ام مکتوم بیٹھے ہوئے تھے جو نابینا تھے، انہوں نے عرض کیا: یا رسول اللہ! پھر آپ کا میرے بارے میں کیا حکم ہے۔ میں تو نابینا ہوں ( جہاد میں نہیں جا سکتا اب مجھ کو بھی مجاہدین کا درجہ ملے گا یا نہیں ) اس وقت یہ آیت یوں اتری «لا يستوي القاعدون من المؤمنين‏» الخ نازل ہوئی۔' WHERE id = 4784;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن حفص نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے شقیق بن سلمہ نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے ہمیں خطبہ دیا اور کہا کہ اللہ کی قسم میں نے کچھ اوپر ستر سورتیں خود رسول اللہ صلی اللہ علیہ وسلم کی زبان مبارک سے سن کر حاصل کی ہیں۔ اللہ کی قسم نبی کریم صلی اللہ علیہ وسلم کے صحابہ کو یہ بات اچھی طرح معلوم ہے کہ میں ان سب سے زیادہ قرآن مجید کا جاننے والا ہوں حالانکہ میں ان سے بہتر نہیں ہوں۔ شقیق نے بیان کیا کہ پھر میں مجلس میں بیٹھا تاکہ صحابہ کی رائے سن سکوں کہ وہ کیا کہتے ہیں لیکن میں نے کسی سے اس بات کی تردید نہیں سنی۔' WHERE id = 4794;
UPDATE hadiths SET urdu = 'اور عثمان بن ہیثم نے کہا کہ ہم سے عوف بن ابی جمیلہ نے بیان کیا، ان سے محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے صدقہ فطر کی حفاظت پر مقرر فرمایا۔ پھر ایک شخص آیا اور دونوں ہاتھوں سے ( کھجوریں ) سمیٹنے لگا۔ میں نے اسے پکڑ لیا اور کہا کہ میں تجھے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں پیش کروں گا۔ پھر انہوں نے یہ پورا قصہ بیان کیا ( مفصل حدیث اس سے پہلے کتاب الوکالۃ میں گزر چکی ہے ) ( جو صدقہ فطر چرانے آیا تھا ) اس نے کہا کہ جب تم رات کو اپنے بستر پر سونے کے لیے جاؤ تو آیت الکرسی پڑھ لیا کرو، پھر صبح تک اللہ تعالیٰ کی طرف سے تمہاری حفاظت کرنے والا ایک فرشتہ مقرر ہو جائے گا اور شیطان تمہارے پاس بھی نہ آ سکے گا۔ ( ابوہریرہ رضی اللہ عنہ نے یہ بات آپ سے بیان کی تو ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا اس نے تمہیں یہ ٹھیک بات بتائی ہے اگرچہ وہ بڑا جھوٹا ہے، وہ شیطان تھا۔' WHERE id = 4804;
UPDATE hadiths SET urdu = 'ہم سے ابوخالد ہدبہ بن خالد نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا ان سے انس بن مالک نے بیان کیا اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کی ( مومن کی ) مثال جو قرآن کی تلاوت کرتا ہے سنگترے کی سی ہے جس کا مزا بھی لذیذ ہوتا ہے اور جس کی خوشبو بھی بہترین ہوتی ہے اور جو مومن قرآن کی تلاوت نہیں کرتا اس کی مثال کھجور کی سی ہے اس کا مزہ تو عمدہ ہوتا ہے لیکن اس میں خوشبو نہیں ہوتی اور اس بدکار ( منافق ) کی مثال جو قرآن کی تلاوت کرتا ہے ریحانہ کی سی ہے کہ اس کی خوشبو تو اچھی ہوتی لیکن مزا کڑوا ہوتا ہے اور اس بدکار کی مثال جو قرآن کی تلاوت بھی نہیں کرتا اندرائن کی سی ہے جس کا مزا بھی کڑوا ہوتا ہے اور اس میں کوئی خوشبو بھی نہیں ہوتی۔' WHERE id = 4814;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبداللہ نے بیان کیا، ان سے ابوحازم نے، ان سے سہل بن سعد رضی اللہ عنہ نے کہ ایک خاتون رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور عرض کیا کہ یا رسول اللہ! میں آپ کی خدمت میں اپنے آپ کو ہبہ کرنے کے لیے آئی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے ان کی طرف نظر اٹھا کر دیکھا اور پھر نظر نیچی کر لی اور سر جھکا لیا۔ جب اس خاتون نے دیکھا کہ ان کے بارے میں کوئی فیصلہ نبی کریم صلی اللہ علیہ وسلم نے نہیں فرمایا تو وہ بیٹھ گئی۔ پھر نبی کریم صلی اللہ علیہ وسلم کے صحابہ میں سے ایک صاحب اٹھے اور عرض کیا: یا رسول اللہ! اگر آپ کو ان کی ضرورت نہیں ہے تو میرے ساتھ ان کا نکاح کر دیں۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا تمہارے پاس کچھ ( مہر کے لیے ) بھی ہے۔ انہوں نے عرض کیا نہیں یا رسول اللہ، اللہ کی قسم! تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اپنے گھر جاؤ اور دیکھو شاید کوئی چیز ملے، وہ صاحب گئے اور واپس آ گئے اور عرض کیا نہیں، اللہ کی قسم! یا رسول اللہ! مجھے وہاں کوئی چیز نہیں ملی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر دیکھ لو ایک لوہے کی انگوٹھی ہی سہی۔ وہ صاحب گئے اور پھر واپس آ گئے اور عرض کیا نہیں اللہ کی قسم، یا رسول اللہ! لوہے کی ایک انگوٹھی بھی مجھے نہیں ملی۔ البتہ یہ ایک تہبند میرے پاس ہے۔ سہل رضی اللہ عنہ کہتے ہیں کہ ان کے پاس کوئی چادر بھی ( اوڑھنے کے لیے ) نہیں تھی۔ اس صحابی نے کہا کہ خاتون کو اس میں سے آدھا پھاڑ کر دے دیجئیے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے اس تہبند کا وہ کیا کرے گی۔ اگر تم اسے پہنتے ہو تو اس کے قابل نہیں رہتا اور اگر وہ پہنتی ہے تو تمہارے قابل نہیں۔ پھر وہ صاحب بیٹھ گئے کافی دیر تک بیٹھے رہنے کے بعد اٹھے۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں جاتے ہوئے دیکھا تو بلوایا۔ جب وہ حاضر ہوئے تو آپ نے دریافت فرمایا کہ تمہیں قرآن مجید کتنا یاد ہے؟ انہوں نے بتلایا کہ فلاں، فلاں، فلاں سورتیں مجھے یاد ہیں۔ انہوں نے ان کے نام گنائے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا تم انہیں زبانی پڑھ لیتے ہو؟ عرض کیا جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ تمہیں قرآن مجید کی جو سورتیں یاد ہیں ان کے بدلے میں میں نے اسے تمہارے نکاح میں دے دیا۔' WHERE id = 4824;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ مجھ سے ابراہیم نے بیان کیا، ان سے علقمہ اور عبدالرحمٰن بن یزید نے اور ان سے ابومسعود انصاری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سورۃ البقرہ کے آخر کی دو آیتوں کو جو شخص رات میں پڑھ لے گا وہ اس کے لیے کافی ہوں گی۔' WHERE id = 4836;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نے، ان سے عبیدہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ مجھ سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مجھے قرآن پڑھ کر سناؤ۔ میں نے عرض کیا: یا رسول اللہ! میں آپ کو پڑھ کر سناؤں، آپ پر تو قرآن مجید نازل ہوتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہاں سناؤ۔ چنانچہ میں نے سورۃ نساء پڑھی جب میں آیت «فكيف إذا جئنا من كل أمة بشهيد وجئنا بك على هؤلاء شهيدا‏» پر پہنچا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب بس کرو۔ میں نے آپ کی طرف دیکھا تو نبی کریم صلی اللہ علیہ وسلم کی آنکھوں سے آنسو جاری تھے۔' WHERE id = 4846;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے ابوعمران جونی نے اور ان سے جندب بن عبداللہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قرآن مجید اس وقت تک پڑھو جب تک اس میں دل لگے، جب جی اچاٹ ہونے لگے تو پڑھنا بند کر دو۔' WHERE id = 4857;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے یحییٰ بن سعید نے، ان سے محمد بن ابراہیم بن حارث نے، ان سے علقمہ بن وقاص نے اور ان سے عمر بن خطاب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عمل کا دارومدار نیت پر ہے اور ہر شخص کو وہی ملتا ہے جس کی وہ نیت کرے۔ اس لیے جس کی ہجرت اللہ اور اس کے رسول کی رضا حاصل کرنے کے لیے ہو، اسے اللہ اور اس کے رسول کی رضا حاصل ہو گی لیکن جس کی ہجرت دنیا حاصل کرنے کی نیت سے یا کسی عورت سے شادی کرنے کے ارادہ سے ہو، اس کی ہجرت اسی کے لیے ہے جس کے لیے اس نے ہجرت کی۔' WHERE id = 4867;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محارب بن دثار نے بیان کیا، کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے عرض کیا کہ میں نے شادی کی تو نبی کریم صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا کہ کس سے شادی کی ہے؟ میں نے عرض کیا کہ ایک عورت سے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کنواری سے کیوں نہ کی کہ اس کے ساتھ تم کھیل کود کرتے۔ محارب نے کہا کہ پھر میں نے نبی کریم صلی اللہ علیہ وسلم کا یہ ارشاد عمرو بن دینار سے بیان کیا تو انہوں نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا ہے۔ مجھ سے انہوں نے نبی کریم صلی اللہ علیہ وسلم کا فرمان اس طرح بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ تم نے کسی کنواری عورت سے شادی کیوں نہ کی کہ تم اس کے ساتھ کھیل کود کرتے اور وہ تمہارے ساتھ کھیلتی۔' WHERE id = 4877;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے، ان سے عبیداللہ عموی نے، کہ مجھ سے سعید بن ابی سعید نے، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عورت سے نکاح چار چیزوں کی بنیاد پر کیا جاتا ہے اس کے مال کی وجہ سے اور اس کے خاندانی شرف کی وجہ سے اور اس کی خوبصورتی کی وجہ سے اور اس کے دین کی وجہ سے اور تو دیندار عورت سے نکاح کر کے کامیابی حاصل کر، اگر ایسا نہ کرے تو تیرے ہاتھوں کو مٹی لگے گی ( یعنی اخیر میں تجھ کو ندامت ہو گی ) ۔' WHERE id = 4887;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، ان سے قتادہ نے، ان سے جابر بن زید نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے کہا گیا کہ آپ حمزہ رضی اللہ عنہ کی بیٹی سے نکاح کیوں نہیں کر لیتے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ میرے دودھ کے بھائی کی بیٹی ہے۔ اور بشر بن عمر نے بیان کیا، ان سے شعبہ نے بیان کیا، انہوں نے قتادہ سے سنا اور انہوں نے اسی طرح جابر بن زید سے سنا۔' WHERE id = 4897;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے شغار سے منع فرمایا ہے۔ شغار یہ ہے کہ کوئی شخص اپنی لڑکی یا بہن کا نکاح اس شرط کے ساتھ کرے کہ وہ دوسرا شخص اپنی ( بیٹی یا بہن ) اس کو بیاہ دے اور کچھ مہر نہ ٹھہرے۔' WHERE id = 4908;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا مجھ سے طلق بن غنام نے بیان کیا، کہا ہم سے زائدہ بن قدام نے بیان کیا، ان سے منصور بن معتمر نے، ان سے مجاہد نے کہ ابن عباس رضی اللہ عنہما نے آیت «فيما عرضتم‏» کی تفسیر میں کہا کہ کوئی شخص کسی ایسی عورت سے جو عدت میں ہو کہے کہ میرا ارادہ نکاح کا ہے اور میری خواہش ہے کہ مجھے کوئی نیک بخت عورت میسر آ جائے اور اس نکاح میں قاسم بن محمد نے کہا کہ ( تعریض یہ ہے کہ ) عدت میں عورت سے کہے کہ تم میری نظر میں بہت اچھی ہو اور میرا خیال نکاح کرنے کا ہے اور اللہ تمہیں بھلائی پہنچائے گا یا اسی طرح کے جملے کہے اور عطاء بن ابی رباح نے کہا کہ تعریض و کنایہ سے کہے۔ صاف صاف نہ کہے ( مثلاً ) کہے کہ مجھے نکاح کی ضرورت ہے اور تمہیں بشارت ہو اور اللہ کے فضل سے اچھی ہو اور عورت اس کے جواب میں کہے کہ تمہاری بات میں نے سن لی ہے ( بصراحت ) کوئی وعدہ نہ کرے ایسی عورت کا ولی بھی اس کے علم کے بغیر کوئی وعدہ نہ کرے اور اگر عورت نے زمانہ عدت میں کسی مرد سے نکاح کا وعدہ کر لیا اور پھر بعد میں اس سے نکاح کیا تو دونوں میں جدائی نہیں کرائی جائے گی۔ حسن نے کہا کہ «لا تواعدوهن سرا‏» سے یہ مراد ہے کہ عورت سے چھپ کر بدکاری نہ کرو۔ ابن عباس رضی اللہ عنہما سے منقول ہے کہ «الكتاب أجله‏» سے مراد عدت کا پورا کرنا ہے۔' WHERE id = 4919;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے وہب نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ان سے نکاح کیا تو ان کی عمر چھ سال تھی اور جب ان سے صحبت کی تو ان کی عمر نو سال تھی۔ ہشام بن عروہ نے کہا کہ مجھے خبر دی گئی ہے کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ نو سال تک رہیں۔' WHERE id = 4929;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے زید بن اسلم نے کہا کہ میں نے ابن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ دو آدمی مدینہ کے مشرق کی طرف سے آئے، وہ مسلمان ہو گئے اور خطبہ دیا، نہایت فصیح و بلیغ۔ رسول اللہ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ بعض تقریر جادو کی اثر کرتی ہے۔' WHERE id = 4940;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے جب مجھ سے شادی کی تو میری والدہ ( ام رومان بنت عامر ) میرے پاس آئیں اور مجھے نبی کریم صلی اللہ علیہ وسلم کے گھر کے اندر لے گئیں۔ گھر کے اندر قبیلہ انصار کی عورتیں موجود تھیں۔ انہوں نے ( مجھ کو اور میری ماں کو ) یوں دعا دی «بارك وبارك الله» ”اللہ کرے تم اچھی ہو تمہارا نصیبہ اچھا ہو۔“' WHERE id = 4950;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا اور انہیں انس بن مالک رضی اللہ عنہ نے خبر دی کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ منورہ ہجرت کر کے آئے تو ان کی عمر دس برس کی تھی۔ میری ماں اور بہنیں نبی کریم صلی اللہ علیہ وسلم کی خدمت کے لیے مجھ کو تاکید کرتی رہتی تھیں۔ چنانچہ میں نے نبی کریم صلی اللہ علیہ وسلم کی دس برس تک خدمت کی اور جب آپ کی وفات ہوئی تو میں بیس برس کا تھا۔ پردہ کے متعلق میں سب سے زیادہ جاننے والوں میں سے ہوں کہ کب نازل ہوا۔ سب سے پہلے یہ حکم اس وقت نازل ہوا تھا جب نبی کریم صلی اللہ علیہ وسلم زینب بنت جحش رضی اللہ عنہما سے نکاح کے بعد انہیں اپنے گھر لائے تھے، آپ ان کے دولہا بنے تھے۔ پھر آپ نے لوگوں کو ( دعوت ولیمہ پر ) بلایا۔ لوگوں نے کھانا کھایا اور چلے گئے۔ لیکن کچھ لوگ ان میں سے نبی کریم صلی اللہ علیہ وسلم کے گھر میں ( کھانے کے بعد بھی ) دیر تک وہیں بیٹھے ( باتیں کرتے رہے ) آخر نبی کریم صلی اللہ علیہ وسلم کھڑے ہوئے اور باہر تشریف لے گئے۔ میں بھی نبی کریم صلی اللہ علیہ وسلم کے ساتھ باہر گیا تاکہ یہ لوگ بھی چلے جائیں۔ نبی کریم صلی اللہ علیہ وسلم چلتے رہے اور میں بھی آپ کے ساتھ رہا۔ جب آپ عائشہ رضی اللہ عنہا کے حجرہ کے پاس دروازے پر آئے تو آپ کو معلوم ہوا کہ وہ لوگ چلے گئے ہیں۔ اس لیے آپ واپس تشریف لائے اور میں بھی آپ کے ساتھ آیا۔ جب آپ زینب رضی اللہ عنہا کے گھر میں داخل ہوئے تو دیکھا کہ وہ لوگ ابھی بیٹھے ہوئے ہیں اور ابھی تک نہیں گئے ہیں۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم وہاں سے پھر واپس تشریف لائے اور میں بھی آپ کے ساتھ واپس آ گیا جب آپ عائشہ رضی اللہ عنہا کے حجرہ کے دروازے پر پہنچے اور آپ کو معلوم ہوا کہ وہ لوگ چلے گئے ہیں تو آپ پھر واپس تشریف لائے اور میں بھی آپ کے ساتھ واپس آیا۔ اب وہ لوگ واقعی جا چکے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے اس کے بعد اپنے اور میرے بیچ میں پردہ ڈال دیا اور پردہ کی آیت نازل ہوئی۔' WHERE id = 4960;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ ابواسید ساعدی رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کو اپنی شادی پر دعوت دی، ان کی دلہن ام اسید سلامہ بنت وہب ضروری جو کام کاج کر رہی تھیں اور وہی دلہن بنی تھیں۔ سہل رضی اللہ عنہ نے کہا تمہیں معلوم ہے انہوں نے نبی کریم صلی اللہ علیہ وسلم کو اس موقع پر کیا پلایا تھا؟ رات کے وقت انہوں نے کچھ کھجوریں پانی میں بھگو دی تھیں ( صبح کو ) جب نبی کریم صلی اللہ علیہ وسلم کھانے سے فارغ ہوئے تو آپ کو وہی پلایا۔' WHERE id = 4970;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے ہر ایک حاکم ہے اور ہر ایک سے ( اس کی رعیت کے بارے میں ) سوال ہو گا۔ پس امام حاکم ہے اس سے سوال ہو گا۔ مرد اپنی بیوی بچوں کا حاکم ہے اور اس سے سوال ہو گا۔ عورت اپنے شوہر کے مال کا حاکم ہے اور اس سے سوال ہو گا۔ غلام اپنے سردار کے مال کا حاکم ہے اور اس سے سوال ہو گا ہاں پس تم میں سے ہر ایک حاکم ہے اور ہر ایک سے سوال ہو گا۔' WHERE id = 4981;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ہشیم نے بیان کیا، کہا ہم سے عوف نے بیان کیا، ان سے ابوحازم نے، ان سے عمران نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے جنت میں جھانک کر دیکھا تو اس کے اکثر رہنے والے غریب لوگ تھے اور میں نے دوزخ میں جھانک کر دیکھا تو اس کے اندر رہنے والی اکثر عورتیں تھیں۔ اس روایت کی متابعت ابوایوب اور سلم بن زریر نے کی ہے۔' WHERE id = 4991;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن اسماء نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا، ان سے امام مالک بن انس نے، ان سے زہری نے، ان سے ابن محیریز نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ( ایک غزوہ میں ) ہمیں قیدی عورتیں ملیں اور ہم نے ان سے عزل کیا۔ پھر ہم نے رسول اللہ صلی اللہ علیہ وسلم سے اس کا حکم پوچھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم واقعی ایسا کرتے ہو؟ تین مرتبہ آپ صلی اللہ علیہ وسلم نے یہ فرمایا ( پھر فرمایا ) قیامت تک جو روح بھی پیدا ہونے والی ہے وہ ( اپنے وقت پر ) پیدا ہو کر رہے گی۔ پس تمہارا عزل کرنا عبث حرکت ہے۔' WHERE id = 5002;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے شقیق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ سے زیادہ غیرت مند اور کوئی نہیں ہے۔ یہی وجہ ہے کہ اس نے بےحیائی کے کاموں کو حرام کیا ہے اور اللہ سے بڑھ کر کوئی اپنی تعریف پسند کرنے والا نہیں ہے۔' WHERE id = 5012;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے مسور بن مخرمہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم ممبر پر فرما رہے تھے کہ ہشام بن مغیرہ جو ابوجہل کا باپ تھا اس کی اولاد ( حارث بن ہشام اور سلم بن ہشام ) نے اپنی بیٹی کا نکاح علی بن ابی طالب سے کرنے کی مجھ سے اجازت مانگی ہے لیکن میں انہیں ہرگز اجازت نہیں دوں گا یقیناً میں اس کی اجازت نہیں دوں گا ہرگز میں اس کی اجازت نہیں دوں گا۔ البتہ اگر علی بن ابی طالب میری بیٹی کو طلاق دے کر ان کی بیٹی سے نکاح کرنا چاہیں ( تو میں اس میں رکاوٹ نہیں بنوں گا ) کیونکہ وہ ( فاطمہ رضی اللہ عنہا ) میرے جگر کا ایک ٹکڑا ہے جو اس کو برا لگے وہ مجھ کو بھی برا لگتا ہے اور جس چیز سے اسے تکلیف پہنچتی ہے اس سے مجھے بھی تکلیف پہنچتی ہے۔' WHERE id = 5022;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے سفیان ثوری رحمہ اللہ نے بیان کیا، ان سے منصور بن معتمر نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی عورت کسی عورت سے ملنے کے بعد اپنے شوہر سے اس کا حلیہ نہ بیان کرے، گویا کہ وہ اسے دیکھ رہا ہے۔' WHERE id = 5032;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں عبدالرحمٰن بن قاسم نے، انہیں ان کے والد قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ( ان کے والد ) ابوبکر رضی اللہ عنہ ان پر غصہ ہوئے اور میری کوکھ میں ہاتھ سے کچوکے لگانے لگے لیکن میں حرکت اس وجہ سے نہ کر سکی کہ رسول اللہ صلی اللہ علیہ وسلم کا سر مبارک میری ران پر رکھا ہوا تھا۔' WHERE id = 5042;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے مسلم بن صبیح نے بیان کیا، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں اختیار دیا تھا اور ہم نے اللہ اور اس کے رسول کو ہی پسند کیا تھا لیکن اس کا ہمارے حق میں کوئی شمار ( طلاق ) میں نہیں ہوا تھا۔' WHERE id = 5054;
UPDATE hadiths SET urdu = 'ہم سے اسحاق واسطی نے بیان کیا، کہا ہم سے خالد طحان نے بیان کیا، ان سے خالد حذاء نے، ان سے عکرمہ نے کہ عبداللہ بن ابی (منافق) کی بہن جمیلہ رضی اللہ عنہا (جو ابی کی بیٹی تھی) نے یہ بیان کیا اور رسول اللہ صلی اللہ علیہ وسلم نے ان سے دریافت فرمایا تھا کہ کیا تم ان ( ثابت رضی اللہ عنہ ) کا باغ واپس کر دو گی؟ انہوں نے عرض کیا ہاں کر دوں گی۔ چنانچہ انہوں نے باغ واپس کر دیا اور انہوں نے ان کے شوہر کو حکم دیا کہ انہیں طلاق دے دیں۔ اور ابراہیم بن طہمان نے بیان کیا کہ ان سے خالد نے، ان سے عکرمہ نے نبی کریم صلی اللہ علیہ وسلم سے اور ( اس روایت میں بیان کیا کہ ) ان کے شوہر ( ثابت رضی اللہ عنہ ) نے انہیں طلاق دے دی۔' WHERE id = 5065;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں حکم نے، انہیں ابراہیم نخعی سے اور وہ اسود سے کہ عائشہ رضی اللہ عنہا نے بریرہ رضی اللہ عنہا کو خریدنے کا ارادہ کیا لیکن ان کے مالکوں نے کہا کہ وہ اسی شرط پر انہیں بیچ سکتے ہیں کہ بریرہ کا ترکہ ہم لیں اور ان کے ساتھ ولاء ( آزادی کے بعد ) انہیں سے قائم ہو۔ عائشہ رضی اللہ عنہا نے جب اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ نے فرمایا کہ انہیں خرید کر آزاد کر دو۔ ترکہ تو اسی کو ملے گا جو لونڈی غلام کو آزاد کرے اور ولاء بھی اسی کے ساتھ قائم ہو سکتی ہے جو آزاد کرے اور نبی کریم صلی اللہ علیہ وسلم کے سامنے گوشت لایا گیا پھر کہا کہ یہ گوشت بریرہ رضی اللہ عنہا کو صدقہ کیا گیا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ ان کے لیے صدقہ ہے اور ہمارے لیے ان کا تحفہ ہے۔ ہم سے آدم بن ابی ایاس نے بیان کیا، ان سے شعبہ نے بیان کیا اور اس روایت میں یہ اضافہ کیا کہ پھر ( آزادی کے بعد ) انہیں ان کے شوہر کے متعلق اختیار دیا گیا ( کہ چاہیں ان کے پاس رہیں اور اگر چاہیں ان سے اپنا نکاح توڑ لیں ) ۔' WHERE id = 5075;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ فتنہ ادھر سے اٹھے گا اور آپ صلی اللہ علیہ وسلم نے مشرق کی طرف اشارہ کیا۔' WHERE id = 5087;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ نے کہ قبیلہ انصار کے ایک صحابی نے اپنی بیوی پر تہمت لگائی تو نبی کریم صلی اللہ علیہ وسلم نے دونوں میاں بیوی سے قسم کھلوائی اور پھر دونوں میں جدائی کرا دی۔' WHERE id = 5097;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے سلیمان بن بلال نے بیان کیا، ان سے یحییٰ بن سعید نے، کہا کہ مجھے عبدالرحمٰن بن قاسم نے خبر دی، انہیں قاسم بن محمد نے اور انہیں ابن عباس رضی اللہ عنہما نے، انہوں نے بیان کیا کہ لعان کرنے والوں کا ذکر نبی کریم صلی اللہ علیہ وسلم کی مجلس میں ہوا تو عاصم بن عدی رضی اللہ عنہ نے اس پر ایک بات کہی ( کہ اگر میں اپنی بیوی کے ساتھ کسی کو پاؤں تو وہیں قتل کر ڈالوں ) پھر واپس آئے تو ان کی قوم کے ایک صاحب ان کے پاس آئے اور ان سے کہا کہ میں نے اپنی بیوی کے ساتھ ایک غیر مرد کو پایا ہے۔ عاصم رضی اللہ عنہ نے کہا کہ اس معاملہ میں میرا یہ ابتلاء میری اس بات کی وجہ سے ہوا ہے ( جس کے کہنے کی جرات میں نے نبی کریم صلی اللہ علیہ وسلم کے سامنے کی تھی ) پھر وہ ان صاحب کو ساتھ لے کر نبی کریم صلی اللہ علیہ وسلم کے پاس گئے اور نبی کریم صلی اللہ علیہ وسلم کو اس صورت سے مطلع کیا جس میں انہوں نے اپنی بیوی کو پایا تھا۔ یہ صاحب زرد رنگ، کم گوشت والے اور سیدھے بالوں والے تھے اور وہ جسے انہوں نے اپنی بیوی کے پاس پایا تھا گندمی رنگ، گھٹے جسم کا زرد، بھرے گوشت والا تھا اس کے بال بہت زیادہ گھونگھریالے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! معاملہ صاف کر دے چنانچہ ان کی بیوی نے جو بچہ جنا وہ اسی شخص سے مشابہ تھا جس کے متعلق شوہر نے کہا تھا کہ انہوں نے اپنی بیوی کے پاس اسے پایا تھا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے دونوں کے درمیان لعان کرایا۔ ابن عباس رضی اللہ عنہما سے ایک شاگرد نے مجلس میں پوچھا، کیا یہ وہی عورت ہے جس کے متعلق نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ اگر میں کسی کو بلا شہادت سنگسار کرتا تو اسے کرتا؟ ابن عباس رضی اللہ عنہما نے کہا کہ نہیں۔ یہ دوسری عورت تھی جو اسلام کے زمانہ میں اعلانیہ بدکاری کیا کرتی تھی۔' WHERE id = 5107;
UPDATE hadiths SET urdu = 'زینب رضی اللہ عنہا نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام حبیبہ رضی اللہ عنہا کے پاس اس وقت گئی جب ان کے والد ابوسفیان بن حرب رضی اللہ عنہ کا انتقال ہوا تھا۔ ام حبیبہ نے خوشبو منگوائی جس میں خلوق خوشبو کی زردی یا کسی اور چیز کی ملاوٹ تھی، پھر وہ خوشبو ایک لونڈی نے ان کو لگائی اور ام المؤمنین نے خود اپنے رخساروں پر اسے لگایا۔ اس کے بعد کہا کہ واللہ! مجھے خوشبو کے استعمال کی کوئی خواہش نہیں تھی لیکن میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کسی عورت کے لیے جو اللہ اور آخرت کے دن پر ایمان رکھتی ہو جائز نہیں کہ وہ تین دن سے زیادہ کسی کا سوگ منائے سوا شوہر کے ( کہ اس کا سوگ ) چار مہینے دس دن کا ہے۔' WHERE id = 5122;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے، ان سے ابوبکر بن عبدالرحمٰن نے اور ان سے ابومسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کتے کی قیمت، کاہن کی کمائی اور زانیہ عورت کے زنا کی کمائی کھانے سے منع فرمایا۔' WHERE id = 5133;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عبدالرحمٰن بن خالد بن مسافر نے بیان کیا، ان سے ابن شہاب نے، ان سے سعید بن المسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بہترین خیرات وہ ہے جسے دینے پر آدمی مالدار ہی رہے اور ابتداء ان سے کرو جو تمہاری نگرانی میں ہیں جن کے کھلانے پہنانے کے تم ذمہ دار ہو۔' WHERE id = 5143;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان، کہا کہ مجھے عبدالملک بن میسرہ نے خبر دی، کہا کہ میں نے زید بن وہب سے سنا اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھے میرا کپڑے کا جوڑا ہدیہ میں دیا تو میں نے اسے خود پہن لیا، پھر میں نے نبی کریم صلی اللہ علیہ وسلم کے چہرہ مبارک پر خفگی دیکھی تو میں نے اسے پھاڑ کر اپنی عورتوں میں تقسیم کر دیا۔' WHERE id = 5153;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، کہا کہ مجھے ولید بن کثیر نے خبر دی، انہوں نے وہب بن کیسان سے سنا، انہوں نے عمر بن ابی سلمہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں بچہ تھا اور رسول اللہ صلی اللہ علیہ وسلم کی پرورش میں تھا اور ( کھاتے وقت ) میرا ہاتھ برتن میں چاروں طرف گھوما کرتا۔ اس لیے آپ صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ بیٹے! بسم اللہ پڑھ لیا کرو، داہنے ہاتھ سے کھایا کرو اور برتن میں وہاں سے کھایا کرو جو جگہ تجھ سے نزدیک ہو۔ چنانچہ اس کے بعد میں ہمیشہ اسی ہدایت کے مطابق کھاتا رہا۔' WHERE id = 5163;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے معاذ بن ہشام نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے یونس نے، علی بن عبداللہ المدینی نے کہا کہ یہ یونس اسکاف ہیں (نہ کہ یونس بن عبید بصریٰ) ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں نہیں جانتا کہ نبی کریم صلی اللہ علیہ وسلم نے کبھی تشتری رکھ کر ( ایک وقت مختلف قسم کا ) کھانا کھایا ہو اور نہ کبھی آپ نے پتلی روٹیاں ( چپاتیاں ) کھائیں اور نہ کبھی آپ صلی اللہ علیہ وسلم نے میز پر کھایا۔ قتادہ سے پوچھا گیا کہ پھر کس چیز پر آپ کھاتے تھے؟ کہا کہ آپ سفرہ ( عام دستر خوان ) پر کھانا کھایا کرتے تھے۔' WHERE id = 5173;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مسلمان ایک آنت میں کھاتا ہے اور کافر ساتوں آنتوں میں کھاتا ہے۔' WHERE id = 5183;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا کہ مجھ سے عثمان ابن عمر نے بیان کیا، ان سے فلیح بن سلیمان نے بیان کیا، ان سے ابوحازم سلمہ بن دینار مدنی نے، کہا ہم سے عبداللہ بن ابی قتادہ نے اور ان سے ان کے والد نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ مکہ کی طرف نکلے ( صلح حدیبیہ کے موقع پر ) دوسری سند ( حدیث دیکھیں)' WHERE id = 5193;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نخعی نے، ان سے اسود بن یزید نے اور ان سے عائشہ رضی اللہ عنہا نے کہ مدینہ ہجرت کرنے کے بعد آل محمد صلی اللہ علیہ وسلم نے کبھی برابر تین دن تک گیہوں کی روٹی پیٹ بھر کر نہیں کھائی یہاں تک کہ آپ دنیا سے تشریف لے گئے۔' WHERE id = 5203;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سیف بن ابی سلیمان نے، کہا کہ میں نے مجاہد سے سنا، کہا کہ مجھ سے عبدالرحمٰن بن ابی لیلیٰ نے بیان کیا کہ یہ لوگ حذیفہ بن الیمان رضی اللہ عنہ کی خدمت میں موجود تھے۔ انہوں نے پانی مانگا تو ایک مجوسی نے ان کو پانی ( چاندی کے پیالے میں ) لا کر دیا۔ جب اس نے پیالہ ان کے ہاتھ میں دیا تو انہوں نے پیالہ کو اس پر پھینک کر مارا اور کہا اگر میں نے اسے بارہا اس سے منع نہ کیا ہوتا ( کہ چاندی سونے کے برتن میں مجھے کچھ نہ دیا کرو ) آگے وہ یہ فرمانا چاہتے تھے کہ تو میں اس سے یہ معاملہ نہ کرتا لیکن میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے کہ ریشم و دیبا نہ پہنو اور نہ سونے چاندی کے برتن میں کچھ پیو اور نہ ان کی پلیٹوں میں کچھ کھاؤ کیونکہ یہ چیزیں ان ( کفار کے لیے ) دنیا میں ہیں اور ہمارے لیے آخرت میں ہیں۔' WHERE id = 5213;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک بن انس نے، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ ایک درزی نے رسول اللہ صلی اللہ علیہ وسلم کو کھانے کی دعوت دی جو انہوں نے نبی کریم صلی اللہ علیہ وسلم کے لیے تیار کیا تھا۔ میں بھی آپ کے ساتھ گیا۔ نبی کریم صلی اللہ علیہ وسلم کے سامنے جَو کی روٹی اور شوربہ پیش کیا گیا۔ جس میں کدو اور خشک گوشت کے ٹکڑے تھے۔ میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم پیالے میں چاروں طرف کدو تلاش کر رہے تھے، اسی دن سے میں بھی کدو پسند کرنے لگا۔' WHERE id = 5223;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے جبلہ بن سحیم نے بیان کیا، کہا کہ ہمیں عبداللہ بن زبیر رضی اللہ عنہما کے ساتھ ( جب وہ حجاز کے خلیفہ تھے ) ایک سال قحط کا سامنا کرنا پڑا تو انہوں نے راشن میں ہمیں کھانے کے لیے کھجوریں دیں۔ عبداللہ بن عمر رضی اللہ عنہما ہمارے پاس سے گزرتے اور ہم کھجور کھاتے ہوتے تو وہ فرماتے کہ دو کھجوروں کو ایک ساتھ ملا کر نہ کھاؤ کیونکہ نبی کریم صلی اللہ علیہ وسلم نے دو کھجوروں کو ایک ساتھ ملا کر کھانے سے منع کیا ہے۔ پھر فرمایا سوا اس صورت کے جب اس کو کھانے والا شخص اپنے ساتھی سے ( جو کھانے میں شریک ہے ) اس کی اجازت لے لے۔ شعبہ نے بیان کیا کہ اجازت والا ٹکڑا ابن عمر رضی اللہ عنہما کا قول ہے۔' WHERE id = 5234;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے عمرو بن دینار نے، ان سے عطاء نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب کوئی شخص کھانا کھائے تو ہاتھ چاٹنے یا کسی کو چٹانے سے پہلے ہاتھ نہ پونچھے۔' WHERE id = 5244;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں پردہ کے حکم کے بارے میں زیادہ جانتا ہوں۔ ابی بن کعب رضی اللہ عنہ بھی مجھ سے اس کے بارے میں پوچھا کرتے تھے۔ زینب بنت جحش رضی اللہ عنہا سے رسول اللہ صلی اللہ علیہ وسلم کی شادی کا موقع تھا۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے نکاح مدینہ منورہ میں کیا تھا۔ دن چڑھنے کے بعد نبی کریم صلی اللہ علیہ وسلم نے لوگوں کی کھانے کی دعوت کی تھی۔ آپ بیٹھے ہوئے تھے اور آپ کے ساتھ بعض اور صحابہ بھی بیٹھے ہوئے تھے۔ اس وقت تک دوسرے لوگ ( کھانے سے فارغ ہو کر ) جا چکے تھے۔ آخر آپ بھی کھڑے ہو گئے اور چلتے رہے۔ میں بھی آپ کے ساتھ چلتا رہا۔ آپ عائشہ رضی اللہ عنہا کے حجرے پر پہنچے پھر آپ نے خیال کیا کہ وہ لوگ ( بھی جو کھانے کے بعد گھر بیٹھے رہ گئے تھے ) جا چکے ہوں گے ( اس لیے آپ واپس تشریف لائے ) میں بھی آپ کے ساتھ واپس آیا لیکن وہ لوگ اب بھی اسی جگہ بیٹھے ہوئے تھے۔ آپ پھر واپس آ گئے۔ میں بھی آپ کے ساتھ دوبارہ واپس آیا۔ آپ عائشہ رضی اللہ عنہا کے حجرہ پر پہنچے پھر آپ وہاں سے واپس ہوئے۔ میں بھی آپ کے ساتھ تھا۔ اب وہ لوگ جا چکے تھے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے اپنے اور میرے درمیان پردہ لٹکایا اور پردہ کی آیت نازل ہوئی۔' WHERE id = 5254;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عبداللہ بن ابی السفر نے، ان سے شعبی نے کہا کہ میں نے عدی بن حاتم رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے بے پر کے تیر یا لکڑی گز سے شکار کے بارے میں پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم اس کی نوک سے شکار کو مار لو تو اسے کھاؤ لیکن اگر اس کی عرض کی طرف سے شکار کو لگے اور اس سے وہ مر جائے تو وہ «موقوذة‏» ( مردار ) ہے اسے نہ کھاؤ۔ میں نے سوال کیا کہ میں اپنا کتا بھی ( شکار کے لیے ) دوڑاتا ہوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم اپنے کتے پر بسم اللہ پڑھ کر شکار کے پیچھے دوڑاؤ تو وہ شکار کھا سکتے ہو۔ میں نے پوچھا اور اگر وہ کتا شکار میں سے کھا لے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر نہ کھاؤ کیونکہ وہ شکار اس نے تمہارے لیے نہیں پکڑا تھا، صرف اپنے لیے پکڑا تھا۔ میں نے پوچھا میں بعض وقت اپنا کتا چھوڑتا ہوں اور بعد میں اس کے ساتھ دوسرا کتا بھی پاتا ہوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ( اس کا شکار ) نہ کھاؤ کیونکہ تم نے بسم اللہ صرف اپنے کتے پر پڑھی ہے، دوسرے پر نہیں پڑھی ہے۔' WHERE id = 5265;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عبداللہ بن ابی السفر نے، ان سے عامر شعبی نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا یا رسول اللہ! میں ( شکار کے لیے ) اپنا کتا چھوڑتے وقت بسم اللہ پڑھ لیتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب کتا چھوڑتے وقت بسم اللہ پڑھ لیا ہو اور پھر وہ کتا شکار پکڑ کے مار ڈالے اور خود بھی کھا لے تو ایسا شکار نہ کھاؤ کیونکہ یہ شکار اس نے خود اپنے لیے پکڑا ہے۔ میں نے کہا کہ میں کتا شکار پر چھوڑتا ہوں لیکن اس کے ساتھ دوسرا کتا بھی مجھے ملتا ہے اور مجھے یہ معلوم نہیں کہ کس نے شکار پکڑا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایسا شکار نہ کھاؤ کیونکہ تم نے اپنے کتے پر بسم اللہ پڑھی ہے دوسرے کتے پر نہیں پڑھی اور میں نے آپ سے بے پر کے تیر یا لکڑی سے شکار کا حکم پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر شکار نوک کی دھار سے مرا ہو تو کھا لیکن اگر تو نے اس کی چوڑائی سے اسے مارا ہے تو ایسا شکار بوجھ سے مرا ہے پس اسے نہ کھا۔' WHERE id = 5275;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نبیل نے بیان کیا، ان سے حیوہ بن شریح نے بیان کیا، انہوں نے کہا کہ مجھ سے ربیعہ بن یزید دمشقی نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوادریس خولانی نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوثعلبہ خشنی رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور کہا: یا رسول اللہ! ہم اہل کتاب کے ملک میں رہتے ہیں اور ان کے برتنوں میں کھاتے ہیں اور ہم شکار کی زمین میں رہتے ہیں اور میں اپنے تیر کمان سے بھی شکار کرتا ہوں اور سدھائے ہوئے کتے سے اور بےسدھائے کتے سے بھی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم نے جو یہ کہا ہے کہ تم اہل کتاب کے ملک میں رہتے ہو تو ان کے برتنوں میں نہ کھایا کرو۔ البتہ اگر ضرورت ہو اور کھانا ہی پڑ جائے تو انہیں خوب دھو لیا کرو اور جو تم نے یہ کہا ہے کہ تم شکار کی زمین میں رہتے ہو تو جو شکار تم اپنے تیر کمان سے کرو اور اس پر اللہ کا نام لیا ہو تو اسے کھاؤ اور جو شکار تم نے اپنے سدھائے ہوئے کتے سے کیا ہو اور اس پر اللہ کا نام لیا ہو وہ بھی کھاؤ اور جو شکار تم نے اپنے بلا سدھائے ہوئے کتے سے کیا ہو اور اسے خود ذبح کیا ہو اسے کھاؤ۔' WHERE id = 5285;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان نے، ان سے ان کے والد نے، ان سے عبایہ بن رفاعہ نے اور ان سے رافع بن خدیج رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کھاؤ یعنی ( ایسے جانور کو جسے ایسی دھاردار چیز سے ذبح کیا گیا ہو ) جو خون بہا دے۔ سوا دانت اور ناخن کے ( یعنی ان سے ذبح کرنا درست نہیں ہے ) ۔' WHERE id = 5295;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھ کو عدی بن ثابت نے خبر دی، کہا کہ میں نے عبداللہ بن زید رضی اللہ عنہ سے سنا، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ نبی کریم صلی اللہ علیہ وسلم نے رہزنی کرنے اور مثلہ کرنے سے منع فرمایا ہے۔' WHERE id = 5305;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدالوہاب ثقفی نے خبر دی، انہیں ایوب نے، انہیں محمد نے اور انہیں انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک صاحب آئے اور عرض کیا کہ میں نے گدھے کا گوشت کھا لیا ہے پھر دوسرے صاحب آئے اور کہا کہ میں نے گدھے کا گوشت کھا لیا ہے پھر تیسرے صاحب آئے اور کہا کہ گدھے ختم ہو گئے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے ایک منادی کے ذریعہ لوگوں میں اعلان کرایا کہ اللہ تعالیٰ اور اس کے رسول تمہیں پالتو گدھوں کا گوشت کھانے سے منع کرتے ہیں کیونکہ وہ ناپاک ہیں چنانچہ اسی وقت ہانڈیاں الٹ دی گئیں حالانکہ وہ ( گدھے کے ) گوشت سے جوش مار رہی تھیں۔' WHERE id = 5316;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے زہری نے بیان کیا، کہا کہ مجھے عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، انہوں نے ابن عباس رضی اللہ عنہما سے سنا، ان سے میمونہ رضی اللہ عنہا نے بیان کیا کہ ایک چوہا گھی میں پڑ کر مر گیا تو نبی کریم صلی اللہ علیہ وسلم سے اس کا حکم پوچھا گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ چوہے کو اور اس کے چاروں طرف سے گھی کو پھینک دو اور باقی گھی کو کھاؤ۔ سفیان سے کہا گیا کہ معمر اس حدیث کو زہری سے بیان کرتے ہیں کہ ان سے سعید بن مسیب اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ میں نے یہ حدیث زہری سے صرف عبیداللہ سے بیان کرتے سنی ہے کہ ان سے ابن عباس رضی اللہ عنہما نے، ان سے میمونہ رضی اللہ عنہا نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا اور میں نے یہ حدیث ان سے بارہا سنی ہے۔' WHERE id = 5326;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ہم سے سفیان نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ( حجۃ الوداع کے موقع پر ) ان کے پاس آئے وہ مکہ مکرمہ میں داخل ہونے سے پہلے مقام سرف میں حائضہ ہو گئی تھیں۔ اس وقت آپ رو رہی تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہے کیا تمہیں حیض کا خون آنے لگا ہے؟ عائشہ رضی اللہ عنہا نے عرض کیا کہ جی ہاں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو اللہ تعالیٰ نے آدم علیہ السلام کی بیٹیوں کے مقدر میں لکھ دیا ہے۔ تم حاجیوں کی طرح تمام اعمال حج ادا کر لو بس بیت اللہ کا طواف نہ کرو، پھر جب ہم منیٰ میں تھے تو ہمارے پاس گائے کا گوشت لایا گیا۔ میں نے پوچھا کہ یہ کیا ہے؟ لوگوں نے بتایا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کی طرف سے گائے کی قربانی کی ہے۔' WHERE id = 5336;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دو چتکبرے مینڈھوں کی قربانی کی۔ میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم اپنے پاؤں جانور کے اوپر رکھے ہوئے ہیں اور بسم اللہ واللہ اکبر پڑھ رہے ہیں۔ اس طرح آپ نے دونوں مینڈھوں کو اپنے ہاتھ سے ذبح کیا۔' WHERE id = 5346;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے سلیمان نے بیان کیا، ان سے یحییٰ بن سعید نے، ان سے قاسم نے، انہیں ابن خزیمہ نے خبر دی، انہوں نے ابوسعید رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ وہ سفر میں تھے جب واپس آئے تو ان کے سامنے گوشت لایا گیا۔ کہا گیا کہ یہ ہماری قربانی کا گوشت ہے۔ ابوسعید رضی اللہ عنہ نے کہا کہ اسے ہٹاؤ میں اسے نہیں چکھوں گا۔ ابوسعید رضی اللہ عنہ نے بیان کیا کہ پھر اٹھ گیا اور گھر سے باہر نکل کر اپنے بھائی ابوقتادہ رضی اللہ عنہ کے پاس آیا وہ ماں کی طرف سے ان کے بھائی تھے اور بدر کی لڑائی میں شرکت کرنے والوں میں سے تھے۔ میں نے ان سے اس کا ذکر کیا اور انہوں نے کہا کہ تمہارے بعد حکم بدل گیا ہے۔' WHERE id = 5356;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، کہا کہ مجھے یونس نے خبر دی، ان سے ابن شہاب نے بیان کیا، کہا کہ میں نے ابوسلمہ بن عبدالرحمٰن اور ابن مسیب سے سنا، وہ بیان کرتے تھے کہ ابوہریرہ رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی شخص جب زنا کرتا ہے تو عین زنا کرتے وقت وہ مومن نہیں ہوتا۔ اسی طرح جب وہ شراب پیتا ہے تو عین شراب پیتے وقت وہ مومن نہیں ہوتا۔ اسی طرح جب چور چوری کرتا ہے تو اس وقت وہ مومن نہیں ہوتا۔ اور ابن شہاب نے بیان کیا، انہیں عبدالملک بن ابی بکر بن عبدالرحمٰن بن حارث بن ہشام نے خبر دی، ان سے ابوبکر رضی اللہ عنہ بیان کرتے تھے اور ان سے ابوہریرہ رضی اللہ عنہ۔ پھر انہوں نے بیان کیا کہ ابوبکر بن عبدالرحمٰن ابوہریرہ رضی اللہ عنہ کی حدیث میں امور مذکورہ کے ساتھ اتنا اور زیادہ کرتے تھے کہ کوئی شخص ( دن دھاڑے ) اگر کسی بڑی پونجی پر اس طور ڈاکہ ڈالتا ہے کہ لوگ دیکھتے کے دیکھتے رہ جاتے ہیں تو وہ مومن رہتے ہوئے یہ لوٹ مار نہیں کرتا۔' WHERE id = 5366;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی رجاء نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ابوحیان تمیمی نے، ان سے شعبی نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ عمر رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کے منبر پر خطبہ دیتے ہوئے کہا جب شراب کی حرمت کا حکم ہوا تو وہ پانچ چیزوں سے بنتی تھی۔ انگور سے، کھجور سے، گیہوں سے، جَو اور شہد سے اور «خمر» ( شراب ) وہ ہے جو عقل کو مخمور کر دے اور تین مسائل ایسے ہیں کہ میری تمنا تھی کہ رسول اللہ صلی اللہ علیہ وسلم ہم سے جدا ہونے سے پہلے ہمیں ان کا حکم بتا جاتے، دادا کا مسئلہ، کلالہ کا مسئلہ اور سود کے چند مسائل۔ ابوحیان نے بیان کیا کہ میں نے شعبی سے پوچھا: اے ابوعمرو! ایک ایسا شربت ہے جو سندھ میں چاول سے بنایا جاتا ہے۔ انہوں نے کہا کہ یہ چیز رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں نہیں پائی جاتی تھی یا کہا کہ عمر رضی اللہ عنہ کے زمانے میں نہ تھی اور فرج ابن منہال نے بھی اس حدیث کو حماد بن سلمہ سے بیان کیا اور ان سے ابوحیان نے اس میں انگور کے بجائے کشمش ہے۔' WHERE id = 5376;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، انہیں ابوالجویریہ نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے «باذق» ( انگور کا شیرہ ہلکی آنچ دیا ہوا ) کے متعلق پوچھا تو انہوں نے کہا کہ محمد صلی اللہ علیہ وسلم «باذق» کے وجود سے پہلے ہی دنیا سے رخصت ہو گئے تھے جو چیز بھی نشہ لائے وہ حرام ہے۔ ابوالجویریہ نے کہا کہ «باذق» تو حلال و طیب ہے۔ ابن عباس رضی اللہ عنہما نے کہا کہ انگور حلال و طیب تھا جب اس کی شراب بن گئی تو وہ حرام خبیث ہے ( نہ کہ حلال و طیب ) ۔' WHERE id = 5386;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کیا ہی عمدہ صدقہ ہے خوب دودھ دینے والی اونٹنی جو کچھ دنوں کے لیے کسی کو عطیہ کے طور پر دی گئی ہو اور خوب دودھ دینے والی بکری جو کچھ دنوں کے لیے عطیہ کے طور پر دی گئی ہو جس سے صبح و شام دودھ برتن بھربھر کر نکالا جائے۔' WHERE id = 5396;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی سلمہ نے بیان کیا، کہا ہم کو ابوالنضر نے خبر دی، انہیں ابن عباس رضی اللہ عنہما کے غلام عمیر نے اور انہیں ام فضل بنت حارث نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کے لیے دودھ کا ایک پیالہ بھیجا میدان عرفات میں۔ وہ عرفہ کے دن کی شام کا وقت تھا اور نبی کریم صلی اللہ علیہ وسلم ( اپنی سواری پر ) سوار تھے، آپ نے اپنے ہاتھ میں وہ پیالہ لیا اور اسے پی لیا۔ مالک نے ابوالنضر سے ”اپنے اونٹ پر“ کے الفاظ زیادہ کئے۔' WHERE id = 5406;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے اسماعیل نے بیان کیا، کہا ہم کو ایوب نے خبر دی، انہیں عکرمہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے مشک کے منہ سے پانی پینے کی ممانعت فرما دی تھی۔' WHERE id = 5416;
UPDATE hadiths SET urdu = 'ہم سے حسن بن مدرک نے بیان کیا، انہوں نے کہا کہ مجھ سے یحییٰ بن حماد نے بیان کیا، انہوں نے کہا ہم کو ابوعوانہ نے خبر دی، ان سے عاصم احول نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کا پیالہ انس بن مالک رضی اللہ عنہ کے پاس دیکھا ہے وہ پھٹ گیا تھا تو انس رضی اللہ عنہ نے اسے چاندی سے جوڑ دیا۔ پھر عاصم نے بیان کیا کہ وہ عمدہ چوڑا پیالہ ہے۔ چمکدار لکڑی کا بنا ہوا۔ بیان کیا کہ انس رضی اللہ عنہ نے بتایا کہ میں نے اس پیالہ سے نبی کریم صلی اللہ علیہ وسلم کو بارہا پلایا ہے۔ راوی نے بیان کیا کہ ابن سیرین نے کہا کہ اس پیالہ میں لوہے کا ایک حلقہ تھا۔ انس رضی اللہ عنہ نے چاہا کہ اس کی جگہ چاندی یا سونے کا حلقہ جڑوا دیں لیکن ابوطلحہ رضی اللہ عنہ نے ان سے کہا کہ جسے رسول اللہ صلی اللہ علیہ وسلم نے بنایا ہے اس میں ہرگز کوئی تبدیلی نہ کرو چنانچہ انہوں نے یہ ارادہ چھوڑ دیا۔' WHERE id = 5426;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے اشعث بن سلیم نے خبر دی، کہا کہ میں نے معاویہ بن سوید بن مقرن سے سنا، ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں سات باتوں کا حکم دیا تھا اور سات باتوں سے منع فرمایا تھا۔ ہمیں نبی کریم صلی اللہ علیہ وسلم نے سونے کی انگوٹھی، ریشم، دیبا، استبرق ( ریشمی کپڑے ) پہننے سے اور قسی اور مثیرہ ( ریشمی ) کپڑوں کی دیگر جملہ قسمیں پہننے سے منع فرمایا تھا اور آپ نے ہمیں یہ حکم دیا تھا کہ ہم جنازہ کے پیچھے چلیں، مریض کی مزاج پرسی کریں اور سلام کو پھیلائیں۔' WHERE id = 5437;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابراہیم تیمی نے بیان کیا، ان سے حارث بن سوید نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا، میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ کو بخار آیا ہوا تھا میں نے اپنے ہاتھ سے نبی کریم صلی اللہ علیہ وسلم کا جسم چھوا اور عرض کیا: یا رسول اللہ! آپ کو تو بڑا تیز بخار ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں مجھے تم میں کے دو آدمیوں کے برابر بخار چڑھتا ہے۔ میں نے عرض کیا یہ اس لیے ہو گا کہ آپ کو دگنا اجر ملتا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کسی بھی مسلمان کو مرض کی تکلیف یا کوئی اور کوئی تکلیف ہوتی ہے تو اللہ تعالیٰ اس کے گناہوں کو اس طرح گراتا ہے جیسے درخت اپنے پتوں کو گرا دیتا ہے۔' WHERE id = 5447;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے بیان کیا، ان سے جعید بن عبدالرحمٰن نے بیان کیا کہ میں نے سائب بن یزید رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ مجھے میری خالہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں بچپن میں لے گئیں اور عرض کیا: یا رسول اللہ! میرے بھانجے کو درد ہے۔ نبی کریم صلی اللہ علیہ وسلم نے میرے سر پر ہاتھ پھیرا اور میرے لیے برکت کی دعا کی پھر آپ صلی اللہ علیہ وسلم نے وضو کیا اور میں نے آپ کے وضو کا پانی پیا اور میں نے آپ کی پیٹھ کے پیچھے کھڑے ہو کر نبوت کی مہر آپ کے دونوں شانوں کے درمیان دیکھی۔ یہ مہر نبوت حجلہ عروس کی گھنڈی جیسی تھی۔' WHERE id = 5457;
UPDATE hadiths SET urdu = 'ہم سے حسین نے بیان کیا، کہا ہم سے احمد بن منیع نے بیان کیا، کہا ہم سے مروان بن شجاع نے بیان کیا، ان سے سالم افطس نے بیان کیا، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ شفاء تین چیزوں میں ہے۔ شہد کے شربت میں، پچھنا لگوانے میں اور آگ سے داغنے میں لیکن میں امت کو آگ سے داغ کر علاج کرنے سے منع کرتا ہوں۔ ابن عباس رضی اللہ عنہما نے اس حدیث کو مرفوعاً نقل کیا ہے اور القمی نے روایت کیا، ان سے لیث نے، ان سے مجاہد نے، ان سے ابن عباس رضی اللہ عنہما نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے شہد اور پچھنا لگوانے کے بارے میں بیان کیا۔' WHERE id = 5467;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی مغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ وہ تلبینہ پکانے کا حکم دیتی تھیں اور فرماتی تھیں کہ اگرچہ وہ ( مریض کو ) ناپسند ہوتا ہے لیکن وہ اس کو فائدہ دیتا ہے۔' WHERE id = 5477;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعیدقطان نے بیان کیا، ان سے شعبہ نے بیان کیا کہ مجھ سے حمید بن نافع نے بیان کیا، ان سے زینب رضی اللہ عنہا نے اور ان سے ام سلمہ رضی اللہ عنہا نے کہ ایک عورت کے شوہر کا انتقال ہو گیا ( زمانہ عدت میں ) اس عورت کی آنکھ دکھنے لگی تو لوگوں نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا۔ ان لوگوں نے نبی کریم صلی اللہ علیہ وسلم کے سامنے سرمہ کا ذکر کیا اور یہ کہ ( اگر سرمہ آنکھ میں نہ لگایا تو ) ان کی آنکھ کے متعلق خطرہ ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ( زمانہ جاہلیت میں ) عدت گزارنے والی تم عورتوں کے اپنے گھر میں سب سے بدتر کپڑے میں پڑا رہنا پڑتا تھا یا ( آپ نے یہ فرمایا کہ ) اپنے کپڑوں میں گھر کے سب سے بدتر حصہ میں پڑا رہنا پڑتا تھا پھر جب کوئی کتا گزرتا تو اس پر وہ مینگنی پھینک کر مارتی ( تب عدت سے باہر ہوتی ) پس چار مہینے دس دن تک سرمہ نہ لگاؤ۔' WHERE id = 5490;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن سلیمان نے بیان کیا، کہا مجھ سے ابن وہب نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بخار جہنم کی بھاپ میں سے ہے پس اس کی گرمی کو پانی سے بجھاؤ۔“ نافع نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما ( کو جب بخار آتا تو ) یوں دعا کرتے کہ ”اللہ! ہم سے اس عذاب کو دور کر دے۔“' WHERE id = 5502;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے امام مالک نے، ان سے سمی نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پیٹ کی بیماری میں یعنی ہیضہ سے مرنے والا شہید ہے اور طاعون کی بیماری میں مرنے والا شہید ہے۔' WHERE id = 5512;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے سلیمان اعمش نے، ان سے مسلم بن صبیح نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم اپنے گھر کے بعض ( بیماروں ) پر یہ دعا پڑھ کر دم کرتے اور اپنا داہنا ہاتھ پھیرتے اور یہ دعا پڑھتے «اللهم رب الناس أذهب الباس،‏‏‏‏ ‏‏‏‏ اشفه وأنت الشافي،‏‏‏‏ ‏‏‏‏ لا شفاء إلا شفاؤك،‏‏‏‏ ‏‏‏‏ شفاء لا يغادر سقما» ”اے اللہ! لوگوں کے پالنے والے! تکلیف کو دور کر دے، اسے شفاء دیدے تو ہی شفاء دینے والا ہے۔ تیری شفاء کے سوا کوئی شفاء نہیں، ایسی شفاء ( دے ) کہ کسی قسم کی بیماری باقی نہ رہ جائے۔“ سفیان ثوری نے بیان کیا کہ میں نے یہ دعا منصور بن معتمر کے سامنے بیان کی تو انہوں نے مجھ سے یہ ابراہیم نخعی سے بیان کی، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے اسی طرح بیان کی۔' WHERE id = 5522;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عثمان بن عمر نے، کہا کہ ہم سے یونس بن یزید ایلی نے، ان سے سالم نے بیان کیا اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”امراض میں چھوت چھات کی اور بدشگونی کی کوئی اصل نہیں اور اگر نحوست ہوتی تو یہ صرف تین چیزوں میں ہوتی عورت میں، گھر میں اور گھوڑے میں۔“' WHERE id = 5532;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا کہ میں نے سفیان بن عیینہ سے سنا، کہا کہ سب سے پہلے یہ حدیث ہم سے ابن جریج نے بیان کی، وہ بیان کرتے تھے کہ مجھ سے یہ حدیث آل عروہ نے عروہ سے بیان کی، اس لیے میں نے ( عروہ کے بیٹے ) ہشام سے اس کے بارے میں پوچھا تو انہوں نے ہم سے اپنے والد ( عروہ ) سے بیان کیا کہ ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم پر جادو کر دیا گیا تھا اور اس کا آپ پر یہ اثر ہوا تھا آپ کو خیال ہوتا کہ آپ نے ازواج مطہرات میں سے کسی کے ساتھ ہمبستری کی ہے حالانکہ آپ نے کی نہیں ہوتی۔ سفیان ثوری نے بیان کیا کہ جادو کی یہ سب سے سخت قسم ہے جب اس کا یہ اثر ہو پھر آپ صلی اللہ علیہ وسلم نے فرمایا عائشہ! تمہیں معلوم ہے اللہ تعالیٰ سے جو بات میں نے پوچھی تھی اس کا جواب اس نے کب کا دے دیا ہے۔ میرے پاس دو فرشتے آئے ایک میرے سر کے پاس کھڑا ہو گیا اور دوسرا میرے پاؤں کے پاس۔ جو فرشتہ میرے سر کی طرف کھڑا تھا اس نے دوسرے سے کہا ان صاحب کا کیا حال ہے؟ دوسرے نے جواب دیا کہ ان پر جادو کر دیا گیا ہے۔ پوچھا کہ کس نے ان پر جادو کیا ہے؟ جواب دیا کہ لبید بن اعصم نے یہ یہودیوں کے حلیف بنی زریق کا ایک شخص تھا اور منافق تھا۔ سوال کیا کہ کس چیز میں ان پر جادو کیا ہے؟ جواب دیا کہ کنگھے اور بال میں۔ پوچھا جادو ہے کہاں؟ جواب دیا کہ نر کھجور کے خوشے میں جو زروان کے کنویں کے اندر رکھے ہوئے پتھر کے نیچے دفن ہے۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم اس کنویں پر تشریف لے گئے اور جادو اندر سے نکالا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہی وہ کنواں ہے جو مجھے خواب میں دکھایا گیا تھا اس کا پانی مہندی کے عرق جیسا رنگین تھا اور اس کے کھجور کے درختوں کے سر شیطانوں کے سروں جیسے تھے۔ بیان کیا کہ پھر وہ جادو کنویں میں سے نکالا گیا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے کہا آپ نے اس جادو کا توڑ کیوں نہیں کرایا۔ فرمایا: ہاں اللہ تعالیٰ نے مجھے شفا دی اب میں لوگوں میں ایک شور ہونا پسند نہیں کرتا۔' WHERE id = 5543;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا ہم سے خالد بن حارث نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے سلیمان نے بیان کیا، انہوں نے کہا کہ میں نے ذکوان سے سنا، وہ ابوہریرہ رضی اللہ عنہ سے یہ حدیث بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے پہاڑ سے اپنے آپ کو گرا کر خودکشی کر لی وہ جہنم کی آگ میں ہو گا اور اس میں ہمیشہ پڑا رہے گا اور جس نے زہر پی کر خودکشی کر لی وہ زہر اس کے ساتھ میں ہو گا اور جہنم کی آگ میں وہ اسے اسی طرح ہمیشہ پیتا رہے گا اور جس نے لوہے کے کسی ہتھیار سے خودکشی کر لی تو اس کا ہتھیار اس کے ساتھ میں ہو گا اور جہنم کی آگ میں ہمیشہ کے لیے وہ اسے اپنے پیٹ میں مارتا رہے گا۔' WHERE id = 5554;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عبدالرحمٰن بن خالد نے بیان کیا، ان سے ابن شہاب نے، ان سے سالم بن عبداللہ نے اور ان سے ان کے والد نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ایک شخص غرور میں اپنا تہمد گھسیٹتا ہوا چل رہا تھا کہ اسے زمین میں دھنسا دیا گیا اور وہ اسی طرح قیامت تک زمین میں دھنستا ہی رہے گا۔“ اس کی متابعت یونس نے زہری سے کی ہے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، اسے مرفوعاً نہیں بیان کیا۔' WHERE id = 5565;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن ابی ملیکہ نے اور ان سے مسور بن مخرمہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے چند قبائیں تقسیم کیں اور مخرمہ رضی اللہ عنہ کو کچھ نہیں دیا تو مخرمہ رضی اللہ عنہ نے کہا بیٹے ہمیں رسول اللہ صلی اللہ علیہ وسلم کے پاس لے چلو چنانچہ میں اپنے والد کو ساتھ لے کر چلا، انہوں نے مجھ سے کہا کہ اندر جاؤ اور نبی کریم صلی اللہ علیہ وسلم سے میرا ذکر کر دو۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے مخرمہ رضی اللہ عنہ کا ذکر کیا تو آپ باہر تشریف لائے۔ نبی کریم صلی اللہ علیہ وسلم انہیں قباؤں میں سے ایک قباء لیے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ میں نے تمہارے ہی لیے رکھ چھوڑی تھی۔ مسور نے بیان کیا کہ مخرمہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کی طرف دیکھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مخرمہ خوش ہو گئے۔' WHERE id = 5575;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم نے اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ ایک عورت ایک چادر لے کر آئیں ( جو اس نے خود بنی تھی ) سہل رضی اللہ عنہ نے کہا تمہیں معلوم ہے وہ پردہ کیا تھا پھر بتلایا کہ یہ ایک اونی چادر تھی جس کے کناروں پر حاشیہ ہوتا ہے۔ ان خاتون نے حاضر ہو کر عرض کیا: یا رسول اللہ! یہ چادر میں نے خاص آپ کے اوڑھنے کے لیے بنی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے وہ چادر ان سے اس طرح لی گویا آپ کو اس کی ضرورت ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم اسے تہمد کے طور پر پہن کر ہمارے پاس تشریف لائے۔ جماعت صحابہ میں سے ایک صاحب ( عبدالرحمٰن بن عوف ) نے اس چادر کو چھوا اور عرض کی یا رسول اللہ! یہ مجھے عنایت فرما دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اچھا۔ جتنی دیر اللہ نے چاہا آپ مجلس میں بیٹھے رہے پھر تشریف لے گئے اور اس چادر کو لپیٹ کر ان صاحب کے پاس بھجوا دیا۔ صحابہ نے اس پر ان سے کہا تم نے اچھی بات نہیں کی کہ نبی کریم صلی اللہ علیہ وسلم سے وہ چادر مانگ لی۔ تمہیں معلوم ہے کہ نبی کریم صلی اللہ علیہ وسلم کبھی سائل کو محروم نہیں فرماتے۔ ان صاحب نے کہا: اللہ کی قسم! میں نے تو صرف نبی کریم صلی اللہ علیہ وسلم سے یہ اس لیے مانگی ہے کہ جب میں مروں تو یہ میرا کفن ہو۔ سہل رضی اللہ عنہ نے بیان کیا چنانچہ وہ چادر اس صحابی کے کفن ہی میں استعمال ہوئی۔' WHERE id = 5585;
UPDATE hadiths SET urdu = 'مجھ سے محمد نے بیان کیا، انہوں نے کہا ہم کو مخلد نے خبر دی، انہوں نے کہا ہم کو ابن جریح نے خبر دی، انہوں نے کہا کہ مجھے ابن شہاب نے خبر دی، انہوں نے کہا ہمیں عبیداللہ بن عبداللہ نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے اشتمال صماء سے منع فرمایا اور اس سے بھی کہ کوئی شخص ایک کپڑے سے پنڈلی اور کمر کو ملا لے اور شرمگاہ پر کوئی دوسرا کپڑا نہ ہو۔' WHERE id = 5596;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے عبدالعزیز بن صہیب نے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، شعبہ نے بیان کیا کہ اس پر میں نے پوچھا کیا یہ روایت نبی کریم صلی اللہ علیہ وسلم سے ہے؟ عبدالعزیز نے بیان کیا کہ قطعاً نبی کریم صلی اللہ علیہ وسلم سے مروی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو مرد ریشمی لباس دنیا میں پہنے گا وہ آخرت میں اسے ہرگز نہیں پہن سکے گا۔' WHERE id = 5606;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں انس بن مالک رضی اللہ عنہ نے خبر دی کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی ام کلثوم رضی اللہ عنہا کو زرد دھاری دار ریشمی جوڑا پہنے دیکھا۔' WHERE id = 5616;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہوں نے کہا ہمیں عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے محرم کو زعفران یا ورس سے رنگا ہوا کپڑا پہننے سے منع فرمایا تھا اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جسے جوتے نہ ملیں وہ موزے ہی پہن لیں لیکن ان کو ٹخنے کے نیچے تک کاٹ دیں۔' WHERE id = 5626;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے کہا کہ مجھ سے ابن ابی ملیکہ نے بیان کیا، ان سے مسور بن مخرمہ رضی اللہ عنہ نے کہ ان سے ان کے والد مخرمہ رضی اللہ عنہ نے کہا بیٹے مجھے معلوم ہوا ہے کہ نبی کریم صلی اللہ علیہ وسلم کے پاس کچھ قبائیں آئی ہیں اور آپ انہیں تقسیم فرما رہے ہیں۔ ہمیں بھی نبی کریم صلی اللہ علیہ وسلم کے پاس لے چلو۔ چنانچہ ہم گئے اور نبی کریم صلی اللہ علیہ وسلم کو آپ کے گھر ہی میں پایا۔ والد نے مجھ سے کہا بیٹے میرا نام لے کر نبی کریم صلی اللہ علیہ وسلم کو بلاؤ۔ میں نے اسے بہت بڑی توہین آمیز بات سمجھا ( کہ نبی کریم صلی اللہ علیہ وسلم کو اپنے والد کے لیے بلا کر تکلیف دوں ) چنانچہ میں نے والد صاحب سے کہا کہ میں آپ کے لیے نبی کریم صلی اللہ علیہ وسلم کو بلاؤں! انہوں نے کہا کہ بیٹے ہاں۔ آپ کوئی جابر صفت انسان نہیں ہیں۔ چنانچہ میں نے بلایا تو نبی کریم صلی اللہ علیہ وسلم باہر تشریف لے آئے۔ آپ صلی اللہ علیہ وسلم کے اوپر دیبا کی ایک قباء تھی جس میں سونے کی گھنڈیاں لگی ہوئی تھیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مخرمہ اسے میں نے تمہارے لیے چھپا کے رکھا ہوا تھا۔ چنانچہ آپ صلی اللہ علیہ وسلم نے وہ قباء انہیں عنایت فرما دی۔' WHERE id = 5636;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلیٰ بن حماد نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا، انہوں نے کہا ہم سے سعید بن ابی عروبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے عجم کے کچھ لوگوں ( شاہان عجم ) کے پاس خط لکھنا چاہا تو آپ سے کہا گیا کہ عجم کے لوگ کوئی خط اس وقت تک نہیں قبول کرتے جب تک اس پر مہر لگی ہوئی نہ ہو۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے چاندی کی ایک انگوٹھی بنوائی۔ جس پر یہ کندہ تھا «محمد رسول الله» ۔ گویا اس وقت نبی کریم صلی اللہ علیہ وسلم کی انگلی یا آپ کی ہتھیلی میں اس کی چمک دیکھ رہا ہوں۔' WHERE id = 5646;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا ہم سے عبدہ بن سلیمان نے بیان کیا، کہا ہم سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ اسماء رضی اللہ عنہا کا ہار ( جو ام المؤمنین عائشہ رضی اللہ عنہا نے عاریت پر لیا تھا ) گم ہو گیا تو نبی کریم صلی اللہ علیہ وسلم نے اسے تلاش کرنے کے لیے چند صحابہ کو بھیجا اسی دوران میں نماز کا وقت ہو گیا اور لوگ بلا وضو ( وضو کے بغیر ) تھے چونکہ پانی بھی موجود نہیں تھا، اس لیے سب نے بلا وضو نماز پڑھی پھر نبی کریم صلی اللہ علیہ وسلم سے اس کا ذکر کیا تو تیمم کی آیت نازل ہوئی۔ ابن نمیر نے یہ اضافہ کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ وہ ہار انہوں نے اسماء سے عاریتاً لیا تھا۔' WHERE id = 5656;
UPDATE hadiths SET urdu = 'ہم سے محمد بن منہال نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے، انہوں نے کہا ہم سے عمر بن محمد بن زید نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم مشرکین کے خلاف کرو، داڑھی چھوڑ دو اور مونچھیں کترواؤ۔“ عبداللہ بن عمر رضی اللہ عنہما جب حج یا عمرہ کرتے تو اپنی داڑھی ( ہاتھ سے ) پکڑ لیتے اور ( مٹھی ) سے جو بال زیادہ ہوتے انہیں کتروا دیتے۔' WHERE id = 5666;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا رات کعبہ کے پاس مجھے دیکھایا گیا، میں نے دیکھا کہ ایک صاحب ہیں گندمی رنگ، گندمی رنگ کے لوگوں میں سب سے زیادہ خوبصورت، ان کے شانوں تک لمبے لمبے بال ہیں ایسے بال والے لوگوں میں سب سے زیادہ خوبصورت، انہوں نے بالوں میں کنگھا کر رکھا ہے اور اس کی وجہ سے سر سے پانی ٹپک رہا ہے۔ دو آدمیوں کا سہارا لیے ہوئے ہیں یا دو آدمیوں کے شانوں کا سہارا لیے ہوئے ہیں اور خانہ کعبہ کا طواف کر رہے ہیں، میں نے پوچھا کہ یہ کون بزرگ ہیں تو مجھے بتایا گیا کہ یہ عیسیٰ ابن مریم علیہ السلام ہیں پھر اچانک میں نے ایک الجھے ہوئے گھونگھریالے بال والے شخص کو دیکھا، دائیں آنکھ سے کانا تھا گویا انگور ہے جو ابھرا ہوا ہے۔ میں نے پوچھا یہ کانا کون ہے؟ مجھے بتایا گیا کہ یہ مسیح دجال ہے۔' WHERE id = 5676;
UPDATE hadiths SET urdu = 'مجھ سے اسماعیل بن ابن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ حفصہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! کیا بات ہے کہ لوگ عمرہ کر کے احرام کھول چکے ہیں حالانکہ آپ نے احرام نہیں کھولا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیونکہ میں نے اپنے سر کے بال جما لیے ہیں اور اپنی ہدی ( قربانی کے جانور ) کے گلے میں قلادہ ڈال دیا ہے۔ اس لیے جب تک میری قربانی کا نحر نہ ہو لے میں احرام نہیں کھول سکتا۔' WHERE id = 5688;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اشعث بن سلیم نے، ان سے ان کے والد نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ہر کام میں جہاں تک ممکن ہوتا داہنی طرف سے شروع کرنے کو پسند فرماتے تھے، کنگھا کرنے اور وضو کرنے میں بھی۔' WHERE id = 5698;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کی بیوی فاطمہ نے، ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مصنوعی بال لگانے والی اور لگوانے والی پر لعنت بھیجی ہے۔' WHERE id = 5708;
UPDATE hadiths SET urdu = 'ہم سے زہیر بن حرب نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے عمارہ نے، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ عمر رضی اللہ عنہ کے پاس ایک عورت لائی گئی جو گودنے کا کام کرتی تھی۔ عمر رضی اللہ عنہ کھڑے ہو گئے ( اور اس وقت موجود صحابہ سے ) کہا میں تمہیں اللہ کا واسطہ دیتا ہوں کسی نے کچھ نبی کریم صلی اللہ علیہ وسلم سے گودنے کے متعلق سنا ہے۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ میں نے کھڑے ہو کر عرض کیا: امیرالمؤمنین! میں نے سنا ہے۔ عمر رضی اللہ عنہ نے پوچھا کیا سنا ہے؟ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے کہ گودنے کا کام نہ کرو اور نہ گدواؤ۔' WHERE id = 5719;
UPDATE hadiths SET urdu = 'اور میں اور نبی کریم صلی اللہ علیہ وسلم ایک ہی برتن میں غسل جنابت کیا کرتے تھے۔' WHERE id = 5729;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے عبدالوہاب نے، کہا ہم سے ایوب سختیانی نے کہ عکرمہ کے سامنے یہ ذکر آیا کہ تین آدمی جو ایک جانور پر چڑھیں اس میں کون بہت برا ہے۔ انہوں نے بیان کیا کہ ابن عباس رضی اللہ عنہما نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم ( مکہ مکرمہ ) تشریف لائے تو آپ قثم بن عباس کو اپنی سواری پر آگے اور فضل بن عباس کو پیچھے بٹھائے ہوئے تھے۔ یا قثم پیچھے تھے اور فضل آگے تھے ( رضی اللہ عنہم ) اب تم ان میں سے کسے برا کہو گے اور کسے اچھا۔' WHERE id = 5739;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن شاہین واسطی نے بیان کیا، کہا ہم سے خالد واسطی نے بیان کیا، ان سے جریری نے، ان سے عبدالرحمٰن بن ابی بکرہ نے اور ان سے ان کے والد رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا: کیا میں تمہیں سب سے بڑا گناہ نہ بتاؤں؟ ہم نے عرض کیا ضرور بتائیے یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے ساتھ شرک کرنا اور والدین کی نافرمانی کرنا۔ نبی کریم صلی اللہ علیہ وسلم اس وقت ٹیک لگائے ہوئے تھے اب آپ سیدھے بیٹھ گئے اور فرمایا آگاہ ہو جاؤ جھوٹی بات بھی اور جھوٹی گواہی بھی ( سب سے بڑے گناہ ہیں ) آگاہ ہو جاؤ جھوٹی بات بھی اور جھوٹی گواہی بھی۔ نبی کریم صلی اللہ علیہ وسلم اسے مسلسل دہراتے رہے اور میں نے سوچا کہ نبی کریم صلی اللہ علیہ وسلم خاموش نہیں ہوں گے۔' WHERE id = 5749;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا، کہا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو چاہتا ہو کہ اس کے رزق میں فراخی ہو اور اس کی عمردراز ہو تو وہ صلہ رحمی کیا کرے۔' WHERE id = 5759;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا ہم سے سعید مقبری نے بیان کیا، کہا ہم سے عمرو بن سلیم نے بیان کیا، کہا ہم سے ابوقتادہ رضی اللہ عنہ نے بیان کیا، کہا کہ نبی کریم صلی اللہ علیہ وسلم باہر تشریف لائے اور امامہ بنت ابی العاص ( جو بچی تھیں ) وہ آپ کے شانہ مبارک پر تھیں پھر نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھی جب آپ رکوع کرتے تو انہیں اتار دیتے اور جب کھڑے ہوتے تو پھر اٹھا لیتے۔' WHERE id = 5769;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے صفوان بن سلیم تابعی اس حدیث کو مرسلاً روایت کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بیواؤں اور مسکینوں کے لیے کوشش کرنے والا اللہ کے راستہ میں جہاد کرنے والے کی طرح ہے یا اس شخص کی طرح ہے جو دن میں روزے رکھتا ہے اور رات کو عبادت کرتا ہے۔' WHERE id = 5779;
UPDATE hadiths SET urdu = 'ہم سے عاصم بن علی نے بیان کیا، انہوں نے کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے سعید نے بیان کیا، ان سے ابوشریح نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے بیان کیا ”واللہ! وہ ایمان والا نہیں۔ واللہ! وہ ایمان والا نہیں۔ واللہ! وہ ایمان والا نہیں۔ عرض کیا گیا کون: یا رسول اللہ؟ فرمایا وہ جس کے شر سے اس کا پڑوسی محفوظ نہ ہو۔ اس حدیث کو شبابہ اور اسد بن موسیٰ نے بھی روایت کیا ہے اور حمید بن اسود اور عثمان بن عمر اور ابوبکر بن عیاش اور شعیب بن اسحاق نے اس حدیث کو ابن ابی ذئب سے یوں روایت کیا ہے، انہوں نے مقبری سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے۔' WHERE id = 5789;
UPDATE hadiths SET urdu = 'ہم سے محمد بن العلاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے پاس جب کوئی مانگنے والا یا ضرورت مند آتا تو آپ صلی اللہ علیہ وسلم فرماتے کہ لوگو! تم سفارش کرو تاکہ تمہیں بھی ثواب ملے اور اللہ اپنے نبی کی زبان پر جو چاہے گا فیصلہ کرائے گا۔' WHERE id = 5800;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے سلام بن مسکین سے سنا، کہا کہ میں نے ثابت سے سنا، کہا کہ ہم سے انس رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کی دس سال تک خدمت کی لیکن آپ نے کبھی مجھے اف تک نہیں کہا اور نہ کبھی یہ کہا کہ فلاں کام کیوں کیا اور فلاں کام کیوں نہیں کیا۔' WHERE id = 5810;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا کہ مجھ سے عدی بن ثابت نے بیان کیا کہ میں نے سلیمان بن صرد سے سنا وہ نبی کریم صلی اللہ علیہ وسلم کے صحابی ہیں، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے دو آدمیوں نے آپس میں گالی گلوچ کی ایک صاحب کو غصہ آ گیا اور بہت زیادہ آیا، ان کا چہرہ پھول گیا اور رنگ بدل دیا گیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس وقت فرمایا کہ مجھے ایک کلمہ معلوم ہے کہ اگر ( غصہ کرنے والا شخص ) اسے کہہ لے تو اس کا غصہ دور ہو جائے گا۔ چنانچہ ایک صاحب نے جا کر غصہ ہونے والے کو نبی کریم صلی اللہ علیہ وسلم کا ارشاد سنایا اور کہا شیطان سے اللہ کی پناہ مانگ وہ کہنے لگا کیا تم مجھ کو روگی سمجھتے ہو یا دیوانہ؟ جا اپنا راستہ لے۔' WHERE id = 5820;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے ابوصالح نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم قیامت کے دن اللہ کے ہاں اس شخص کو سب سے بدتر پاؤ گے جو کچھ لوگوں کے سامنے ایک رخ سے آتا ہے اور دوسروں کے سامنے دوسرے رخ سے جاتا ہے۔' WHERE id = 5830;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے کیا، کہا ہم سے لیث بن سعد نے یہی حدیث نقل کی اور (اس میں یوں ہے کہ) عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک دن نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف لائے اور فرمایا عائشہ میں گمان کرتا ہوں کہ فلاں فلاں لوگ ہم جس دین پر ہیں اس کو نہیں پہچانتے۔' WHERE id = 5840;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے عبدالصمد بن عبدالوارث نے، کہا کہ مجھ سے میرے والد نے بیان کیا، کہا کہ مجھ سے یحییٰ بن ابی اسحاق نے، کہا کہ مجھ سے سالم بن عبداللہ نے پوچھا کہ «إستبرق» کیا چیز ہے؟ میں نے کہا کہ دیبا سے بنا ہوا دبیز اور کھردرا کپڑا پھر انہوں نے بیان کیا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ عمر رضی اللہ عنہ نے ایک شخص کو استبرق کا جوڑا پہنے ہوئے دیکھا تو نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اسے لے کر حاضر ہوئے اور عرض کیا کہ یا رسول اللہ! اسے آپ خرید لیں اور وفد جب آپ سے ملاقات کے لیے آئیں تو ان کی ملاقات کے وقت اسے پہن لیا کریں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ریشم تو وہی پہن سکتا ہے جس کا ( آخرت میں ) کوئی حصہ نہ ہو خیر اس بات پر ایک مدت گزر گئی پھر ایسا ہوا کہ ایک دن نبی کریم صلی اللہ علیہ وسلم نے خود انہیں ایک جوڑا بھیجا تو وہ اسے لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا آپ نے یہ جوڑا میرے لیے بھیجا ہے، حالانکہ اس کے بارے میں آپ اس سے پہلے ایسا ارشاد فرما چکے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ میں نے تمہارے پاس اس لیے بھیجا ہے تاکہ تم اس کے ذریعہ ( بیچ کر ) مال حاصل کرو۔ چنانچہ ابن عمر رضی اللہ عنہما اسی حدیث کی وجہ سے کپڑے میں ( ریشم کے ) بیل بوٹوں کو بھی مکروہ جانتے تھے۔' WHERE id = 5851;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا کہ مجھ سے ابن وہب نے بیان کیا، انہوں نے کہا ہم کو عمرو نے خبر دی، ان سے ابوالنضر نے بیان کیا، ان سے سلیمان بن یسار نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو اس طرح کھل کر کبھی ہنستے نہیں دیکھا کہ آپ کے حلق کا کوا نظر آنے لگتا ہو، آپ صلی اللہ علیہ وسلم صرف مسکراتے تھے۔' WHERE id = 5861;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے عبداللہ بن مبارک نے، کہا ہم کو شعبہ نے خبر دی، انہیں قتادہ نے، کہا میں نے عبداللہ بن عتبہ سے سنا، جو انس رضی اللہ عنہ کے غلام ہیں کہ ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کنواری لڑکیوں سے بھی زیادہ شرمیلے تھے، جب آپ کوئی ایسی چیز دیکھتے جو آپ کو ناگوار ہوتی تو ہم آپ کے چہرے مبارک سے سمجھ جاتے تھے۔' WHERE id = 5871;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو اسماعیل بن جعفر نے خبر دی، کہا ہم کو ربیعہ بن ابی عبدالرحمٰن نے خبر دی، انہیں زید بن خالد جہنی نے کہ ایک صاحب نے رسول اللہ صلی اللہ علیہ وسلم سے لقطہٰ ( راستہ میں گری پڑی چیز جسے کسی نے اٹھا لیا ہو ) کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا سال بھر لوگوں سے پوچھتے رہو پھر اس کا سر بندھن اور ظرف پہچان کے رکھ اور خرچ کر ڈال۔ پھر اگر اس کے بعد اس کا مالک آ جائے تو وہ چیز اسے آپس کر دے۔ پوچھا: یا رسول اللہ! بھولی بھٹکی بکری کے متعلق کیا حکم ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے پکڑ لا کیونکہ وہ تمہارے بھائی کی ہے یا پھر بھیڑیئے کی ہو گی۔ پوچھا: یا رسول اللہ! اور کھویا ہوا اونٹ؟ بیان کیا کہ اس پر نبی کریم صلی اللہ علیہ وسلم ناراض ہو گئے اور آپ کے دونوں رخسار سرخ ہو گئے، یا راوی نے یوں کہا کہ آپ کا چہرہ سرخ ہو گیا، پھر آپ نے فرمایا کہ تمہیں اس اونٹ سے کیا غرض ہے اس کے ساتھ تو اس کے پاؤں ہیں اور اس کا پانی ہے وہ کبھی نہ کبھی اپنے مالک کو پا لے گا۔' WHERE id = 5881;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محارب بن دثار نے، کہا کہ میں نے ابن عمر رضی اللہ عنہا سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مومن کی مثال اس سرسبز درخت کی ہے، جس کے پتے نہیں جھڑتے۔ صحابہ نے کہا کہ یہ فلاں درخت ہے، یہ فلاں درخت ہے۔ میرے دل میں آیا کہ کہوں کہ یہ کھجور کا درخت ہے لیکن چونکہ میں نوجوان تھا، اس لیے مجھ کو بولتے ہوئے حیاء آئی۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ کھجور کا درخت ہے۔ اور اسی سند سے شعبہ سے روایت ہے کہ کہا ہم سے خبیب بن عبدالرحمٰن نے، ان سے حفص بن عاصم نے اور ان سے ابن عمر رضی اللہ عنہما نے اسی طرح بیان کیا اور یہ اضافہ کیا کہ پھر میں نے اس کا ذکر عمر رضی اللہ عنہ سے کیا تو انہوں نے کہا اگر تم نے کہہ دیا ہوتا تو مجھے اتنا اتنا مال ملنے سے بھی زیادہ خوشی حاصل ہوتی۔' WHERE id = 5891;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا ہم کو ابن علیہ نے خبر دی، کہا ہم کو ایوب نے خبر دی، انہیں عبداللہ بن ابی ملیکہ نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کے پاس ہدیہ میں دیبا کی چند قبائیں آئیں، ان میں سونے کے بٹن لگے ہوئے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے وہ قبائیں اپنے صحابہ میں تقسیم کر دیں اور مخرمہ کے لیے باقی رکھی، جب مخرمہ آیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ میں نے تمہارے لیے چھپا رکھی تھی۔ ایوب نے کہا یعنی اپنے کپڑے میں چھپا رکھی تھی آپ مخرمہ کو خوش کرنے کے لیے اس کے تکمے یا گھنڈی کو دکھلا رہے تھے کیونکہ وہ ذرا سخت مزاج آدمی تھے۔ اس حدیث کو حماد بن زید نے بھی ایوب کے واسطہ سے روایت کیا مرسلات میں اور حاتم بن وردان نے کہا ہم سے ایوب نے بیان کیا، ان سے ابی ملیکہ نے اور ان سے مسور بن مخرمہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے پاس چند قبائیں تحفہ میں آئیں پھر ایسی ہی حدیث بیان کی۔' WHERE id = 5901;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن کثیر نے بیان کیا، ان سے عبیداللہ نے کہا کہ مجھ سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے اس درخت کا نام بتاؤ، جس کی مثال مسلمان کی سی ہے۔ وہ ہمیشہ اپنے رب کے حکم سے پھل دیتا ہے اور اس کے پتے نہیں جھڑا کرتے۔ میرے دل میں آیا کہ کہہ دوں کہ وہ کھجور کا درخت ہے لیکن میں نے کہنا پسند نہیں کیا۔ کیونکہ مجلس میں حضرات ابوبکر اور عمر رضی اللہ عنہما جیسے اکابر بھی موجود تھے۔ پھر جب ان دونوں بزرگوں نے کچھ نہیں کہا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ کھجور کا درخت ہے۔ جب میں اپنے والد کے ساتھ نکلا تو میں نے عرض کیا کہ میرے دل میں آیا کہ کہہ دوں یہ کھجور کا درخت ہے، انہوں نے کہا پھر تم نے کہا کیوں نہیں؟ اگر تم نے کہہ دیا ہوتا میرے لیے اتنا مال اور اسباب ملنے سے بھی زیادہ خوشی ہوتی۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ ( میں نے عرض کیا ) صرف اس وجہ سے میں نے نہیں کہا کہ جب میں نے آپ کو اور ابوبکر رضی اللہ عنہ جیسے بزرگ کو خاموش دیکھا تو میں نے آپ بزرگوں کے سامنے بات کرنا برا جانا۔' WHERE id = 5912;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو حنظلہ نے خبر دی، انہیں سالم نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر تم میں سے کوئی شخص اپنا پیٹ پیپ سے بھرے تو یہ اس سے بہتر ہے کہ وہ اسے شعر سے بھرے۔“' WHERE id = 5922;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل ابوالحسن نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو امام اوزاعی نے خبر دی، کہا کہ مجھ کو ابن شہاب نے خبر دی، بیان کیا ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ایک صحابی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا: یا رسول اللہ! میں تو تباہ ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، افسوس ( کیا بات ہوئی؟ ) انہوں نے کہا کہ میں نے رمضان میں اپنی بیوی سے صحبت کر لی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ایک غلام آزاد کر۔ انہوں نے عرض کیا کہ میرے پاس غلام ہے ہی نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر دو مہینے متواتر روزے رکھ۔ اس نے کہا کہ اس کی مجھ میں طاقت نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ساٹھ مسکینوں کو کھانا کھلا۔ کہا کہ اتنا بھی میں اپنے پاس نہیں پاتا۔ اس کے بعد کھجور کا ایک ٹوکرا آیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے لے اور صدقہ کر دے۔ انہوں نے عرض کیا: یا رسول اللہ! کیا اپنے گھر والوں کے سوا کسی اور کو؟ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے! سارے مدینہ کے دونوں طنابوں یعنی دونوں کناروں میں مجھ سے زیادہ کوئی محتاج نہیں۔ نبی کریم صلی اللہ علیہ وسلم اس پر اتنا ہنس دیئے کہ آپ کے آگے کے دندان مبارک دکھائی دینے لگے۔ فرمایا کہ جاؤ تم ہی لے لو۔ اوازاعی کے ساتھ اس حدیث کو یونس نے بھی زہری سے روایت کیا اور عبدالرحمٰن بن خالد نے زہری سے اس حدیث میں بجائے لفظ «ويحك» کے لفظ «ويلك‏.‏» روایت کیا ہے ( معنی دونوں کے ایک ہی ہیں ) ۔' WHERE id = 5932;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، ان سے ابوالتیاح یزید بن حمید نے بیان کیا، ان سے ابوحمزہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب قبیلہ عبدالقیس کا وفد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مرحبا ان لوگوں کو جو آن پہنچے تو نہ وہ ذلیل ہوئے، نہ شرمندہ ( خوشی سے مسلمان ہو گئے ورنہ مارے جاتے شرمندہ ہوتے ) انہوں نے عرض کیا: یا رسول اللہ! ہم قبیلہ ربیع کی شاخ سے تعلق رکھتے ہیں اور چونکہ ہمارے اور آپ کے درمیان قبیلہ مضر کے کافر لوگ حائل ہیں اس لیے ہم آپ کی خدمت میں صرف حرمت والے مہینوں ہی میں حاضر ہو سکتے ہیں ( جن میں لوٹ کھسوٹ نہیں ہوتی ) آپ کچھ ایسی جچی تلی بات بتا دیں جس پر عمل کرنے سے ہم جنت میں داخل ہو جائیں اور جو لوگ نہیں آ سکے ہیں انہیں بھی اس کی دعوت پہنچائیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ چار چار چیزیں ہیں۔ نماز قائم کرو، زکوٰۃ دو، رمضان کے روزے رکھو اور غنیمت کا پانچواں حصہ ( بیت المال کو ) ادا کرو اور دباء، حنتم، نقیر اور مزفت میں نہ پیو۔' WHERE id = 5942;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم کو سفیان بن عیینہ نے خبر دی، ان سے ابن المنکدر نے بیان کیا اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ ہم میں سے ایک صاحب کے یہاں بچہ پیدا ہوا تو انہوں نے اس کا نام قاسم رکھا۔ ہم نے ان سے کہا کہ ہم تم کو ابوالقاسم کہہ کر نہیں پکاریں گے ( کیونکہ ابوالقاسم نبی کریم صلی اللہ علیہ وسلم کی کنیت تھی ) اور نہ ہم تمہاری عزت کے لیے ایسا کریں گے۔ ان صاحب نے اس کی خبر نبی کریم صلی اللہ علیہ وسلم کو دی، تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اپنے بیٹے کا نام عبدالرحمٰن رکھ لے۔' WHERE id = 5952;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حصین بن عبدالرحمٰن نے، ان سے سالم بن ابی الجعد نے اور ان سے جریر بن عبداللہ انصاری نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میرے نام پر نام رکھو، لیکن میری کنیت نہ اختیار کرو کیونکہ میں قاسم ( تقسیم کرنے والا ) ہوں اور تمہارے درمیان ( علوم دین کو ) تقسیم کرتا ہوں۔“ اور اس روایت کو انس رضی اللہ عنہ نے بھی نبی کریم صلی اللہ علیہ وسلم سے نقل کیا۔' WHERE id = 5962;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے وہ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ اللہ کے نزدیک سب سے بدترین نام۔ اور کبھی سفیان نے ایک سے زیادہ مرتبہ یہ روایت اس طرح بیان کیا کہ اللہ کے نزدیک سب سے بدترین ناموں ( جمع کے صیغے کے ساتھ ) میں اس کا نام ہو گا جو ”ملک الاملاک“ اپنا نام رکھے گا۔ سفیان نے بیان کیا کہ ابوالزناد کے غیر نے کہا کہ اس کا مفہوم ہے ”شاہان شاہ“۔' WHERE id = 5972;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے کہا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے عثمان بن غیاث نے، کہا ہم سے ابوعثمان نہدی نے بیان کیا اور ان سے ابوموسیٰ اشعری نے کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ مدینہ کے باغوں میں سے ایک باغ میں تھے۔ نبی کریم صلی اللہ علیہ وسلم کے ہاتھ میں ایک لکڑی تھی، آپ اس کو پانی اور کیچڑ میں مار رہے تھے۔ اس دوران میں ایک صاحب نے باغ کا دروازہ کھلوانا چاہا۔ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ اس کے لیے دروازہ کھول دے اور انہیں جنت کی خوشخبری سنا دے۔ میں گیا تو وہاں ابوبکر رضی اللہ عنہ موجود تھے، میں نے ان کے لیے دروازہ کھولا اور انہیں جنت کی خوشخبری سنائی پھر ایک اور صاحب نے دروازہ کھلوایا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دروازہ کھول دے اور انہیں جنت کی خوشخبری سنا دے اس مرتبہ عمر رضی اللہ عنہ تھے۔ میں نے ان کے لیے بھی دروازہ کھولا اور انہیں بھی جنت کی خوشخبری سنا دی۔ پھر ایک تیسرے صاحب نے دروازہ کھلوایا۔ نبی کریم صلی اللہ علیہ وسلم اس وقت ٹیک لگائے ہوئے تھے اب سیدھے بیٹھ گئے۔ پھر فرمایا دروازہ کھول دے اور جنت کی خوشخبری سنا دے، ان آزمائشوں کے ساتھ جس سے ( دنیا میں ) انہیں دوچار ہونا پڑے گا۔ میں گیا تو وہاں عثمان رضی اللہ عنہ تھے۔ ان کے لیے بھی میں نے دروازہ کھولا اور انہیں جنت کی خوشخبری سنائی اور وہ بات بھی بتا دی جو نبی کریم صلی اللہ علیہ وسلم نے فرمائی تھی۔ عثمان رضی اللہ عنہ نے کہا خیر اللہ مددگار ہے۔' WHERE id = 5982;
UPDATE hadiths SET urdu = 'ہم سے عاصم بن علی نے بیان کیا، انہوں نے کہا ہم سے ابن ابی ذئب نے بیان کیا، انہوں نے کہا کہ ہم سے سعید مقبری نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ چھینک کو پسند کرتا ہے کیونکہ وہ بعض دفعہ صحت کی علامت ہے اور جمائی کو ناپسند کرتا ہے۔ اس لیے جب تم میں سے کوئی شخص چھینکے تو وہ الحمدللہ کہے لیکن جمائی لینا شیطان کی طرف سے ہوتا ہے۔ اس لیے جب تم میں سے کسی کو جمائی آئے تو وہ اپنی قوت و طاقت کے مطابق اسے روکے۔ اس لیے کہ جب تم میں سے کوئی جمائی لیتا ہے تو شیطان ہنستا ہے۔' WHERE id = 5992;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے یزید نے بیان کیا، ان سے ابوالخیر نے، ان سے عبداللہ بن عمر و رضی اللہ عنہ نے کہ ایک صاحب نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا: اسلام کی کون سی حالت افضل ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ کہ ( اللہ کی مخلوق کو ) کھانا کھلاؤ اور سلام کرو، اسے بھی جسے تم پہچانتے ہو اور اسے بھی جسے نہیں پہچانتے۔' WHERE id = 6002;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عمر بن ذر نے بیان کیا (دوسری سند) اور ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو مجاہد نے خبر دی، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ( آپ کے گھر میں ) داخل ہوا نبی کریم صلی اللہ علیہ وسلم نے ایک بڑے پیالے میں دودھ پایا تو فرمایا ”ابوہریرہ! اہل صفہ کے پاس جا اور انہیں میرے پاس بلا لا۔ میں ان کے پاس آیا اور انہیں بلا لایا۔ وہ آئے اور ( اندر آنے کی ) اجازت چاہی پھر جب اجازت دی گئی تو داخل ہوئے۔“' WHERE id = 6012;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہوں نے کہا کہ مجھے عروہ نے خبر دی، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ کچھ یہودی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور کہا کہ «السام عليك‏.‏» ( تمہیں موت آئے ) میں ان کی بات سمجھ گئی اور میں نے جواب دیا «عليكم السام واللعنة‏.‏» نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عائشہ صبر سے کام لے کیونکہ اللہ تعالیٰ تمام معاملات میں نرمی کو پسند کرتا ہے، میں نے عرض کیا: یا رسول اللہ! کیا آپ نے نہیں سنا کہ انہوں نے کیا کہا تھا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے ان کو جواب دے دیا تھا کہ «وعليكم» ( اور تمہیں بھی ) ۔' WHERE id = 6022;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو بشر بن شعیب نے خبر دی، کہا مجھ سے میرے والد نے بیان کیا، ان سے زہری نے، کہا مجھ کو عبداللہ بن کعب نے خبر دی اور ان کو عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ علی بن ابی طالب رضی اللہ عنہ ( مرض الموت میں ) نبی کریم صلی اللہ علیہ وسلم کے پاس سے نکلے ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا اور ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عنبسہ بن خالد نے بیان کیا، کہا ہم سے یونس بن یزید نے بیان کیا، ان سے ابن شہاب زہری نے بیان کیا، کہا مجھ کو عبداللہ بن کعب بن مالک نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ علی بن ابی طالب رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے یہاں سے نکلے، یہ اس مرض کا واقعہ ہے جس میں نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تھی۔ لوگوں نے پوچھا: اے ابوالحسن! نبی کریم صلی اللہ علیہ وسلم نے صبح کیسی گزاری؟ انہوں نے کہا کہ بحمدللہ آپ کو سکون رہا ہے۔ پھر علی رضی اللہ عنہ کا ہاتھ عباس رضی اللہ عنہ نے پکڑ کر کہا۔ کیا تم نبی کریم صلی اللہ علیہ وسلم کو دیکھتے نہیں ہو۔ ( واللہ ) تین دن کے بعد تمہیں لاٹھی کا بندہ بننا پڑے گا۔ واللہ میں سمجھتا ہوں کہ اس مرض میں آپ وفات پا جائیں گے۔ میں بنی عبدالمطلب کے چہروں پر موت کے آثار کو خوب پہچانتا ہوں، اس لیے ہمارے ساتھ تم نبی کریم صلی اللہ علیہ وسلم کے پاس چلو۔ تاکہ پوچھا جائے کہ نبی کریم صلی اللہ علیہ وسلم کے بعد خلافت کس کے ہاتھ میں رہے گی اگر وہ ہمیں لوگوں کو ملتی ہے تو ہمیں معلوم ہو جائے گا اور اگر دوسروں کے پاس جائے گی تو ہم عرض کریں گے تاکہ نبی کریم صلی اللہ علیہ وسلم ہمارے بارے میں کچھ وصیت کریں۔ علی رضی اللہ عنہ نے کہا کہ واللہ! اگر ہم نے نبی کریم صلی اللہ علیہ وسلم سے خلافت کی درخواست کی اور نبی کریم صلی اللہ علیہ وسلم نے انکار کر دیا تو پھر لوگ ہمیں کبھی نہیں دیں گے میں تو نبی کریم صلی اللہ علیہ وسلم سے کبھی نہیں پوچھوں گا کہ آپ کے بعد کون خلیفہ ہو۔' WHERE id = 6032;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم تخت کے وسط میں نماز پڑھتے تھے اور میں نبی کریم صلی اللہ علیہ وسلم اور قبلہ کے درمیان لیٹی رہتی تھی مجھے کوئی ضرورت ہوتی لیکن مجھ کو کھڑے ہو کر آپ کے سامنے آنا برا معلوم ہوتا۔ البتہ آپ کی طرف رخ کر کے میں آہستہ سے کھسک جاتی تھی۔' WHERE id = 6042;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے منصور بن معتمر نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب تین آدمی ہوں تو تیسرے ساتھی کو چھوڑ کر تم آپس میں کانا پھوسی ( سرگوشی ) نہ کیا کرو۔ اس لیے کہ لوگوں کو رنج ہو گا البتہ اگر دوسرے آدمی بھی ہوں تو مضائقہ نہیں۔“' WHERE id = 6054;
UPDATE hadiths SET urdu = 'اور عبداللہ ابن ادریس بن یزید نے اپنے والد سے بیان کیا، ان سے ابواسحاق نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تو میرا ختنہ ہو چکا تھا۔' WHERE id = 6064;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم رات میں ( تہجد کی ) گیارہ رکعات پڑھتے تھے پھر جب فجر طلوع ہو جاتی تو دو ہلکی رکعات ( سنت فجر ) پڑھتے۔ اس کے بعد آپ دائیں پہلو لیٹ جاتے آخر مؤذن آتا اور نبی کریم صلی اللہ علیہ وسلم کو اطلاع دیتا تو آپ فجر کی نماز پڑھاتے۔' WHERE id = 6074;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، کہا ہم سے عبیداللہ بن عمر نے بیان کیا، کہا مجھ سے سعید بن ابی سعید مقبری نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب تم میں سے کوئی شخص بستر پر لیٹے تو پہلے اپنا بستر اپنے ازار کے کنارے سے جھاڑ لے کیونکہ وہ نہیں جانتا کہ اس کی بےخبری میں کیا چیز اس پر آ گئی ہے پھر یہ دعا پڑھے «باسمك رب وضعت جنبي،‏‏‏‏ وبك أرفعه،‏‏‏‏ إن أمسكت نفسي فارحمها،‏‏‏‏ وإن أرسلتها فاحفظها بما تحفظ به الصالحين‏ ‏‏.‏» ”میرے پالنے والے! تیرے نام سے میں نے اپنا پہلو رکھا ہے اور تیرے ہی نام سے اٹھاؤں گا اگر تو نے میری جان کو روک لیا تو اس پر رحم کرنا اور اگر چھوڑ دیا ( زندگی باقی رکھی ) تو اس کی اس طرح حفاظت کرنا جس طرح تو صالحین کی حفاظت کرتا ہے۔“ اس کی روایت ابوضمرہ اور اسماعیل بن زکریا نے عبیداللہ کے حوالے سے کی اور یحییٰ اور بشر نے بیان کیا، ان سے عبیداللہ نے، ان سے سعید نے، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے اور اس کی روایت امام مالک اور ابن عجلان نے کی ہے۔ ان سے سعید نے، ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اس طرح روایت کی ہے۔' WHERE id = 6084;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے منصور بن معتمر نے، ان سے مسیب بن رافع نے، ان سے مغیرہ بن شعبہ رضی اللہ عنہ کے مولا وراد نے بیان کیا کہ مغیرہ بن شعبہ رضی اللہ عنہ نے معاویہ بن ابی سفیان رضی اللہ عنہما کو لکھا کہ رسول اللہ صلی اللہ علیہ وسلم ہر نماز کے بعد جب سلام پھیرتے تو یہ کہا کرتے تھے «لا إله إلا الله،‏‏‏‏ وحده لا شريك له،‏‏‏‏ له الملك،‏‏‏‏ وله الحمد،‏‏‏‏ وهو على كل شىء قدير،‏‏‏‏ اللهم لا مانع لما أعطيت،‏‏‏‏ ولا معطي لما منعت،‏‏‏‏ ولا ينفع ذا الجد منك الجد‏ ‏‏.‏» ”اللہ کے سوا کوئی معبود نہیں وہ تنہا ہے اس کا کوئی شریک نہیں، ملک اسی کے لیے ہے اور اسی کے لیے تمام تعریفیں ہیں اور وہ ہر چیز پر قدرت رکھنے والا ہے۔ اے اللہ! جو کچھ تو نے دیا ہے اسے کوئی روکنے والا نہیں اور جو کچھ تو نے روک دیا اسے کوئی دینے والا نہیں اور کسی مالدار اور نصیبہ ور ( کو تیری بارگاہ میں ) اس کا مال نفع نہیں پہنچا سکتا۔“ اور شعبہ نے بیان کیا، ان سے منصور نے بیان کیا کہ میں نے مسیب رضی اللہ عنہ سے سنا۔' WHERE id = 6094;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عبدالرحمٰن بن ازہر کے غلام ابوعبید نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بندہ کی دعا قبول ہوتی ہے جب تک کہ وہ جلدی نہ کرے کہ کہنے لگے کہ میں نے دعا کی تھی اور میری دعا قبول نہیں ہوئی۔“' WHERE id = 6104;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے اسماعیل بن ابی خالد نے بیان کیا، ان سے قیس بن ابی حازم نے بیان کیا، کہا کہ میں خباب بن ارت رضی اللہ عنہ کی خدمت میں حاضر ہوا انہوں نے اپنے پیٹ پر سات داغ لگوا رکھے تھے، میں نے سنا کہ وہ کہہ رہے تھے کہ اگر نبی کریم صلی اللہ علیہ وسلم نے ہمیں موت کی دعا کرنے سے منع نہ کیا ہوتا تو میں اس کی ضرور دعا کر لیتا۔' WHERE id = 6114;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے، ان سے عبداللہ بن ابی بکر نے، ان سے ان کے والد نے اور ان سے عمرو بن سلیم زرقی نے بیان کیا کہ ہم کو ابو حمید ساعدی رضی اللہ عنہ نے خبر دی کہ صحابہ نے عرض کیا: یا رسول اللہ! ہم آپ پر کس طرح درود بھیجیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس طرح کہو «اللهم صل على محمد وأزواجه وذريته،‏‏‏‏ كما صليت على آل إبراهيم،‏‏‏‏ وبارك على محمد وأزواجه وذريته،‏‏‏‏ كما باركت على آل إبراهيم،‏‏‏‏ إنك حميد مجيد» ”اے اللہ! محمد اور آپ کی ازواج اور آپ کی اولاد پر اپنی رحمت نازل کر جیسا کہ تو نے ابراہیم اور آل ابراہیم پر رحمت نازل کی اور محمد اور ان کی ازواج اور ان کی اولاد پر برکت نازل کر، جیسا کہ تو نے ابراہیم اور آل ابراہیم پر برکت نازل کی۔ بلاشبہ تو تعریف کیا گیا شان و عظمت والا ہے۔“' WHERE id = 6124;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا مجھ سے غندر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے عبدالملک بن عمیر نے بیان کیا، ان سے مصعب بن سعد نے بیان کیا اور ان سے سعد بن ابی وقاص رضی اللہ عنہ نے کہ وہ ان پانچ باتوں سے پناہ مانگنے کا حکم دیتے تھے اور انہیں نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے بیان کرتے تھے کہ «اللهم إني أعوذ بك من البخل،‏‏‏‏ وأعوذ بك من الجبن،‏‏‏‏ وأعوذ بك أن أرد إلى أرذل العمر،‏‏‏‏ وأعوذ بك من فتنة الدنيا،‏‏‏‏ وأعوذ بك من عذاب القبر» ”اے اللہ! میں تیری پناہ مانگتا ہوں بخل سے، میں تیری پناہ مانگتا ہوں بزدلی سے، میں تیری پناہ مانگتا ہوں اس سے کہ ناکارہ عمر میں پہنچا دیا جاؤں، میں تیری پناہ مانگتا ہوں دنیا کی آزمائش سے اور میں تیری پناہ مانگتا ہوں قبر کے عذاب سے۔“' WHERE id = 6134;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے اسامہ نے بیان کیا، ان سے برید بن عبداللہ نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پانی مانگا، پھر آپ صلی اللہ علیہ وسلم نے وضو کیا، پھر ہاتھ اٹھا کر یہ دعا کی ”اے اللہ! عبید ابوعامر کی مغفرت فرما۔“ میں نے اس وقت نبی کریم صلی اللہ علیہ وسلم کی بغل کی سفیدی دیکھی۔ پھر آپ صلی اللہ علیہ وسلم نے دعا کی ”اے اللہ! قیامت کے دن اسے اپنی بہت سی انسانی مخلوق سے بلند مرتبہ عطا فرمائیو۔“' WHERE id = 6145;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے یحییٰ نے، ان سے ابوسلمہ نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب عشاء کی آخر رکعت میں ( رکوع سے اٹھتے ہوئے ) «سمع الله لمن حمده» کہتے تھے تو دعائے قنوت پڑھتے تھے «اللهم أنج عياش بن أبي ربيعة،‏‏‏‏ اللهم أنج الوليد بن الوليد،‏‏‏‏ اللهم أنج سلمة بن هشام،‏‏‏‏ اللهم أنج المستضعفين من المؤمنين،‏‏‏‏ اللهم اشدد وطأتك على مضر،‏‏‏‏ اللهم اجعلها سنين كسني يوسف» ”اے اللہ! عیاش بن ابی ربیعہ کو نجات دے، اے اللہ! ولید بن ولید کو نجات دے، اے اللہ! سلمہ بن ہشام کو نجات دے، اے اللہ! کمزور ناتواں مومنوں کو نجات دے، اے اللہ! اے اللہ! قبیلہ مضر پر اپنی پکڑ کو سخت کر دے، اے اللہ! وہاں ایسا قحط پیدا کر دے جیسا یوسف علیہ السلام کے زمانہ میں ہوا تھا۔“' WHERE id = 6155;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے سمی نے، ان سے ابوصالح نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے یہ کلمہ کہ اللہ کے سوا کوئی معبود نہیں، تنہا ہے اس کا کوئی شریک نہیں، اسی کے لیے بادشاہی ہے اور اسی کے لیے تعریفیں ہیں اور وہ ہر چیز پر قدرت رکھنے والا ہے۔“ دن میں سو دفعہ پڑھا اسے دس غلاموں کو آزاد کرنے کا ثواب ملے گا اور اس کے لیے سو نیکیاں لکھ دی جائیں گی اور اس کی سو برائیاں مٹا دی جائیں گی اور اس دن وہ شیطان کے شر سے محفوظ رہے گا شام تک کے لیے اور کوئی شخص اس دن اس سے بہتر کام کرنے والا نہیں سمجھا جائے گا، سوا اس کے جو اس سے زیادہ کرے۔“' WHERE id = 6165;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے معاویہ بن قرہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا «اللهم لا عيش إلا عيش الآخره،‏‏‏‏ ‏‏‏‏ فأصلح الأنصار والمهاجره» ”اے اللہ! آخرت کی زندگی کے سوا اور کوئی زندگی نہیں۔ پس تو انصار و مہاجرین میں صلاح کو باقی رکھ۔“' WHERE id = 6175;
UPDATE hadiths SET urdu = 'انہوں نے بیان کیا کہ عتبان بن مالک انصاری رضی اللہ عنہ سے میں نے سنا، پھر بنی سالم کے ایک صاحب سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف لائے اور فرمایا ”کوئی بندہ جب قیامت کے دن اس حالت میں پیش ہو گا کہ اس نے کلمہ «لا إله إلا الله» کا اقرار کیا ہو گا اور اس سے اس کا مقصود اللہ کی خوشنودی حاصل کرنا ہو گی تو اللہ تعالیٰ دوزخ کی آگ کو اس پر حرم کر دے گا۔“' WHERE id = 6185;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، انہوں نے کہا ہم سے شیبان بن عبدالرحمٰن نے بیان کیا، ان سے یحییٰ نے بیان کیا، ان سے محمد بن ابراہیم قرشی نے بیان کیا کہ مجھے معاذ بن عبدالرحمٰن نے خبر دی، انہیں حمران بن ابان نے خبر دی، انہوں نے کہا کہ میں عثمان رضی اللہ عنہ کے لیے وضو کا پانی لے کر آیا وہ چبوترے پر بیٹھے ہوئے تھے، پھر انہوں نے اچھی طرح وضو کیا۔ اس کے بعد کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو اسی جگہ وضو کرتے ہوئے دیکھا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اچھی طرح وضو کیا، پھر فرمایا کہ جس نے اس طرح وضو کیا اور پھر مسجد میں آ کر دو رکعت نماز پڑھی تو اس کے پچھلے گناہ معاف ہو جاتے ہیں۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس پر یہ بھی فرمایا کہ اس پر مغرور نہ ہو جاؤ۔' WHERE id = 6195;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے عبدالعزیز بن رفیع نے، ان سے زید بن وہب نے اور ان سے ابوذرغفاری رضی اللہ عنہ نے بیان کیا کہ ایک روز میں باہر نکلا تو دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم تنہا چل رہے تھے اور آپ کے ساتھ کوئی بھی نہ تھا، ابوذر رضی اللہ عنہ کہتے ہیں کہ اس سے میں سمجھا کہ نبی کریم صلی اللہ علیہ وسلم اسے پسند نہیں فرمائیں گے کہ آپ کے ساتھ اس وقت کوئی رہے۔ اس لیے میں چاند کے سائے میں نبی کریم صلی اللہ علیہ وسلم کے پیچھے پیچھے چلنے لگا۔ اس کے بعد آپ مڑے تو مجھے دیکھا اور دریافت فرمایا کون ہے؟ میں نے عرض کیا: ابوذر! اللہ مجھے آپ پر قربان کرے۔ آپ صلی اللہ علیہ وسلم نے فرمایا، ابوذر! یہاں آؤ۔ بیان کیا کہ پھر میں تھوڑی دیر تک آپ کے ساتھ چلتا رہا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو لوگ ( دنیا میں ) زیادہ مال و دولت جمع کئے ہوئے ہیں قیامت کے دن وہی خسارے میں ہوں گے۔ سوائے ان کے جنہیں اللہ تعالیٰ نے مال دیا ہو اور انہوں نے اسے دائیں بائیں، آگے پیچھے خرچ کیا ہو اور اسے بھلے کاموں میں لگایا ہو۔ ( ابوذر رضی اللہ عنہ نے ) بیان کیا کہ پھر تھوڑی دیر تک میں آپ کے ساتھ چلتا رہا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہاں بیٹھ جاؤ۔ نبی کریم صلی اللہ علیہ وسلم نے مجھے ایک ہموار زمین پر بٹھا دیا جس کے چاروں طرف پتھر تھے اور فرمایا کہ یہاں اس وقت تک بیٹھے رہو جب تک میں تمہارے پاس لوٹ آؤں۔ پھر آپ پتھریلی زمین کی طرف چلے گئے اور نظروں سے اوجھل ہو گئے۔ آپ وہاں رہے اور دیر تک وہیں رہے۔ پھر میں نے آپ سے سنا، آپ یہ کہتے ہوئے تشریف لا رہے تھے ”چاہے چوری ہو، چاہے زنا ہو“ ابوذر کہتے ہیں کہ جب نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو مجھ سے صبر نہیں ہو سکا اور میں نے عرض کیا: اے اللہ کے نبی! اللہ آپ پر مجھے قربان کرے۔ اس پتھریلی زمین کے کنارے آپ کس سے باتیں کر رہے تھے۔ میں نے تو کسی دوسرے کو آپ سے بات کرتے نہیں دیکھا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ جبرائیل علیہ السلام تھے۔ پتھریلی زمین ( حرہ ) کے کنارے وہ مجھ سے ملے اور کہا کہ اپنی امت کو خوشخبری سنا دو کہ جو بھی اس حال میں مرے گا کہ اللہ کے ساتھ کسی چیز کو شریک نہ ٹھہراتا ہو تو وہ جنت میں جائے گا۔ میں نے عرض کیا: اے جبرائیل! خواہ اس نے چوری کی ہو، زنا کیا ہو؟ جبرائیل علیہ السلام نے کہا ہاں، خواہ اس نے شراب ہی پی ہو۔ نضر نے بیان کیا کہ ہمیں شعبہ نے خبر دی ( کہا ) ہم سے حبیب بن ابی ثابت، اعمش اور عبدالعزیز بن رفیع نے بیان کیا، ان سے زید بن وہب نے اسی طرح بیان کیا۔ امام بخاری رحمہ اللہ نے کہا ابوصالح نے جو اسی باب میں ابودرداء سے روایت کی ہے وہ منقطع ہے ( ابوصالح نے ابودرداء سے نہیں سنا ) اور صحیح نہیں ہے ہم نے یہ بیان کر دیا تاکہ اس حدیث کا حال معلوم ہو جائے اور صحیح ابوذر کی حدیث ہے ( جو اوپر مذکور ہوئی ) کسی نے امام بخاری رحمہ اللہ سے پوچھا عطاء بن یسار نے بھی تو یہ حدیث ابودرداء سے روایت کی ہے۔ انہوں نے کہا وہ بھی منقطع ہے اور صحیح نہیں ہے۔ آخر صحیح وہی ابوذر کی حدیث نکلی۔ امام بخاری رحمہ اللہ نے کہا ابودرداء کی حدیث کو چھوڑو ( وہ سند لینے کے لائق نہیں ہے کیونکہ وہ منقطع ہے ) امام بخاری رحمہ اللہ نے کہا کہ ابوذر کی حدیث کا مطلب یہ ہے کہ مرتے وقت آدمی «لا إله إلا الله» کہے اور توحید پر خاتمہ ہو ( تو وہ ایک نہ ایک دن ضرور جنت میں جائے گا گو کتنا ہی گنہگار ہو ) ۔ بعض نسخوں میں یہ ہے «هذا اذا تاب وقال لا إله إلا الله عند الموت» یعنی ابوذر کی حدیث اس شخص کے بارے میں ہے جو گناہ سے توبہ کرے اور مرتے وقت «لا إله إلا الله» کہے۔' WHERE id = 6205;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس نے بیان کیا، کہا کہ میں نے سعد بن ابی وقاص رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں سب سے پہلا عرب ہوں جس نے اللہ کے راستے میں تیر چلائے۔ ہم نے اس حال میں وقت گزارا ہے کہ جہاد کر رہے ہیں اور ہمارے پاس کھانے کی کوئی چیز حبلہ کے پتوں اور اس ببول کے سوا کھانے کے لیے نہیں تھی اور بکری کی مینگنیوں کی طرح ہم پاخانہ کیا کرتے تھے۔ اب یہ بنو اسد کے لوگ مجھ کو اسلام سکھلا کر درست کرنا چاہتے ہیں پھر تو میں بالکل بدنصیب ٹھہرا اور میرا سارا کیا کرایا اکارت گیا۔' WHERE id = 6215;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم سے کسی شخص کو اس کا عمل نجات نہیں دلا سکے گا۔“ صحابہ نے عرض کی اور آپ کو بھی نہیں یا رسول اللہ؟ فرمایا ”اور مجھے بھی نہیں، سوا اس کے کہ اللہ تعالیٰ مجھے اپنی رحمت کے سایہ میں لے لے۔ پس تم کو چاہئے کہ درستی کے ساتھ عمل کرو اور میانہ روی اختیار کرو۔ صبح اور شام، اسی طرح رات کو ذرا سا چل لیا کرو اور اعتدال کے ساتھ چلا کرو منزل مقصود کو پہنچ جاؤ گے۔“' WHERE id = 6225;
UPDATE hadiths SET urdu = 'ہم سے علی بن مسلم نے بیان کیا، کہا ہم سے ہشیم نے بیان کیا، کہا ہم کو ایک سے زیادہ کئی آدمیوں نے خبر دی جن میں مغیرہ بن مقسم اور فلاں نے (مجالد بن سعید، ان کی روایت کو ابن خزیمہ نے نکالا) اور ایک تیسرے صاحب داود بن ابی ہند بھی ہیں، انہیں شعبی نے، انہیں مغیرہ بن شعبہ رضی اللہ عنہ کے کاتب وراد نے کہ معاویہ رضی اللہ عنہ نے مغیرہ کو لکھا کہ کوئی حدیث جو آپ نے نبی کریم صلی اللہ علیہ وسلم سے سنی ہو وہ مجھے لکھ بھیجو۔ راوی نے بیان کیا کہ پھر مغیرہ رضی اللہ عنہ نے انہیں لکھا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے، آپ نماز سے فارغ ہونے کے بعد یہ دعا پڑھتے «لا إله إلا الله،‏‏‏‏ وحده لا شريك له،‏‏‏‏ له الملك،‏‏‏‏ وله الحمد،‏‏‏‏ وهو على كل شىء قدير» کہ ”اللہ کے سوا کوئی معبود نہیں جو تنہا ہے اس کا کوئی شریک نہیں، بادشاہت اسی کی ہے اور تمام تعریفیں اسی کے لیے ہیں اور وہ ہر چیز پر قدرت رکھنے والا ہے۔“ یہ تین مرتبہ پڑھتے۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم بےفائدہ بات چیت کرنے، زیادہ سوال کرنے، مال ضائع کرنے، اپنی چیز بچا کر رکھنے اور دوسروں کی مانگتے رہنے، ماؤں کی نافرمانی کرنے اور لڑکیوں کو زندہ درگور کرنے سے منع فرماتے تھے۔ اور ہشیم سے روایت ہے، انہیں عبدالملک ابن عمیر نے خبر دی، کہا کہ میں نے وراد سے سنا، وہ یہ حدیث مغیرہ رضی اللہ عنہ سے بیان کرتے تھے اور وہ نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 6235;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا کہ میری اور لوگوں کی مثال ایک ایسے شخص کی ہے جس نے آگ جلائی، جب اس کے چاروں طرف روشنی ہو گئی تو پروانے اور یہ کیڑے مکوڑے جو آگ پر گرتے ہیں اس میں گرنے لگے اور آگ جلانے والا انہیں اس میں سے نکالنے لگا لیکن وہ اس کے قابو میں نہیں آئے اور آگ میں گرتے رہے۔ اسی طرح میں تمہاری کمر کو پکڑ کر آگ سے تمہیں نکالتا ہوں اور تم ہو کہ اسی میں گرتے جاتے ہو۔' WHERE id = 6245;
UPDATE hadiths SET urdu = 'ہم سے علی بن عیاش نے بیان کیا، انہوں نے کہا ہم سے ابوغسان نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوحازم نے بیان کیا، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک شخص کو دیکھا جو مشرکین سے جنگ میں مصروف تھا، یہ شخص مسلمانوں کے صاحب مال و دولت لوگوں میں سے تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر کوئی چاہتا ہے کہ کسی جہنمی کو دیکھے تو وہ اس شخص کو دیکھے۔ اس پر ایک صحابی اس شخص کے پیچھے لگ گئے وہ شخص برابر لڑتا رہا اور آخر زخمی ہو گیا۔ پھر اس نے چاہا کہ جلدی مر جائے۔ پس اپنی تلوار ہی کی دھار اپنے سینے کے درمیان رکھ کر اس پر اپنے آپ کو ڈال دیا اور تلوار اس کے شانوں کو چیرتی ہوئی نکل گئی ( اس طرح وہ خودکشی کر کے مر گیا ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بندہ لوگوں کی نظر میں اہل جنت کے کام کرتا رہتا ہے حالانکہ وہ جہنم میں سے ہوتا ہے۔ ایک دوسرا بندہ لوگوں کی نظر میں اہل جہنم کے کام کرتا رہتا ہے حالانکہ وہ جنتی ہوتا ہے اور اعمال کا اعتبار تو خاتمہ پر موقوف ہے۔' WHERE id = 6255;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان نے بیان کیا، کہا ہم سے ابوحازم نے بیان کیا، ان سے سہل رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں اور قیامت اتنے نزدیک نزدیک بھیجے گئے ہیں اور نبی کریم صلی اللہ علیہ وسلم نے اپنی دو انگلیوں کے اشارہ سے ( اس نزدیکی کو ) بتایا پھر ان دونوں کو پھیلایا۔“' WHERE id = 6265;
UPDATE hadiths SET urdu = 'مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبدربہ بن سعید نے، ان سے محمد بن عمر نے بیان کیا، ان سے طلحہ بن کعب نے بیان کیا، ان سے ابوقتادہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ مرنے والا یا تو آرام پانے والا ہے یا دوسرے بندوں کو آرام دینے والا ہے۔' WHERE id = 6275;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے یونس بن محمد بغدادی نے بیان کیا، کہا ہم سے شیبان نحوی نے بیان کیا، کہا ان سے قتادہ نے، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ایک صحابی نے کہا، اے اللہ کے نبی! قیامت میں کافروں کو ان کے چہرے کے بل کس طرح حشر کیا جائے گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ ذات جس نے انہیں دنیا میں دو پاؤں پر چلایا اسے اس پر قدرت نہیں ہے کہ قیامت کے دن انہیں چہرے کے بل چلا دے۔ قتادہ رضی اللہ عنہ نے کہا کہ ضرور ہے، ہمارے رب کی عزت کی قسم، بیشک وہ منہ کے بل چلا سکتا ہے۔' WHERE id = 6285;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا مجھ سے شقیق نے بیان کیا، کہا میں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سب سے پہلے جس چیز کا فیصلہ لوگوں کے درمیان ہو گا وہ ناحق خون کے بدلہ کا ہو گا۔“' WHERE id = 6295;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابومریم نے بیان کیا، کہا ہم سے ابوغسان نے بیان کیا، کہا کہ مجھ سے ابوحازم نے بیان کیا، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جنت میں میری امت کے ستر ہزار یا سات لاکھ ( راوی کو ان میں سے کسی ایک تعداد میں شک تھا ) آدمی اس طرح داخل ہوں گے کہ بعض بعض کو پکڑے ہوئے ہوں گے اور اس طرح ان میں کے اگلے پچھلے سب جنت میں داخل ہو جائیں گے اور ان کے چہرے چودھویں رات کے چاند کی طرح روشن ہوں گے۔“' WHERE id = 6305;
UPDATE hadiths SET urdu = 'ابوحازم نے بیان کیا کہ پھر میں نے یہ حدیث نعمان بن ابی عیاش سے بیان کی تو انہوں نے کہا کہ مجھ سے ابوسعید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جنت میں ایک درخت ہو گا جس کے سایہ میں عمدہ اور تیز رفتار گھوڑے پر سوار شخص سو سال تک چلتا رہے گا اور پھر بھی اسے طے نہ کر سکے گا۔“' WHERE id = 6315;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، ان سے خیثمہ بن عبدالرحمٰن نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے جہنم کا ذکر کیا اور روئے مبارک پھیر لیا اور اس سے پناہ مانگی۔ پھر جہنم کا ذکر کیا اور روئے مبارک پھیر لیا اور اس سے پناہ مانگی۔ اس کے بعد فرمایا کہ دوزخ سے بچو صدقہ دے کر خواہ کھجور کے ایک ٹکڑے ہی کے ذریعہ ہو سکے، جسے یہ بھی نہ ملے اسے چاہئے کہ اچھی بات کہہ کر۔' WHERE id = 6325;
UPDATE hadiths SET urdu = 'عطاء نے بیان کیا کہ ابو سعید خدری رضی اللہ عنہ بھی اس وقت ابوہریرہ رضی اللہ عنہ کے ساتھ بیٹھے ہوئے تھے اور انہوں نے ان کی کسی بات پر اعتراض نہیں کیا لیکن جب ابوہریرہ رضی اللہ عنہ حدیث کے اس ٹکڑے تک پہنچے کہ تمہاری یہ ساری خواہشات پوری کی جاتی ہیں اور اتنی ہی اور زیادہ نعمتیں دی جاتی ہیں تو ابو سعید خدری رضی اللہ عنہ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہاری یہ ساری خواہشات پوری کی جاتی ہیں اور اس سے دس گنا اور زیادہ نعمتیں دی جاتی ہیں۔ اور ابوہریرہ رضی اللہ عنہ نے کہا کہ نہیں میں نے یوں ہی سنا ہے، یہ سب چیزیں اور اتنی ہی اور۔' WHERE id = 6335;
UPDATE hadiths SET urdu = 'ابوحازم نے بیان کیا کہ یہ حدیث مجھ سے نعمان بن ابی عیاش نے سنی اور کہا کہ میں گواہی دیتا ہوں کہ میں نے ابو سعید خدری رضی اللہ عنہ سے یہ حدیث اسی طرح سنی تھی اور وہ اس حدیث میں کچھ زیادتی کے ساتھ بیان کرتے تھے۔ ( یعنی یہ کہ نبی کریم صلی اللہ علیہ وسلم فرمائیں گے کہ ) میں کہوں گا کہ یہ تو مجھ میں سے ہیں ) نبی کریم صلی اللہ علیہ وسلم سے کہا جائے گا کہ آپ کو نہیں معلوم کہ انہوں نے آپ کے بعد دین میں کیا کیا نئی چیزیں ایجاد کر لی تھیں۔ اس پر میں کہوں گا کہ دور ہو وہ شخص جس نے میرے بعد دین میں تبدیلی کر لی تھی۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ «سحقا» بمعنی «بعدا» ہے، «سحيق» یعنی «بعيد»،‏‏‏‏ «أسحقه» یعنی «أبعده‏.‏» ۔' WHERE id = 6345;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا مجھ کو سلیمان اعمش نے خبر دی، کہا کہ میں نے زید بن وہب سے سنا، ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ہم کو رسول اللہ صلی اللہ علیہ وسلم نے بیان سنایا اور آپ سچوں کے سچے تھے اور آپ کی سچائی کی زبردست گواہی دی گئی۔ فرمایا کہ تم میں سے ہر شخص پہلے اپنی ماں کے پیٹ میں چالیس دن تک نطفہ ہی رکھا جاتا ہے۔ پھر اتنی ہی مدت میں «علقة» یعنی خون کی پھٹکی ( بستہ خون ) بنتا ہے پھر اتنے ہی عرصہ میں «مضغة» ( یعنی گوشت کا لوتھڑا ) پھر چار ماہ بعد اللہ تعالیٰ ایک فرشتہ بھیجتا ہے اور اس کے بارے میں ( ماں کے پیٹ ہی میں ) چار باتوں کے لکھنے کا حکم دیا جاتا ہے۔ اس کی روزی کا، اس کی موت کا، اس کا کہ وہ بدبخت ہے یا نیک بخت۔ پس واللہ، تم میں سے ایک شخص دوزخ والوں کے سے کام کرتا رہتا ہے اور جب اس کے اور دوزخ کے درمیان صرف ایک بالشت کا فاصلہ یا ایک ہاتھ کا فاصلہ باقی رہ جاتا ہے تو اس کی تقدیر اس پر غالب آتی ہے اور وہ جنت والوں کے سے کام کرنے لگتا ہے اور جنت میں جاتا ہے۔ اسی طرح ایک شخص جنت والوں کے سے کام کرتا رہتا ہے اور جب اس کے اور جنت کے درمیان ایک ہاتھ کا فاصلہ باقی رہ جاتا ہے تو اس کی تقدیر اس پر غالب آتی ہے اور وہ دوزخ والوں کے کام کرنے لگتا ہے اور دوزخ میں جاتا ہے۔ امام بخاری رحمہ اللہ کہتے ہیں کہ آدم بن ابی ایاس نے اپنی روایت میں یوں کہا کہ جب ایک ہاتھ کا فاصلہ رہ جاتا ہے۔' WHERE id = 6355;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ خیبر کی لڑائی میں موجود تھے، نبی کریم صلی اللہ علیہ وسلم نے ایک شخص کے بارے میں جو آپ کے ساتھ شریک جہاد تھا اور اسلام کا دعویدار تھا فرمایا کہ یہ جہنمی ہے۔ جب جنگ ہونے لگی تو اس شخص نے بہت جم کر لڑائی میں حصہ لیا اور بہت زیادہ زخمی ہو گیا پھر بھی وہ ثابت قدم رہا۔ نبی کریم صلی اللہ علیہ وسلم کے ایک صحابی نے آ کر عرض کیا: یا رسول اللہ! اس شخص کے بارے میں آپ کو معلوم ہے جس کے بارے میں ابھی آپ نے فرمایا تھا کہ وہ جہنمی ہے وہ تو اللہ کے راستے میں بہت جم کر لڑا ہے اور بہت زیادہ زخمی ہو گیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اب بھی یہی فرمایا کہ وہ جہنمی ہے۔ ممکن تھا کہ بعض مسلمان شبہ میں پڑ جاتے لیکن اس عرصہ میں اس شخص نے زخموں کی تاب نہ لا کر اپنا ترکش کھولا اور اس میں سے ایک تیر نکال کر اپنے آپ کو ذبح کر لیا۔ پھر بہت سے مسلمان نبی کریم صلی اللہ علیہ وسلم کی خدمت میں دوڑتے ہوئے پہنچے اور عرض کیا: یا رسول اللہ! اللہ تعالیٰ نے آپ کی بات سچ کر دکھائی۔ اس شخص نے اپنے آپ کو ہلاک کر کے اپنی جان خود ہی ختم کر ڈالی۔ نبی کریم صلی اللہ علیہ وسلم نے اس موقع پر فرمایا کہ اے بلال! اٹھو اور لوگوں میں اعلان کر دو کہ جنت میں صرف مومن ہی داخل ہو گا اور یہ کہ اللہ تعالیٰ اس دین کی خدمت و مدد بےدین آدمی سے بھی کراتا ہے۔' WHERE id = 6366;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے سمی نے بیان کیا، ان سے ابوصالح نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ سے پناہ مانگا کرو آزمائش کی مشقت، بدبختی کی پستی، برے خاتمے اور دشمن کے ہنسنے سے۔' WHERE id = 6376;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق یعنی ابن ابراہیم نے بیان کیا، کہا ہم سے یحییٰ بن صالح نے بیان کیا، انہوں نے کہا ہم سے معاویہ نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے، ان سے عکرمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”وہ شخص جو اپنے گھر والوں کے معاملہ میں قسم پر اڑا رہتا ہے وہ اس سے بڑا گناہ کرتا ہے کہ اس قسم کا کفارہ ادا کر دے۔“' WHERE id = 6386;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا ہم سے ہمارے والد نے، کہا ہم سے اعمش نے، ان سے معرور نے، ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم تک پہنچا تو آپ کعبہ کے سایہ میں بیٹھے ہوئے فرما رہے تھے کعبہ کے رب کی قسم! وہی سب سے زیادہ خسارے والے ہیں۔ کعبہ کے رب کی قسم! وہی سب سے زیادہ خسارے والے ہیں۔ میں نے کہا کہ یا رسول اللہ! میری حالت کیسی ہے، کیا مجھ میں ( بھی ) کوئی ایسی بات نظر آئی ہے؟ میری حالت کیسی ہے؟ پھر میں نبی کریم صلی اللہ علیہ وسلم کے پاس بیٹھ گیا اور نبی کریم صلی اللہ علیہ وسلم فرماتے جا رہے تھے، میں آپ کو خاموش نہیں کرا سکتا تھا اور اللہ کی مشیت کے مطابق مجھ پر عجیب بےقراری طاری ہو گئی۔ میں نے پھر عرض کی، میرے ماں باپ آپ پر فدا ہوں، یا رسول اللہ! وہ کون لوگ ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ وہ لوگ ہیں جن کے پاس مال زیادہ ہے۔ لیکن اس سے وہ مستثنیٰ ہیں۔ جنہوں نے اس میں سے اس اس طرح ( یعنی دائیں اور بائیں بےدریغ مستحقین پر ) اللہ کی راہ میں خرچ کیا ہو گا۔' WHERE id = 6397;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن مسلم نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن دینار نے بیان کیا، انہوں نے کہا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اپنے باپ دادوں کی قسم نہ کھاؤ۔“' WHERE id = 6407;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نے، ان سے عبیدہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے پوچھا گیا کہ کون لوگ اچھے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرا زمانہ، پھر وہ لوگ جو اس سے قریب ہوں گے پھر وہ لوگ جو اس سے قریب ہوں گے۔ اس کے بعد ایک ایسی قوم پیدا ہو گی جس کی گواہی قسم سے پہلے زبان پر آ جایا کرے گی اور قسم گواہی سے پہلے۔ ابراہیم نے کہا کہ ہمارے اساتذہ جب ہم کم عمر تھے تو ہمیں قسم کھانے سے منع کیا کرتے تھے کہ ہم گواہی یا عہد میں قسم کھائیں۔' WHERE id = 6417;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے محمد بن عبدالرحمٰن بن ابی ذئب نے بیان کیا، ان سے زہری نے بیان کیا، ان سے اعرج نے اور ان سے عبداللہ بن بجینہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں نماز پڑھائی اور پہلی دو رکعات کے بعد بیٹھنے سے پہلے ہی اٹھ گئے اور نماز پوری کر لی۔ جب نماز پڑھ چکے تو لوگوں نے نبی کریم صلی اللہ علیہ وسلم کے سلام کا انتظار کیا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے تکبیر کہی اور سلام پھیرنے سے پہلے سجدہ کیا، پھر سجدہ سے سر اٹھایا اور دوبارہ تکبیر کہہ کر سجدہ کیا۔ پھر سجدہ سے سر اٹھایا اور سلام پھیرا۔' WHERE id = 6428;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے محمد بن فضیل نے بیان کیا، انہوں نے کہا ہم سے عمارہ بن قعقاع نے بیان کیا، انہوں نے کہا ہم سے ابوزرعہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”دو کلمے جو زبان پر ہلکے ہیں لیکن ترازو پر ( آخرت میں ) بھاری ہیں اور اللہ رحمن کے یہاں پسندیدہ ہیں وہ یہ ہیں «سبحان الله وبحمده،‏‏‏‏ سبحان الله العظيم‏ ‏‏.» ۔' WHERE id = 6439;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن صالح نے بیان کیا، انہوں نے کہا ہم سے فلیح بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے سعید بن الحارث نے بیان کیا، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، انہوں نے کہا، کیا لوگوں کو نذر سے منع نہیں کیا گیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نذر کسی چیز کو نہ آگے کر سکتی ہے نہ پیچھے، البتہ اس کے ذریعہ بخیل کا مال نکالا جا سکتا ہے۔' WHERE id = 6449;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے، ان سے سلیمان احول نے، ان سے طاؤس نے، ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک شخص کو دیکھا کہ وہ کعبہ کا طواف لگام یا اس کے سوا کسی اور چیز کے ذریعہ کر رہا تھا تو نبی کریم صلی اللہ علیہ وسلم نے اسے کاٹ دیا۔' WHERE id = 6459;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے قاسم بن مالک مزنی نے بیان کیا، کہا ہم سے جعید بن عبدالرحمٰن نے بیان کیا، ان سے سائب بن یزید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں ایک صاع تمہارے زمانہ کے مد سے ایک مد اور تہائی کے برابر ہوتا تھا۔ بعد میں عمر بن عبدالعزیز کے زمانہ میں اس میں زیادتی کی گئی۔' WHERE id = 6469;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے عثمان بن عمر بن فارس نے بیان کیا، انہوں نے کہا ہم کو عبداللہ ابن عون نے خبر دی، انہیں امام حسن بصری نے، ان سے عبدالرحمٰن بن سمرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کبھی تم حکومت کا عہدہ طلب نہ کرنا کیونکہ اگر بلا مانگے تمہیں یہ مل جائے گا تو اس میں تمہاری منجانب اللہ مدد کی جائے گی، لیکن اگر مانگنے پر ملا تو سارا بوجھ تمہیں پر ڈال دیا جائے گا اور اگر تم کوئی قسم کھا لو اور اس کے سوا کوئی اور بات بہتر نظر آئے تو وہی کرو جو بہتر ہو اور قسم کا کفارہ ادا کر دو۔ عثمان بن عمر کے ساتھ اس حدیث کو اشہل بن حاتم نے بھی عبداللہ بن عون سے روایت کیا، اس کو ابوعوانہ اور حاکم نے وصل کیا اور عبداللہ بن عون کے ساتھ اس حدیث کو یونس اور سماک بن عطیہ اور سماک بن حرب اور حمید اور قتادہ اور منصور اور ہشام اور ربیع نے بھی روایت کیا۔' WHERE id = 6479;
UPDATE hadiths SET urdu = 'مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم سے ابوالنضر نے بیان کیا، کہا ہم سے ابومعاویہ شیبان نے بیان کیا، ان سے اشعث بن ابی الشعثاء نے، ان سے اسود بن یزید نے بیان کیا کہ معاذ بن جبل رضی اللہ عنہ ہمارے یہاں یمن میں معلم و امیر بن کر تشریف لائے۔ ہم نے ان سے ایک ایسے شخص کے ترکہ کے بارے میں پوچھا جس کی وفات ہوئی ہو اور اس نے ایک بیٹی اور ایک بہن چھوڑی ہو اور اس نے اپنی بیٹی کو آدھا اور بہن کو بھی آدھا دیا ہو۔' WHERE id = 6490;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے، ان سے ابواسحاق نے، ان سے براء رضی اللہ عنہ نے بیان کیا کہ آخری آیت ( میراث کی ) سورۃ نساء کے آخر کی آیتیں نازل ہوئیں «يستفتونك قل الله يفتيكم في الكلالة‏» کہ ”آپ سے فتویٰ پوچھتے ہیں، کہہ دیجئیے کہ اللہ تعالیٰ تمہیں کلالہ کے بارے میں فتویٰ دیتا ہے۔“' WHERE id = 6500;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے منصور نے، ان سے ابراہیم نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے کہ بریرہ کو انہوں نے آزاد کرنے کے لیے خریدنا چاہا لیکن ان کے نائکوں نے اپنے ولاء کی شرط لگا دی عائشہ رضی اللہ عنہا نے کہا یا رسول اللہ! میں نے آزاد کرنے کے لیے بریرہ کو خریدنا چاہا لیکن ان کے مالکوں نے اپنے لیے ان کی ولاء کی شرط لگا دی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں آزاد کر دے، ولاء تو آزاد کرنے والے کے ساتھ قائم ہوتی ہے۔ بیان کیا کہ پھر میں نے انہیں خریدا اور آزاد کر دیا اور میں نے بریرہ کو اختیار دیا ( کہ چاہیں تو شوہر کے ساتھ رہ سکتی ہیں ورنہ علیحدہ بھی ہو سکتی ہیں ) تو انہوں نے شوہر سے علیحدگی کو پسند کیا اور کہا کہ مجھے اتنا اتنا مال بھی دیا جائے تو میں پہلے شوہر کے ساتھ نہیں رہوں گی۔ اسود نے بیان کیا کہ ان کے شوہر آزاد تھے۔ اسود کا قول منقطع ہے اور ابن عباس رضی اللہ عنہما کا قول صحیح ہے کہ میں نے انہیں غلام دیکھا۔' WHERE id = 6510;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے علی بن حسین نے بیان کیا، ان سے عمر بن عثمان نے بیان کیا اور ان سے اسامہ بن زید رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مسلمان باپ کافر بیٹے کا وارث نہیں ہوتا اور نہ کافر بیٹا مسلمان باپ کا۔“' WHERE id = 6520;
UPDATE hadiths SET urdu = 'ہم سے مسلم نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے شراب پینے پر چھڑی اور جوتوں سے مارا تھا اور ابوبکر رضی اللہ عنہ نے چالیس ( 40 ) کوڑے لگوائے تھے۔' WHERE id = 6531;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے، ان سے عقیل نے، ان سے شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو جب بھی دو چیزوں میں سے ایک کے اختیار کرنے کا حکم دیا گیا تو آپ نے ان میں سے آسان ہی کو پسند کیا، بشرطیکہ اس میں گناہ کا کوئی پہلو نہ ہو، اگر اس میں گناہ کا کوئی پہلو ہوتا تو آپ اس سے سب سے زیادہ دور ہوتے۔ اللہ کی قسم! نبی کریم صلی اللہ علیہ وسلم نے کبھی اپنے ذاتی معاملہ میں کسی سے بدلہ نہیں لیا، البتہ جب اللہ کی حرمتوں کو توڑا جاتا تو آپ اللہ کے لیے بدلہ لیتے تھے۔' WHERE id = 6541;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک ڈھال کی چوری پر ہاتھ کاٹا تھا جس کی قیمت تین درہم تھی۔' WHERE id = 6551;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں عبیداللہ بن عمر عمری نے، انہیں خبیب بن عبدالرحمٰن نے، انہیں حفص بن عاصم نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سات آدمی ایسے ہیں جنہیں اللہ تعالیٰ قیامت کے دن اپنے عرش کے نیچے سایہ دے گا جبکہ اس کے عرش کے سایہ کے سوا اور کوئی سایہ نہیں ہو گا۔ عادل حاکم، نوجوان جس نے اللہ کی عبادت میں جوانی پائی، ایسا شخص جس نے اللہ کو تنہائی میں یاد کیا اور اس کی آنکھوں سے آنسو نکل پڑے، وہ شخص جس کا دل مسجد میں لگا رہتا ہے، وہ آدمی جو اللہ کے لیے محبت کرتے ہیں، وہ شخص جسے کسی بلند مرتبہ اور خوبصورت عورت نے اپنی طرف بلایا اور اس نے جواب دیا کہ میں اللہ سے ڈرتا ہوں اور وہ شخص جس نے اتنا پوشیدہ صدقہ کیا کہ اس کے بائیں ہاتھ کو بھی پتہ نہ چل سکا کہ دائیں نے کتنا اور کیا صدقہ کیا ہے۔“' WHERE id = 6561;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محمد بن زیاد نے بیان کیا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”لڑکا اسی کو ملتا ہے جس کی جورو یا لونڈی کے پیٹ سے ہوا ہو اور حرام کار کے لیے صرف پتھر ہیں۔“' WHERE id = 6572;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، کہا ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ان مردوں پر لعنت کی ہے جو مخنث بنتے ہیں اور ان عورتوں پر لعنت کی ہے جو مرد بنیں اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اپنے گھروں سے نکال دو۔ اور نبی کریم صلی اللہ علیہ وسلم نے فلاں کو گھر سے نکالا تھا اور عمر رضی اللہ عنہ نے فلاں کو نکالا تھا۔' WHERE id = 6585;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا مجھ سے ابن وہب نے بیان کیا، انہوں نے کہا مجھ کو عمرو نے خبر دی، ان سے بکیر نے بیان کیا کہ میں سلیمان بن یسار کے پاس بیٹھا ہوا تھا کہ عبدالرحمٰن بن جابر آئے اور سلیمان بن یسار سے بیان کیا پھر سلیمان بن یسار ہماری طرف متوجہ ہوئے اور انہوں نے کہا کہ مجھ سے عبدالرحمٰن بن جابر نے بیان کیا ہے کہ ان سے ان کے والد نے بیان کیا اور انہوں نے ابوبردہ انصاری رضی اللہ عنہ سے سنا۔ انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ حدود اللہ میں سے کسی حد کے سوا کسی سزا میں دس کوڑے سے زیادہ کی سزا نہ دو۔' WHERE id = 6598;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، کہا ہم سے اسحاق بن سعید بن عمرو بن سعد بن العاص رضی اللہ عنہما نے بیان کیا، ان سے ان کے والد نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مومن اس وقت تک اپنے دین کے بارے میں برابر کشادہ رہتا ہے ( اسے ہر وقت مغفرت کی امید رہتی ہے ) جب تک ناحق خون نہ کرے جہاں ناحق کیا تو مغفرت کا دروازہ تنگ ہو جاتا ہے۔“' WHERE id = 6609;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے ہم پر ہتھیار اٹھایا وہ ہم میں سے نہیں ہے۔“ ابوموسیٰ رضی اللہ عنہ نے بھی نبی کریم صلی اللہ علیہ وسلم سے یہ حدیث روایت کی ہے۔' WHERE id = 6620;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم کو حبان بن ہلال نے خبر دی، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ایک یہودی نے ایک لڑکی کا سر دو پتھروں کے درمیان میں لے کر کچل دیا تھا۔ اس لڑکی سے پوچھا گیا کہ یہ تمہارے ساتھ کس نے کیا؟ کیا فلاں نے کیا ہے؟ کیا فلاں نے کیا ہے؟ آخر جب اس یہودی کا نام لیا گیا تو اس نے اپنے سر کے اشارے سے ( ہاں ) کہا پھر یہودی لایا گیا اور اس نے اقرار کر لیا چنانچہ نبی کریم صلی اللہ علیہ وسلم کے حکم سے اس کا بھی سر پتھر سے کچل دیا گیا۔ ہمام نے دو پتھروں کا ذکر کیا ہے۔' WHERE id = 6630;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”یہ اور یہ برابر یعنی چھنگلیا اور انگوٹھا دیت میں برابر ہیں۔“' WHERE id = 6640;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے کہ عمر رضی اللہ عنہ نے لوگوں سے قسم دے کر پوچھا کہ کس نے نبی کریم صلی اللہ علیہ وسلم سے حمل گرنے کے سلسلے میں فیصلہ سنا ہے؟ مغیرہ رضی اللہ عنہ نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے، آپ نے اس میں ایک غلام یا کنیز دینے کا فیصلہ کیا تھا۔' WHERE id = 6652;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم کو جریر بن عبدالحمید نے بیان کیا، انہوں نے اعمش سے، انہوں نے ابراہیم نخعی سے، انہوں نے علقمہ سے، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے، انہوں نے کہا کہ جب ( سورۃ الانعام کی ) یہ آیت «الذين آمنوا ولم يلبسوا إيمانهم بظلم‏» اتری ”جو لوگ ایمان لائے اور انہوں نے ایمان کو گناہ سے آلود نہیں کیا ( یعنی ظلم سے ) “ تو نبی کریم صلی اللہ علیہ وسلم کے صحابہ کو بہت گراں گزری وہ کہنے لگے بھلا ہم میں سے کون ایسا ہے جس نے ایمان کے ساتھ کوئی ظلم ( یعنی گناہ ) نہ کیا ہو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس آیت میں ظلم سے گناہ مراد نہیں ہے ( بلکہ شرک مراد ہے ) کیا تم نے لقمان علیہ السلام کا قول نہیں سنا «إن الشرك لظلم عظيم‏» ”شرک بڑا ظلم ہے“۔' WHERE id = 6663;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم ہمارے سے والد نے، کہا ہم سے اعمش نے، کہا ہم سے خیثمہ بن عبدالرحمٰن نے، کہا ہم سے سوید بن غفلہ نے کہ علی رضی اللہ عنہ نے کہا جب میں تم سے نبی کریم صلی اللہ علیہ وسلم کی کوئی حدیث بیان کروں تو قسم اللہ کی اگر میں آسمان سے نیچے گر پڑوں یہ مجھ کو اس سے اچھا لگتا ہے کہ میں نبی کریم صلی اللہ علیہ وسلم پر جھوٹ باندھوں ہاں جب مجھ میں تم میں آپس میں گفتگو ہو تو اس میں بنا کر بات کہنے میں کوئی قباحت نہیں کیونکہ ( نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے ) لڑائی تدبیر اور مکر کا نام ہے۔ دیکھو میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے آپ صلی اللہ علیہ وسلم فرماتے تھے کہ اخیر زمانہ قریب ہے جب ایسے لوگ مسلمانوں میں نکلیں گے جو نوعمر بیوقوف ہوں گے ( ان کی عقل میں فتور ہو گا ) ظاہر میں تو ساری خلق کے کلاموں میں جو بہتر ہے ( یعنی حدیث شریف ) وہ پڑھیں گے مگر درحقیقت ایمان کا نور ان کے حلق سے نیچے نہیں اترے گا، وہ دین سے اس طرح باہر ہو جائیں گے جیسے تیر شکار کے جانور سے پار نکل جاتا ہے۔ ( اس میں کچھ لگا نہیں رہتا ) تم ان لوگوں کو جہاں پانا بے تامل قتل کرنا، ان کو جہاں پاؤ قتل کرنے میں قیامت کے دن ثواب ملے گا۔' WHERE id = 6674;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے خالف بن یزید نے بیان کیا، ان سے سعید بن ابی ہلال بن اسامہ نے، انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نماز میں دعا کرتے تھے کہ اے اللہ عیاش بن ابی ربیعہ، سلمہ بن ہشام اور ولید بن الولید ( رضی اللہ عنہم ) کو نجات دے۔ اے اللہ بےبس مسلمانوں کو نجات دے۔ اے اللہ قبیلہ مضر کے لوگوں کو سختی کے ساتھ پیس ڈال اور ان پر ایسی قحط سالی بھیج جیسی یوسف علیہ السلام کے زمانہ میں آئی تھی۔' WHERE id = 6684;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم سے شعیب نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ابراہیم علیہ السلام نے سارہ علیہا السلام کو ساتھ لے کر ہجرت کی تو ایک ایسی بستی میں پہنچے جس میں بادشاہوں میں سے ایک بادشاہ یا ظالموں میں سے ایک ظالم رہتا تھا اس ظالم نے ابراہیم علیہ السلام کے پاس یہ حکم بھیجا کہ سارہ علیہا السلام کو اس کے پاس بھیجیں آپ نے سارہ کو بھیج دیا وہ ظالم ان کے پاس آیا تو وہ ( سارہ علیہا السلام ) وضو کر کے نماز پڑھ رہی تھیں انہوں نے دعا کی کہ اے اللہ! اگر میں تجھ پر اور تیرے رسول پر ایمان رکھتی ہوں تو تو مجھ پر کافر کو نہ مسلط کر پھر ایسا ہوا کہ وہ کم بخت بادشاہ اچانک خراٹے لینے اور گر کر پاؤں ہلانے لگا۔' WHERE id = 6694;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہ ہم سے امام مالک نے، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بچا ہوا بےضرورت پانی اس لیے نہ روکا جائے کہ اس کی وجہ سے بچی ہوئی گھاس بھی بچی رہے ( اس میں بھی حیلہ سازی سے روکا گیا ہے ) ۔' WHERE id = 6705;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم حلوہ ( یعنی میٹھی چیز ) اور شہد پسند کرتے تھے اور عصر کی نماز سے فارغ ہونے کے بعد اپنی ازواج سے ( ان میں سے کسی کے حجرہ میں جانے کے لیے ) اجازت لیتے تھے اور ان کے پاس جاتے تھے۔ ایک مرتبہ آپ حفصہ رضی اللہ عنہا کے گھر گئے اور ان کے یہاں اس سے زیادہ دیر تک ٹھہرے رہے جتنی دیر تک ٹھہرنے کا آپ کا معمول تھا۔ میں نے اس کے متعلق نبی کریم صلی اللہ علیہ وسلم سے پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان کی قوم کی ایک خاتون نے شہد کی ایک کپی انہیں ہدیہ کی تھی اور انہوں نے نبی کریم صلی اللہ علیہ وسلم کو اس کا شربت پلایا تھا۔ میں نے اس پر کہا کہ اب میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک حیلہ کروں گی چنانچہ میں نے اس کا ذکر سودہ رضی اللہ عنہا سے کیا اور کہا جب نبی کریم صلی اللہ علیہ وسلم آپ کے یہاں آئیں تو آپ کے قریب بھی آئیں گے اس وقت تم آپ سے کہنا یا رسول اللہ! شاید آپ نے مغافیر کھایا ہے؟ اس پر آپ جواب دیں گے کہ نہیں۔ تم کہنا کہ پھر یہ بو کس چیز کی ہے؟ نبی کریم صلی اللہ علیہ وسلم کو یہ بات بہت ناگوار تھی کہ آپ کے جسم کے کسی حصہ سے بو آئے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم اس کا جواب یہ دیں گے کہ حفصہ نے مجھے شہد کا شربت پلایا تھا۔ اس پر کہنا کہ شہد کی مکھیوں نے غرفط کا رس چوسا ہو گا اور میں بھی نبی کریم صلی اللہ علیہ وسلم سے یہی بات کہوں گی اور صفیہ تم بھی نبی کریم صلی اللہ علیہ وسلم سے یہ کہنا چنانچہ جب نبی کریم صلی اللہ علیہ وسلم سودہ کے یہاں تشریف لے گئے تو ان کا بیان ہے کہ اس ذات کی قسم جس کے سوا کوئی معبود نہیں کہ تمہارے خوف سے قریب تھا کہ میں اس وقت نبی کریم صلی اللہ علیہ وسلم سے یہ بات جلدی میں کہہ دیتی جبکہ آپ دروازے ہی پر تھے۔ آخر جب نبی کریم صلی اللہ علیہ وسلم قریب آئے تو میں نے عرض کیا: یا رسول اللہ! آپ نے مغافیر کھایا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے کہا پھر بو کیسی ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ حفصہ نے مجھے شہد کا شربت پلایا ہے میں نے کہا اس شہد کی مکھیوں نے غرفط کا رس چوسا ہو گا اور صفیہ رضی اللہ عنہا کے پاس جب آپ تشریف لے گئے تو انہوں نے بھی یہی کہا۔ اس کے بعد جب حفصہ کے پاس آپ صلی اللہ علیہ وسلم گئے تو انہوں نے عرض کیا: یا رسول اللہ! وہ شہد میں پھر آپ کو پلاؤں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کی ضرورت نہیں۔ بیان کیا ہے کہ اس پر سودہ رضی اللہ عنہا بولیں۔ سبحان اللہ یہ ہم نے کیا کیا گویا شہد آپ پر حرام کر دیا، میں نے کہا چپ رہو۔' WHERE id = 6715;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا ‘ ان سے عقیل بن خالد نے بیان کیا ‘ اور ان سے ابن شہاب نے بیان کیا (دوسری سند امام بخاری رحمہ اللہ نے کہا) کہ مجھ سے عبداللہ بن محمد مسندی نے بیان کیا ‘ انہوں نے کہا مجھ سے عبدالرزاق نے بیان کیا ‘ ان سے معمر نے بیان کیا ‘ ان سے زہری نے کہا کہ مجھے عروہ نے خبر دی اور ان سے عائشہ رضی اللہ عنہا عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم پر وحی کی ابتداء سونے کی حالت میں سچے خواب کے ذریعہ ہوئی۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم جو خواب بھی دیکھتے تو وہ صبح کی روشنی کی طرح سامنے آ جاتا اور نبی کریم صلی اللہ علیہ وسلم غار حرا میں چلے جاتے اور اس میں تنہا اللہ کی یاد کرتے تھے چند مقررہ دنوں کے لیے ( یہاں آتے ) اور ان دنوں کا توشہ بھی ساتھ لاتے۔ پھر خدیجہ رضی اللہ عنہا کے پاس واپس تشریف لے جاتے اور وہ پھر اتنا ہی توشہ آپ کے ساتھ کر دیتیں یہاں تک کہ حق آپ کے پاس اچانک آ گیا اور آپ غار حرا ہی میں تھے۔ چنانچہ اس میں فرشتہ آپ کے پاس آیا اور کہا کہ پڑھیے۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے فرمایا کہ میں پڑھا ہوا نہیں ہوں۔ آخر اس نے مجھے پکڑ لیا اور زور سے دابا اور خوب دابا جس کی وجہ سے مجھ کو بہت تکلیف ہوئی۔ پھر اس نے مجھے چھوڑ دیا اور کہا کہ پڑھیے آپ صلی اللہ علیہ وسلم نے پھر وہی جواب دیا کہ میں پڑھا ہوا نہیں ہوں۔ اس نے مجھے ایسا دابا کہ میں بے قابو ہو گیا یا انہوں نے اپنا زور ختم کر دیا اور پھر چھوڑ کر اس نے مجھ سے کہا کہ پڑھیے اپنے رب کے نام سے جس نے پیدا کیا ہے۔ الفاظ «ما لم يعلم‏» تک۔ پھر جب آپ صلی اللہ علیہ وسلم خدیجہ رضی اللہ عنہا کے پاس آئے تو آپ کے مونڈھوں کے گوشت ( ڈر کے مارے ) پھڑک رہے تھے۔ جب گھر میں آپ صلی اللہ علیہ وسلم داخل ہوئے تو فرمایا کہ مجھے چادر اڑھا دو ‘ مجھے چادر اڑھا دو، چنانچہ آپ کو چادر اڑھا دی گئی اور جب آپ صلی اللہ علیہ وسلم کا خوف دور ہو گیا تو فرمایا کہ خدیجہ میرا حال کیا ہو گیا ہے؟ پھر آپ صلی اللہ علیہ وسلم نے اپنا سارا حال بیان کیا اور فرمایا کہ مجھے اپنی جان کا ڈر ہے۔ لیکن خدیجہ رضی اللہ عنہا نے کہا اللہ کی قسم ایسا ہرگز نہیں ہو سکتا، آپ خوش رہئیے اللہ تعالیٰ آپ کو کبھی رسوا نہیں کرے گا۔ آپ تو صلہ رحمی کرتے ہیں، بات سچی بولتے ہیں، ناداروں کا بوجھ اٹھاتے ہیں، مہمان نوازی کرتے ہیں اور حق کی وجہ سے پیش آنے والی مصیبتوں پر لوگوں کی مدد کرتے ہیں۔ پھر آپ کو خدیجہ رضی اللہ عنہا ورقہ بن نوفل بن اسد بن عبدالعزیٰ بن قصی کے پاس لائیں جو خدیجہ رضی اللہ عنہا کے والد خویلد کے بھائی کے بیٹے تھے۔ جو زمانہ جاہلیت میں عیسائی ہو گئے تھے اور عربی لکھ لیتے تھے اور وہ جتنا اللہ تعالیٰ چاہتا عربی میں انجیل کا ترجمہ لکھا کرتے تھے، وہ اس وقت بہت بوڑھے ہو گئے تھے اور بینائی بھی جاتی رہی تھی۔ ان سے خدیجہ رضی اللہ عنہا نے کہا: بھائی! اپنے بھتیجے کی بات سنو۔ ورقہ نے پوچھا: بھتیجے تم کیا دیکھتے ہو؟ نبی کریم صلی اللہ علیہ وسلم نے جو دیکھا تھا وہ سنایا تو ورقہ نے کہا کہ یہ تو وہی فرشتہ ( جبرائیل علیہ السلام ) ہے جو موسیٰ علیہ السلام پر آیا تھا۔ کاش میں اس وقت جوان ہوتا جب تمہیں تمہاری قوم نکال دے گی اور زندہ رہتا نبی کریم صلی اللہ علیہ وسلم نے پوچھا: کیا یہ مجھے نکالیں گے؟ ورقہ نے کہا کہ ہاں۔ جب بھی کوئی نبی و رسول وہ پیغام لے کر آیا جسے لے کر آپ آئے ہیں تو اس کے ساتھ دشمنی کی گئی اور اگر میں نے تمہارے وہ دن پا لیے تو میں تمہاری بھرپور مدد کروں گا لیکن کچھ ہی دنوں بعد ورقہ کا انتقال ہو گیا اور وحی کا سلسلہ کٹ گیا اور نبی کریم صلی اللہ علیہ وسلم کو اس کی وجہ سے اتنا غم تھا کہ آپ نے کئی مرتبہ پہاڑ کی بلند چوٹی سے اپنے آپ کو گرا دینا چاہا لیکن جب بھی آپ کسی پہاڑ کی چوٹی پر چڑھے تاکہ اس پر سے اپنے آپ کو گرا دیں تو جبرائیل علیہ السلام آپ کے سامنے آ گئے اور کہا کہ یا محمد! آپ یقیناً اللہ کے رسول ہیں۔ اس سے نبی کریم صلی اللہ علیہ وسلم کو سکون ہوتا اور آپ واپس آ جاتے لیکن جب وحی زیادہ دنوں تک رکی رہی تو آپ نے ایک مرتبہ اور ایسا ارادہ کیا لیکن جب پہاڑ کی چوٹی پر چڑھے تو جبرائیل علیہ السلام سامنے آئے اور اسی طرح کی بات پھر کہی۔ ابن عباس رضی اللہ عنہما نے کہا ( سورۃ الانعام ) میں لفظ «‏‏‏‏فالق الإصباح‏» سے مراد دن میں سورج کی روشنی اور رات میں چاند کی روشنی ہے۔' WHERE id = 6725;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ نے بیان کیا، انہوں نے کہا ہم سے جویریہ نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے زہری نے بیان کیا، انہیں سعید بن مسیب اور ابوعبیدہ نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر میں اتنے دنوں قید میں رہتا جتنے دنوں یوسف علیہ السلام پڑے رہے اور پھر میرے پاس قاصد بلانے آتا تو میں اس کی دعوت قبول کر لیتا۔“' WHERE id = 6735;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا مجھ سے لیث بن سعد نے بیان کیا، کہا مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے، انہیں خارجہ بن ثابت نے خبر دی ‘ انہیں ام علاء رضی اللہ عنہا نے جو ایک انصاری عورت تھیں جنہوں نے نبی کریم صلی اللہ علیہ وسلم سے بیعت کی تھی خبر دی کہ انہوں نے مہاجرین کے ساتھ سلسلہ اخوت قائم کرنے کے لیے قرعہ اندازی کی تو ہمارا قرعہ عثمان بن مظعون رضی اللہ عنہ کے نام نکلا۔ پھر ہم نے انہیں اپنے گھر میں ٹھہرایا۔ اس کے بعد انہیں ایک بیماری ہو گئی جس میں ان کی وفات ہو گئی۔ جب ان کی وفات ہو گئی تو انہیں غسل دیا گیا اور ان کے کپڑوں کا کفن دیا گیا تو رسول اللہ صلی اللہ علیہ وسلم تشریف لائے۔ میں نے کہا ابوالسائب ( عثمان رضی اللہ عنہ ) تم پر اللہ کی رحمت ہو، تمہارے متعلق میری گواہی ہے کہ تمہیں اللہ نے عزت بخشی ہے؟ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ تمہیں کیسے معلوم ہوا کہ اللہ نے انہیں عزت بخشی ہے۔ میں نے عرض کیا، میرے ماں باپ آپ پر قربان ہوں یا رسول اللہ! پھر اللہ کسے عزت بخشے گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، جہاں تک ان کا تعلق ہے تو یقینی چیز ( موت ) ان پر آ چکی ہے اور اللہ کی قسم میں بھی ان کے لیے بھلائی کی امید رکھتا ہوں اور اللہ کی قسم میں رسول اللہ ہونے کے باوجود حتمی طور پر نہیں جانتا کہ میرے ساتھ کیا کیا جائے گا۔ انہوں نے اس کے بعد کہا کہ اللہ کی قسم اس کے بعد میں کبھی کسی کی برات نہیں کروں گی۔' WHERE id = 6745;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہیں سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں «جوامع الكلم» کے ساتھ مبعوث کیا گیا ہوں اور میری مدد رعب کے ذریعہ کی گئی ہے اور میں سویا ہوا تھا کہ زمین کے خزانوں کی کنجیاں میرے پاس لائی گئیں اور میرے ہاتھ میں انہیں رکھ دیا گیا اور محمد نے بیان کیا کہ مجھ تک یہ بات پہنچی ہے کہ «جوامع الكلم» سے مراد یہ ہے کہ بہت سے امور جو نبی کریم صلی اللہ علیہ وسلم سے پہلے کتابوں میں لکھے ہوئے تھے، ان کو اللہ تعالیٰ نے ایک یا دو امور یا اسی جیسے میں جمع کر دیا ہے۔' WHERE id = 6755;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے پاس بیٹھے ہوئے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں سویا ہوا تھا کہ میں نے اپنے آپ کو جنت میں دیکھا وہاں ایک عورت ایک محل کے کنارے وضو کر رہی تھی۔ میں نے پوچھا یہ محل کس کا ہے؟ کہا عمر رضی اللہ عنہ کا۔ پھر میں نے ان کی غیرت یاد کی اور وہاں سے لوٹ کر چلا آیا۔“ اس پر عمر رضی اللہ عنہ رو دئیے اور عرض کیا: یا رسول اللہ! میرے ماں باپ آپ پر فدا ہوں، کیا آپ پر غیرت کروں گا۔' WHERE id = 6766;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا مجھ سے ابوبکر بن ابی اویس نے بیان کیا، انہوں نے کہا مجھ سے سلیمان نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، ان سے سالم نے بیان کیا، ان سے ان کے والد عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں نے ایک پراگندہ بال، کالی عورت دیکھی جو مدینہ سے نکلی اور مہیعہ میں جا کر ٹھہر گئی۔ میں نے اس کی تعبیر یہ لی کہ مدینہ کی وبا مہیعہ یعنی منتقل ہو گئی۔“' WHERE id = 6778;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے زید بن وہب نے بیان کیا، انہوں نے عبداللہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہم سے فرمایا ”تم میرے بعد بعض کام ایسے دیکھو گے جو تم کو برے لگیں گے۔“ صحابہ نے عرض کیا: یا رسول اللہ! آپ اس سلسلے میں کیا حکم فرماتے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”انہیں ان کا حق ادا کرو اور اپنا حق اللہ سے مانگو۔“' WHERE id = 6790;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے، کہا ہم سے شعبہ نے، ان سے واصل نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے اور میرا خیال ہے کہ اس حدیث کو انہوں نے مرفوعاً بیان کیا، کہا کہ قیامت سے پہلے «هرج» کے دن ہوں گے، ان میں علم ختم ہو جائے گا اور جہالت غالب ہو گی۔ ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ حبشی زبان میں «هرج» بمعنی قتل ہے۔' WHERE id = 6802;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے شقیق نے بیان کیا، کہا کہ عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مسلمان کو گالی دینا فسق ہے اور اس کو قتل کرنا کفر ہے۔“' WHERE id = 6812;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، کہا ہم سے اعمش نے بیان کیا، ان سے زید بن وہب نے بیان کیا، ان سے حذیفہ نے بیان کیا کہا ہم سے رسول اللہ صلی اللہ علیہ وسلم نے دو احادیث فرمائی تھیں جن میں سے ایک تو میں نے دیکھ لی دوسری کا انتظار ہے۔ ہم سے آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ امانت لوگوں کے دلوں کی جڑوں میں نازل ہوئی تھی پھر لوگوں نے اسے قرآن سے سیکھا، پھر سنت سے سیکھا اور نبی کریم صلی اللہ علیہ وسلم نے ہم سے امانت کے اٹھ جانے کے متعلق فرمایا تھا کہ ایک شخص ایک نیند سوئے گا اور امانت اس کے دل سے نکال دی جائے گی اور اس کا نشان ایک دھبے جتنا باقی رہ جائے گا، پھر وہ ایک نیند سوئے گا اور پھر امانت نکالی جائے گی تو اس کے دل میں آبلے کی طرح اس کا نشان باقی رہ جائے گا، جیسے تم نے کوئی چنگاری اپنے پاؤں پر گرا لی ہو اور اس کی وجہ سے آبلہ پڑ جائے، تم اس میں سوجن دیکھو گے لیکن اندر کچھ نہیں ہو گا اور لوگ خرید و فروخت کریں گے لیکن کوئی امانت ادا کرنے والا نہیں ہو گا۔ پھر کہا جائے گا کہ فلاں قبیلے میں ایک امانت دار آدمی ہے اور کسی کے متعلق کہا جائے گا کہ وہ کس قدر عقلمند، کتنا خوش طبع، کتنا دلاور آدمی ہے حالانکہ اس کے دل میں رائی کے دانے کے برابر بھی ایمان نہ ہو گا اور مجھ پر ایک زمانہ گزر گیا اور میں اس کی پروا نہیں کرتا تھا کہ تم میں سے کس کے ساتھ میں لین دین کرتا ہوں اگر وہ مسلمان ہوتا تو اس کا اسلام اسے میرے حق کے ادا کرنے پر مجبور کرتا اور اگر وہ نصرانی ہوتا تو اس کے حاکم لوگ اس کو دباتے ایمانداری پر مجبور کرتے۔ لیکن آج کل تو میں صرف فلاں فلاں لوگوں سے ہی لین دین کرتا ہوں۔' WHERE id = 6822;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے شقیق نے بیان کیا، انہوں نے حذیفہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم عمر رضی اللہ عنہ کی خدمت میں بیٹھے ہوئے تھے کہ انہوں نے پوچھا: تم میں سے کسے فتنہ کے بارے میں نبی کریم صلی اللہ علیہ وسلم کا فرمان یاد ہے؟ حذیفہ رضی اللہ عنہ نے کہا کہ انسان کا فتنہ ( آزمائش ) اس کی بیوی، اس کے مال، اس کے بچے اور پڑوسی کے معاملات میں ہوتا ہے جس کا کفارہ نماز، صدقہ، امربالمعروف اور نہی عن المنکر کر دیتا ہے۔ عمر رضی اللہ عنہ نے کہا کہ میں اس کے متعلق نہیں پوچھتا بلکہ اس فتنہ کے بارے میں پوچھتا ہوں جو دریا کی طرح ٹھاٹھیں مارے گا۔ حذیفہ رضی اللہ عنہ نے بیان کیا کہ امیرالمؤمنین آپ پر اس کا کوئی خطرہ نہیں اس کے اور آپ کے درمیان ایک بند دروازہ رکاوٹ ہے۔ عمر رضی اللہ عنہ نے پوچھا کیا وہ دروازہ توڑ دیا جائے گا یا کھولا جائے گا؟ بیان کیا توڑ دیا جائے گا۔ عمر رضی اللہ عنہ نے اس پر کہا کہ پھر تو وہ کبھی بند نہ ہو سکے گا۔ میں نے کہا جی ہاں۔ ہم نے حذیفہ رضی اللہ عنہ سے پوچھا: کیا عمر رضی اللہ عنہ اس دروازہ کے متعلق جانتے تھے؟ فرمایا کہ ہاں، جس طرح میں جانتا ہوں کہ کل سے پہلے رات آئے گی کیونکہ میں نے ایسی بات بیان کی تھی جو بےبنیاد نہیں تھی۔ ہمیں ان سے یہ پوچھتے ہوئے ڈر لگا کہ وہ دروازہ کون تھے۔ چنانچہ ہم نے مسروق سے کہا ( کہ وہ پوچھیں ) جب انہوں نے پوچھا کہ وہ دروازہ کون تھے؟ تو انہوں نے کہا کہ وہ دروازہ عمر رضی اللہ عنہ تھے۔' WHERE id = 6832;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے شہاب نے بیان کیا، ان سے عوف نے بیان کیا، ان سے ابومنہال نے بیان کیا کہ جب عبداللہ بن زیاد اور مروان شام میں تھے اور ابن زبیر رضی اللہ عنہ نے مکہ میں اور خوارج نے بصرہ میں قبضہ کر لیا تھا تو میں اپنے والد کے ساتھ ابوبرزہ اسلمی رضی اللہ عنہ کے پاس گیا۔ جب ہم ان کے گھر میں ایک کمرہ کے سایہ میں بیٹھے ہوئے تھے جو بانس کا بنا ہوا تھا، ہم ان کے پاس بیٹھ گئے اور میرے والد ان سے بات کرنے لگے اور کہا: اے ابوبرزہ! آپ نہیں دیکھتے لوگ کن باتوں میں آفت اور اختلاف میں الجھ گئے ہیں۔ میں نے ان کی زبان سے سب سے پہلی بات یہ سنی کہ میں جو ان قریش کے لوگوں سے ناراض ہوں تو محض اللہ کی رضا مندی کے لیے، اللہ میرا اجر دینے والا ہے۔ عرب کے لوگو! تم جانتے ہو پہلے تمہارا کیا حال تھا تم گمراہی میں گرفتار تھے، اللہ نے اسلام کے ذریعہ اور محمد صلی اللہ علیہ وسلم کے ذریعہ تم کو اس بری حالت سے نجات دی۔ یہاں تک کہ تم اس رتبہ کو پہنچے۔ ( دنیا کے حاکم اور سردار بن گئے ) پھر اسی دنیا نے تم کو خراب کر دیا۔ دیکھو! یہ شخص جو شام میں حاکم بن بیٹھا ہے یعنی مروان دنیا کے لیے لڑ رہا ہے۔ یہ لوگ جو تمہارے سامنے ہیں۔ ( خوارج ) واللہ! یہ لوگ صرف دنیا کے لیے لڑ رہے ہیں اور وہ جو مکہ میں ہے عبداللہ بن زبیر رضی اللہ عنہما، واللہ! وہ بھی صرف دنیا کے لیے لڑ رہا ہے۔' WHERE id = 6844;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا مجھ سے اسماعیل نے بیان کیا، ان سے قیس نے بیان کیا، کہ مجھ سے مغیرہ بن شعبہ رضی اللہ عنہ نے کہا کہ دجال کے بارے میں نبی کریم صلی اللہ علیہ وسلم سے جتنا میں نے پوچھا اتنا کسی نے نہیں پوچھا اور نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا تھا کہ اس سے تمہیں کیا نقصان پہنچے گا۔ میں نے عرض کیا کہ لوگ کہتے ہیں کہ اس کے ساتھ روٹی کا پہاڑ اور پانی کی نہر ہو گی، فرمایا کہ وہ اللہ پر اس سے بھی زیادہ آسان ہے۔' WHERE id = 6854;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے خبر دی، ان سے ابوسعید رضی اللہ عنہ نے بیان کیا کہ ایک دن رسول اللہ صلی اللہ علیہ وسلم نے ہم سے دجال کے متعلق ایک طویل حدیث بیان کی۔ نبی کریم صلی اللہ علیہ وسلم کے ارشادات میں یہ بھی تھا کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”دجال آئے گا اور اس کے لیے ناممکن ہو گا کہ مدینہ کی گھاٹیوں میں داخل ہو۔ چنانچہ وہ مدینہ منورہ کے قریب کسی شور والی زمین پر قیام کرے گا۔ پھر اس دن اس کے پاس ایک مرد مومن جائے گا اور وہ افضل ترین لوگوں میں سے ہو گا۔ اور اس سے کہے گا کہ میں گواہی دیتا ہوں اس بات کی جو رسول اللہ صلی اللہ علیہ وسلم نے ہم سے بیان فرمایا تھا۔ اس پر دجال کہے گا کیا تم دیکھتے ہو اگر میں اسے قتل کر دوں اور پھر زندہ کروں تو کیا تمہیں میرے معاملہ میں شک و شبہ باقی رہے گا؟ اس کے پاس والے لوگ کہیں گے کہ نہیں، چنانچہ وہ اس صاحب کو قتل کر دے گا اور پھر اسے زندہ کر دے گا۔ اب وہ صاحب کہیں گے کہ واللہ! آج سے زیادہ مجھے تیرے معاملے میں پہلے اتنی بصیرت حاصل نہ تھی۔ اس پر دجال پھر انہیں قتل کرنا چاہے گا لیکن اس مرتبہ اسے مار نہ سکے گا۔“' WHERE id = 6864;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے ابوالتیاح نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سنو اور اطاعت کرو، خواہ تم پر کسی ایسے حبشی غلام کو ہی عامل بنایا جائے جس کا سر منقیٰ کی طرح چھوٹا ہو۔“' WHERE id = 6874;
UPDATE hadiths SET urdu = 'ہم سے اسحاق واسطی نے بیان کیا، کہا ہم سے خالد نے، ان سے جریری نے، ان سے ظریف ابوتمیمہ نے بیان کیا کہ میں صفوان اور جندب اور ان کے ساتھیوں کے پاس موجود تھا۔ صفوان اپنے ساتھیوں ( شاگردوں ) کو وصیت کر رہے تھے، پھر ( صفوان اور ان کے ساتھیوں نے جندب رضی اللہ عنہ سے ) پوچھا: کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے کچھ سنا ہے؟ انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے سنا ہے کہ جو لوگوں کو ریاکاری کے طور پر دکھانے کے لیے کام کرے گا اللہ قیامت کے دن اس کی ریاکاری کا حال لوگوں کو سنا دے گا اور فرمایا کہ جو لوگوں کو تکلیف میں مبتلا کرے گا اللہ تعالیٰ قیامت کے دن اسے تکلیف میں مبتلا کرے گا، پھر ان لوگوں نے کہا کہ ہمیں کوئی وصیت کیجئے۔ انہوں نے کہا کہ سب سے پہلے انسان کے جسم میں اس کا پیٹ سڑتا ہے پس جو کوئی طاقت رکھتا ہو کہ پاک و طیب کے سوا اور کچھ نہ کھائے تو اسے ایسا ہی کرنا چاہئے اور جو کوئی طاقت رکھتا ہو وہ چلو بھر لہو بہا کر ( یعنی ناحق خون کر کے ) اپنے آپ کو بہشت میں جانے سے روکے۔ جریری کہتے ہیں کہ میں نے ابوعبداللہ سے پوچھا، کون صاحب اس حدیث میں یہ کہتے ہیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا؟ کیا جندب کہتے ہیں؟ انہوں نے کہا کہ ہاں وہی کہتے ہیں۔' WHERE id = 6884;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، کہا کہ میں نے قتادہ سے سنا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم نے اہل روم کو خط لکھنا چاہا تو صحابہ نے کہا کہ رومی صرف مہر لگا ہوا خط ہی قبول کرتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے چاندی کی ایک مہر بنوائی گویا میں اس کی چمک کو اس وقت بھی دیکھ رہا ہوں اور اس پر کلمہ «محمد رسول الله‏.‏» نقش تھا۔' WHERE id = 6894;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے عبدالملک بن عمرو عقدی نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے سعید بن ابی بردہ نے بیان کیا کہ میں نے اپنے والد سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے میرے والد ( ابوموسیٰ رضی اللہ عنہ ) اور معاذ بن جبل رضی اللہ عنہ کو یمن بھیجا اور ان سے فرمایا کہ آسانی پیدا کرنا اور تنگی نہ کرنا اور خوشخبری دینا اور نفرت نہ دلانا اور آپس میں اتفاق رکھنا۔ ابوموسیٰ رضی اللہ عنہ نے پوچھا کہ ہمارے ملک میں شہد کا نبیذ ( تبع ) بنایا جاتا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر نشہ آور چیز حرام ہے۔ نضر بن شمیل، ابوداؤد طیالسی، یزید بن ہارو اور وکیع نے شعبہ سے بیان کیا، ان سے سعید نے، ان سے ان کے والد نے، ان سے ان کے دادا نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث نقل کی۔' WHERE id = 6904;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں عروہ بن زبیر نے، انہیں زینب بنت ابی سلمہ رضی اللہ عنہا نے خبر دی، ان سے ان کی والدہ ام سلمہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے دروازے پر جھگڑا کرنے والوں کی آواز سنی اور ان کی طرف نکلے۔ پھر ان سے فرمایا کہ میں تمہارے ہی جیسا انسان ہوں، میرے پاس لوگ مقدمہ لے کر آتے ہیں، ممکن ہے ایک فریق دوسرے سے زیادہ عمدہ بولنے والا ہو اور میں اس کے لیے اس حق کا فیصلہ کر دوں اور یہ سمجھوں کہ میں نے فیصلہ صحیح کیا ہے ( حالانکہ وہ صحیح نہ ہو ) تو جس کے لیے میں کسی مسلمان کے حق کا فیصلہ کر دوں تو بلاشبہ یہ فیصلہ جہنم کا ایک ٹکڑا ہے۔' WHERE id = 6915;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدہ بن سلیمان نے خبر دی، ان سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے، ان سے ابو حمید ساعدی نے کہ نبی کریم صلی اللہ علیہ وسلم نے ابن الاتیہ کو بنی سلیم کے صدقہ کی وصول یابی کے لیے عامل بنایا۔ جب وہ نبی کریم صلی اللہ علیہ وسلم کے پاس ( وصول یابی کر کے ) آئے اور نبی کریم صلی اللہ علیہ وسلم نے ان سے حساب طلب فرمایا تو انہوں نے کہا یہ تو آپ لوگوں کا ہے اور یہ مجھے ہدیہ دیا گیا ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم اپنے ماں باپ کے گھر کیوں نہ بیٹھے رہے، اگر تم سچے ہو تو وہاں بھی تمہارے پاس ہدیہ آتا۔ پھر آپ کھڑے ہوئے اور لوگوں کو خطبہ دیا۔ آپ نے حمد و ثنا کے بعد فرمایا، امابعد! میں کچھ لوگوں کو بعض ان کاموں کے لیے عامل بناتا ہوں جو اللہ تعالیٰ نے مجھے سونپے ہیں، پھر تم میں سے کوئی ایک آتا ہے اور کہتا ہے کہ یہ مال تمہارا ہے اور یہ ہدیہ ہے جو مجھے دیا گیا ہے۔ اگر وہ سچا ہے تو پھر کیوں نہ وہ اپنے باپ یا اپنی ماں کے گھر میں بیٹھا رہا تاکہ وہیں اس کا ہدیہ پہنچ جاتا۔ پس اللہ کی قسم! تم میں سے کوئی اگر اس مال میں سے کوئی چیز لے گا۔ ہشام نے آگے کا مضمون اس طرح بیان کیا کہ بلا حق کے تو قیامت کے دن اللہ تعالیٰ اسے اس طرح لائے گا کہ وہ اس کو اٹھائے ہوئے ہو گا۔ آگاہ ہو جاؤ کہ میں اسے پہچان لوں گا جو اللہ کے پاس وہ شخص لے کر آئے گا، اونٹ جو آواز نکال رہا ہو گا یا گائے جو اپنی آواز نکال رہی ہو گی یا بکری جو اپنی آواز نکال رہی ہو گی۔ پھر آپ نے اپنے ہاتھ اٹھائے یہاں تک کہ میں نے آپ کے بغلوں کی سفیدی دیکھی اور فرمایا کیا میں نے پہنچا دیا۔' WHERE id = 6926;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن یزید نے بیان کیا، ان سے سعید ابن ابی ایوب نے بیان کیا، ان سے ابوعقیل زہرہ بن معبد نے بیان کیا انہوں نے اپنے دادا عبداللہ بن ہشام رضی اللہ عنہ سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم کا زمانہ پایا تھا اور ان کی والدہ زینب بنت حمید ان کو رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لے کر حاضر ہوئی تھیں اور عرض کیا تھا یا رسول اللہ! اس سے بیعت لے لیجئے۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ابھی کمسن ہے پھر نبی کریم صلی اللہ علیہ وسلم نے اس کے سر پر ہاتھ پھیرا اور ان کے لیے دعا فرمائی اور اپنے تمام گھر والوں کی طرف سے ایک ہی بکری قربانی کیا کرتے تھے۔' WHERE id = 6938;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے، ان سے قیس بن مسلم نے، ان سے طارق بن شہاب نے کہ ابوبکر رضی اللہ عنہ نے قبائل بزاخہ کے وفد سے ( جو نبی کریم صلی اللہ علیہ وسلم کی وفات کے بعد مرتد ہو گیا تھا اور اب معافی کے لیے آیا تھا ) فرمایا کہ اونٹوں کی دموں کے پیچھے پیچھے جنگلوں میں گھومتے رہو، یہاں تک کہ اللہ تعالیٰ اپنے نبی کریم صلی اللہ علیہ وسلم کے خلیفہ اور مہاجرین کو کوئی امر بتلا دے جس کی وجہ سے وہ تمہارا قصور معاف کر دیں۔' WHERE id = 6949;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، ان سے ابوالاحوص نے، ان سے عاصم نے بیان کیا، ان سے نضر بن انس نے بیان کیا کہ انس بن مالک رضی اللہ عنہ نے کہا اگر میں نے رسول اللہ صلی اللہ علیہ وسلم سے یہ نہ سنا ہوتا کہ موت کی تمنا نہ کرو تو میں موت کی آرزو کرتا۔' WHERE id = 6960;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے ابوالاحوص نے بیان کیا، کہا ہم سے اشعث نے، ان سے اسود بن یزید نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے ( خانہ کعبہ کے ) حطیم کے بارے میں پوچھا کہ کیا یہ بھی خانہ کعبہ کا حصہ ہے؟ فرمایا کہ ہاں۔ میں نے کہا: پھر کیوں ان لوگوں نے اسے بیت اللہ میں داخل نہیں کیا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہاری قوم کے پاس خرچ کی کمی ہو گئی تھی، میں نے کہا کہ یہ خانہ کعبہ کا دروازہ اونچائی پر کیوں ہے؟ فرمایا کہ یہ اس لیے انہوں نے کیا ہے تاکہ جسے چاہیں اندر داخل کریں اور جسے چاہیں روک دیں۔ اگر تمہاری قوم ( قریش ) کا زمانہ جاہلیت سے قریب نہ ہوتا اور مجھے خوف نہ ہوتا کہ ان کے دلوں میں اس سے انکار پیدا ہو گا تو میں حطیم کو بھی خانہ کعبہ میں شامل کر دیتا اور اس کے دروازے کو زمین کے برابر کر دیتا۔' WHERE id = 6970;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن قزعہ نے بیان کیا، انہوں نے کہا مجھ سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ میں ابوطلحہ انصاری، ابوعبیدہ بن الجراح اور ابی بن کعب رضی اللہ عنہم کو کھجور کی شراب پلا رہا تھا۔ اتنے میں ایک آنے والے شخص نے آ کر خبر دی کہ شراب حرام کر دی گئی ہے۔ ابوطلحہ رضی اللہ عنہ نے اس شخص کی خبر سنتے ہی کہا: انس! ان مٹکوں کو بڑھ کر سب کو توڑ دے۔ انس رضی اللہ عنہ نے بیان کیا کہ میں ایک ہاون دستہ کی طرف بڑھا جو ہمارے پاس تھا اور میں نے اس کے نچلے حصہ سے ان مٹکوں پر مارا جس سے وہ سب ٹوٹ گئے۔' WHERE id = 6980;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے یزید بن ابی عبید نے، ان سے سلمہ بن الاکوع رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے قبیلہ اسلم کے ایک صاحب ہند بن اسماء سے فرمایا کہ اپنی قوم میں یا لوگوں میں اعلان کر دو عاشورہ کے دن کہ جس نے کھا لیا ہو وہ اپنا بقیہ دن ( بے کھائے ) پورا کرے اور اس نے نہ کھایا ہو وہ روزہ رکھے۔' WHERE id = 6991;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عباس نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے، کہا ہم سے سفیان ثوری نے، ان سے واصل نے، ان سے ابووائل نے بیان کیا کہ اس مسجد ( خانہ کعبہ ) میں، میں شیبہ بن عثمان حجبی ( جو کعبہ کے کلیدبردار تھے ) کے پاس بیٹھا تو انہوں نے کہا کہ جہاں تم بیٹھے ہو، وہیں عمر رضی اللہ عنہ بھی میرے پاس بیٹھے تھے اور انہوں نے کہا تھا کہ میرا ارادہ ہے کہ کعبہ میں کسی طرح کا سونا چاندی نہ چھوڑوں اور سب مسلمانوں میں تقسیم کر دوں جو نذر اللہ کعبہ میں جمع ہے۔ میں نے کہا کہ آپ ایسا نہیں کر سکتے۔ کہاں کیوں؟ میں نے کہا کہ آپ کے دونوں ساتھیوں ( رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ ) نے ایسا نہیں کیا تھا۔ اس پر انہوں نے کہا کہ وہ دونوں بزرگ ایسے ہی تھے جن کی اقتداء کرنی ہی چاہیے۔' WHERE id = 7001;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید المقری نے بیان کیا، کہا ہم سے سعید بن ابی ایوب نے بیان کیا، کہا مجھ سے عقیل بن خالد نے بیان کیا، ان سے ابن شہاب نے، ان سے عامر بن سعد بن ابی وقاص نے، ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سب سے بڑا مجرم وہ مسلمان ہے جس نے کسی ایسی چیز کے متعلق پوچھا جو حرام نہیں تھی اور اس کے سوال کی وجہ سے وہ حرام کر دی گئی۔“' WHERE id = 7013;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ہشام نے، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم صوم وصال ( افطار و سحر کے بغیر کئی دن کے روزے ) نہ رکھا کرو۔ صحابہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم تو صوم وصال رکھتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تم جیسا نہیں ہوں۔ میں رات گزارتا ہوں اور میرا رب مجھے کھلاتا پلاتا ہے لیکن لوگ صوم وصال سے نہیں رکے۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے ان کے ساتھ دو دن یا دو راتوں میں صوم وصال کیا، پھر لوگوں نے چاند دیکھ لیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر چاند نہ نظر آتا تو میں اور وصال کرتا، نبی کریم صلی اللہ علیہ وسلم کا مقصد انہیں سرزنش کرنا تھا۔' WHERE id = 7023;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا میں نے محمد بن المنکدر سے سنا، بیان کیا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ میں بیمار پڑا تو رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ عیادت کے لیے تشریف لائے۔ یہ دونوں بزرگ پیدل چل کر آئے تھے، پھر نبی کریم صلی اللہ علیہ وسلم پہنچے تو مجھ پر بے ہوشی طاری تھی۔ نبی کریم صلی اللہ علیہ وسلم نے وضو کیا اور وضو کا پانی مجھ پر چھڑکا، اس سے مجھے افاقہ ہوا تو میں نے عرض کیا: یا رسول اللہ! اور بعض اوقات سفیان نے یہ الفاظ بیان کئے کہ میں نے کہا: یا رسول اللہ! میں اپنے مال کے بارے میں کس طرح فیصلہ کروں، میں اپنے مال کا کیا کروں؟ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کوئی جواب نہیں دیا، یہاں تک کہ میراث کی آیت نازل ہوئی۔' WHERE id = 7033;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان نے، کہا ہم سے اعمش نے، ان سے عبداللہ بن مروہ نے، ان سے مسروق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص بھی ظلم کے ساتھ قتل کیا جائے گا اس کے ( گناہ کا ) ایک حصہ آدم علیہ السلام کے پہلے بیٹے ( قابیل ) پر بھی پڑے گا۔“ بعض اوقات سفیان نے اس طرح بیان کیا کہ ”اس کے خون کا“ کیونکہ اسی نے سب سے پہلے ناحق خون کی بری رسم قائم کی۔' WHERE id = 7044;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے مطلب کے مولیٰ عمرو نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ احد پہاڑ رسول اللہ صلی اللہ علیہ وسلم کو ( راستے میں ) دکھائی دیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ وہ پہاڑ ہے جو ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں۔ اے اللہ! ابراہیم علیہ السلام نے مکہ کو حرمت والا قرار دیا تھا اور میں تیرے حکم سے اس کے دونوں پتھریلے کناروں کے درمیانی علاقہ کو حرمت والا قرار دیتا ہوں۔ اس روایت کی متابعت سہل رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے احد کے متعلق کی ہے۔' WHERE id = 7055;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن مبارک نے بیان کیا، کہا ہم سے فضیل نے بیان کیا، انہوں نے کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، ان سے سالم بن عبداللہ نے، ان سے ان کے والد عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کو جب کہ آپ مقام ذوالحلیفہ میں پڑاؤ کئے ہوئے تھے، خواب دکھایا گیا اور کہا گیا کہ آپ ایک مبارک وادی میں ہیں۔' WHERE id = 7066;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر بیکندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے منصور بن صفیہ نے، ان سے کی والدہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ایک خاتون نے رسول اللہ صلی اللہ علیہ وسلم سے سوال کیا ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا اور ہم سے محمد نے بیان کیا یعنی ابن عقبہ نے، کہا ہم سے فضیل بن سلیمان النمیری نے بیان کیا، کہا ہم سے منصور بن عبدالرحمٰن بن شیبہ نے بیان کیا، ان سے ان کی والدہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ایک عورت نے رسول اللہ صلی اللہ علیہ وسلم سے حیض کے متعلق پوچھا کہ اس سے غسل کس طرح کیا جائے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مشک لگا ہوا ایک کپڑا لے کر اس سے پاکی حاصل کر۔ اس عورت نے پوچھا: یا رسول اللہ! میں اس سے پاکی کس طرح حاصل کروں گی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس سے پاکی حاصل کرو۔ انہوں نے پھر پوچھا کہ کس طرح پاکی حاصل کروں؟ نبی کریم صلی اللہ علیہ وسلم نے پھر وہی جواب دیا کہ پاکی حاصل کرو۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کا منشا سمجھ گئی اور اس عورت کو میں نے اپنی طرف کھینچ لیا اور انہیں طریقہ بتایا کہ پاکی سے آپ کا مطلب یہ ہے کہ اس کپڑے کو خون کے مقاموں پر پھیر تاکہ خون کی بدبو رفع ہو جائے۔' WHERE id = 7077;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے عطاء نے بیان کیا، ان سے جابر رضی اللہ عنہ نے (دوسری سند) امام ابوعبداللہ بخاری رحمہ اللہ نے کہا کہ محمد بن بکر برقی نے بیان کیا، ان سے ابن جریج نے بیان کیا، کہا کہ مجھے عطاء نے خبر دی، انہوں نے جابر رضی اللہ عنہ سے سنا، اس وقت اور لوگ بھی ان کے ساتھ تھے، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے صحابہ نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ خالص حج کا احرام باندھا اس کے ساتھ عمرہ کا نہیں باندھا۔ عطاء نے بیان کیا کہ جابر رضی اللہ عنہ نے کہا کہ پھر نبی کریم صلی اللہ علیہ وسلم 4 ذی الحجہ کی صبح کو آئے اور جب ہم بھی حاضر ہوئے تو آپ نے ہمیں حکم دیا کہ ہم حلال ہو جائیں اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ حلال ہو جاؤ اور اپنی بیویوں کے پاس جاؤ۔ عطاء نے بیان کیا اور ان سے جابر رضی اللہ عنہ نے کہ ان پر یہ ضروری نہیں قرار دیا بلکہ صرف حلال کیا، پھر نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ ہم میں یہ بات ہو رہی ہے کہ عرفہ پہنچنے میں صرف پانچ دن رہ گئے ہیں اور پھر بھی نبی کریم صلی اللہ علیہ وسلم نے ہمیں اپنی عورتوں کے پاس جانے کا حکم دیا ہے، کیا ہم عرفات اس حالت میں جائیں کہ مذی یا منی ہمارے ذکر سے ٹپک رہی ہو۔ عطاء نے کہا کہ جابر رضی اللہ عنہ نے اپنے ہاتھ سے اشارہ کیا کہ اس طرح مذی ٹپک رہی ہو، اس کو ہلایا۔ پھر نبی کریم صلی اللہ علیہ وسلم کھڑے ہوئے اور فرمایا، تمہیں معلوم ہے کہ میں تم میں اللہ سے سب سے زیادہ ڈرنے والا ہوں، تم میں سب سے زیادہ سچا ہوں اور سب سے زیادہ نیک ہوں اور اگر میرے پاس ہدی ( قربانی کا جانور ) نہ ہوتا تو میں بھی حلال ہو جاتا، پس تم بھی حلال ہو جاؤ۔ اگر مجھے وہ بات پہلے سے معلوم ہو جاتی جو بعد میں معلوم ہوئی تو میں قربانی کا جانور ساتھ نہ لاتا۔ چنانچہ ہم حلال ہو گئے اور ہم نے نبی کریم صلی اللہ علیہ وسلم کی بات سنی اور آپ کی اطاعت کی۔' WHERE id = 7087;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے عاصم احول نے، ان سے ابوعثمان نہدی نے اور ان سے اسامہ بن زید رضی اللہ عنہما نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے پاس تھے کہ آپ کی ایک صاحبزادی زینب کے بھیجے ہوئے ایک شخص آپ کی خدمت میں حاضر ہوئے کہ ان کے لڑکے جاں کنی میں مبتلا ہیں اور وہ نبی کریم صلی اللہ علیہ وسلم کو بلا رہی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تم جا کر انہیں بتا دو کہ اللہ ہی کا سب مال ہے جو چاہے لے لے اور جو چاہے دیدے اور اس کی بارگاہ میں ہر چیز کے لیے ایک وقت مقرر ہے پس ان سے کہو کہ صبر کریں اور اس پر صبر ثواب کی نیت سے کریں۔ صاحبزادی نے دوبارہ آپ کو قسم دے کر کہلا بھیجا کہ آپ ضرور تشریف لائے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم کھڑے ہوئے اور آپ کے ساتھ سعد بن معاذ اور معاذ بن جبل رضی اللہ عنہما بھی کھڑے ہوئے ( پھر جب آپ صاحبزادی کے گھر پہنچے تو ) بچہ آپ کو دیا گیا اور اس کی سانس اکھڑ رہی تھی جیسے پرانی مشک کا حال ہوتا ہے۔ یہ دیکھ کر نبی کریم صلی اللہ علیہ وسلم کی آنکھوں میں آنسو بھر آئے۔ اس پر سعد رضی اللہ عنہ نے کہا: یا رسول اللہ! یہ کیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ رحمت ہے جو اللہ تعالیٰ نے اپنے بندوں کے دلوں میں رکھی ہے اور اللہ بھی اپنے انہیں بندوں پر رحم کرتا ہے جو رحم دل ہوتے ہیں۔' WHERE id = 7097;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو ابن وہب نے خبر دی، انہوں نے کہا مجھ کو یونس نے خبر دی، انہیں ابن شہاب نے، ان سے عروہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جبرائیل علیہ السلام نے مجھے پکار کر کہا کہ اللہ نے آپ کی قوم کی بات سن لی اور وہ بھی سن لیا جو انہوں نے آپ کو جواب دیا۔“' WHERE id = 7108;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دو مینڈھوں کی قربانی کی اور ذبح کرتے وقت بسم اللہ اللہ اکبر پڑھا۔' WHERE id = 7118;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم سے عفان نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، کہا مجھ سے محمد بن یحییٰ بن حبان نے بیان کیا، ان سے ابن محیریز نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ غزوہ بنو المصطلق میں انہیں باندیاں غنیمت میں ملیں تو انہوں نے چاہا کہ ان سے ہمبستری کریں لیکن حمل نہ ٹھہرے۔ چنانچہ لوگوں نے نبی کریم صلی اللہ علیہ وسلم سے عزل کے متعلق پوچھا: تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم عزل بھی کرو تو کوئی قباحت نہیں مگر قیامت تک جس جان کے متعلق اللہ تعالیٰ نے پیدا ہونا لکھ دیا ہے وہ ضرور پیدا ہو کر رہے گی ( اس لیے تمہارا عزل کرنا بیکار ہے۔ موجودہ جبری نسل بندی کا جواز اس سے نکالنا بالکل غلط ہے۔ اور مجاہد نے قزعہ سے بیان کیا کہ انہوں نے ابو سعید خدری رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی بھی جان جو پیدا ہونی ہے، اللہ تعالیٰ ضرور اسے پیدا کر کے رہے گا۔)' WHERE id = 7128;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا ہم سے عیسیٰ بن طہمان نے بیان کیا، انہوں نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ پردہ کی آیت ام المؤمنین زینب بن جحش رضی اللہ عنہا کے بارے میں نازل ہوئی اور اس دن آپ نے روٹی اور گوشت کے ولیمہ کی دعوت دی اور زینب رضی اللہ عنہا تمام ازواج مطہرات پر فخر کیا کرتی تھیں اور کہتی تھیں کہ میرا نکاح اللہ نے آسمان پر کرایا تھا۔' WHERE id = 7139;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن الولید نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم تیمی نے، ان سے ان کے والد نے اور ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے آیت «والشمس تجري لمستقر لها‏» کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کا مستقر عرش کے نیچے ہے۔' WHERE id = 7150;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن عبدالصمد نے بیان کیا، ان سے ابوعمران نے، ان سے ابوبکر بن عبداللہ بن قیس نے، ان سے ان کی والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دو جنتیں ایسی ہوں گی جو خود اور اس میں سارا سامان چاندی کا ہو گا اور دو جنتیں ایسی ہوں گی جو خود اور اس کا سارا سامان سونے کا ہو گا اور جنت عدن میں قوم اور اللہ کے دیدار کے درمیان صرف چادر کبریائی رکاوٹ ہو گی جو اللہ رب العزت کے منہ پر پڑی ہو گی۔“' WHERE id = 7160;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا ہم سے اعمش نے بیان کیا، انہوں نے کہا زید بن وہب سے سنا اور انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا کہ ہم سے رسول اللہ صلی اللہ علیہ وسلم نے بیان فرمایا جو صادق و مصدق ہیں کہ انسان کا نطفہ ماں کے پیٹ میں چالیس دن اور راتوں تک جمع رہتا ہے پھر وہ خون کی پھٹکی بن جاتا ہے، پھر وہ گوشت کا لوتھڑا ہو جاتا ہے پھر اس کے بعد فرشتہ بھیجا جاتا ہے اور اسے چار چیزوں کا حکم ہوتا ہے۔ چنانچہ وہ اس کی روزی، اس کی موت، اس کا عمل اور یہ کہ وہ بدبخت ہے یا نیک بخت لکھ لیتا ہے۔ پھر اس میں روح پھونکتا ہے اور تم میں سے ایک شخص جنت والوں کے سے عمل کرتا ہے اور جب اس کے اور جنت کے درمیان صرف ایک ہاتھ کا فرق رہ جاتا ہے تو اس کی تقدیر غالب آتی ہے اور وہ دوزخ والوں کے عمل کرنے لگتا ہے اور دوزخ میں داخل ہوتا ہے۔ اسی طرح ایک شخص دوزخ والوں کے عمل کرتا ہے اور جب اس کے اور دوزخ کے درمیان صرف ایک بالشت کا فاصلہ رہ جاتا ہے تو تقدیر غالب آتی ہے اور جنت والوں کے کام کرنے لگتا ہے، پھر جنت میں داخل ہوتا ہے۔' WHERE id = 7170;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے عبدالوارث نے بیان کیا، ان سے عبدالعزیز نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب تم دعا کرو تو عزم کے ساتھ کرو اور کوئی دعا میں یہ نہ کہے کہ اگر تو چاہے تو فلاں چیز مجھے عطا کر، کیونکہ اللہ سے کوئی زبردستی کرنے والا نہیں۔“' WHERE id = 7180;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، ان سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ہر نبی کی ایک دعا قبول ہوتی ہے تو میں چاہتا ہوں اگر اللہ نے چاہا کہ اپنی دعا قیامت کے دن اپنی امت کی شفاعت کے لیے محفوظ رکھوں۔“' WHERE id = 7190;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جس قدر مجھے خدیجہ رضی اللہ عنہا پر غیرت آتی تھی اور کسی عورت پر نہیں آتی تھی اور ان کے رب نے حکم دیا تھا کہ انہیں جنت میں ایک گھر کی بشارت دے دیں۔' WHERE id = 7200;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے ابوعبداللہ الاغر نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ہمارا رب تبارک و تعالیٰ ہر رات آسمان دنیا پر آتا ہے، اس وقت جب رات کا آخری تہائی حصہ باقی رہ جاتا ہے اور کہتا ہے کہ مجھے کون بلاتا ہے کہ میں اسے جواب دوں، مجھ سے کون مانگتا ہے کہ میں اسے عطا کروں، مجھ سے کون مغفرت طلب کرتا ہے میں اس کی مغفرت کروں؟“' WHERE id = 7210;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ایک شخص نے جس نے ( بنی اسرائیل میں سے ) کوئی نیک کام کبھی نہیں کیا تھا، وصیت کی کہ جب وہ مر جائے تو اسے جلا ڈالیں اور اس کی آدھی راکھ خشکی میں اور آدھی دریا میں بکھیر دیں کیونکہ اللہ کی قسم اگر اللہ نے مجھ پر قابو پا لیا تو ایسا عذاب مجھ کو دے گا جو دنیا کے کسی شخص کو بھی وہ نہیں دے گا۔ پھر اللہ نے سمندر کو حکم دیا اور اس نے تمام راکھ جمع کر دی جو اس کے اندر تھی۔ پھر اس نے خشکی کو حکم دیا اور اس نے بھی اپنی تمام راکھ جمع کر دی جو اس کے اندر تھی۔ پھر اللہ تعالیٰ نے اس سے پوچھا تو نے ایسا کیوں کیا تھا؟ اس نے عرض کیا اے رب! تیرے خوف سے میں نے ایسا کیا اور تو سب سے زیادہ جاننے والا ہے۔ پس اللہ تعالیٰ نے اس کو بخش دیا۔“' WHERE id = 7221;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ہشام نے بیان کیا، انہوں نے کہا ہم سے قتادہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ایمان والے قیامت کے دن جمع کئے جائیں گے اور وہ کہیں گے کہ کاش کوئی ہماری شفاعت کرتا تاکہ ہم اپنی اس حالت سے نجات پاتے، چنانچہ وہ آدم علیہ السلام کے پاس آئیں گے اور کہیں گے کہ آپ آدم ہیں انسانوں کے پردادا۔ اللہ نے آپ کو اپنے ہاتھ سے پیدا کیا، آپ کو سجدہ کرنے کا فرشتوں کو حکم دیا اور ہر چیز کے نام آپ کو سکھائے پس آپ اپنے رب کے حضور میں ہماری شفاعت کریں، آپ جواب دیں گے کہ میں اس قابل نہیں ہوں اور آپ اپنی غلطی انہیں یاد دلائیں گے جو آپ سے سرزد ہوئی تھی۔“' WHERE id = 7231;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ آیت «ولا تجهر بصلاتك ولا تخافت بها‏» دعا کے بارے میں نازل ہوئی، یعنی دعا نہ بہت چلا کر مانگ نہ آہستہ بلکہ درمیانہ راستہ اختیار کر۔' WHERE id = 7241;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے محمد بن زیاد نے بیان کیا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا ان سے نبی کریم صلی اللہ علیہ وسلم نے، اللہ تعالیٰ سے روایت کرتے ہیں کہ پروردگار نے فرمایا ہر گناہ کا ایک کفارہ ہے ( جس سے وہ گناہ معاف ہو جاتا ہے ) اور روزہ خاص میرے لیے ہے اور میں ہی اس کی جزا دوں گا اور روزہ دار کے منہ کی بو اللہ کے نزدیک مشک کی خوشبو سے بڑھ کر ہے۔' WHERE id = 7253;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا ہم مجھ سے امام مالک نے بیان کا، ان سے عبدالرحمٰن بن عبداللہ بن عبدالرحمٰن بن ابی صعصعہ نے بیان کیا، ان سے ان کے والد نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے خبر دی کہ انہوں نے ان سے کہا میرا خیال ہے کہ تم بکریوں کو اور جنگل کو پسند کرتے ہو۔ پس جب تم اپنی بکریوں میں یا جنگل میں ہو اور نماز کے لیے اذان دو تو بلند آواز کے ساتھ دو کیونکہ مؤذن کی آواز جہاں تک بھی پہنچے گی اور اسے جن و انس اور دوسری جو چیزیں بھی سنیں گی وہ قیامت کے دن اس کی گواہی دیں گی۔ ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ میں نے اس حدیث کو رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے۔' WHERE id = 7263;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، ان سے حماد بن زید نے بیان کیا، ان سے ایوب نے بیان کیا، ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ان تصویروں کو بنانے والوں پر قیامت میں عذاب ہو گا اور ان سے کہا جائے گا کہ تم نے جو بنایا ہے اسے زندہ بھی کرو۔“' WHERE id = 7273;
